{
  "name": "ForgeAI Game Engine",
  "description": "An AI-powered game development platform where you upload assets and prompts to generate fully playable web games instantly.",
  "requestFramePermissions": [
    "camera",
    "microphone"
  ]
}

export type AssetType = 'character' | 'environment' | 'animation' | 'dialogue' | 'music';

export interface GameAsset {
  id: string;
  name: string;
  type: AssetType;
  content: string; // Base64 for files, text for dialogue
  mimeType: string;
}

export interface GenerationStatus {
  step: 'idle' | 'analyzing' | 'coding' | 'compiling' | 'ready' | 'error';
  message: string;
}

export interface GeneratedGame {
  code: string; // HTML/JS combo
  title: string;
}

import { GoogleGenAI, Type } from "@google/genai";
import { GameAsset } from "../types";

export const generateGame = async (
  prompt: string,
  assets: GameAsset[]
): Promise<{ code: string; title: string }> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const assetDescriptions = assets.map(a => `- ${a.name} (${a.type})`).join('\n');

  const systemInstruction = `
    You are a world-class Game Developer and Creative Technologist. 
    Your task is to generate a fully functional, single-file HTML/JavaScript game based on user-provided assets and a prompt.

    GUIDELINES:
    1. Output a single HTML string containing all CSS and JS.
    2. Use Phaser.js (CDN: https://cdn.jsdelivr.net/npm/phaser@3.60.0/dist/phaser.min.js) for the engine.
    3. For assets:
       - Use the base64 data provided in the parts to create data URIs for images/sounds.
       - Map the provided asset names to their data URIs in the Phaser loader.
    4. The game must be polished, responsive to 'window.innerWidth/Height', and include basic controls.
    5. The prompt is: "${prompt}".
    6. Ensure the game logic reflects the "dialogue" or "music" assets if provided.
    7. Return your response in JSON format with 'code' and 'title' fields.
  `;

  // Prepare content parts
  const parts: any[] = [
    { text: `Create a game with this prompt: ${prompt}` },
    { text: `Available assets metadata:\n${assetDescriptions}` }
  ];

  // Add asset data as parts
  assets.forEach(asset => {
    if (asset.content.startsWith('data:')) {
      const base64Data = asset.content.split(',')[1];
      parts.push({
        inlineData: {
          mimeType: asset.mimeType,
          data: base64Data
        }
      });
      parts.push({ text: `This is the data for asset: ${asset.name}` });
    } else {
      parts.push({ text: `Dialogue/Text asset "${asset.name}": ${asset.content}` });
    }
  });

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: { parts },
    config: {
      systemInstruction,
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          code: { type: Type.STRING, description: 'The complete HTML/JS/CSS source code for the game.' },
          title: { type: Type.STRING, description: 'A catchy title for the generated game.' }
        },
        required: ['code', 'title']
      }
    }
  });

  const result = JSON.parse(response.text || '{}');
  return {
    code: result.code || '<h1>Failed to generate game.</h1>',
    title: result.title || 'Untitled Forge Game'
  };
};

import React from 'react';
import { AssetType, GameAsset } from '../types';
import { Upload, X, Gamepad2, Image as ImageIcon, Music, MessageSquare, Play } from 'lucide-react';

interface AssetUploaderProps {
  assets: GameAsset[];
  onAssetsChange: (assets: GameAsset[]) => void;
}

export const AssetUploader: React.FC<AssetUploaderProps> = ({ assets, onAssetsChange }) => {
  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>, type: AssetType) => {
    const files = e.target.files;
    if (!files) return;

    Array.from(files).forEach(file => {
      const reader = new FileReader();
      reader.onload = (event) => {
        const newAsset: GameAsset = {
          id: Math.random().toString(36).substr(2, 9),
          name: file.name,
          type,
          content: event.target?.result as string,
          mimeType: file.type
        };
        onAssetsChange([...assets, newAsset]);
      };
      reader.readAsDataURL(file);
    });
  };

  const removeAsset = (id: string) => {
    onAssetsChange(assets.filter(a => a.id !== id));
  };

  const AssetSection = ({ type, icon: Icon, label }: { type: AssetType, icon: any, label: string }) => (
    <div className="bg-zinc-900/50 p-4 rounded-xl border border-zinc-800">
      <div className="flex items-center justify-between mb-3">
        <div className="flex items-center gap-2">
          <Icon className="w-4 h-4 text-emerald-400" />
          <span className="text-sm font-medium">{label}</span>
        </div>
        <label className="cursor-pointer bg-zinc-800 hover:bg-zinc-700 px-3 py-1 rounded text-xs transition-colors">
          Add
          <input 
            type="file" 
            className="hidden" 
            onChange={(e) => handleFileUpload(e, type)}
            accept={type === 'music' ? 'audio/*' : 'image/*'}
          />
        </label>
      </div>

      <div className="space-y-2 max-h-40 overflow-y-auto">
        {assets.filter(a => a.type === type).length === 0 ? (
          <p className="text-xs text-zinc-500 italic">No {label.toLowerCase()} added</p>
        ) : (
          assets.filter(a => a.type === type).map(asset => (
            <div key={asset.id} className="flex items-center justify-between bg-zinc-800/50 p-2 rounded text-xs group">
              <span className="truncate max-w-[150px]">{asset.name}</span>
              <button 
                onClick={() => removeAsset(asset.id)}
                className="text-zinc-500 hover:text-red-400 opacity-0 group-hover:opacity-100 transition-opacity"
              >
                <X className="w-3 h-3" />
              </button>
            </div>
          ))
        )}
      </div>
    </div>
  );

  return (
    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
      <AssetSection type="character" icon={Gamepad2} label="Characters" />
      <AssetSection type="environment" icon={ImageIcon} label="Environments" />
      <AssetSection type="music" icon={Music} label="Music / SFX" />
      <AssetSection type="dialogue" icon={MessageSquare} label="Dialogue / Scripts" />
    </div>
  );
};

import React, { useEffect, useRef } from 'react';

interface GameRunnerProps {
  code: string;
  title: string;
}

export const GameRunner: React.FC<GameRunnerProps> = ({ code, title }) => {
  const iframeRef = useRef<HTMLIFrameElement>(null);

  useEffect(() => {
    if (iframeRef.current) {
      const doc = iframeRef.current.contentDocument;
      if (doc) {
        doc.open();
        doc.write(code);
        doc.close();
      }
    }
  }, [code]);

  return (
    <div className="w-full h-full flex flex-col">
      <div className="bg-zinc-900 border-b border-zinc-800 px-4 py-2 flex items-center justify-between">
        <h3 className="text-sm font-bold text-emerald-400">{title}</h3>
        <div className="flex gap-1">
          <div className="w-2 h-2 rounded-full bg-red-500"></div>
          <div className="w-2 h-2 rounded-full bg-yellow-500"></div>
          <div className="w-2 h-2 rounded-full bg-green-500"></div>
        </div>
      </div>
      <div className="flex-1 bg-black relative">
        <iframe
          ref={iframeRef}
          title="Generated Game"
          className="w-full h-full border-none"
          sandbox="allow-scripts"
        />
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { AssetUploader } from './components/AssetUploader';
import { GameRunner } from './components/GameRunner';
import { generateGame } from './services/gemini';
import { GameAsset, GenerationStatus, GeneratedGame } from './types';
import { Wand2, Loader2, Sparkles, Terminal, Rocket, Layout, Settings } from 'lucide-react';

const App: React.FC = () => {
  const [assets, setAssets] = useState<GameAsset[]>([]);
  const [prompt, setPrompt] = useState('');
  const [status, setStatus] = useState<GenerationStatus>({ step: 'idle', message: '' });
  const [game, setGame] = useState<GeneratedGame | null>(null);

  const handleGenerate = async () => {
    if (!prompt.trim()) return;

    setStatus({ step: 'analyzing', message: 'Analyzing your vision and assets...' });
    try {
      setStatus({ step: 'coding', message: 'Gemini is writing the game engine logic...' });
      const result = await generateGame(prompt, assets);

      setStatus({ step: 'compiling', message: 'Optimizing and compiling the game world...' });
      setTimeout(() => {
        setGame(result);
        setStatus({ step: 'ready', message: 'Game successfully deployed!' });
      }, 1000);

    } catch (error) {
      console.error(error);
      setStatus({ step: 'error', message: 'Failed to generate game. Please try again.' });
    }
  };

  return (
    <div className="flex flex-col h-screen max-h-screen">
      {/* Header */}
      <header className="border-b border-zinc-800 p-4 bg-zinc-950 flex items-center justify-between">
        <div className="flex items-center gap-2">
          <div className="bg-emerald-500 p-1.5 rounded-lg">
            <Rocket className="w-6 h-6 text-black" />
          </div>
          <div>
            <h1 className="text-xl font-bold tracking-tight">ForgeAI</h1>
            <p className="text-[10px] text-zinc-500 uppercase tracking-widest font-semibold">Generative Game Engine</p>
          </div>
        </div>

        <div className="flex items-center gap-4">
          <div className="hidden md:flex items-center gap-4 text-xs text-zinc-400">
             <span className="flex items-center gap-1"><Layout className="w-3 h-3" /> Dashboard</span>
             <span className="flex items-center gap-1"><Settings className="w-3 h-3" /> Engine Config</span>
          </div>
          <button 
            disabled={status.step !== 'idle' && status.step !== 'ready' && status.step !== 'error'}
            onClick={handleGenerate}
            className={`flex items-center gap-2 px-6 py-2 rounded-full font-bold transition-all ${
              status.step === 'idle' || status.step === 'ready' || status.step === 'error'
                ? 'bg-emerald-500 text-black hover:bg-emerald-400 shadow-[0_0_20px_rgba(16,185,129,0.3)]' 
                : 'bg-zinc-800 text-zinc-500 cursor-not-allowed'
            }`}
          >
            {status.step === 'idle' || status.step === 'ready' || status.step === 'error' ? (
              <>
                <Wand2 className="w-4 h-4" />
                Forge Game
              </>
            ) : (
              <>
                <Loader2 className="w-4 h-4 animate-spin" />
                Forging...
              </>
            )}
          </button>
        </div>
      </header>

      <main className="flex-1 flex overflow-hidden">
        {/* Left Panel: Inputs */}
        <div className="w-full md:w-96 border-r border-zinc-800 bg-zinc-950/50 p-6 flex flex-col gap-6 overflow-y-auto">
          <section>
            <div className="flex items-center gap-2 mb-3">
              <Sparkles className="w-4 h-4 text-emerald-400" />
              <h2 className="text-sm font-bold uppercase tracking-wider text-zinc-400">Game Concept</h2>
            </div>
            <textarea
              value={prompt}
              onChange={(e) => setPrompt(e.target.value)}
              placeholder="Describe your game idea (e.g., A side-scrolling space shooter where I play as a cat explorer)..."
              className="w-full h-32 bg-zinc-900 border border-zinc-800 rounded-xl p-4 text-sm focus:outline-none focus:ring-2 focus:ring-emerald-500/50 transition-all resize-none"
            />
          </section>

          <section className="flex-1">
            <div className="flex items-center gap-2 mb-3">
              <Terminal className="w-4 h-4 text-emerald-400" />
              <h2 className="text-sm font-bold uppercase tracking-wider text-zinc-400">Asset Vault</h2>
            </div>
            <AssetUploader assets={assets} onAssetsChange={setAssets} />
          </section>

          {status.message && (
            <div className={`p-4 rounded-xl border text-xs font-medium ${
              status.step === 'error' ? 'bg-red-500/10 border-red-500/20 text-red-400' : 'bg-emerald-500/10 border-emerald-500/20 text-emerald-400'
            }`}>
              <div className="flex items-center gap-2">
                {status.step !== 'ready' && status.step !== 'error' && <Loader2 className="w-3 h-3 animate-spin" />}
                {status.message}
              </div>
            </div>
          )}
        </div>

        {/* Right Panel: Output */}
        <div className="flex-1 bg-zinc-900 flex items-center justify-center p-6 md:p-12 overflow-hidden">
          {game ? (
            <div className="w-full h-full max-w-5xl rounded-2xl overflow-hidden shadow-2xl border border-zinc-800 bg-black flex flex-col">
              <GameRunner code={game.code} title={game.title} />
            </div>
          ) : (
            <div className="text-center space-y-4 max-w-md">
              <div className="w-20 h-20 bg-zinc-800 rounded-3xl flex items-center justify-center mx-auto mb-6 rotate-3">
                <Rocket className="w-10 h-10 text-zinc-600" />
              </div>
              <h3 className="text-2xl font-bold text-zinc-300">No Game Forged Yet</h3>
              <p className="text-zinc-500 text-sm">
                Upload your characters, environments, and background music. 
                Then describe your vision to see it come to life in the Forge.
              </p>
              <div className="flex gap-2 justify-center pt-4">
                <div className="px-3 py-1 bg-zinc-800 rounded-full text-[10px] text-zinc-500 border border-zinc-700">Single Player</div>
                <div className="px-3 py-1 bg-zinc-800 rounded-full text-[10px] text-zinc-500 border border-zinc-700">Instant Deploy</div>
                <div className="px-3 py-1 bg-zinc-800 rounded-full text-[10px] text-zinc-500 border border-zinc-700">AI Driven</div>
              </div>
            </div>
          )}
        </div>
      </main>

      {/* Footer Info */}
      <footer className="h-8 bg-zinc-950 border-t border-zinc-900 px-4 flex items-center justify-between text-[10px] text-zinc-600">
        <div>GPU ACCELERATED ENGINE • v1.0.4-BETA</div>
        <div className="flex gap-4">
          <span>{assets.length} ASSETS CACHED</span>
          <span className="text-emerald-500/50">SYSTEMS NOMINAL</span>
        </div>
      </footer>
    </div>
  );
};

export default App;

