import React, { useState } from 'react';
import { AssetType, GameAsset } from '../types';
import { Upload, X, Gamepad2, Image as ImageIcon, Music, MessageSquare, Plus } from 'lucide-react';

interface AssetUploaderProps {
  assets: GameAsset[];
  onAssetsChange: (assets: GameAsset[]) => void;
}

export const AssetUploader: React.FC<AssetUploaderProps> = ({ assets, onAssetsChange }) => {
  const [dialogueInput, setDialogueInput] = useState('');

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>, type: AssetType) => {
    const files = e.target.files;
    if (!files) return;

    Array.from(files).forEach(file => {
      const reader = new FileReader();
      reader.onload = (event) => {
        const newAsset: GameAsset = {
          id: Math.random().toString(36).substr(2, 9),
          name: file.name,
          type,
          content: event.target?.result as string,
          mimeType: file.type
        };
        onAssetsChange([...assets, newAsset]);
      };
      reader.readAsDataURL(file);
    });
    // Reset input
    e.target.value = '';
  };

  const addDialogueAsset = () => {
    if (!dialogueInput.trim()) return;
    const newAsset: GameAsset = {
      id: Math.random().toString(36).substr(2, 9),
      name: `Script ${assets.filter(a => a.type === 'dialogue').length + 1}`,
      type: 'dialogue',
      content: dialogueInput,
      mimeType: 'text/plain'
    };
    onAssetsChange([...assets, newAsset]);
    setDialogueInput('');
  };

  const removeAsset = (id: string) => {
    onAssetsChange(assets.filter(a => a.id !== id));
  };

  const AssetSection = ({ type, icon: Icon, label, allowText }: { type: AssetType, icon: any, label: string, allowText?: boolean }) => (
    <div className="bg-zinc-900/50 p-4 rounded-xl border border-zinc-800 flex flex-col h-full min-h-[160px]">
      <div className="flex items-center justify-between mb-3 shrink-0">
        <div className="flex items-center gap-2">
          <Icon className="w-4 h-4 text-emerald-400" />
          <span className="text-sm font-medium">{label}</span>
        </div>
        {!allowText && (
          <label className="cursor-pointer bg-zinc-800 hover:bg-zinc-700 px-3 py-1 rounded text-[10px] font-bold transition-colors">
            UPLOAD
            <input 
              type="file" 
              className="hidden" 
              onChange={(e) => handleFileUpload(e, type)}
              accept={type === 'music' ? 'audio/*' : 'image/*'}
            />
          </label>
        )}
      </div>

      {allowText && (
        <div className="flex gap-2 mb-3 shrink-0">
          <input 
            type="text" 
            value={dialogueInput}
            onChange={(e) => setDialogueInput(e.target.value)}
            placeholder="Add story beats..."
            className="flex-1 bg-zinc-800 border border-zinc-700 rounded px-2 py-1 text-xs focus:outline-none focus:ring-1 focus:ring-emerald-500"
            onKeyDown={(e) => e.key === 'Enter' && addDialogueAsset()}
          />
          <button 
            onClick={addDialogueAsset}
            className="bg-emerald-500 text-black p-1 rounded hover:bg-emerald-400"
          >
            <Plus className="w-4 h-4" />
          </button>
        </div>
      )}

      <div className="space-y-1 overflow-y-auto flex-1 pr-1">
        {assets.filter(a => a.type === type).length === 0 ? (
          <p className="text-[10px] text-zinc-600 italic mt-2">No {label.toLowerCase()} added</p>
        ) : (
          assets.filter(a => a.type === type).map(asset => (
            <div key={asset.id} className="flex items-center justify-between bg-zinc-800/30 p-1.5 rounded text-[10px] group border border-transparent hover:border-zinc-700 transition-colors">
              <span className="truncate max-w-[120px] text-zinc-300">{asset.name}</span>
              <button 
                onClick={() => removeAsset(asset.id)}
                className="text-zinc-600 hover:text-red-400 opacity-0 group-hover:opacity-100 transition-opacity"
              >
                <X className="w-3 h-3" />
              </button>
            </div>
          ))
        )}
      </div>
    </div>
  );

  return (
    <div className="grid grid-cols-1 md:grid-cols-2 gap-3 h-full">
      <AssetSection type="character" icon={Gamepad2} label="Characters" />
      <AssetSection type="environment" icon={ImageIcon} label="Environments" />
      <AssetSection type="music" icon={Music} label="Music / SFX" />
      <AssetSection type="dialogue" icon={MessageSquare} label="Dialogue / Scripts" allowText />
    </div>
  );
};

import { GoogleGenAI, Type } from "@google/genai";
import { GameAsset } from "../types";

export const generateGame = async (
  prompt: string,
  assets: GameAsset[]
): Promise<{ code: string; title: string }> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const assetDescriptions = assets.map(a => `- ${a.name} (${a.type})`).join('\n');

  const systemInstruction = `
    You are an elite Game Architect. Create a standalone, high-performance HTML5 game using Phaser 3.

    ENGINE SPECS:
    - Use Phaser CDN: https://cdn.jsdelivr.net/npm/phaser@3.60.0/dist/phaser.min.js
    - Target container: document.body (full screen)
    - Handle window resizing correctly.

    ASSET INTEGRATION:
    - Use the provided data URIs for images and audio. 
    - Map asset names carefully: if an asset is named "Hero.png", load it as 'hero'.
    - If dialogue/scripts are provided, use them for game narrative, NPC interactions, or levels.

    CODE STRUCTURE:
    - Output a COMPLETE single-file HTML document (<!DOCTYPE html>...</html>).
    - Include CSS to hide scrollbars and center the canvas.
    - Write clean, commented ES6+ JavaScript.
    - Ensure basic input handling (keyboard/mouse).

    GAME CONCEPT: ${prompt}

    AVAILABLE ASSETS:
    ${assetDescriptions}

    RESPONSE FORMAT:
    You MUST return JSON with:
    {
      "code": "Full HTML string",
      "title": "Short catchy title"
    }
  `;

  const parts: any[] = [
    { text: `Request: Generate a game titled around '${prompt}'.` }
  ];

  assets.forEach(asset => {
    if (asset.content.startsWith('data:')) {
      const [header, data] = asset.content.split(',');
      const mime = header.split(':')[1].split(';')[0];
      parts.push({
        inlineData: {
          mimeType: mime,
          data: data
        }
      });
      parts.push({ text: `Asset content for: ${asset.name} (${asset.type})` });
    } else {
      parts.push({ text: `Textual asset "${asset.name}": ${asset.content}` });
    }
  });

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: { parts },
    config: {
      systemInstruction,
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          code: { type: Type.STRING },
          title: { type: Type.STRING }
        },
        required: ['code', 'title']
      }
    }
  });

  try {
    const result = JSON.parse(response.text || '{}');
    return {
      code: result.code || '<html><body><h1>Error Generating Engine</h1></body></html>',
      title: result.title || 'Forged Game'
    };
  } catch (e) {
    console.error("Failed to parse Gemini response:", response.text);
    return {
      code: `<html><body style="background:#000;color:#fff;display:flex;align-items:center;justify-content:center;height:100vh;font-family:sans-serif;">
              <div style="text-align:center;">
                <h1>Forge Malfunction</h1>
                <p>The AI response was malformed. Please try again.</p>
                <pre style="text-align:left;max-width:80vw;overflow:auto;background:#222;padding:1rem;">${(response.text || '').substring(0, 500)}...</pre>
              </div>
            </body></html>`,
      title: 'Forge Error'
    };
  }
};

import React, { useState } from 'react';
import { AssetUploader } from './components/AssetUploader';
import { GameRunner } from './components/GameRunner';
import { generateGame } from './services/gemini';
import { GameAsset, GenerationStatus, GeneratedGame } from './types';
import { Wand2, Loader2, Sparkles, Terminal, Rocket, Layout, Settings, Trash2, Cpu } from 'lucide-react';

const App: React.FC = () => {
  const [assets, setAssets] = useState<GameAsset[]>([]);
  const [prompt, setPrompt] = useState('');
  const [status, setStatus] = useState<GenerationStatus>({ step: 'idle', message: '' });
  const [game, setGame] = useState<GeneratedGame | null>(null);

  const handleGenerate = async () => {
    if (!prompt.trim()) return;

    setGame(null);
    setStatus({ step: 'analyzing', message: 'Synthesizing creative prompt and assets...' });
    try {
      setStatus({ step: 'coding', message: 'Gemini is architecting the game logic...' });
      const result = await generateGame(prompt, assets);

      setStatus({ step: 'compiling', message: 'Finalizing build and deploying to sandbox...' });
      setTimeout(() => {
        setGame(result);
        setStatus({ step: 'ready', message: 'Engine ready. Initializing world...' });
      }, 800);

    } catch (error) {
      console.error(error);
      setStatus({ step: 'error', message: 'Forge failure: Unable to construct game world.' });
    }
  };

  const clearAssets = () => {
    if (confirm('Clear all uploaded assets?')) {
      setAssets([]);
    }
  };

  return (
    <div className="flex flex-col h-screen max-h-screen font-sans selection:bg-emerald-500/30">
      {/* Header */}
      <header className="border-b border-zinc-800 p-4 bg-zinc-950/80 backdrop-blur-md sticky top-0 z-50 flex items-center justify-between">
        <div className="flex items-center gap-3">
