import React, { useState } from 'react';
import { AssetType, GameAsset } from '../types';
import { Upload, X, Gamepad2, Image as ImageIcon, Music, MessageSquare, Plus, Box } from 'lucide-react';

interface AssetUploaderProps {
  assets: GameAsset[];
  onAssetsChange: (assets: GameAsset[]) => void;
}

export const AssetUploader: React.FC<AssetUploaderProps> = ({ assets, onAssetsChange }) => {
  const [dialogueInput, setDialogueInput] = useState('');

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>, type: AssetType) => {
    const files = e.target.files;
    if (!files) return;

    Array.from(files).forEach(file => {
      const reader = new FileReader();
      reader.onload = (event) => {
        const newAsset: GameAsset = {
          id: Math.random().toString(36).substr(2, 9),
          name: file.name,
          type,
          content: event.target?.result as string,
          mimeType: file.type || 'application/octet-stream'
        };
        onAssetsChange([...assets, newAsset]);
      };
      reader.readAsDataURL(file);
    });
    // Reset input
    e.target.value = '';
  };

  const addDialogueAsset = () => {
    if (!dialogueInput.trim()) return;
    const newAsset: GameAsset = {
      id: Math.random().toString(36).substr(2, 9),
      name: `Script ${assets.filter(a => a.type === 'dialogue').length + 1}`,
      type: 'dialogue',
      content: dialogueInput,
      mimeType: 'text/plain'
    };
    onAssetsChange([...assets, newAsset]);
    setDialogueInput('');
  };

  const removeAsset = (id: string) => {
    onAssetsChange(assets.filter(a => a.id !== id));
  };

  const AssetSection = ({ type, icon: Icon, label, allowText, accept }: { type: AssetType, icon: any, label: string, allowText?: boolean, accept?: string }) => (
    <div className="bg-zinc-900/50 p-4 rounded-xl border border-zinc-800 flex flex-col h-full min-h-[160px]">
      <div className="flex items-center justify-between mb-3 shrink-0">
        <div className="flex items-center gap-2">
          <Icon className="w-4 h-4 text-emerald-400" />
          <span className="text-sm font-medium">{label}</span>
        </div>
        {!allowText && (
          <label className="cursor-pointer bg-zinc-800 hover:bg-zinc-700 px-3 py-1 rounded text-[10px] font-bold transition-colors">
            UPLOAD
            <input 
              type="file" 
              className="hidden" 
              onChange={(e) => handleFileUpload(e, type)}
              accept={accept}
            />
          </label>
        )}
      </div>

      {allowText && (
        <div className="flex gap-2 mb-3 shrink-0">
          <input 
            type="text" 
            value={dialogueInput}
            onChange={(e) => setDialogueInput(e.target.value)}
            placeholder="Add story beats..."
            className="flex-1 bg-zinc-800 border border-zinc-700 rounded px-2 py-1 text-xs focus:outline-none focus:ring-1 focus:ring-emerald-500"
            onKeyDown={(e) => e.key === 'Enter' && addDialogueAsset()}
          />
          <button 
            onClick={addDialogueAsset}
            className="bg-emerald-500 text-black p-1 rounded hover:bg-emerald-400"
          >
            <Plus className="w-4 h-4" />
          </button>
        </div>
      )}

      <div className="space-y-1 overflow-y-auto flex-1 pr-1">
        {assets.filter(a => a.type === type).length === 0 ? (
          <p className="text-[10px] text-zinc-600 italic mt-2">No {label.toLowerCase()} added</p>
        ) : (
          assets.filter(a => a.type === type).map(asset => (
            <div key={asset.id} className="flex items-center justify-between bg-zinc-800/30 p-1.5 rounded text-[10px] group border border-transparent hover:border-zinc-700 transition-colors">
              <span className="truncate max-w-[120px] text-zinc-300">{asset.name}</span>
              <button 
                onClick={() => removeAsset(asset.id)}
                className="text-zinc-600 hover:text-red-400 opacity-0 group-hover:opacity-100 transition-opacity"
              >
                <X className="w-3 h-3" />
              </button>
            </div>
          ))
        )}
      </div>
    </div>
  );

  return (
    <div className="grid grid-cols-1 md:grid-cols-2 gap-3 h-full">
      <AssetSection type="model" icon={Box} label="3D Models" accept=".glb,.fbx,.obj" />
      <AssetSection type="character" icon={Gamepad2} label="Characters (2D)" accept="image/*" />
      <AssetSection type="environment" icon={ImageIcon} label="Environments" accept="image/*" />
      <AssetSection type="music" icon={Music} label="Music / SFX" accept="audio/*" />
      <AssetSection type="dialogue" icon={MessageSquare} label="Dialogue / Scripts" allowText />
    </div>
  );
};

import { GoogleGenAI, Type } from "@google/genai";
import { GameAsset } from "../types";

export const generateGame = async (
  prompt: string,
  assets: GameAsset[]
): Promise<{ code: string; title: string }> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const has3D = assets.some(a => a.type === 'model');
  const assetDescriptions = assets.map(a => `- ${a.name} (${a.type})`).join('\n');

  const systemInstruction = `
    You are an elite Game Architect. Create a standalone, high-performance HTML5 game.

    ENGINE CHOICE:
    - If 3D models (GLB, FBX) are provided, use Three.js (CDN: https://cdnjs.cloudflare.com/ajax/libs/three.js/0.160.0/three.min.js).
    - If strictly 2D assets are provided, use Phaser 3 (CDN: https://cdn.jsdelivr.net/npm/phaser@3.60.0/dist/phaser.min.js).

    ASSET INTEGRATION:
    - Use the provided data URIs for images, models, and audio. 
    - For 3D (Three.js):
      - Include GLTFLoader if GLB is provided: https://cdn.jsdelivr.net/npm/three@0.160.0/examples/jsm/loaders/GLTFLoader.js
      - Include FBXLoader if FBX is provided: https://cdn.jsdelivr.net/npm/three@0.160.0/examples/jsm/loaders/FBXLoader.js
      - NOTE: Load these via script tags or use the UMD versions if available, or write the loading logic using the provided base64 data.
      - Convert Base64 data strings back into Blobs/URLs if needed for the loaders (URL.createObjectURL).

    CODE STRUCTURE:
    - Output a COMPLETE single-file HTML document (<!DOCTYPE html>...</html>).
    - Include CSS to hide scrollbars and center the viewport.
    - Write clean, commented ES6+ JavaScript.
    - Ensure basic input handling (WASD/Arrows/Mouse).

    GAME CONCEPT: ${prompt}

    AVAILABLE ASSETS:
    ${assetDescriptions}

    RESPONSE FORMAT:
    You MUST return JSON with:
    {
      "code": "Full HTML string",
      "title": "Short catchy title"
    }
  `;

  const parts: any[] = [
    { text: `Request: Generate a ${has3D ? '3D' : '2D'} game titled around '${prompt}'.` }
  ];

  assets.forEach(asset => {
    if (asset.content.startsWith('data:')) {
      const [header, data] = asset.content.split(',');
      const mime = header.split(':')[1].split(';')[0];
      parts.push({
        inlineData: {
          mimeType: mime,
          data: data
        }
      });
      parts.push({ text: `Asset content for: ${asset.name} (${asset.type})` });
    } else {
      parts.push({ text: `Textual asset "${asset.name}": ${asset.content}` });
    }
  });

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: { parts },
    config: {
      systemInstruction,
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          code: { type: Type.STRING },
          title: { type: Type.STRING }
        },
        required: ['code', 'title']
      }
    }
  });

  try {
    const text = response.text || '{}';
    const result = JSON.parse(text);
    return {
      code: result.code || '<html><body><h1>Error Generating Engine</h1></body></html>',
      title: result.title || 'Forged Game'
    };
  } catch (e) {
    console.error("Failed to parse Gemini response:", response.text);
    return {
      code: `<html><body style="background:#000;color:#fff;display:flex;align-items:center;justify-content:center;height:100vh;font-family:sans-serif;padding:2rem;">
              <div style="text-align:center;">
                <h1 style="color:#10b981;">Forge Malfunction</h1>
                <p>The AI architecture failed to crystallize into valid JSON. This usually happens with very complex 3D asset requests.</p>
                <div style="text-align:left;max-height:50vh;overflow:auto;background:#111;padding:1rem;border-radius:8px;border:1px solid #333;font-size:12px;">
                  <code style="white-space:pre-wrap;">${(response.text || '').substring(0, 2000)}...</code>
                </div>
                <button onclick="location.reload()" style="margin-top:1rem;background:#10b981;color:#000;border:none;padding:0.5rem 1.5rem;border-radius:4px;font-weight:bold;cursor:pointer;">Retry Forge</button>
              </div>
            </body></html>`,
      title: 'Forge Error'
    };
  }
};

