      responseSchema: {
        type: Type.OBJECT,
        properties: {
          code: { type: Type.STRING },
          title: { type: Type.STRING }
        },
        required: ['code', 'title']
      }
    }
  });

  try {
    const text = response.text || '{}';
    const result = JSON.parse(text);
    return {
      code: result.code || '<html><body><h1>Error Generating Engine</h1></body></html>',
      title: result.title || 'Forged Game'
    };
  } catch (e) {
    console.error("Failed to parse Gemini response:", response.text);
    return {
      code: `<html><body style="background:#000;color:#fff;display:flex;align-items:center;justify-content:center;height:100vh;font-family:sans-serif;padding:2rem;">
              <div style="text-align:center;">
                <h1 style="color:#10b981;">Forge Malfunction</h1>
                <p>The AI architecture failed to crystallize into valid JSON. This usually happens with very complex 3D asset requests.</p>
                <div style="text-align:left;max-height:50vh;overflow:auto;background:#111;padding:1rem;border-radius:8px;border:1px solid #333;font-size:12px;">
                  <code style="white-space:pre-wrap;">${(response.text || '').substring(0, 2000)}...</code>
                </div>
                <button onclick="location.reload()" style="margin-top:1rem;background:#10b981;color:#000;border:none;padding:0.5rem 1.5rem;border-radius:4px;font-weight:bold;cursor:pointer;">Retry Forge</button>
              </div>
