    };
  }
};

import React, { useState } from 'react';
import { AssetType, GameAsset } from '../types';
import { Upload, X, Gamepad2, Image as ImageIcon, Music, MessageSquare, Plus, Box } from 'lucide-react';

interface AssetUploaderProps {
  assets: GameAsset[];
  onAssetsChange: (assets: GameAsset[]) => void;
}

export const AssetUploader: React.FC<AssetUploaderProps> = ({ assets, onAssetsChange }) => {
  const [dialogueInput, setDialogueInput] = useState('');

  const getMimeType = (file: File): string => {
    if (file.type) return file.type;
    const extension = file.name.split('.').pop()?.toLowerCase();
    switch (extension) {
      case 'glb': return 'model/gltf-binary';
      case 'gltf': return 'model/gltf+json';
      case 'fbx': return 'application/octet-stream';
      case 'obj': return 'text/plain';
      default: return 'application/octet-stream';
    }
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>, type: AssetType) => {
    const files = e.target.files;
    if (!files) return;

    Array.from(files).forEach(file => {
      const reader = new FileReader();
      reader.onload = (event) => {
        const mimeType = getMimeType(file);
        const newAsset: GameAsset = {
          id: Math.random().toString(36).substr(2, 9),
          name: file.name,
          type,
          content: event.target?.result as string,
          mimeType
        };
        onAssetsChange([...assets, newAsset]);
      };
      reader.readAsDataURL(file);
    });
    // Reset input
    e.target.value = '';
  };

  const addDialogueAsset = () => {
    if (!dialogueInput.trim()) return;
    const newAsset: GameAsset = {
      id: Math.random().toString(36).substr(2, 9),
      name: `Script ${assets.filter(a => a.type === 'dialogue').length + 1}`,
      type: 'dialogue',
      content: dialogueInput,
      mimeType: 'text/plain'
    };
    onAssetsChange([...assets, newAsset]);
    setDialogueInput('');
  };

  const removeAsset = (id: string) => {
    onAssetsChange(assets.filter(a => a.id !== id));
  };

  const AssetSection = ({ type, icon: Icon, label, allowText, accept }: { type: AssetType, icon: any, label: string, allowText?: boolean, accept?: string }) => (
    <div className="bg-zinc-900/50 p-4 rounded-xl border border-zinc-800 flex flex-col h-full min-h-[160px]">
      <div className="flex items-center justify-between mb-3 shrink-0">
        <div className="flex items-center gap-2">
          <Icon className="w-4 h-4 text-emerald-400" />
          <span className="text-sm font-medium">{label}</span>
        </div>
        {!allowText && (
          <label className="cursor-pointer bg-zinc-800 hover:bg-zinc-700 px-3 py-1 rounded text-[10px] font-bold transition-colors">
            UPLOAD
            <input 
              type="file" 
              className="hidden" 
              onChange={(e) => handleFileUpload(e, type)}
              accept={accept}
            />
          </label>
