import { GoogleGenAI, Type } from "@google/genai";
import { GameAsset } from "../types";

export const generateGame = async (
  prompt: string,
  assets: GameAsset[]
): Promise<{ code: string; title: string }> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const assetDescriptions = assets.map(a => `- ${a.name} (${a.type})`).join('\n');

  const systemInstruction = `
    You are a Master 3D Game Architect specializing in Three.js and WebGL.
    Your mission: Forge a fully immersive 3D experience based on user assets and prompts.

    ENGINE STACK:
    - Primary Engine: Three.js (CDN: https://cdnjs.cloudflare.com/ajax/libs/three.js/0.160.0/three.min.js)
    - Loaders: 
      - GLTFLoader (https://cdn.jsdelivr.net/npm/three@0.160.0/examples/jsm/loaders/GLTFLoader.js)
      - FBXLoader (https://cdn.jsdelivr.net/npm/three@0.160.0/examples/jsm/loaders/FBXLoader.js)
      - RGBELoader for environment maps if needed.
    - Physics: Optional basic raycasting or simple velocity-based physics.

    FORGING RULES:
    1. EVERYTHING IS 3D: If a user uploads a 2D image, treat it as a Texture, a Sprite (Billboard), or a Skybox element.
    2. ASSET LOADING: Use URL.createObjectURL(base64ToBlob(data)) for all binary assets. You must include a utility function for base64ToBlob in your JS.
    3. SCENE COMPOSITION: Setup high-quality lighting (Ambient + Directional with shadows), a camera with OrbitControls or FirstPersonControls, and a ground plane.
    4. INTERACTION: Ensure WASD + Mouse controls are standard.
    5. SINGLE FILE: The output must be one HTML document containing all scripts, CSS, and logic.

    GAME CONCEPT: ${prompt}

    ASSET MATRIX:
    ${assetDescriptions}

    RESPONSE SCHEMA:
    Return JSON with 'code' (full HTML) and 'title' (catchy name).
  `;

  const parts: any[] = [
    { text: `Forge a high-fidelity 3D world for: ${prompt}` }
  ];

  assets.forEach(asset => {
    const isMultimodal = asset.mimeType.startsWith('image/') || asset.mimeType.startsWith('audio/');

    if (asset.content.startsWith('data:') && isMultimodal) {
      const [header, data] = asset.content.split(',');
      const mime = header.split(':')[1].split(';')[0];
      parts.push({
        inlineData: { mimeType: mime, data: data }
      });
      parts.push({ text: `Asset ${asset.name} is a visual/auditory texture/map for the 3D scene.` });
    } else if (asset.content.startsWith('data:')) {
      parts.push({ text: `3D Model/Binary Data for "${asset.name}" (${asset.type}):\n${asset.content}` });
    } else {
      parts.push({ text: `Narrative Script "${asset.name}": ${asset.content}` });
    }
  });

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: { parts },
    config: {
      systemInstruction,
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          code: { type: Type.STRING },
          title: { type: Type.STRING }
        },
        required: ['code', 'title']
      }
    }
  });

  try {
    const result = JSON.parse(response.text || '{}');
    return {
      code: result.code || '<html><body style="background:#000;color:#fff;display:flex;align-items:center;justify-content:center;height:100vh;"><h1>Engine Initialization Failure</h1></body></html>',
      title: result.title || 'Forged 3D World'
    };
  } catch (e) {
    return {
      code: `<html><body style="background:#000;color:#fff;padding:2rem;font-family:monospace;"><h1>Critical Forge Malfunction</h1><p>The 3D matrix collapsed during synthesis. Try a simpler prompt or fewer assets.</p></body></html>`,
      title: 'Forge Error'
    };
  }
};

import React, { useState } from 'react';
import { AssetType, GameAsset } from '../types';
import { X, Box, Image as ImageIcon, Music, MessageSquare, Plus, Globe } from 'lucide-react';

interface AssetUploaderProps {
  assets: GameAsset[];
  onAssetsChange: (assets: GameAsset[]) => void;
}

export const AssetUploader: React.FC<AssetUploaderProps> = ({ assets, onAssetsChange }) => {
  const [dialogueInput, setDialogueInput] = useState('');

  const getMimeType = (file: File): string => {
    if (file.type) return file.type;
    const extension = file.name.split('.').pop()?.toLowerCase();
    switch (extension) {
      case 'glb': return 'model/gltf-binary';
      case 'gltf': return 'model/gltf+json';
      case 'fbx': return 'application/octet-stream';
      case 'obj': return 'text/plain';
      default: return 'application/octet-stream';
    }
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>, type: AssetType) => {
    const files = e.target.files;
    if (!files) return;

    Array.from(files).forEach(file => {
      const reader = new FileReader();
      reader.onload = (event) => {
        const mimeType = getMimeType(file);
        const newAsset: GameAsset = {
          id: Math.random().toString(36).substr(2, 9),
          name: file.name,
          type,
          content: event.target?.result as string,
          mimeType
        };
        onAssetsChange([...assets, newAsset]);
      };
      reader.readAsDataURL(file);
    });
    e.target.value = '';
  };

  const addDialogueAsset = () => {
    if (!dialogueInput.trim()) return;
    const newAsset: GameAsset = {
      id: Math.random().toString(36).substr(2, 9),
      name: `Logic Node ${assets.filter(a => a.type === 'dialogue').length + 1}`,
      type: 'dialogue',
      content: dialogueInput,
      mimeType: 'text/plain'
    };
    onAssetsChange([...assets, newAsset]);
    setDialogueInput('');
  };

  const removeAsset = (id: string) => {
    onAssetsChange(assets.filter(a => a.id !== id));
  };

  const AssetSection = ({ type, icon: Icon, label, allowText, accept }: { type: AssetType, icon: any, label: string, allowText?: boolean, accept?: string }) => (
    <div className="bg-zinc-900/40 p-3 rounded-xl border border-zinc-800 flex flex-col h-full min-h-[140px] group hover:border-emerald-500/30 transition-all">
      <div className="flex items-center justify-between mb-2 shrink-0">
        <div className="flex items-center gap-1.5">
          <Icon className="w-3.5 h-3.5 text-emerald-400" />
          <span className="text-[11px] font-bold uppercase tracking-wider text-zinc-300">{label}</span>
        </div>
        {!allowText && (
          <label className="cursor-pointer bg-zinc-800 hover:bg-emerald-500 hover:text-black px-2 py-0.5 rounded text-[9px] font-black transition-all">
            + ADD
            <input 
              type="file" 
              className="hidden" 
              onChange={(e) => handleFileUpload(e, type)}
              accept={accept}
            />
          </label>
        )}
      </div>

      {allowText && (
        <div className="flex gap-1.5 mb-2 shrink-0">
          <input 
            type="text" 
            value={dialogueInput}
            onChange={(e) => setDialogueInput(e.target.value)}
            placeholder="Scene triggers..."
            className="flex-1 bg-zinc-800/50 border border-zinc-700 rounded px-2 py-1 text-[10px] focus:outline-none focus:ring-1 focus:ring-emerald-500"
            onKeyDown={(e) => e.key === 'Enter' && addDialogueAsset()}
          />
          <button 
            onClick={addDialogueAsset}
            className="bg-emerald-500 text-black p-1 rounded hover:bg-emerald-400"
          >
            <Plus className="w-3 h-3" />
          </button>
        </div>
      )}

      <div className="space-y-1 overflow-y-auto flex-1 pr-1">
        {assets.filter(a => a.type === type).length === 0 ? (
          <div className="flex flex-col items-center justify-center h-full opacity-20 py-4">
             <Icon className="w-6 h-6 mb-1" />
          </div>
        ) : (
          assets.filter(a => a.type === type).map(asset => (
            <div key={asset.id} className="flex items-center justify-between bg-zinc-800/30 p-1.5 rounded text-[9px] group/item border border-transparent hover:border-zinc-700 transition-colors">
              <span className="truncate max-w-[110px] text-zinc-400 font-mono">{asset.name}</span>
              <button 
                onClick={() => removeAsset(asset.id)}
                className="text-zinc-600 hover:text-red-400 opacity-0 group-hover/item:opacity-100 transition-opacity"
              >
                <X className="w-2.5 h-2.5" />
              </button>
            </div>
          ))
        )}
      </div>
    </div>
  );

  return (
    <div className="grid grid-cols-2 gap-2 h-full">
      <AssetSection type="model" icon={Box} label="3D Models" accept=".glb,.fbx" />
      <AssetSection type="environment" icon={Globe} label="Environment" accept="image/*,.hdr" />
      <AssetSection type="character" icon={ImageIcon} label="Textures/Maps" accept="image/*" />
      <AssetSection type="music" icon={Music} label="Spatial Audio" accept="audio/*" />
      <div className="col-span-2">
        <AssetSection type="dialogue" icon={MessageSquare} label="Logic & Scripts" allowText />
      </div>
    </div>
  );
};

