import { GoogleGenAI, Type } from "@google/genai";
import { GameAsset } from "../types";

export const generateGame = async (
  prompt: string,
  assets: GameAsset[]
): Promise<{ code: string; title: string }> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  // We send only the names and types to the model to avoid exceeding token limits.
  // The actual binary data is injected into the preview iframe via a manifest.
  const assetMetadata = assets.map(a => ({
    name: a.name,
    type: a.type,
    mimeType: a.mimeType
  }));

  const systemInstruction = `
    You are a Master 3D Game Architect specializing in Three.js and WebGL.
    Forge a fully immersive 3D experience based on the provided asset metadata and prompt.

    CRITICAL - ASSET LOADING:
    - DO NOT embed raw base64 data in your code.
    - Instead, use the global variable 'window.FORGE_ASSETS' which is a dictionary mapping asset names to their data URLs.
    - Example: To load a texture named "Hero.png", use window.FORGE_ASSETS["Hero.png"].
    - Example for 3D loaders:
      const blobUrl = window.FORGE_ASSETS["Ship.glb"];
      loader.load(blobUrl, (gltf) => { ... });

    ENGINE STACK:
    - Primary Engine: Three.js (CDN: https://cdnjs.cloudflare.com/ajax/libs/three.js/0.160.0/three.min.js)
    - Loaders (Add these if needed): 
      - GLTFLoader (https://cdn.jsdelivr.net/npm/three@0.160.0/examples/jsm/loaders/GLTFLoader.js)
      - FBXLoader (https://cdn.jsdelivr.net/npm/three@0.160.0/examples/jsm/loaders/FBXLoader.js)
    - Controls: Include OrbitControls (https://cdn.jsdelivr.net/npm/three@0.160.0/examples/jsm/controls/OrbitControls.js) or implement WASD logic.

    REQUIREMENTS:
    1. EVERYTHING IS 3D: Use Three.js.
    2. SCENE: Setup high-quality lighting, a responsive camera, and a ground/environment.
    3. INTERACTION: Ensure standard game controls.
    4. SINGLE FILE: Output a complete HTML document.

    GAME CONCEPT: ${prompt}

    AVAILABLE ASSET NAMES IN window.FORGE_ASSETS:
    ${JSON.stringify(assetMetadata, null, 2)}

    RESPONSE SCHEMA:
    Return JSON with 'code' (full HTML) and 'title' (catchy name).
  `;

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: [{ text: `Generate the 3D game logic for: ${prompt}` }],
    config: {
      systemInstruction,
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          code: { type: Type.STRING },
          title: { type: Type.STRING }
        },
        required: ['code', 'title']
      }
    }
  });

  try {
    const result = JSON.parse(response.text || '{}');
    return {
      code: result.code || '<html><body><h1>Engine Initialization Failure</h1></body></html>',
      title: result.title || 'Forged 3D World'
    };
  } catch (e) {
    console.error("Parse Error:", e);
    return {
      code: `<html><body style="background:#000;color:#fff;padding:2rem;font-family:monospace;"><h1>Critical Forge Malfunction</h1><p>The 3D matrix collapsed. This usually happens if the requested logic is too complex.</p></body></html>`,
      title: 'Forge Error'
    };
  }
};

import React, { useEffect, useRef } from 'react';
import { GameAsset } from '../types';

interface GameRunnerProps {
  code: string;
  title: string;
  assets: GameAsset[];
}

export const GameRunner: React.FC<GameRunnerProps> = ({ code, title, assets }) => {
  const iframeRef = useRef<HTMLIFrameElement>(null);

  useEffect(() => {
    if (iframeRef.current) {
      const doc = iframeRef.current.contentDocument;
      if (doc) {
        // Prepare the asset manifest for injection
        const assetMap = assets.reduce((acc, asset) => {
          acc[asset.name] = asset.content;
          return acc;
        }, {} as Record<string, string>);

        const injectionScript = `
          <script>
            window.FORGE_ASSETS = ${JSON.stringify(assetMap)};
            console.log("FORGE_ASSETS initialized with " + Object.keys(window.FORGE_ASSETS).length + " assets.");
          </script>
        `;

        // We combine the injection script with the generated code
        // We look for the head tag to inject or just prepend it
        let finalCode = code;
        if (code.includes('<head>')) {
          finalCode = code.replace('<head>', `<head>${injectionScript}`);
        } else {
          finalCode = injectionScript + code;
        }

        doc.open();
        doc.write(finalCode);
        doc.close();
      }
    }
  }, [code, assets]);

  return (
