import { GoogleGenAI, Type } from "@google/genai";
import { GameAsset } from "../types";

export const generateGame = async (
  prompt: string,
  assets: GameAsset[]
): Promise<{ code: string; title: string }> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const assetMetadata = assets.map(a => ({
    name: a.name,
    type: a.type,
    mimeType: a.mimeType
  }));

  const systemInstruction = `
    You are a Master 3D Game Architect. Create a high-performance Three.js game.

    ASSET SYSTEM:
    - Use 'window.getAssetUrl(name)' to get a valid URL for any uploaded asset.
    - Example: loader.load(window.getAssetUrl("car.glb"), (model) => { ... });
    - Example: new THREE.TextureLoader().load(window.getAssetUrl("map.jpg"));

    ENGINE REQUIREMENTS:
    - Use Three.js (CDN: https://cdnjs.cloudflare.com/ajax/libs/three.js/0.160.0/three.min.js).
    - Always include OrbitControls if the user doesn't specify character movement.
    - Setup a complete scene: Scene, PerspectiveCamera, WebGLRenderer, Lights (Ambient + Directional with Shadow maps).
    - If assets are missing, use Three.js primitives (Box, Sphere) as placeholders with high-quality Materials.
    - Ensure the renderer handles window resizing.

    STYLING:
    - Background: Black (#000000).
    - Use Bloom or Neon effects (emissive materials) if requested by the prompt.

    PROMPT: ${prompt}
    AVAILABLE ASSETS: ${JSON.stringify(assetMetadata)}

    OUTPUT: Return ONLY a JSON object with "code" (the full HTML) and "title".
  `;

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: [{ text: `Generate a 3D simulation for: ${prompt}` }],
    config: {
      systemInstruction,
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          code: { type: Type.STRING },
          title: { type: Type.STRING }
        },
        required: ['code', 'title']
      }
    }
  });

  try {
    const result = JSON.parse(response.text || '{}');
    return {
      code: result.code || '<html><body style="background:black;color:white;">Engine Error</body></html>',
      title: result.title || 'Forged Experience'
    };
  } catch (e) {
    return {
      code: `<html><body style="background:black;color:red;padding:20px;"><h1>Compilation Failed</h1><p>${e}</p></body></html>`,
      title: 'Forge Error'
    };
  }
};

import React, { useMemo } from 'react';
import { GameAsset } from '../types';

interface GameRunnerProps {
  code: string;
  title: string;
  assets: GameAsset[];
}

export const GameRunner: React.FC<GameRunnerProps> = ({ code, title, assets }) => {
  const combinedSrcDoc = useMemo(() => {
    // Create a mapping of asset names to base64
    const assetMap = assets.reduce((acc, asset) => {
      acc[asset.name] = asset.content;
      return acc;
    }, {} as Record<string, string>);

    const bootstrapScript = `
      <script>
        (function() {
          const rawAssets = ${JSON.stringify(assetMap)};
          const blobUrls = {};

          function base64ToBlob(base64, mime) {
            const byteString = atob(base64.split(',')[1]);
            const ab = new ArrayBuffer(byteString.length);
            const ia = new Uint8Array(ab);
            for (let i = 0; i < byteString.length; i++) {
              ia[i] = byteString.charCodeAt(i);
            }
            return new Blob([ab], { type: mime });
          }

          window.getAssetUrl = function(name) {
            if (blobUrls[name]) return blobUrls[name];
            const data = rawAssets[name];
            if (!data) {
              console.warn("Asset not found: " + name);
              return "";
            }
            const mime = data.split(':')[1].split(';')[0];
            const blob = base64ToBlob(data, mime);
            const url = URL.createObjectURL(blob);
            blobUrls[name] = url;
            return url;
          };

          console.log("Forge Core: Asset helper initialized.");
        })();
      </script>
    `;

    // Inject the bootstrap script before any other content
    if (code.includes('<head>')) {
      return code.replace('<head>', `<head>${bootstrapScript}`);
    }
    return bootstrapScript + code;
  }, [code, assets]);

  return (
    <div className="w-full h-full flex flex-col bg-black group">
      <div className="bg-zinc-900/80 backdrop-blur-md border-b border-emerald-500/20 px-4 py-2 flex items-center justify-between shrink-0">
        <div className="flex items-center gap-2">
          <div className="w-2 h-2 rounded-full bg-emerald-500 animate-pulse" />
          <h3 className="text-[10px] font-black text-emerald-400 uppercase tracking-[0.2em]">{title}</h3>
        </div>
        <div className="flex gap-1.5 opacity-50 group-hover:opacity-100 transition-opacity">
          <div className="w-2.5 h-2.5 rounded-full bg-zinc-800 border border-zinc-700"></div>
          <div className="w-2.5 h-2.5 rounded-full bg-zinc-800 border border-zinc-700"></div>
          <div className="w-2.5 h-2.5 rounded-full bg-emerald-500"></div>
        </div>
      </div>
      <div className="flex-1 relative overflow-hidden">
        <div className="absolute inset-0 pointer-events-none border-[3px] border-emerald-500/30 shadow-[inset_0_0_40px_rgba(16,185,129,0.1)] z-20" />
        <iframe
          srcDoc={combinedSrcDoc}
          title="Forge Reality"
          className="w-full h-full border-none"
          sandbox="allow-scripts allow-modals allow-pointer-lock"
        />
      </div>
    </div>
  );
};

