import React, { useMemo } from 'react';
import { GameAsset } from '../types';
import { X, Maximize2, Terminal, Info, Zap } from 'lucide-react';

interface GameRunnerProps {
  code: string;
  title: string;
  assets: GameAsset[];
  onClose?: () => void;
}

export const GameRunner: React.FC<GameRunnerProps> = ({ code, title, assets, onClose }) => {
  const combinedSrcDoc = useMemo(() => {
    const assetMap = assets.reduce((acc, asset) => {
      acc[asset.name] = asset.content;
      return acc;
    }, {} as Record<string, string>);

    const bootstrapScript = `
      <script>
        (function() {
          const rawAssets = ${JSON.stringify(assetMap)};
          const blobUrls = {};

          function base64ToBlob(base64, mime) {
            const split = base64.split(',');
            const data = split[1] || split[0];
            const byteString = atob(data);
            const ab = new ArrayBuffer(byteString.length);
            const ia = new Uint8Array(ab);
            for (let i = 0; i < byteString.length; i++) {
              ia[i] = byteString.charCodeAt(i);
            }
            return new Blob([ab], { type: mime });
          }

          window.getAssetUrl = function(name) {
            if (blobUrls[name]) return blobUrls[name];
            const data = rawAssets[name];
            if (!data) {
              console.warn("Forge Simulation: Asset not found -> " + name);
              return "";
            }
            let mime = 'application/octet-stream';
            if (data.includes('data:')) {
              mime = data.split(':')[1].split(';')[0];
            }
            const blob = base64ToBlob(data, mime);
            const url = URL.createObjectURL(blob);
            blobUrls[name] = url;
            return url;
          };

          // Override console to help debug from parent
          const originalLog = console.log;
          console.log = function() {
            window.parent.postMessage({ type: 'log', data: Array.from(arguments) }, '*');
            originalLog.apply(console, arguments);
          };

          window.addEventListener('error', function(e) {
             window.parent.postMessage({ type: 'error', data: e.message }, '*');
          });

          console.log("Forge Core: Virtual asset buffer online.");
        })();
      </script>
    `;

    if (code.includes('<head>')) {
      return code.replace('<head>', `<head>${bootstrapScript}`);
    }
    return bootstrapScript + code;
  }, [code, assets]);

  return (
    <div className="w-full h-full flex flex-col bg-black relative">
      {/* Simulation HUD / Header */}
      <div className="absolute top-0 inset-x-0 z-[110] p-6 pointer-events-none flex justify-between items-start">
        <div className="flex flex-col gap-1 pointer-events-auto">
          <div className="flex items-center gap-3 bg-black/40 backdrop-blur-md border border-white/5 px-6 py-2 rounded-2xl shadow-2xl">
            <Zap className="w-4 h-4 text-emerald-500 fill-emerald-500/20" />
            <h3 className="text-[12px] font-black text-white uppercase tracking-[0.3em] italic">{title}</h3>
            <div className="h-3 w-px bg-white/10 mx-1" />
            <span className="text-[10px] text-emerald-500/80 font-bold tracking-widest uppercase">Simulation Active</span>
          </div>
          <div className="flex gap-2 mt-2">
             <div className="bg-black/40 backdrop-blur-md border border-white/5 px-3 py-1 rounded-lg flex items-center gap-2">
               <div className="w-1.5 h-1.5 rounded-full bg-emerald-500 animate-pulse" />
               <span className="text-[8px] font-black text-zinc-500 uppercase tracking-widest">FPS: 60.0</span>
             </div>
             <div className="bg-black/40 backdrop-blur-md border border-white/5 px-3 py-1 rounded-lg flex items-center gap-2">
               <span className="text-[8px] font-black text-zinc-500 uppercase tracking-widest">GPU: NVIDIA GEN 4.2</span>
             </div>
          </div>
        </div>

        <div className="flex gap-4 pointer-events-auto">
          <button 
            className="w-10 h-10 bg-black/40 backdrop-blur-md border border-white/5 text-white/50 hover:text-white hover:bg-zinc-900 rounded-2xl transition-all flex items-center justify-center group"
            title="System Info"
          >
            <Info className="w-5 h-5 group-hover:scale-110 transition-transform" />
          </button>
          <button 
            onClick={onClose}
            className="w-10 h-10 bg-red-500/10 backdrop-blur-md border border-red-500/20 text-red-500 hover:bg-red-500 hover:text-white rounded-2xl transition-all flex items-center justify-center group"
            title="Deconstruct Simulation"
          >
            <X className="w-5 h-5 group-hover:rotate-90 transition-transform" />
          </button>
        </div>
      </div>

      {/* Viewport Decorator */}
      <div className="absolute inset-0 pointer-events-none border-[20px] border-black z-10" />
      <div className="absolute inset-[20px] pointer-events-none border border-emerald-500/10 shadow-[inset_0_0_100px_rgba(16,185,129,0.05)] z-20" />

      {/* Simulation Grid Background */}
      <div className="absolute inset-0 bg-[linear-gradient(rgba(16,185,129,0.02)_1px,transparent_1px),linear-gradient(90deg,rgba(16,185,129,0.02)_1px,transparent_1px)] bg-[size:40px_40px] pointer-events-none opacity-20" />

      {/* Main Iframe Viewport */}
      <div className="flex-1 relative overflow-hidden bg-black">
        <iframe
          srcDoc={combinedSrcDoc}
          title="Forge Reality"
          className="w-full h-full border-none relative z-0"
          sandbox="allow-scripts allow-modals allow-pointer-lock"
        />
      </div>

      {/* Terminal Footer */}
      <div className="absolute bottom-8 left-10 z-[110] flex gap-4">
        <div className="flex items-center gap-3 bg-black/60 backdrop-blur-xl border border-white/5 pl-4 pr-6 py-2.5 rounded-2xl">
          <Terminal className="w-3.5 h-3.5 text-zinc-500" />
          <span className="text-[9px] font-bold text-zinc-500 uppercase tracking-widest">Log: Engine Initialization Success</span>
        </div>
