import { GoogleGenAI, Type } from "@google/genai";
import { GameAsset } from "../types";

export const generateGame = async (
  prompt: string,
  assets: GameAsset[]
): Promise<{ code: string; title: string }> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const assetMetadata = assets.map(a => ({
    name: a.name,
    type: a.type,
    mimeType: a.mimeType
  }));

  const systemInstruction = `
    You are a Senior Game Engine Architect and Creative Director. Your goal is to produce a high-fidelity, logically sound 3D game using Three.js.

    ARCHITECTURAL REQUIREMENTS:
    1. GAME LOOP: Implement a robust 'requestAnimationFrame' loop with delta time (dt) for smooth movement independent of framerate.
    2. STATE MANAGEMENT: Use a class or structured object for the Game State (e.g., loading, playing, gameover).
    3. ASSET PIPELINE: Use 'window.getAssetUrl(name)' exclusively. Handle loading asynchronously and show a loading progress bar or text if possible.
    4. PHYSICS & COLLISION: Implement logical collisions. If it's a car game, use raycasting or bounding box logic. If it's a shooter, implement projectiles.
    5. INPUT SYSTEM: Support WASD/Arrows and Mouse. Ensure events are cleaned up or managed.
    6. VISUALS: Use Three.js PBR materials (MeshStandardMaterial). Setup a clear lighting rig (HemisphereLight + DirectionalLight with shadows). 
    7. FEEDBACK: Add a HUD (Heads-Up Display) using HTML/CSS inside the game to show score, health, or speed.

    ASSET HANDLING:
    - window.getAssetUrl("name.glb") returns a blob URL for 3D models.
    - window.getAssetUrl("texture.jpg") returns a blob URL for images.
    - window.getAssetUrl("sound.mp3") returns a blob URL for audio.

    THEME: ${prompt}
    AVAILABLE ASSET NAMES: ${JSON.stringify(assetMetadata)}

    OUTPUT FORMAT:
    Return a JSON object with:
    - "code": A single-file HTML document (including <style> and <script>).
    - "title": A professional game title.
  `;

  // Using gemini-3-pro-preview for complex reasoning and larger thinking budget
  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    // Fixed: contents parameter should be a string for text tasks per SDK guidelines
    contents: `Construct the complete logic and rendering code for: ${prompt}`,
    config: {
      systemInstruction,
      thinkingConfig: { thinkingBudget: 16000 }, // High thinking budget for complex game logic
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          code: { type: Type.STRING },
          title: { type: Type.STRING }
        },
        required: ['code', 'title']
      }
    }
  });

  try {
    // Fixed: correctly access .text property from response
    const result = JSON.parse(response.text || '{}');
    return {
      code: result.code || '<html><body style="background:black;color:white;">Engine Error</body></html>',
      title: result.title || 'Forged Experience'
    };
  } catch (e) {
    console.error("Parse Error:", e);
    return {
      code: `<html><body style="background:black;color:red;padding:20px;"><h1>Architectural Failure</h1><p>${e}</p></body></html>`,
      title: 'Forge Error'
    };
  }
};

export type AssetType = 'character' | 'environment' | 'animation' | 'dialogue' | 'music' | 'model';

export interface GameAsset {
  id: string;
  name: string;
  type: AssetType;
