import { GoogleGenAI, Type } from "@google/genai";
import { GameAsset, ChatMessage } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const generateGame = async (
  prompt: string,
  assets: GameAsset[],
  history: ChatMessage[] = [],
  currentCode: string = ""
): Promise<{ code: string; title: string; explanation: string }> => {

  const assetMetadata = assets.map(a => ({
    name: a.name,
    type: a.type,
    mimeType: a.mimeType
  }));

  const isRefinement = history.length > 0 && currentCode !== "";

  const systemInstruction = `
    You are a Senior Game Architect (AAA Studio). You are working in a live sandbox environment.

    ENVIRONMENT:
    - Three.js (0.160.0), WebGL.
    - Asset Access: Use window.getAssetUrl(name).

    MODUS OPERANDI:
    - If this is a NEW game: Build a complete, playable 3D experience from scratch.
    - If this is a REFINEMENT: Modify the existing code strictly based on the user's latest request while maintaining the core structure.

    ARCHITECTURAL RULES:
    1. ROBUST LOOP: Use delta-time (dt) for all physics/movements.
    2. PHYSICS: Implement logical collisions (BoundingBoxes, Raycasting).
    3. HUD: Always include a beautiful overlay (HTML/CSS) for game stats (Speed, Health, Score).
    4. QUALITY: Use PBR materials, shadows, and responsive resizing.
    5. FEEDBACK: If the user asks for "faster", "brighter", etc., identify the specific variables in the code and adjust them.

    CURRENT STATE:
    - Asset Manifest: ${JSON.stringify(assetMetadata)}
    - Current Logic: ${isRefinement ? "Code provided below" : "Empty (New Project)"}

    RESPONSE SCHEMA:
    Return a JSON object with:
    - "code": The full updated HTML code.
    - "title": The project title.
    - "explanation": A brief, professional message to the user explaining what you did/improved.
  `;

  const userPrompt = isRefinement 
    ? `Current Code: ${currentCode}\n\nUser Modification Request: ${prompt}\n\nPlease apply these changes.`
    : `Initial Prompt: ${prompt}`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: userPrompt,
    config: {
      systemInstruction,
      thinkingConfig: { thinkingBudget: 20000 },
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          code: { type: Type.STRING },
          title: { type: Type.STRING },
          explanation: { type: Type.STRING }
        },
        required: ['code', 'title', 'explanation']
      }
    }
  });

  try {
    const result = JSON.parse(response.text || '{}');
    return {
      code: result.code || currentCode,
      title: result.title || 'Studio Project',
      explanation: result.explanation || 'Logic updated.'
    };
  } catch (e) {
    console.error("Studio Synthesis Error:", e);
    throw new Error("Logic synthesis failed.");
  }
};

import React, { useState, useRef, useEffect } from 'react';
