            }`}>
              {msg.text}
            </div>
          </div>
        ))}

        {isProcessing && (
          <div className="flex gap-3 animate-pulse">
            <div className="shrink-0 w-8 h-8 rounded-xl bg-emerald-500/10 border border-emerald-500/20 flex items-center justify-center">
              <Loader2 className="w-4 h-4 text-emerald-400 animate-spin" />
            </div>
            <div className="bg-zinc-800/30 border border-emerald-500/5 p-3 rounded-2xl text-[10px] font-black uppercase tracking-widest text-emerald-500/50">
              Applying Code Refinements...
            </div>
          </div>
        )}
      </div>

      <form onSubmit={handleSubmit} className="p-4 border-t border-white/5 bg-zinc-950/80">
        <div className="relative">
          <input
            type="text"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            disabled={isProcessing}
            placeholder="Instruct the AI Architect..."
            className="w-full bg-zinc-900/50 border border-white/5 rounded-xl py-3 px-4 pr-12 text-xs text-zinc-300 placeholder:text-zinc-600 focus:outline-none focus:border-emerald-500/40 transition-all"
          />
          <button
            type="submit"
            disabled={isProcessing || !input.trim()}
            className="absolute right-2 top-1.5 p-2 rounded-lg bg-emerald-500 text-black hover:bg-emerald-400 disabled:opacity-30 transition-all"
          >
            <Send className="w-4 h-4" />
