              className="shrink-0 px-2 py-1 rounded-md border border-white/5 bg-zinc-900/40 text-[8px] font-black uppercase tracking-widest text-zinc-600 hover:text-emerald-500 hover:border-emerald-500/20 transition-all"
            >
              {tag}
            </button>
          ))}
        </div>
      </form>
    </div>
  );
};

