              <span className="text-[7px] text-zinc-500 font-black uppercase tracking-[0.2em]">Alpha Engine v3.5</span>
            </div>
          </div>
        </div>

        <div className="flex items-center gap-3">
          {game && (
            <button 
              onClick={handleExport}
              className="flex items-center gap-2 px-3 py-1.5 rounded-lg bg-zinc-900 border border-white/5 text-[10px] font-black uppercase tracking-widest text-zinc-400 hover:text-white hover:bg-zinc-800 transition-all"
