import React, { useMemo, useEffect, useRef } from 'react';
import { GameAsset } from '../types';
import { Maximize2, Activity, ShieldCheck, Zap } from 'lucide-react';

interface GameRunnerProps {
  code: string;
  title: string;
  assets: GameAsset[];
}

export const GameRunner: React.FC<GameRunnerProps> = ({ code, title, assets }) => {
  const iframeRef = useRef<HTMLIFrameElement>(null);

  const combinedSrcDoc = useMemo(() => {
    const assetMap = assets.reduce((acc, asset) => {
      acc[asset.name] = asset.content;
      return acc;
    }, {} as Record<string, string>);

    const bootstrapScript = `
      <script>
        (function() {
          const rawAssets = ${JSON.stringify(assetMap)};
          const blobUrls = {};

          function base64ToBlob(base64, mime) {
            const split = base64.split(',');
            const data = split[1] || split[0];
            const byteString = atob(data);
            const ab = new ArrayBuffer(byteString.length);
            const ia = new Uint8Array(ab);
            for (let i = 0; i < byteString.length; i++) {
              ia[i] = byteString.charCodeAt(i);
            }
            return new Blob([ab], { type: mime });
          }

          window.getAssetUrl = function(name) {
            if (blobUrls[name]) return blobUrls[name];
            const data = rawAssets[name];
            if (!data) {
              console.warn("Forge Studio Error: Asset [" + name + "] is unmapped.");
              return "";
            }
            let mime = 'application/octet-stream';
            if (data.includes('data:')) {
              mime = data.split(':')[1].split(';')[0];
            }
            const blob = base64ToBlob(data, mime);
            const url = URL.createObjectURL(blob);
            blobUrls[name] = url;
            return url;
          };

          console.log("%c Forge Studio Core %c Live Simulation Active ", "background: #10b981; color: #000; font-weight: bold; border-radius: 4px 0 0 4px", "background: #18181b; color: #10b981; border-radius: 0 4px 4px 0");
        })();
      </script>
      <style>
        body { margin: 0; background: #000; overflow: hidden; }
        canvas { display: block; width: 100vw; height: 100vh; }
      </style>
    `;

    if (code.includes('<head>')) {
      return code.replace('<head>', `<head>${bootstrapScript}`);
    }
    return bootstrapScript + code;
  }, [code, assets]);

  return (
    <div className="w-full h-full flex flex-col bg-black relative group">
      {/* Production Overlay HUD */}
      <div className="absolute inset-0 pointer-events-none z-30 flex flex-col justify-between p-6">
        <div className="flex justify-between items-start opacity-0 group-hover:opacity-100 transition-opacity duration-500">
          <div className="bg-black/60 backdrop-blur-md border border-white/5 px-4 py-2 rounded-xl flex items-center gap-3">
            <Zap className="w-3.5 h-3.5 text-emerald-500 animate-pulse" />
            <h3 className="text-[10px] font-black text-white uppercase tracking-[0.3em] italic">{title}</h3>
          </div>
          <div className="flex gap-2">
            <div className="bg-black/60 backdrop-blur-md border border-white/5 px-3 py-1.5 rounded-lg flex items-center gap-2">
              <Activity className="w-3 h-3 text-zinc-500" />
              <span className="text-[8px] font-black text-zinc-400 uppercase tracking-widest">FPS: 60.0</span>
            </div>
            <button className="bg-black/60 backdrop-blur-md border border-white/5 p-1.5 rounded-lg text-zinc-400 hover:text-white pointer-events-auto transition-colors">
              <Maximize2 className="w-3.5 h-3.5" />
            </button>
          </div>
        </div>

        <div className="flex justify-between items-end opacity-0 group-hover:opacity-100 transition-opacity duration-500">
          <div className="flex gap-4">
             <div className="flex items-center gap-2 bg-emerald-500/10 border border-emerald-500/20 px-3 py-1 rounded-md">
               <ShieldCheck className="w-3 h-3 text-emerald-500" />
               <span className="text-[7px] font-black text-emerald-500 uppercase tracking-widest">Secure Runtime</span>
             </div>
          </div>
          <span className="text-[8px] font-black text-zinc-700 uppercase tracking-[0.5em]">Live Rendering Environment</span>
        </div>
      </div>

      {/* Grid Pattern Floor (Studio Aesthetic) */}
      <div className="absolute inset-0 bg-[linear-gradient(rgba(16,185,129,0.01)_1px,transparent_1px),linear-gradient(90deg,rgba(16,185,129,0.01)_1px,transparent_1px)] bg-[size:50px_50px] pointer-events-none" />

      {/* Main Viewport */}
      <iframe
        ref={iframeRef}
        srcDoc={combinedSrcDoc}
        title="Production Simulation"
        className="w-full h-full border-none relative z-10"
        sandbox="allow-scripts allow-modals allow-pointer-lock"
      />
    </div>
  );
};

import React, { useState } from 'react';
import { AssetType, GameAsset } from '../types';
import { X, Box, Image as ImageIcon, Music, MessageSquare, Plus, Globe } from 'lucide-react';

interface AssetUploaderProps {
  assets: GameAsset[];
  onAssetsChange: (assets: GameAsset[]) => void;
}

export const AssetUploader: React.FC<AssetUploaderProps> = ({ assets, onAssetsChange }) => {
  const [dialogueInput, setDialogueInput] = useState('');

  const getMimeType = (file: File): string => {
    if (file.type) return file.type;
    const extension = file.name.split('.').pop()?.toLowerCase();
    switch (extension) {
      case 'glb': return 'model/gltf-binary';
      case 'gltf': return 'model/gltf+json';
      case 'fbx': return 'application/octet-stream';
      case 'obj': return 'text/plain';
      default: return 'application/octet-stream';
    }
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>, type: AssetType) => {
    const files = e.target.files;
    if (!files) return;

    Array.from(files).forEach(file => {
      const reader = new FileReader();
      reader.onload = (event) => {
        const mimeType = getMimeType(file);
        const newAsset: GameAsset = {
          id: Math.random().toString(36).substr(2, 9),
          name: file.name,
          type,
          content: event.target?.result as string,
          mimeType
        };
        onAssetsChange([...assets, newAsset]);
      };
      reader.readAsDataURL(file);
    });
    e.target.value = '';
  };

  const removeAsset = (id: string) => {
    onAssetsChange(assets.filter(a => a.id !== id));
  };

  const AssetSection = ({ type, icon: Icon, label, accept }: { type: AssetType, icon: any, label: string, accept?: string }) => (
    <div className="flex flex-col gap-2">
      <div className="flex items-center justify-between">
        <div className="flex items-center gap-1.5 opacity-40">
          <Icon className="w-3 h-3" />
          <span className="text-[8px] font-black uppercase tracking-widest">{label}</span>
        </div>
        <label className="cursor-pointer bg-zinc-900 border border-white/5 hover:border-emerald-500/40 px-2 py-0.5 rounded text-[8px] font-black text-zinc-500 hover:text-emerald-500 transition-all">
          +
          <input 
            type="file" 
            className="hidden" 
            onChange={(e) => handleFileUpload(e, type)}
            accept={accept}
          />
        </label>
      </div>

      <div className="space-y-1">
        {assets.filter(a => a.type === type).map(asset => (
          <div key={asset.id} className="flex items-center justify-between bg-zinc-900/40 p-1.5 rounded-lg text-[9px] group/item border border-transparent hover:border-white/5 transition-all">
            <span className="truncate max-w-[150px] text-zinc-500 font-mono">{asset.name}</span>
            <button 
              onClick={() => removeAsset(asset.id)}
              className="text-zinc-700 hover:text-red-400 opacity-0 group-hover/item:opacity-100 transition-opacity"
            >
              <X className="w-2.5 h-2.5" />
            </button>
          </div>
        ))}
        {assets.filter(a => a.type === type).length === 0 && (
           <div className="h-4 border border-dashed border-white/5 rounded-lg opacity-20" />
        )}
      </div>
    </div>
  );

  return (
    <div className="space-y-6">
      <AssetSection type="model" icon={Box} label="3D Geometry" accept=".glb,.fbx" />
      <AssetSection type="environment" icon={Globe} label="Env Maps" accept="image/*,.hdr" />
      <AssetSection type="character" icon={ImageIcon} label="Textures" accept="image/*" />
      <AssetSection type="music" icon={Music} label="Spatial Audio" accept="audio/*" />

      <div className="flex flex-col gap-2 pt-4 border-t border-white/5">
        <div className="flex items-center gap-1.5 opacity-40">
          <MessageSquare className="w-3 h-3" />
          <span className="text-[8px] font-black uppercase tracking-widest">Logic Nodes</span>
        </div>
        <div className="flex gap-2">
          <input 
            type="text" 
            value={dialogueInput}
            onChange={(e) => setDialogueInput(e.target.value)}
            placeholder="Add node..."
            className="flex-1 bg-zinc-900/40 border border-white/5 rounded-lg px-2 py-1.5 text-[10px] focus:outline-none focus:border-emerald-500/20"
            onKeyDown={(e) => {
              if (e.key === 'Enter' && dialogueInput.trim()) {
                const newAsset: GameAsset = {
                  id: Math.random().toString(36).substr(2, 9),
                  name: `Node_${assets.filter(a => a.type === 'dialogue').length + 1}`,
                  type: 'dialogue',
                  content: dialogueInput,
                  mimeType: 'text/plain'
                };
                onAssetsChange([...assets, newAsset]);
                setDialogueInput('');
              }
            }}
          />
        </div>
        <div className="space-y-1">
          {assets.filter(a => a.type === 'dialogue').map(asset => (
            <div key={asset.id} className="flex items-center justify-between bg-zinc-900/40 p-1.5 rounded-lg text-[9px] group/item">
              <span className="truncate max-w-[150px] text-zinc-600 italic">"{asset.content}"</span>
              <button onClick={() => removeAsset(asset.id)} className="text-zinc-700 hover:text-red-400 opacity-0 group-hover/item:opacity-100">
                <X className="w-2.5 h-2.5" />
              </button>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};

