}

export const GameRunner: React.FC<GameRunnerProps> = ({ code, title, assets }) => {
  const iframeRef = useRef<HTMLIFrameElement>(null);

  const combinedSrcDoc = useMemo(() => {
    const assetMap = assets.reduce((acc, asset) => {
      acc[asset.name] = asset.content;
      return acc;
    }, {} as Record<string, string>);

    const bootstrapScript = `
      <script>
        (function() {
          const rawAssets = ${JSON.stringify(assetMap)};
          const blobUrls = {};

          function base64ToBlob(base64, mime) {
            const split = base64.split(',');
            const data = split[1] || split[0];
            const byteString = atob(data);
            const ab = new ArrayBuffer(byteString.length);
            const ia = new Uint8Array(ab);
            for (let i = 0; i < byteString.length; i++) {
              ia[i] = byteString.charCodeAt(i);
            }
            return new Blob([ab], { type: mime });
          }

          window.getAssetUrl = function(name) {
            if (blobUrls[name]) return blobUrls[name];
            const data = rawAssets[name];
            if (!data) {
              console.warn("Forge Studio Error: Asset [" + name + "] is unmapped.");
              return "";
            }
            let mime = 'application/octet-stream';
            if (data.includes('data:')) {
              mime = data.split(':')[1].split(';')[0];
            }
            const blob = base64ToBlob(data, mime);
            const url = URL.createObjectURL(blob);
            blobUrls[name] = url;
            return url;
          };

          console.log("%c Forge Studio %c Live Build Online ", "background: #10b981; color: #000; font-weight: bold; padding: 2px 4px; border-radius: 4px 0 0 4px", "background: #18181b; color: #10b981; padding: 2px 4px; border-radius: 0 4px 4px 0");
        })();
      </script>
      <style>
        body { margin: 0; background: #000; overflow: hidden; display: flex; align-items: center; justify-content: center; }
        canvas { display: block; width: 100vw; height: 100vh; object-fit: contain; }
      </style>
    `;

    if (code.includes('<head>')) {
      return code.replace('<head>', `<head>${bootstrapScript}`);
    }
    return bootstrapScript + code;
  }, [code, assets]);

  return (
    <div className="w-full h-full flex flex-col bg-black relative group overflow-hidden">
      {/* HUD: Cinematic Borders */}
      <div className="absolute inset-0 pointer-events-none z-40">
        <div className="absolute top-0 inset-x-0 h-4 bg-gradient-to-b from-black/80 to-transparent" />
        <div className="absolute bottom-0 inset-x-0 h-4 bg-gradient-to-t from-black/80 to-transparent" />
        <div className="absolute inset-0 border-[1px] border-white/5 opacity-50" />
      </div>

      {/* HUD: Interactive Production Overlays */}
      <div className="absolute inset-0 pointer-events-none z-50 flex flex-col justify-between p-6">
        <div className="flex justify-between items-start">
          <div className="flex items-center gap-3">
            <div className="bg-black/60 backdrop-blur-xl border border-white/10 px-4 py-2 rounded-xl flex items-center gap-3 shadow-2xl">
              <div className="relative">
