                <div className="absolute -inset-1 bg-emerald-500/20 blur-sm rounded-full animate-pulse" />
              </div>
              <div className="flex flex-col">
                <h3 className="text-[11px] font-black text-white uppercase tracking-[0.2em] italic leading-none">{title}</h3>
                <span className="text-[7px] text-emerald-500/70 font-black uppercase tracking-widest mt-1">Live Substrate Render</span>
