          <BrainCircuit className="w-4 h-4 text-emerald-400" />
          <h2 className="text-[9px] font-black uppercase tracking-[0.3em] text-zinc-500">AI Architect</h2>
        </div>
        <div className="flex items-center gap-2">
          <Zap className="w-3 h-3 text-yellow-500 animate-pulse" />
          <span className="text-[7px] font-black text-zinc-700 tracking-widest uppercase">Neural Link Active</span>
        </div>
      </div>

      {/* Messages Feed */}
      <div ref={scrollRef} className="flex-1 overflow-y-auto p-5 space-y-6 scroll-smooth no-scrollbar">
        {history.length === 0 && (
          <div className="h-full flex flex-col items-center justify-center text-center px-10">
            <div className="w-12 h-12 bg-emerald-500/5 rounded-2xl flex items-center justify-center mb-4 border border-emerald-500/10">
              <Sparkles className="w-6 h-6 text-emerald-500/40" />
            </div>
            <p className="text-[9px] font-black uppercase tracking-[0.4em] leading-relaxed text-zinc-800">
              Substrate clear.<br/>Define simulation parameters.
            </p>
          </div>
        )}

        {history.map((msg, i) => (
          <div key={i} className={`flex gap-4 ${msg.role === 'user' ? 'flex-row-reverse' : ''}`}>
            <div className={`shrink-0 w-8 h-8 rounded-xl flex items-center justify-center border shadow-xl ${
              msg.role === 'user' ? 'bg-zinc-900 border-white/5' : 'bg-emerald-500/10 border-emerald-500/20'
            }`}>
              {msg.role === 'user' ? <User className="w-4 h-4 text-zinc-600" /> : <Bot className="w-4 h-4 text-emerald-400" />}
            </div>
            <div className={`max-w-[80%] p-3 rounded-2xl text-[12px] leading-relaxed shadow-lg ${
              msg.role === 'user' 
                ? 'bg-zinc-900/80 text-zinc-300 border border-white/5' 
                : 'bg-emerald-500/5 text-emerald-50 border border-emerald-500/10'
            }`}>
              {msg.text}
            </div>
          </div>
        ))}

        {isProcessing && (
          <div className="flex gap-4 animate-pulse">
            <div className="shrink-0 w-8 h-8 rounded-xl bg-emerald-500/10 border border-emerald-500/20 flex items-center justify-center">
              <Loader2 className="w-4 h-4 text-emerald-400 animate-spin" />
            </div>
            <div className="bg-emerald-500/5 border border-emerald-500/10 p-3 rounded-2xl text-[9px] font-black uppercase tracking-widest text-emerald-500/50">
              Synthesizing Architectural Changes...
            </div>
          </div>
        )}
      </div>

      {/* Input Bar */}
      <form onSubmit={handleSubmit} className="p-4 border-t border-white/5 bg-zinc-950/60">
        <div className="relative group">
          <input
            type="text"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            disabled={isProcessing}
            placeholder="Instruct the Architect..."
            className="w-full bg-zinc-900/40 border border-white/10 rounded-xl py-3.5 px-5 pr-14 text-[13px] text-zinc-300 placeholder:text-zinc-700 focus:outline-none focus:border-emerald-500/40 focus:bg-zinc-900/60 transition-all"
          />
          <button
            type="submit"
            disabled={isProcessing || !input.trim()}
            className="absolute right-2 top-2 p-2.5 rounded-lg bg-emerald-500 text-black hover:bg-emerald-400 disabled:opacity-30 transition-all shadow-[0_0_15px_rgba(16,185,129,0.2)]"
          >
            <Send className="w-4 h-4" />
          </button>
        </div>

        {/* Quick Suggestions */}
        <div className="mt-4 flex gap-2 overflow-x-auto pb-1 no-scrollbar">
          {['Add Traffic AI', 'Realistic Fog', 'Optimize Steering', 'Neon Skybox'].map(tag => (
            <button
              key={tag}
              type="button"
              onClick={() => setInput(tag)}
              className="shrink-0 px-3 py-1.5 rounded-lg border border-white/5 bg-zinc-900/20 text-[8px] font-black uppercase tracking-widest text-zinc-700 hover:text-emerald-500 hover:border-emerald-500/20 transition-all active:scale-95"
            >
              {tag}
            </button>
          ))}
        </div>
      </form>
    </div>
  );
};

import React, { useState, useCallback } from 'react';
import { AssetUploader } from './components/AssetUploader';
import { GameRunner } from './components/GameRunner';
import { AIChat } from './components/AIChat';
import { generateGame } from './services/gemini';
import { GameAsset, GenerationStatus, GeneratedGame, ChatMessage } from './types';
import { Box, Cpu, Activity, Download, Layers, Monitor, Code, Play, Terminal, Zap, Sparkles, ExternalLink, BoxSelect } from 'lucide-react';

type ViewMode = 'studio' | 'preview';

const App: React.FC = () => {
  const [viewMode, setViewMode] = useState<ViewMode>('studio');
  const [assets, setAssets] = useState<GameAsset[]>([]);
  const [prompt, setPrompt] = useState('');
  const [status, setStatus] = useState<GenerationStatus>({ step: 'idle', message: '' });
  const [game, setGame] = useState<GeneratedGame | null>(null);
  const [chatHistory, setChatHistory] = useState<ChatMessage[]>([]);
  const [logs, setLogs] = useState<string[]>(['> Initializing Forge Studio v3.5-L...', '> Ready for substrate mounting.']);

  const addLog = (msg: string) => {
    setLogs(prev => [...prev.slice(-15), `> ${msg}`]);
  };

  const processGeneration = useCallback(async (instruction: string) => {
    setStatus({ step: 'analyzing', message: 'Synthesizing Architecture...' });
    addLog(`Neural synthesis requested: "${instruction.slice(0, 30)}..."`);

    const newUserMsg: ChatMessage = { role: 'user', text: instruction };
    setChatHistory(prev => [...prev, newUserMsg]);

    try {
      const result = await generateGame(
        instruction, 
        assets, 
        chatHistory, 
        game?.code || ""
      );

      setGame({ code: result.code, title: result.title });
      setChatHistory(prev => [...prev, { role: 'ai', text: result.explanation }]);
      setStatus({ step: 'ready', message: 'Simulation Online.' });
      addLog(`Simulation "${result.title}" compiled successfully.`);

      // Auto-launch if it's the first build
      if (!game) {
        setTimeout(() => setViewMode('preview'), 800);
      }
    } catch (error: any) {
      console.error(error);
      setStatus({ step: 'error', message: 'Forge Critical Failure.' });
      setChatHistory(prev => [...prev, { role: 'ai', text: 'Architectural collapse. Please refine instructions.' }]);
      addLog(`CRITICAL: Logic synthesis failed.`);
    }
  }, [assets, chatHistory, game]);

  // Handle exiting preview
  const exitPreview = () => setViewMode('studio');

  return (
    <div className="flex flex-col h-screen max-h-screen bg-[#020203] text-zinc-100 overflow-hidden font-sans relative">

      {/* 
