      )}

      {/* Subtle Exit Control (Appears on Hover at Top) */}
      <div className="absolute top-0 left-0 right-0 h-20 z-[1050] flex justify-center opacity-0 hover:opacity-100 transition-opacity duration-300 group">
        <button 
          onClick={onExit}
          className="mt-6 flex items-center gap-3 bg-black/80 backdrop-blur-3xl border border-white/10 px-6 py-2.5 rounded-2xl hover:bg-white hover:text-black hover:border-white transition-all transform hover:scale-105 active:scale-95 shadow-2xl pointer-events-auto"
        >
          <Power className="w-4 h-4" />
          <span className="text-[9px] font-black uppercase tracking-[0.2em]">Exit Simulation</span>
        </button>
      </div>

      {/* Pure Game Iframe */}
      <iframe
        ref={iframeRef}
        srcDoc={combinedSrcDoc}
        title="Forge Runtime"
        className={`w-full h-full border-none transition-opacity duration-1000 ${isMounting ? 'opacity-0' : 'opacity-100'}`}
        sandbox="allow-scripts allow-modals allow-pointer-lock"
      />
    </div>
  );
};

import React, { useState, useCallback } from 'react';
import { AssetUploader } from './components/AssetUploader';
import { GameRunner } from './components/GameRunner';
import { AIChat } from './components/AIChat';
import { generateGame } from './services/gemini';
import { GameAsset, GenerationStatus, GeneratedGame, ChatMessage } from './types';
import { Box, Activity, Download, Layers, Monitor, Terminal, Zap, Sparkles, Play, BoxSelect, Menu, X, MessageSquareCode } from 'lucide-react';

type ViewMode = 'editor' | 'preview';

const App: React.FC = () => {
  const [viewMode, setViewMode] = useState<ViewMode>('editor');
  const [assets, setAssets] = useState<GameAsset[]>([]);
  const [prompt, setPrompt] = useState('');
  const [status, setStatus] = useState<GenerationStatus>({ step: 'idle', message: '' });
  const [game, setGame] = useState<GeneratedGame | null>(null);
  const [chatHistory, setChatHistory] = useState<ChatMessage[]>([]);
  const [logs, setLogs] = useState<string[]>(['> Initializing Forge Studio...', '> Systems ready for substrate mounting.']);
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [activeConsoleTab, setActiveConsoleTab] = useState<'logs' | 'chat'>('chat');

  const addLog = (msg: string) => {
    setLogs(prev => [...prev.slice(-15), `> ${msg}`]);
  };

  const processGeneration = useCallback(async (instruction: string) => {
    setStatus({ step: 'analyzing', message: 'Synthesizing Architecture...' });
    addLog(`Neural synthesis requested: "${instruction.slice(0, 30)}..."`);

    const newUserMsg: ChatMessage = { role: 'user', text: instruction };
    setChatHistory(prev => [...prev, newUserMsg]);

    try {
      const result = await generateGame(
        instruction, 
        assets, 
        chatHistory, 
        game?.code || ""
      );

      setGame({ code: result.code, title: result.title });
      setChatHistory(prev => [...prev, { role: 'ai', text: result.explanation }]);
      setStatus({ step: 'ready', message: 'Simulation Compiled.' });
      addLog(`Build "${result.title}" staged successfully.`);

    } catch (error: any) {
      console.error(error);
      setStatus({ step: 'error', message: 'Forge Critical Failure.' });
      setChatHistory(prev => [...prev, { role: 'ai', text: 'Architectural collapse. Please refine instructions.' }]);
      addLog(`CRITICAL: Logic synthesis failed.`);
    }
  }, [assets, chatHistory, game]);

  const enterPreview = () => {
    if (game) setViewMode('preview');
  };

  const exitPreview = () => setViewMode('editor');

  // Preview Mode: Pure Runtime View
  if (viewMode === 'preview' && game) {
    return (
      <div className="fixed inset-0 z-[500] bg-black">
        <GameRunner 
          code={game.code} 
          title={game.title} 
          assets={assets} 
          onExit={exitPreview}
