          <button 
            onClick={() => setIsSidebarOpen(!isSidebarOpen)}
            className="md:hidden p-2 hover:bg-white/5 rounded-lg transition-colors"
          >
            {isSidebarOpen ? <X className="w-5 h-5" /> : <Menu className="w-5 h-5" />}
          </button>

          <div className="flex items-center gap-2 md:gap-3">
            <div className="bg-emerald-500 p-1 rounded-lg shadow-[0_0_15px_rgba(16,185,129,0.3)]">
              <Box className="w-3.5 h-3.5 md:w-4 md:h-4 text-black" />
            </div>
            <div className="flex flex-col">
              <h1 className="text-xs md:text-sm font-black tracking-tighter italic uppercase">
                Forge<span className="text-emerald-500">Studio</span>
              </h1>
              <span className="text-[6px] md:text-[7px] text-zinc-600 font-black uppercase tracking-[0.3em] -mt-0.5 hidden xs:block">Creation Suite</span>
            </div>
          </div>

          <div className="h-8 w-px bg-white/5 hidden sm:block" />

          <div className="hidden lg:flex items-center gap-4 text-[9px] font-black uppercase tracking-widest text-zinc-500">
            <div className="flex items-center gap-1.5">
              <Activity className="w-3 h-3 text-emerald-500/50" />
              <span>LOGIC: ACTIVE</span>
            </div>
            <div className="flex items-center gap-1.5">
              <Zap className="w-3 h-3 text-yellow-500/50" />
              <span>NEURAL: LINKED</span>
            </div>
          </div>
        </div>

        <div className="flex items-center gap-2 md:gap-3">
          {game && (
            <div className="flex items-center gap-1 md:gap-2">
              <button 
                onClick={enterPreview}
