import { GoogleGenAI, Type } from "@google/genai";
import { GameAsset, ChatMessage } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const generateGame = async (
  prompt: string,
  assets: GameAsset[],
  history: ChatMessage[] = [],
  currentCode: string = ""
): Promise<{ code: string; title: string; explanation: string }> => {

  const assetMetadata = assets.map(a => ({
    name: a.name,
    type: a.type,
    mimeType: a.mimeType
  }));

  const isRefinement = history.length > 0 && currentCode !== "";

  const systemInstruction = `
    You are the Lead 3D Engine Architect. You specialize in high-performance Three.js applications.

    CORE DIRECTIVE:
    Every asset provided in the matrix is a 3D component. 
    - "entity": These are the 3D models for characters, props, or actors.
    - "scenery": 3D geometry for the level, terrain, or skybox.
    - "kinematics": Animation files (GLB/FBX) that contain clips to be applied to entities.
    - "material": PBR textures to be applied to MeshStandardMaterials.

    ASSET LOADING:
    - Use window.getAssetUrl(name) to retrieve blob URLs.
    - For entities/scenery/kinematics: Use THREE.GLTFLoader or THREE.FBXLoader.
    - For kinematics: Always implement a AnimationMixer to play back clips found in the file.

    ENGINE ARCHITECTURE:
    1. SCENE GRAPH: Organize your world with Groups for Entities and Scenery.
    2. PHYSICS: Use Ammo.js or simple raycasting/AABB logic for interactions.
    3. RENDERER: Enable shadows, use ACESFilmicToneMapping, and handle window resizing.
    4. HUD: Create a clean, responsive HTML overlay for gameplay stats.

    RESPONSE REQUIREMENT:
    Return a JSON object with:
    - "code": The full, functional HTML/JS code (including library CDNs).
    - "title": A professional game title.
    - "explanation": A brief dev log of the 3D implementation.
  `;

  const userPrompt = isRefinement 
    ? `Current Build Code: ${currentCode}\n\nArchitectural Modification: ${prompt}\n\nAvailable 3D Matrix: ${JSON.stringify(assetMetadata)}`
    : `Initial Project Seed: ${prompt}\n\n3D Matrix: ${JSON.stringify(assetMetadata)}`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: userPrompt,
    config: {
      systemInstruction,
      thinkingConfig: { thinkingBudget: 25000 },
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          code: { type: Type.STRING },
          title: { type: Type.STRING },
          explanation: { type: Type.STRING }
        },
        required: ['code', 'title', 'explanation']
      }
    }
  });

  try {
    const result = JSON.parse(response.text || '{}');
    return {
      code: result.code || currentCode,
      title: result.title || 'Studio Project',
      explanation: result.explanation || 'Logic updated.'
    };
  } catch (e) {
    console.error("Studio Synthesis Error:", e);
    throw new Error("Logic synthesis failed.");
  }
};

