import React, { useState } from 'react';
import { AssetType, GameAsset } from '../types';
import { X, Box, Music, MessageSquare, Plus, Globe, Activity, Users, Info } from 'lucide-react';

interface AssetUploaderProps {
  assets: GameAsset[];
  onAssetsChange: (assets: GameAsset[]) => void;
}

const LIMITS: Record<AssetType, number | null> = {
  character1: 4,
  motion1: 10,
  character2: 4,
  motion2: 10,
  environment: null,
  music: null,
  dialogue: null
};

export const AssetUploader: React.FC<AssetUploaderProps> = ({ assets, onAssetsChange }) => {
  const [dialogueInput, setDialogueInput] = useState('');

  const getMimeType = (file: File): string => {
    if (file.type) return file.type;
    const extension = file.name.split('.').pop()?.toLowerCase();
    switch (extension) {
      case 'glb': return 'model/gltf-binary';
      case 'gltf': return 'model/gltf+json';
      case 'fbx': return 'application/octet-stream';
      default: return 'application/octet-stream';
    }
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>, type: AssetType) => {
    const files = e.target.files;
    if (!files) return;

    const currentCount = assets.filter(a => a.type === type).length;
    const limit = LIMITS[type];

    const filesToUpload = Array.from(files);

    if (limit !== null && currentCount + filesToUpload.length > limit) {
      alert(`Capacity Warning: ${type} slot is limited to ${limit} assets.`);
      e.target.value = '';
      return;
    }

    filesToUpload.forEach((file: File) => {
      const reader = new FileReader();
      reader.onload = (event) => {
        const mimeType = getMimeType(file);
        const newAsset: GameAsset = {
          id: Math.random().toString(36).substr(2, 9),
          name: file.name,
          type,
          content: event.target?.result as string,
          mimeType
        };
        onAssetsChange([...assets, newAsset]);
      };
      reader.readAsDataURL(file);
    });
    e.target.value = '';
  };

  const removeAsset = (id: string) => {
    onAssetsChange(assets.filter(a => a.id !== id));
  };

  const AssetSection = ({ 
    type, 
    icon: Icon, 
    label, 
    accept = ".glb,.fbx", 
    description 
  }: { 
    type: AssetType, 
    icon: any, 
    label: string, 
    accept?: string, 
    description?: string 
  }) => {
    const currentAssets = assets.filter(a => a.type === type);
    const limit = LIMITS[type];
    const isFull = limit !== null && currentAssets.length >= limit;

    return (
      <div className="flex flex-col gap-2">
        <div className="flex items-center justify-between">
          <div className="flex items-center gap-2">
            <div className="p-1.5 rounded-md bg-zinc-900 border border-white/5">
              <Icon className="w-3.5 h-3.5 text-emerald-500" />
            </div>
            <div className="flex flex-col">
              <span className="text-[10px] font-black uppercase tracking-wider text-zinc-300">{label}</span>
              <div className="flex items-center gap-1">
                <span className="text-[7px] text-zinc-600 font-bold uppercase tracking-tight">
                  {limit ? `${currentAssets.length}/${limit} Slots` : 'Unlimited'}
                </span>
                {limit && currentAssets.length === limit && (
                  <div className="w-1 h-1 rounded-full bg-red-500 animate-pulse" />
