import { GoogleGenAI, Type } from "@google/genai";
import { GameAsset, ChatMessage } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const generateGame = async (
  prompt: string,
  assets: GameAsset[],
  history: ChatMessage[] = [],
  currentCode: string = ""
): Promise<{ code: string; title: string; explanation: string }> => {

  const assetMetadata = assets.map(a => ({
    name: a.name,
    type: a.type,
    mimeType: a.mimeType
  }));

  const isRefinement = history.length > 0 && currentCode !== "";

  const systemInstruction = `
    You are the Lead 3D Engine Architect. You specialize in high-performance Three.js applications.

    CORE DIRECTIVE:
    Every asset provided in the matrix is a 3D component. You must build a runtime that maps assets as follows:
    - Entity A (Character 1 Pool): Up to 4 character models and 10 motion files.
    - Entity B (Character 2 Pool): Up to 4 character models and 10 motion files.
    - Environment: Static geometry or stage.
    - Music: Ambient background tracks.
    - Dialogue/Logic: Behavioral scripts or gameplay rules.

    ASSET LOADING:
    - Use window.getAssetUrl(name) to retrieve blob URLs.
    - For Characters/Environment/Motions: Use THREE.GLTFLoader (preferred) or THREE.FBXLoader.
    - Motions must be applied to characters using THREE.AnimationMixer.

    ENGINE ARCHITECTURE:
    1. SCENE GRAPH: Organize your world with distinct Groups for Character 1 and Character 2.
    2. PHYSICS: Implement collision logic (Entity A vs Entity B) if requested. Use simple Raycasting or OBB/AABB.
    3. RENDERER: Use a high-fidelity setup: WebGLRenderer, Shadows enabled, ACESFilmicToneMapping, and bloom if applicable.
    4. HUD: Render a clean, non-dev UI for HP, score, or labels.

    MANDATORY:
    The output must be a self-contained HTML/JS game. Do not include development tools or debug overlays in the code.

    RESPONSE REQUIREMENT:
    Return a JSON object with:
    - "code": Full HTML/JS string.
    - "title": Professional game title.
    - "explanation": Brief dev log of the 3D binding logic.
  `;

  const userPrompt = isRefinement 
    ? `Update Build Logic. Modifications: ${prompt}\n\nCurrent Code State: ${currentCode}\n\nAsset Manifest: ${JSON.stringify(assetMetadata)}`
    : `Initialize 3D Simulation. Prompt: ${prompt}\n\nAsset Manifest: ${JSON.stringify(assetMetadata)}`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: userPrompt,
    config: {
      systemInstruction,
      thinkingConfig: { thinkingBudget: 28000 },
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          code: { type: Type.STRING },
          title: { type: Type.STRING },
          explanation: { type: Type.STRING }
        },
        required: ['code', 'title', 'explanation']
      }
    }
  });

  try {
    const result = JSON.parse(response.text || '{}');
    return {
      code: result.code || currentCode,
      title: result.title || 'Studio Project',
      explanation: result.explanation || 'Substrate updated.'
    };
  } catch (e) {
    console.error("Studio Synthesis Error:", e);
    throw new Error("Logic synthesis failed.");
  }
};

