    - Use delta time (dt) from THREE.Clock for frame-rate independent movement.
    - Implement a 'Cleanup' function to dispose of geometries/textures to prevent memory leaks during hot-reloads.
    - Ensure the UI (HUD) is responsive and reflects the internal game state accurately.

    MANDATORY RESPONSE FORMAT:
    Return ONLY a JSON object with:
    - "code": The complete, production-ready HTML/JS string. Include all libraries (Three.js, GSAP for easing, etc.) via CDN.
    - "title": A compelling game title.
    - "explanation": A detailed technical dev log explaining how you implemented the mechanics and integrated the provided assets.
  `;

  const userPrompt = isRefinement 
    ? `System Update Request: ${prompt}\n\nMaintain current architectural integrity while applying these logical modifications.\n\nCurrent Codebase: ${currentCode}\n\nAsset Matrix: ${JSON.stringify(assetMetadata)}`
    : `Initial System Seed: ${prompt}\n\nSynthesize a full 3D simulation using these assets: ${JSON.stringify(assetMetadata)}`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: userPrompt,
    config: {
      systemInstruction,
      thinkingConfig: { thinkingBudget: 32000 }, // Maximize thinking budget for complex mechanics
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          code: { type: Type.STRING },
          title: { type: Type.STRING },
          explanation: { type: Type.STRING }
        },
        required: ['code', 'title', 'explanation']
      }
    }
  });

  try {
    const result = JSON.parse(response.text || '{}');
    return {
      code: result.code || currentCode,
      title: result.title || 'Studio Build',
      explanation: result.explanation || 'Logical synthesis complete.'
    };
  } catch (e) {
    console.error("Architectural Synthesis Failure:", e);
    throw new Error("The AI Architect encountered a logical paradox. Please refine your instructions.");
  }
};

import React, { useState, useRef, useEffect } from 'react';
