import { GoogleGenAI, Type } from "@google/genai";
import { GameAsset, ChatMessage } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const generateGame = async (
  prompt: string,
  assets: GameAsset[],
  history: ChatMessage[] = [],
  currentCode: string = ""
): Promise<{ code: string; title: string; explanation: string }> => {

  const assetMetadata = assets.map(a => ({
    name: a.name,
    type: a.type,
    mimeType: a.mimeType
  }));

  const isRefinement = history.length > 0 && currentCode !== "";

  const systemInstruction = `
    You are the Senior Neural Game Architect, a world-class expert in Three.js, ECS patterns, and game logic.

    CORE DIRECTIVE:
    Generate complex, logically robust 3D web games. Every response must follow a two-step mental model:
    1. ANALYZE: Deconstruct the user's intent and the mechanical implications.
    2. SYNTHESIZE: Produce highly performant Three.js code that integrates assets.

    LOGICAL THINKING REQUIREMENTS:
    - STATE MACHINES: Implement explicit state management (Intro -> Play -> Result).
    - INTERACTION LOOPS: Define clear triggers, actions, and feedback.
    - MATH & PHYSICS: Use vector math for movement, interpolation for smoothness, and efficient collision bounds.
    - ASSET BINDING: Use window.getAssetUrl(name) to map assets to Entity A (Character1/Motion1) and Entity B (Character2/Motion2).

    EXPLANATION STRUCTURE (MANDATORY):
    Your 'explanation' field must be a structured dev log:
    - [UNDERSTANDING]: A concise summary of what you believe the user wants to achieve.
    - [LOGICAL PLAN]: A bulleted list of the specific mechanical and architectural changes you are implementing.
    - [INTEGRATION]: How you are mapping the 3D assets to the code.

    ENGINE BEST PRACTICES:
    - Use THREE.Clock for dt-based movement.
    - Implement cleanup for memory efficiency.
    - Responsive HUD in HTML/CSS overlay.

    RESPONSE REQUIREMENT:
    Return a JSON object with "code", "title", and "explanation".
  `;

  const userPrompt = isRefinement 
    ? `MODIFICATION REQUEST: ${prompt}\n\nMaintain current game loop while applying these changes.\n\nCurrent Code: ${currentCode}\n\nAsset Matrix: ${JSON.stringify(assetMetadata)}`
    : `NEW PROJECT SEED: ${prompt}\n\nAssets: ${JSON.stringify(assetMetadata)}`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: userPrompt,
    config: {
      systemInstruction,
      thinkingConfig: { thinkingBudget: 32768 },
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          code: { type: Type.STRING },
          title: { type: Type.STRING },
          explanation: { type: Type.STRING }
        },
        required: ['code', 'title', 'explanation']
      }
    }
  });

  try {
    const result = JSON.parse(response.text || '{}');
    return {
      code: result.code || currentCode,
      title: result.title || 'Studio Project',
      explanation: result.explanation || 'Synthesis complete.'
    };
  } catch (e) {
    console.error("Logic Error:", e);
    throw new Error("Architectural synthesis failed.");
  }
};

import React, { useState, useCallback } from 'react';
import { AssetUploader } from './components/AssetUploader';
import { GameRunner } from './components/GameRunner';
import { AIChat } from './components/AIChat';
import { generateGame } from './services/gemini';
import { GameAsset, GenerationStatus, GeneratedGame, ChatMessage } from './types';
import { Box, Activity, Layers, Monitor, Terminal, Sparkles, Play, BoxSelect, Menu, X, MessageSquareCode } from 'lucide-react';

type ViewMode = 'editor' | 'preview';

const App: React.FC = () => {
  const [viewMode, setViewMode] = useState<ViewMode>('editor');
  const [assets, setAssets] = useState<GameAsset[]>([]);
  const [status, setStatus] = useState<GenerationStatus>({ step: 'idle', message: '' });
  const [game, setGame] = useState<GeneratedGame | null>(null);
  const [chatHistory, setChatHistory] = useState<ChatMessage[]>([]);
  const [logs, setLogs] = useState<string[]>(['> Initializing Forge Studio...', '> Systems ready for substrate mounting.']);
  const [isLeftSidebarOpen, setIsLeftSidebarOpen] = useState(false);
  const [isRightSidebarOpen, setIsRightSidebarOpen] = useState(false);
  const [activeMobileView, setActiveMobileView] = useState<'staging' | 'chat' | 'logs'>('staging');

  const addLog = (msg: string) => {
    setLogs(prev => [...prev.slice(-15), `> ${msg}`]);
  };

  const processGeneration = useCallback(async (instruction: string) => {
    setStatus({ step: 'analyzing', message: 'Analyzing Intent...' });
    addLog(`Instruction received: "${instruction.slice(0, 40)}..."`);

    setChatHistory(prev => [...prev, { role: 'user', text: instruction }]);

    try {
      const result = await generateGame(
        instruction, 
        assets, 
        chatHistory, 
        game?.code || ""
      );

      // Step 1: Respond first with understanding and plan
      setStatus({ step: 'coding', message: 'Staging Architecture...' });
      const aiMessage: ChatMessage = { 
        role: 'ai', 
        text: result.explanation,
        isApplying: true 
      };
      setChatHistory(prev => [...prev, aiMessage]);

      // Step 2: Brief intentional delay so user can read the "plan"
      await new Promise(resolve => setTimeout(resolve, 1500));

      // Step 3: Apply the changes instantly to the preview
      setGame({ code: result.code, title: result.title });
      setStatus({ step: 'ready', message: 'Logic Mounted.' });

      // Mark as done applying
      setChatHistory(prev => prev.map((m, idx) => 
        idx === prev.length - 1 ? { ...m, isApplying: false } : m
      ));

      addLog(`Build "${result.title}" updated and applied.`);

    } catch (error: any) {
      console.error(error);
      setStatus({ step: 'error', message: 'Architectural Failure.' });
      setChatHistory(prev => [...prev, { role: 'ai', text: 'Critical logical paradox encountered. Please clarify your instructions.' }]);
      addLog(`CRITICAL: Synthesis interrupted.`);
    }
  }, [assets, chatHistory, game]);

  const enterPreview = () => {
    if (game) setViewMode('preview');
  };

  const exitPreview = () => setViewMode('editor');

  if (viewMode === 'preview' && game) {
    return (
      <div className="fixed inset-0 z-[500] bg-black">
        <GameRunner 
          code={game.code} 
          title={game.title} 
          assets={assets} 
          onExit={exitPreview}
        />
      </div>
    );
  }

  return (
    <div className="flex flex-col h-screen max-h-screen bg-[#020203] text-zinc-100 overflow-hidden font-sans relative">
      {/* STUDIO EDITOR HEADER */}
      <header className="h-14 border-b border-white/5 bg-zinc-950/90 backdrop-blur-3xl flex items-center justify-between px-4 md:px-6 shrink-0 z-50">
        <div className="flex items-center gap-3 md:gap-6">
          <button 
            onClick={() => setIsLeftSidebarOpen(!isLeftSidebarOpen)}
            className="md:hidden p-2 hover:bg-white/5 rounded-lg transition-colors text-zinc-400"
          >
            {isLeftSidebarOpen ? <X className="w-5 h-5" /> : <Menu className="w-5 h-5" />}
          </button>

          <div className="flex items-center gap-2 md:gap-3">
            <div className="bg-emerald-500 p-1 rounded-lg">
              <Box className="w-3.5 h-3.5 md:w-4 md:h-4 text-black" />
            </div>
            <div className="flex flex-col">
              <h1 className="text-xs md:text-sm font-black tracking-tighter italic uppercase">
                Forge<span className="text-emerald-500">Studio</span>
              </h1>
              <span className="text-[6px] md:text-[7px] text-zinc-600 font-black uppercase tracking-[0.3em] -mt-0.5 hidden xs:block">Neural Engine</span>
            </div>
          </div>

          <div className="h-8 w-px bg-white/5 hidden sm:block" />

          <div className="hidden lg:flex items-center gap-4 text-[9px] font-black uppercase tracking-widest text-zinc-500">
            <div className="flex items-center gap-1.5">
              <Activity className={`w-3 h-3 ${status.step === 'ready' ? 'text-emerald-500' : 'text-zinc-700'}`} />
              <span>CORE: {status.step === 'ready' ? 'ONLINE' : 'STANDBY'}</span>
            </div>
          </div>
        </div>

        <div className="flex items-center gap-2 md:gap-3">
          {game && (
            <button 
              onClick={enterPreview}
              className="flex items-center gap-2 px-3 md:px-5 py-1.5 rounded-lg bg-emerald-500 text-black font-black text-[9px] md:text-[10px] uppercase tracking-widest hover:bg-emerald-400 transition-all shadow-[0_0_20px_rgba(16,185,129,0.2)]"
