            </div>
          </div>
        </div>

        {/* Right Sidebar: AI Architect */}
        <div className={`
          fixed inset-y-0 right-0 z-40 w-full md:w-[400px] lg:w-[450px] border-l border-white/5 bg-zinc-950/95 md:bg-zinc-950/30 backdrop-blur-3xl md:backdrop-blur-none
