import { GoogleGenAI, Type } from "@google/genai";
import { GameAsset, ChatMessage } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const generateGame = async (
  prompt: string,
  assets: GameAsset[],
  history: ChatMessage[] = [],
  currentCode: string = ""
): Promise<{ code: string; title: string; explanation: string }> => {

  const assetMetadata = assets.map(a => ({
    name: a.name,
    type: a.type,
    mimeType: a.mimeType,
    logicContext: a.type === 'dialogue' ? a.content : undefined
  }));

  const isRefinement = history.length > 0 && currentCode !== "";

  const systemInstruction = `
    You are the "Core Neural Architect" of ForgeAI Studio—a top-tier expert in Three.js, ECS (Entity Component System), and Game Design Patterns.

    CORE OPERATING MANDATE:
    Every response must be a masterclass in architectural reasoning. You do not just "code"; you solve mechanical puzzles.

    LOGICAL THINKING PROTOCOLS:
    1. GENRE RECOGNITION & BLUEPRINTING:
       - Identify if the user wants an Action, Adventure, Puzzle, or Simulation game.
       - Apply specific genre mechanics (e.g., 'Third Person' requires camera offsets and spring-arm logic; 'Platformer' requires coyote time and variable jump height).

    2. PHYSICS PARADIGMS:
       - Choose between KINEMATIC (math-driven movement) and DYNAMIC (physics-body driven).
       - Implement precise OBB (Oriented Bounding Box) or Sphere-based collisions.
       - Use THREE.Raycaster for ground detection, "climbable" checks, and interaction triggers.

    3. DEEP ASSET SYNERGY:
       - 'character1' (Player): Must have state-driven animations (Idle -> Walk -> Run -> Jump) using THREE.AnimationMixer and smoothly cross-faded clips from 'motion1'.
       - 'character2' (AI): Implement Finite State Machines (FSM) or Steering Behaviors (Wander, Seek, Avoid).
       - 'environment': Correctly scale and position the GLB model. Ensure lighting (Directional + Ambient) creates depth.
       - 'dialogue' (Logic Nodes): THESE ARE CORE RULES. If a node says "Speed is 2x at night", you MUST implement a day/night variable and apply that multiplier.

    4. ADVANCED CONTROL SURFACE:
       - Implement "Pointer Lock API" for FPS/Action games.
       - Use 'THREE.OrbitControls' for inspect/debug modes.
       - Map WASD + Mouse Delta + Controller/Touch inputs to a single "Input Map" object.

    5. PERSISTENCE ENGINE:
       - Deeply integrate window.PERSISTED_STATE. Save player position, inventory, and logic flags using window.saveState(data).

    REQUIRED RESPONSE STRUCTURE (JSON):
    - "explanation": A technical dev log using these headers:
      [GENRE ANALYSIS]: Classification of the game type.
      [MECHANICAL DERIVATION]: The math/physics logic used (e.g., "Verlet integration for rope physics").
      [LOGIC NODE BINDING]: How you translated "Logic Nodes" into code variables.
      [ASSET MAPPING]: Specific 3D model and animation integration details.
    - "code": Production-ready HTML/JS string.
    - "title": A professional project codename.

    ENGINE CONSTRAINTS:
    - Use Three.js (0.160.0) and OrbitControls from specified CDNs.
    - Always implement a 'dispose()' or 'cleanup()' method.
    - Use Delta Time (dt) for all calculations.
  `;

  const userPrompt = isRefinement 
    ? `ARCHITECTURAL REFINEMENT PROTOCOL:
       Input Instructions: ${prompt}
       Current Substrate Status: ${currentCode}
       Available Buffers: ${JSON.stringify(assetMetadata)}

       MANDATE: Evolve the existing logic. Do not simplify. Enhance the mechanical fidelity.`
    : `SYSTEM INITIALIZATION SEED:
       Project Description: ${prompt}
       Available Buffers: ${JSON.stringify(assetMetadata)}

       MANDATE: Synthesize a full-scale 3D simulation with high logical depth and professional mechanical standards.`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: userPrompt,
    config: {
      systemInstruction,
      thinkingConfig: { thinkingBudget: 32768 },
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          code: { type: Type.STRING },
          title: { type: Type.STRING },
          explanation: { type: Type.STRING }
        },
        required: ['code', 'title', 'explanation']
      }
    }
  });

  try {
    const result = JSON.parse(response.text || '{}');
    return {
      code: result.code || currentCode,
      title: result.title || 'Studio Synthesis',
      explanation: result.explanation || 'Logic synthesis complete.'
    };
  } catch (e) {
    console.error("Architectural Collision:", e);
    throw new Error("Logic synthesis failure. The engine requires clearer mechanical constraints.");
  }
};

import React, { useState, useRef, useEffect } from 'react';
import { Send, Sparkles, Bot, User, Loader2, BrainCircuit, Terminal, Zap, ChevronRight } from 'lucide-react';
import { ChatMessage } from '../types';

interface AIChatProps {
  history: ChatMessage[];
  onSendMessage: (msg: string) => void;
  isProcessing: boolean;
}

export const AIChat: React.FC<AIChatProps> = ({ history, onSendMessage, isProcessing }) => {
  const [input, setInput] = useState('');
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [history, isProcessing]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (input.trim() && !isProcessing) {
      onSendMessage(input);
      setInput('');
    }
  };

  // Helper to format the AI's structured response
  const formatReport = (text: string) => {
    return text.split('\n').map((line, i) => {
      if (line.startsWith('[') && line.includes(']')) {
        return (
          <div key={i} className="flex items-center gap-2 mt-4 mb-1">
            <ChevronRight className="w-3 h-3 text-emerald-500" />
            <span className="text-[8px] font-black uppercase tracking-[0.2em] text-emerald-500/80">
              {line.replace('[', '').replace(']', '')}
            </span>
          </div>
        );
      }
      return <p key={i} className="mb-1">{line}</p>;
    });
  };

  return (
    <div className="flex flex-col h-full bg-transparent font-sans md:border-l border-white/5">
      {/* Chat Header */}
      <div className="hidden md:flex px-5 py-4 border-b border-white/5 items-center justify-between bg-zinc-950/60 backdrop-blur-md">
        <div className="flex items-center gap-2.5">
          <div className="p-1.5 rounded-lg bg-emerald-500/10 border border-emerald-500/20">
            <BrainCircuit className="w-4 h-4 text-emerald-400" />
          </div>
          <div className="flex flex-col">
            <h2 className="text-[10px] font-black uppercase tracking-[0.2em] text-zinc-200">Neural Architect</h2>
            <span className="text-[6px] text-zinc-500 uppercase tracking-widest font-bold">Mechanical Core 5.0</span>
          </div>
        </div>
      </div>

      {/* Messages Feed */}
      <div ref={scrollRef} className="flex-1 overflow-y-auto p-4 md:p-6 space-y-6 scroll-smooth no-scrollbar">
        {history.length === 0 && (
          <div className="h-full flex flex-col items-center justify-center text-center px-8">
            <div className="w-14 h-14 bg-zinc-900/40 border border-white/5 rounded-3xl flex items-center justify-center mb-6">
              <Sparkles className="w-6 h-6 text-zinc-700" />
            </div>
            <p className="text-[9px] font-black uppercase tracking-[0.4em] text-zinc-700 leading-relaxed">
              Synthesizer Idle.<br/>Define mechanics or upload substrates to begin.
            </p>
          </div>
        )}

        {history.map((msg, i) => (
          <div key={i} className={`flex gap-4 ${msg.role === 'user' ? 'flex-row-reverse' : ''} animate-in fade-in slide-in-from-bottom-2 duration-300`}>
            <div className={`shrink-0 w-8 h-8 rounded-xl flex items-center justify-center border ${
              msg.role === 'user' ? 'bg-zinc-900 border-white/10' : 'bg-emerald-500/10 border-emerald-500/20'
            }`}>
              {msg.role === 'user' ? <User className="w-4 h-4 text-zinc-500" /> : <Bot className="w-4 h-4 text-emerald-400" />}
            </div>
            <div className={`max-w-[90%] md:max-w-[85%] p-4 rounded-2xl text-[11px] md:text-[12px] leading-relaxed shadow-xl group relative ${
              msg.role === 'user' 
                ? 'bg-zinc-900/50 text-zinc-300 border border-white/5' 
                : 'bg-zinc-950/40 text-emerald-50 border border-emerald-500/10'
            }`}>
              {msg.role === 'ai' && (
                <div className="flex items-center justify-between mb-2">
                  <div className="flex items-center gap-1.5 opacity-30">
                    <Terminal className="w-3 h-3" />
                    <span className="text-[7px] font-black uppercase tracking-widest">Architectural Plan</span>
                  </div>
                  {msg.isApplying && (
                    <div className="flex items-center gap-2 px-2 py-0.5 rounded-full bg-emerald-500/20 border border-emerald-500/40">
                      <Zap className="w-2 h-2 text-emerald-400 animate-pulse" />
                      <span className="text-[6px] font-black uppercase tracking-widest text-emerald-400">Updating Simulation</span>
                    </div>
                  )}
                </div>
              )}
              <div className="whitespace-pre-wrap font-medium">
                {msg.role === 'ai' ? formatReport(msg.text) : msg.text}
              </div>
            </div>
          </div>
        ))}

        {isProcessing && (
          <div className="flex gap-4 animate-pulse">
            <div className="shrink-0 w-8 h-8 rounded-xl bg-emerald-500/10 border border-emerald-500/20 flex items-center justify-center">
              <Loader2 className="w-4 h-4 text-emerald-400 animate-spin" />
            </div>
            <div className="bg-zinc-950/40 border border-emerald-500/10 p-4 rounded-2xl text-[8px] font-black uppercase tracking-[0.2em] text-emerald-500/60 flex items-center gap-3">
              Deconstructing Mechanical Intent...
            </div>
          </div>
        )}
      </div>

      {/* Input Bar */}
      <form onSubmit={handleSubmit} className="p-4 md:p-6 border-t border-white/5 bg-zinc-950/80 backdrop-blur-xl">
        <div className="relative group">
          <input
            type="text"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            disabled={isProcessing}
            placeholder="Command the Architect..."
            className="w-full bg-zinc-900/30 border border-white/10 rounded-2xl py-4 px-5 pr-14 text-[13px] text-zinc-300 placeholder:text-zinc-700 focus:outline-none focus:border-emerald-500/30 transition-all font-medium"
          />
          <button
            type="submit"
            disabled={isProcessing || !input.trim()}
