import React, { useState, useCallback } from 'react';
import { AssetUploader } from './components/AssetUploader';
import { GameRunner } from './components/GameRunner';
import { AIChat } from './components/AIChat';
import { generateGame } from './services/gemini';
import { GameAsset, GenerationStatus, GeneratedGame, ChatMessage } from './types';
import { Box, Activity, Layers, Monitor, Terminal, Sparkles, Play, BoxSelect, Menu, X, MessageSquareCode, BrainCircuit } from 'lucide-react';

type ViewMode = 'editor' | 'preview';

const App: React.FC = () => {
  const [viewMode, setViewMode] = useState<ViewMode>('editor');
  const [assets, setAssets] = useState<GameAsset[]>([]);
  const [status, setStatus] = useState<GenerationStatus>({ step: 'idle', message: '' });
  const [game, setGame] = useState<GeneratedGame | null>(null);
  const [chatHistory, setChatHistory] = useState<ChatMessage[]>([]);
  const [logs, setLogs] = useState<string[]>(['> Initializing Forge Studio...', '> Neural core optimized for logic synthesis.']);
  const [isLeftSidebarOpen, setIsLeftSidebarOpen] = useState(false);
  const [isRightSidebarOpen, setIsRightSidebarOpen] = useState(false);
  const [activeMobileView, setActiveMobileView] = useState<'staging' | 'chat' | 'logs'>('staging');

  const addLog = (msg: string) => {
    setLogs(prev => [...prev.slice(-15), `> ${msg}`]);
  };

  const processGeneration = useCallback(async (instruction: string) => {
    setStatus({ step: 'analyzing', message: 'Analyzing Architectural Logic...' });
    addLog(`Deconstructing mechanical intent: "${instruction.slice(0, 40)}..."`);

    setChatHistory(prev => [...prev, { role: 'user', text: instruction }]);

    try {
      const result = await generateGame(
        instruction, 
        assets, 
        chatHistory, 
        game?.code || ""
      );

      // Step 1: Respond first with understanding and plan
      setStatus({ step: 'coding', message: 'Synthesizing Complex Systems...' });
      const aiMessage: ChatMessage = { 
        role: 'ai', 
        text: result.explanation,
        isApplying: true 
      };
      setChatHistory(prev => [...prev, aiMessage]);

      // Step 2: Extended intentional delay for "Deep Logic Synthesis"
      await new Promise(resolve => setTimeout(resolve, 3000));

      // Step 3: Apply the changes instantly to the preview
      setGame({ code: result.code, title: result.title });
      setStatus({ step: 'ready', message: 'Logic Substrate Compiled.' });

      // Mark as done applying
      setChatHistory(prev => prev.map((m, idx) => 
        idx === prev.length - 1 ? { ...m, isApplying: false } : m
      ));

      addLog(`Build "${result.title}" systems integrated.`);

    } catch (error: any) {
      console.error(error);
      setStatus({ step: 'error', message: 'Logic Collision Detected.' });
      setChatHistory(prev => [...prev, { role: 'ai', text: 'Critical logical failure. The architect requires clearer mechanical constraints to maintain structural integrity.' }]);
      addLog(`CRITICAL: Logical paradox in synthesis.`);
    }
  }, [assets, chatHistory, game]);

  const enterPreview = () => {
    if (game) setViewMode('preview');
  };

  const exitPreview = () => setViewMode('editor');

  if (viewMode === 'preview' && game) {
    return (
      <div className="fixed inset-0 z-[500] bg-black">
        <GameRunner 
          code={game.code} 
          title={game.title} 
          assets={assets} 
          onExit={exitPreview}
        />
      </div>
    );
  }

  return (
    <div className="flex flex-col h-screen max-h-screen bg-[#020203] text-zinc-100 overflow-hidden font-sans relative">
      {/* STUDIO EDITOR HEADER */}
      <header className="h-14 border-b border-white/5 bg-zinc-950/90 backdrop-blur-3xl flex items-center justify-between px-4 md:px-6 shrink-0 z-50">
        <div className="flex items-center gap-3 md:gap-6">
          <button 
            onClick={() => setIsLeftSidebarOpen(!isLeftSidebarOpen)}
            className="md:hidden p-2 hover:bg-white/5 rounded-lg transition-colors text-zinc-400"
          >
            {isLeftSidebarOpen ? <X className="w-5 h-5" /> : <Menu className="w-5 h-5" />}
          </button>

          <div className="flex items-center gap-2 md:gap-3">
            <div className="bg-emerald-500 p-1 rounded-lg">
              <Box className="w-3.5 h-3.5 md:w-4 md:h-4 text-black" />
            </div>
            <div className="flex flex-col">
              <h1 className="text-xs md:text-sm font-black tracking-tighter italic uppercase">
                Forge<span className="text-emerald-500">Studio</span>
              </h1>
              <span className="text-[6px] md:text-[7px] text-zinc-600 font-black uppercase tracking-[0.3em] -mt-0.5 hidden xs:block">Neural Core v5.1</span>
            </div>
          </div>

          <div className="h-8 w-px bg-white/5 hidden sm:block" />

          <div className="hidden lg:flex items-center gap-4 text-[9px] font-black uppercase tracking-widest text-zinc-500">
            <div className="flex items-center gap-1.5">
              <BrainCircuit className={`w-3 h-3 ${status.step === 'ready' ? 'text-emerald-500' : status.step !== 'idle' ? 'text-yellow-500 animate-pulse' : 'text-zinc-700'}`} />
              <span>SYSTEM: {status.step === 'ready' ? 'OPTIMAL' : status.step === 'idle' ? 'STANDBY' : 'PROCESSING'}</span>
            </div>
          </div>
        </div>

        <div className="flex items-center gap-2 md:gap-3">
          {game && (
            <button 
              onClick={enterPreview}
              className="flex items-center gap-2 px-3 md:px-5 py-1.5 rounded-lg bg-emerald-500 text-black font-black text-[9px] md:text-[10px] uppercase tracking-widest hover:bg-emerald-400 transition-all shadow-[0_0_20px_rgba(16,185,129,0.2)] active:scale-95"
            >
              <Play className="w-3.5 h-3.5 fill-current" />
              <span className="hidden sm:inline">Launch Runtime</span>
            </button>
          )}
          <button 
            onClick={() => setIsRightSidebarOpen(!isRightSidebarOpen)}
            className="md:hidden p-2 hover:bg-white/5 rounded-lg transition-colors text-zinc-400"
          >
            <MessageSquareCode className="w-5 h-5" />
          </button>
        </div>
      </header>

      <main className="flex-1 flex overflow-hidden relative">
