import { GoogleGenAI, Type } from "@google/genai";
import { GameAsset, ChatMessage } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const generateGame = async (
  prompt: string,
  assets: GameAsset[],
  history: ChatMessage[] = [],
  currentCode: string = ""
): Promise<{ code: string; title: string; explanation: string }> => {

  const assetMetadata = assets.map(a => ({
    name: a.name,
    type: a.type,
    mimeType: a.mimeType,
    logicContext: a.type === 'dialogue' ? a.content : undefined
  }));

  const isRefinement = history.length > 0 && currentCode !== "";

  const systemInstruction = `
    You are the "Core Neural Architect" of ForgeAI Studio—a top-tier expert in Three.js, ECS (Entity Component System), and Game Design Patterns.

    CORE OPERATING MANDATE:
    Every response must be a masterclass in architectural reasoning. You do not just "code"; you solve mechanical puzzles.

    LOGICAL THINKING PROTOCOLS:
    1. GENRE RECOGNITION & BLUEPRINTING: Identify genre-specific requirements (e.g., camera offsets for 3rd person, raycasting for platformers).
    2. PHYSICS PARADIGMS: Choose between KINEMATIC and DYNAMIC movement. Implement precise collisions.
    3. DEEP ASSET SYNERGY: Map models and animations correctly. 'dialogue' assets are MANDATORY logic rules.
    4. ADVANCED CONTROL SURFACE: Support Keyboard/Mouse/Touch with a unified input map.
    5. PERSISTENCE ENGINE: Use window.PERSISTED_STATE and window.saveState(data) for state persistence.

    MANDATORY EXPLANATION STRUCTURE:
    Your "explanation" field MUST follow this strict four-part technical dev log format. Do not omit any section:

    [GENRE ANALYSIS]: 
    Classify the game type and explain the specific architectural blueprint required for this genre.

    [MECHANICAL DERIVATION]: 
    Detail the physics, math, or kinematic logic implemented (e.g., velocity integration, collision resolution, or pathfinding algorithms).

    [LOGIC NODE BINDING]: 
    Explicitly explain how you translated the user's "Logic Nodes" (dialogue assets) into functional code variables or state flags.

    [ASSET MAPPING]: 
    Provide technical details on how provided 3D models, textures, and animation clips are integrated into the scene graph.

    ENGINE CONSTRAINTS:
    - Include Three.js (0.160.0) and OrbitControls via CDN.
    - Always implement a 'dispose()' or 'cleanup()' method.
    - Use Delta Time (dt) for all movement and physics calculations.
  `;

  const userPrompt = isRefinement 
    ? `ARCHITECTURAL REFINEMENT PROTOCOL:
       Input Instructions: ${prompt}
       Current Substrate Status: ${currentCode}
       Available Buffers: ${JSON.stringify(assetMetadata)}

       MANDATE: Evolve the existing logic. Provide the mandatory four-part report in your explanation.`
    : `SYSTEM INITIALIZATION SEED:
       Project Description: ${prompt}
       Available Buffers: ${JSON.stringify(assetMetadata)}

       MANDATE: Synthesize a full-scale 3D simulation. Provide the mandatory four-part report in your explanation.`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: userPrompt,
    config: {
      systemInstruction,
      thinkingConfig: { thinkingBudget: 32768 },
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          code: { 
            type: Type.STRING, 
            description: "The complete self-contained HTML/JavaScript game code." 
          },
          title: { 
            type: Type.STRING, 
            description: "A professional codename for the project." 
          },
          explanation: { 
            type: Type.STRING, 
            description: "A four-part technical dev log including [GENRE ANALYSIS], [MECHANICAL DERIVATION], [LOGIC NODE BINDING], and [ASSET MAPPING]." 
          }
        },
        required: ['code', 'title', 'explanation']
      }
    }
  });

  try {
    const result = JSON.parse(response.text || '{}');
    return {
      code: result.code || currentCode,
      title: result.title || 'Studio Synthesis',
      explanation: result.explanation || 'Logic synthesis complete.'
    };
  } catch (e) {
    console.error("Architectural Collision:", e);
    throw new Error("Logic synthesis failure. The engine requires a structured architectural report.");
  }
};

