{
  "name": "TExt2GAme",
  "description": "An AI-powered game development platform where you upload assets and prompts to generate fully playable web games instantly.",
  "requestFramePermissions": [
    "camera",
    "microphone"
  ]
}

export type AssetType = 
  | 'character1' 
  | 'motion1' 
  | 'character2' 
  | 'motion2' 
  | 'environment' 
  | 'music' 
  | 'dialogue';

export interface GameAsset {
  id: string;
  name: string;
  type: AssetType;
  content: string; // Base64 for files, text for dialogue
  mimeType: string;
  isOptimized?: boolean;
}

export interface ChatMessage {
  role: 'user' | 'ai';
  text: string;
  isApplying?: boolean;
}

export interface GenerationStatus {
  step: 'idle' | 'analyzing' | 'coding' | 'compiling' | 'ready' | 'error';
  message: string;
}

export interface GeneratedGame {
  code: string; // HTML/JS combo
  title: string;
}

import { GoogleGenAI, Type } from "@google/genai";
import { GameAsset, ChatMessage } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const generateGame = async (
  prompt: string,
  assets: GameAsset[],
  history: ChatMessage[] = [],
  currentCode: string = ""
): Promise<{ code: string; title: string; explanation: string }> => {

  const assetMetadata = assets.map(a => ({
    name: a.name,
    type: a.type,
    mimeType: a.mimeType,
    isOptimized: !!a.isOptimized,
    logicContext: a.type === 'dialogue' ? a.content : undefined
  }));

  const isRefinement = history.length > 0 && currentCode !== "";

  const systemInstruction = `
    You are the "Core Neural Architect" of ForgeAI Studio—a world-class expert in Three.js, ECS (Entity Component System), and Real-time Physics simulations.

    CORE OPERATING MANDATE:
    Every response must be a masterclass in architectural reasoning. You do not just "code"; you solve mechanical puzzles.

    LOGICAL THINKING PROTOCOLS:
    1. GENRE RECOGNITION & BLUEPRINTING: Identify genre-specific requirements (e.g., camera offsets for 3rd person, raycasting for platformers).
    2. PHYSICS ENGINE CORE (MANDATORY):
       - GRAVITY: Implement a consistent downward force (e.g., Vector3(0, -9.8, 0)) applied to dynamic entities.
       - COLLISION SYSTEM: Use THREE.Raycaster for precise environmental interaction. 
       - GROUND DETECTION: Entities must detect ground surfaces ('environment' assets) to stop falling and enable jumping.
       - KINEMATIC RESOLUTION: Calculate new positions based on velocity, acceleration, and friction (dt-based).
    3. DEEP ASSET SYNERGY: 
       - Map models and animations correctly. 
       - PERFORMANCE: If an asset is marked as "isOptimized: true", leverage higher-fidelity shaders or more complex logic. If not, use simplified proxy geometry for collisions and standard materials to maintain 60FPS.
    4. ADVANCED CONTROL SURFACE: Support Keyboard/Mouse/Touch with a unified input map.
    5. PERSISTENCE ENGINE: Use window.PERSISTED_STATE and window.saveState(data) for state persistence.

    MANDATORY EXPLANATION STRUCTURE:
    Your "explanation" field MUST follow this strict four-part technical dev log format:

    [GENRE ANALYSIS]: Classify game type and architectural blueprint.
    [MECHANICAL DERIVATION]: Detail physics engine, gravity constants, and collision strategy.
    [LOGIC NODE BINDING]: Explain translation of "Logic Nodes" into functional code.
    [ASSET MAPPING]: Detail 3D integration, including performance considerations for optimized vs raw assets.

    ENGINE CONSTRAINTS:
    - Include Three.js (0.160.0) and OrbitControls via CDN.
    - Always implement a 'dispose()' or 'cleanup()' method.
    - Use Delta Time (dt) for all movement and physics calculations.
  `;

  const userPrompt = isRefinement 
    ? `ARCHITECTURAL REFINEMENT PROTOCOL:
       Input Instructions: ${prompt}
       Current Substrate Status: ${currentCode}
       Available Buffers: ${JSON.stringify(assetMetadata)}

       MANDATE: Evolve the physics and logic. Ensure gravity and environmental collisions are robust. Provide the mandatory four-part report.`
    : `SYSTEM INITIALIZATION SEED:
       Project Description: ${prompt}
       Available Buffers: ${JSON.stringify(assetMetadata)}

       MANDATE: Synthesize a full-scale 3D simulation with a functional physics engine. Provide the mandatory four-part report.`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: userPrompt,
    config: {
      systemInstruction,
      thinkingConfig: { thinkingBudget: 32768 },
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          code: { type: Type.STRING },
          title: { type: Type.STRING },
          explanation: { type: Type.STRING }
        },
        required: ['code', 'title', 'explanation']
      }
    }
  });

  try {
    const result = JSON.parse(response.text || '{}');
    return {
      code: result.code || currentCode,
      title: result.title || 'Studio Synthesis',
      explanation: result.explanation || 'Logic synthesis complete.'
    };
  } catch (e) {
    console.error("Architectural Collision:", e);
    throw new Error("Logic synthesis failure. The engine requires a structured architectural report.");
  }
};

import React, { useState } from 'react';
import { AssetType, GameAsset } from '../types';
import { X, Box, Music, MessageSquare, Plus, Globe, Activity, Users, Zap, Loader2, CheckCircle2 } from 'lucide-react';

interface AssetUploaderProps {
  assets: GameAsset[];
  onAssetsChange: (assets: GameAsset[]) => void;
}

const LIMITS: Record<AssetType, number | null> = {
  character1: 4,
  motion1: 10,
  character2: 4,
  motion2: 10,
  environment: null,
  music: null,
  dialogue: null
};

export const AssetUploader: React.FC<AssetUploaderProps> = ({ assets, onAssetsChange }) => {
  const [dialogueInput, setDialogueInput] = useState('');
  const [optimizingId, setOptimizingId] = useState<string | null>(null);

  const getMimeType = (file: File): string => {
    if (file.type) return file.type;
    const extension = file.name.split('.').pop()?.toLowerCase();
    switch (extension) {
      case 'glb': return 'model/gltf-binary';
      case 'gltf': return 'model/gltf+json';
      case 'fbx': return 'application/octet-stream';
      default: return 'application/octet-stream';
    }
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>, type: AssetType) => {
    const files = e.target.files;
    if (!files) return;

    const currentCount = assets.filter(a => a.type === type).length;
    const limit = LIMITS[type];

    const filesToUpload = Array.from(files);

    if (limit !== null && currentCount + filesToUpload.length > limit) {
      alert(`Capacity Warning: ${type} slot is limited to ${limit} assets.`);
      e.target.value = '';
      return;
    }

    filesToUpload.forEach((file: File) => {
      const reader = new FileReader();
      reader.onload = (event) => {
        const mimeType = getMimeType(file);
        const newAsset: GameAsset = {
          id: Math.random().toString(36).substr(2, 9),
          name: file.name,
          type,
          content: event.target?.result as string,
          mimeType,
          isOptimized: false
        };
        onAssetsChange([...assets, newAsset]);
      };
      reader.readAsDataURL(file);
    });
    e.target.value = '';
  };

  const removeAsset = (id: string) => {
    onAssetsChange(assets.filter(a => a.id !== id));
  };

  const optimizeAsset = async (id: string) => {
    setOptimizingId(id);
    // Simulate Neural Optimization Pass (Mesh Simplification & Texture Compression)
    await new Promise(resolve => setTimeout(resolve, 2000));

    onAssetsChange(assets.map(a => 
      a.id === id ? { ...a, isOptimized: true } : a
    ));
    setOptimizingId(null);
  };

  const AssetSection = ({ 
    type, 
    icon: Icon, 
    label, 
    accept = ".glb,.fbx", 
  }: { 
    type: AssetType, 
    icon: any, 
    label: string, 
    accept?: string, 
  }) => {
    const currentAssets = assets.filter(a => a.type === type);
    const limit = LIMITS[type];
    const isFull = limit !== null && currentAssets.length >= limit;
    const canOptimize = type.includes('character') || type === 'environment';

    return (
      <div className="flex flex-col gap-2">
        <div className="flex items-center justify-between">
          <div className="flex items-center gap-2">
            <div className="p-1.5 rounded-md bg-zinc-900 border border-white/5">
              <Icon className="w-3.5 h-3.5 text-emerald-500" />
            </div>
            <div className="flex flex-col">
              <span className="text-[10px] font-black uppercase tracking-wider text-zinc-300">{label}</span>
              <div className="flex items-center gap-1">
                <span className="text-[7px] text-zinc-600 font-bold uppercase tracking-tight">
                  {limit ? `${currentAssets.length}/${limit} Slots` : 'Unlimited'}
                </span>
              </div>
            </div>
          </div>
          <label className={`cursor-pointer px-3 py-1.5 rounded-lg border text-[9px] font-black uppercase transition-all flex items-center gap-1.5 ${
            isFull 
              ? 'bg-zinc-950 border-white/5 text-zinc-700 cursor-not-allowed' 
              : 'bg-zinc-900 border-white/10 text-zinc-400 hover:border-emerald-500/50 hover:text-emerald-500'
          }`}>
            <Plus className="w-3 h-3" />
            Add
            {!isFull && (
              <input 
                type="file" 
                multiple
                className="hidden" 
                onChange={(e) => handleFileUpload(e, type)}
                accept={accept}
              />
            )}
          </label>
        </div>

        <div className="space-y-1.5 ml-1.5 pl-3 border-l border-white/5">
          {currentAssets.map(asset => (
            <div key={asset.id} className="flex flex-col gap-1 bg-zinc-900/40 px-2.5 py-2 rounded-lg border border-white/5 group/item hover:border-emerald-500/20 transition-all">
              <div className="flex items-center justify-between">
                <div className="flex items-center gap-2 truncate">
                  <span className="truncate text-[9px] text-zinc-400 font-mono tracking-tight">{asset.name}</span>
                  {asset.isOptimized && (
                    <div className="flex items-center gap-1 px-1.5 py-0.5 rounded-full bg-emerald-500/10 border border-emerald-500/20">
                      <CheckCircle2 className="w-2.5 h-2.5 text-emerald-500" />
                      <span className="text-[6px] font-black uppercase text-emerald-500">Optimized</span>
                    </div>
                  )}
                </div>
                <div className="flex items-center gap-1">
                  {canOptimize && !asset.isOptimized && (
                    <button 
                      onClick={() => optimizeAsset(asset.id)}
                      disabled={optimizingId !== null}
                      className="p-1 text-zinc-600 hover:text-emerald-500 disabled:opacity-30 transition-colors"
                      title="Run Neural Optimization Pass"
                    >
                      {optimizingId === asset.id ? (
                        <Loader2 className="w-3 h-3 animate-spin" />
                      ) : (
                        <Zap className="w-3 h-3" />
                      )}
                    </button>
                  )}
                  <button 
                    onClick={() => removeAsset(asset.id)}
                    className="text-zinc-700 hover:text-red-500 transition-colors p-1"
                  >
                    <X className="w-3 h-3" />
                  </button>
                </div>
              </div>
              {optimizingId === asset.id && (
                <div className="w-full h-0.5 bg-zinc-800 rounded-full overflow-hidden mt-1">
                  <div className="h-full bg-emerald-500 animate-[loading_2s_ease-in-out_infinite]" />
                </div>
              )}
            </div>
          ))}
          {currentAssets.length === 0 && (
            <span className="text-[8px] text-zinc-800 font-bold uppercase tracking-widest italic pl-1">Empty Buffer</span>
          )}
        </div>
      </div>
    );
  };

  return (
    <div className="space-y-10 pb-10">
      <style>{`
        @keyframes loading {
          0% { transform: translateX(-100%); }
          50% { transform: translateX(0%); }
          100% { transform: translateX(100%); }
        }
      `}</style>

      {/* Character Pool 1 */}
      <div className="space-y-6 p-4 rounded-2xl bg-zinc-950/40 border border-white/5 shadow-inner">
        <div className="flex items-center gap-2 mb-2">
          <Users className="w-4 h-4 text-emerald-500" />
          <h3 className="text-[11px] font-black uppercase tracking-[0.2em] text-zinc-400">Entity A System</h3>
        </div>
        <AssetSection type="character1" icon={Box} label="3D Characters" />
        <AssetSection type="motion1" icon={Activity} label="Motion Data" />
      </div>

      {/* Character Pool 2 */}
      <div className="space-y-6 p-4 rounded-2xl bg-zinc-950/40 border border-white/5 shadow-inner">
        <div className="flex items-center gap-2 mb-2">
          <Users className="w-4 h-4 text-blue-500" />
          <h3 className="text-[11px] font-black uppercase tracking-[0.2em] text-zinc-400">Entity B System</h3>
        </div>
        <AssetSection type="character2" icon={Box} label="3D Characters" />
        <AssetSection type="motion2" icon={Activity} label="Motion Data" />
      </div>

      {/* World Substrate */}
      <div className="space-y-6">
        <div className="flex items-center gap-2 opacity-50 px-4">
          <Globe className="w-4 h-4 text-zinc-500" />
          <h3 className="text-[10px] font-black uppercase tracking-[0.2em]">World Substrate</h3>
        </div>
        <div className="px-4 space-y-6">
          <AssetSection type="environment" icon={Globe} label="Environment" accept=".glb,.gltf,.hdr,image/*" />
          <AssetSection type="music" icon={Music} label="Soundscape" accept="audio/*" />
        </div>
      </div>

      {/* Interaction Logic */}
      <div className="space-y-4 pt-6 border-t border-white/5 px-4">
        <div className="flex items-center gap-2">
          <MessageSquare className="w-3.5 h-3.5 text-yellow-500/50" />
          <span className="text-[10px] font-black uppercase tracking-wider text-zinc-400">Gameplay Logic Nodes</span>
        </div>
        <div className="relative">
          <input 
            type="text" 
            value={dialogueInput}
            onChange={(e) => setDialogueInput(e.target.value)}
            placeholder="Define behavior... (e.g. Gravity: 2x)"
            className="w-full bg-zinc-900/30 border border-white/5 rounded-xl px-4 py-3 text-[10px] focus:outline-none focus:border-emerald-500/30 text-zinc-300 placeholder:text-zinc-700 font-medium"
            onKeyDown={(e) => {
              if (e.key === 'Enter' && dialogueInput.trim()) {
                const newAsset: GameAsset = {
                  id: Math.random().toString(36).substr(2, 9),
                  name: `Logic_${assets.filter(a => a.type === 'dialogue').length + 1}`,
                  type: 'dialogue',
                  content: dialogueInput,
                  mimeType: 'text/plain'
                };
                onAssetsChange([...assets, newAsset]);
                setDialogueInput('');
              }
            }}
          />
          <Plus className="absolute right-3 top-1/2 -translate-y-1/2 w-4 h-4 text-zinc-800" />
        </div>
        <div className="space-y-1.5 max-h-48 overflow-y-auto no-scrollbar">
          {assets.filter(a => a.type === 'dialogue').map(asset => (
            <div key={asset.id} className="flex items-center justify-between bg-zinc-900/20 px-3 py-2.5 rounded-lg text-[9px] group/item border border-white/5 hover:border-yellow-500/10 transition-all">
              <span className="truncate flex-1 pr-2 text-zinc-500 italic">"{asset.content}"</span>
              <button onClick={() => removeAsset(asset.id)} className="text-zinc-700 hover:text-red-500 opacity-60 transition-opacity">
                <X className="w-3 h-3" />
              </button>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};

