  const [viewMode, setViewMode] = useState<ViewMode>('editor');
  const [assets, setAssets] = useState<GameAsset[]>([]);
  const [status, setStatus] = useState<GenerationStatus>({ step: 'idle', message: '' });
  const [game, setGame] = useState<GeneratedGame | null>(null);
  const [chatHistory, setChatHistory] = useState<ChatMessage[]>([]);
  const [logs, setLogs] = useState<string[]>([
    '> Initializing TExt2GAme Studio...', 
    '> Neural core optimized for logic synthesis.',
    '> Physics Subsystem: Gravity & Raycasting Active.'
  ]);
  const [isLeftSidebarOpen, setIsLeftSidebarOpen] = useState(false);
  const [isRightSidebarOpen, setIsRightSidebarOpen] = useState(false);
  const [activeMobileView, setActiveMobileView] = useState<'staging' | 'chat' | 'logs'>('staging');
  const [isLiveSyncing, setIsLiveSyncing] = useState(false);

  const prevAssetsCount = useRef(0);
  const autoSyncTimer = useRef<NodeJS.Timeout | null>(null);

  const addLog = (msg: string) => {
    setLogs(prev => [...prev.slice(-15), `> ${msg}`]);
  };

  const processGeneration = useCallback(async (instruction: string, isAutoSync: boolean = false) => {
    if (!isAutoSync) {
      setStatus({ step: 'analyzing', message: 'Analyzing Architectural Logic...' });
      addLog(`Deconstructing mechanical intent: "${instruction.slice(0, 40)}..."`);
      setChatHistory(prev => [...prev, { role: 'user', text: instruction }]);
    } else {
      setIsLiveSyncing(true);
      addLog(`Auto-Sync: Integrating buffer changes...`);
    }

    try {
      const result = await generateGame(
        instruction, 
        assets, 
        chatHistory, 
        game?.code || ""
      );

      if (!isAutoSync) {
        setStatus({ step: 'coding', message: 'Synthesizing Complex Systems...' });
        const aiMessage: ChatMessage = { 
          role: 'ai', 
          text: result.explanation,
          isApplying: true 
        };
        setChatHistory(prev => [...prev, aiMessage]);

        await new Promise(resolve => setTimeout(resolve, 3000));

        setChatHistory(prev => prev.map((m, idx) => 
          idx === prev.length - 1 ? { ...m, isApplying: false } : m
        ));
      }

      setGame({ code: result.code, title: result.title });
      setStatus({ step: 'ready', message: 'Logic Substrate Compiled.' });
      setIsLiveSyncing(false);

      addLog(`Substrate ${isAutoSync ? 'synchronized' : 'integrated'}: "${result.title}"`);

    } catch (error: any) {
      console.error(error);
      setStatus({ step: 'error', message: 'Logic Collision Detected.' });
      setIsLiveSyncing(false);
      if (!isAutoSync) {
        setChatHistory(prev => [...prev, { role: 'ai', text: 'Critical logical failure. The architect requires clearer mechanical constraints to maintain structural integrity.' }]);
      }
      addLog(`CRITICAL: Logical paradox in synthesis.`);
    }
  }, [assets, chatHistory, game]);

  // Real-time synchronization effect
  useEffect(() => {
    // Only auto-sync if a game already exists and assets have actually changed
    if (game && assets.length !== prevAssetsCount.current) {
      if (autoSyncTimer.current) clearTimeout(autoSyncTimer.current);

      autoSyncTimer.current = setTimeout(() => {
        const lastUserPrompt = chatHistory.filter(m => m.role === 'user').pop()?.text || "Synchronize reality based on updated asset matrix.";
        processGeneration(`AUTOMATIC SYNCHRONIZATION: The asset matrix or logic nodes have been updated. Integrate the changes into the current substrate without changing the fundamental genre or goal. Current instruction set remains: ${lastUserPrompt}`, true);
      }, 5000); // 5s debounce for meaningful batching
    }
    prevAssetsCount.current = assets.length;
  }, [assets, game, chatHistory, processGeneration]);

  const enterPreview = () => {
    if (game) setViewMode('preview');
  };

  const exitPreview = () => setViewMode('editor');

  if (viewMode === 'preview' && game) {
    return (
      <div className="fixed inset-0 z-[500] bg-black">
        <GameRunner 
          code={game.code} 
          title={game.title} 
          assets={assets} 
          onExit={exitPreview}
        />
      </div>
    );
  }

  return (
    <div className="flex flex-col h-screen max-h-screen bg-[#020203] text-zinc-100 overflow-hidden font-sans relative">
      {/* STUDIO EDITOR HEADER */}
      <header className="h-14 border-b border-white/5 bg-zinc-950/90 backdrop-blur-3xl flex items-center justify-between px-4 md:px-6 shrink-0 z-50">
        <div className="flex items-center gap-3 md:gap-6">
          <button 
            onClick={() => setIsLeftSidebarOpen(!isLeftSidebarOpen)}
            className="md:hidden p-2 hover:bg-white/5 rounded-lg transition-colors text-zinc-400"
          >
            {isLeftSidebarOpen ? <X className="w-5 h-5" /> : <Menu className="w-5 h-5" />}
          </button>

          <div className="flex items-center gap-2 md:gap-3">
            <div className="bg-emerald-500 p-1 rounded-lg">
              <Box className="w-3.5 h-3.5 md:w-4 md:h-4 text-black" />
            </div>
            <div className="flex flex-col">
              <h1 className="text-xs md:text-sm font-black tracking-tighter italic uppercase">
                TExt<span className="text-emerald-500">2GAme</span>
              </h1>
              <span className="text-[6px] md:text-[7px] text-zinc-600 font-black uppercase tracking-[0.3em] -mt-0.5 hidden xs:block">Neural Core v5.1</span>
            </div>
          </div>

          <div className="h-8 w-px bg-white/5 hidden sm:block" />

          <div className="hidden lg:flex items-center gap-4 text-[9px] font-black uppercase tracking-widest text-zinc-500">
            <div className="flex items-center gap-1.5">
              <BrainCircuit className={`w-3 h-3 ${status.step === 'ready' ? 'text-emerald-500' : status.step !== 'idle' ? 'text-yellow-500 animate-pulse' : 'text-zinc-700'}`} />
              <span>SYSTEM: {status.step === 'ready' ? 'OPTIMAL' : status.step === 'idle' ? 'STANDBY' : 'PROCESSING'}</span>
            </div>
            {isLiveSyncing && (
              <div className="flex items-center gap-1.5 text-emerald-500/80 animate-pulse">
                <RefreshCw className="w-3 h-3 animate-spin" />
                <span>LIVE SYNC ACTIVE</span>
              </div>
            )}
          </div>
        </div>

        <div className="flex items-center gap-2 md:gap-3">
          {game && (
            <button 
              onClick={enterPreview}
              className="flex items-center gap-2 px-3 md:px-5 py-1.5 rounded-lg bg-emerald-500 text-black font-black text-[9px] md:text-[10px] uppercase tracking-widest hover:bg-emerald-400 transition-all shadow-[0_0_20px_rgba(16,185,129,0.2)] active:scale-95"
            >
              <Play className="w-3.5 h-3.5 fill-current" />
              <span className="hidden sm:inline">Launch Runtime</span>
            </button>
          )}
          <button 
            onClick={() => setIsRightSidebarOpen(!isRightSidebarOpen)}
            className="md:hidden p-2 hover:bg-white/5 rounded-lg transition-colors text-zinc-400"
          >
            <MessageSquareCode className="w-5 h-5" />
          </button>
        </div>
      </header>

      <main className="flex-1 flex overflow-hidden relative">
        {/* Left Sidebar: Asset Matrix */}
        <div className={`
          fixed inset-y-0 left-0 z-40 w-[280px] md:w-[300px] border-r border-white/5 bg-zinc-950/95 md:bg-zinc-950/40 backdrop-blur-3xl md:backdrop-blur-none
          flex flex-col shrink-0 transition-transform duration-300 transform
          ${isLeftSidebarOpen ? 'translate-x-0' : '-translate-x-full md:translate-x-0'}
          md:static md:z-0
        `}>
          <div className="p-5 flex flex-col gap-8 overflow-y-auto flex-1 no-scrollbar pt-20 md:pt-5">
            <section className="flex-1">
              <div className="flex items-center justify-between mb-4">
                <div className="flex items-center gap-2">
                  <Layers className="w-3.5 h-3.5 text-emerald-500/50" />
                  <h2 className="text-[9px] font-black uppercase tracking-[0.3em] text-zinc-500">Asset Matrix</h2>
                </div>
                <span className="text-[7px] font-black text-zinc-700 uppercase tracking-widest">{assets.length} Buffers</span>
              </div>
              <AssetUploader assets={assets} onAssetsChange={setAssets} />
            </section>
          </div>
        </div>

        {/* Center: Staging Area & Console */}
        <div className={`flex-1 flex flex-col overflow-hidden bg-[#050507] transition-all ${activeMobileView === 'staging' || activeMobileView === 'logs' ? 'flex' : 'hidden md:flex'}`}>
          <div className={`flex-1 relative flex flex-col border-b border-white/5 items-center justify-center p-4 ${activeMobileView === 'staging' ? 'flex' : 'hidden md:flex'}`}>
            <div className="absolute inset-0 bg-[radial-gradient(circle_at_50%_50%,rgba(16,185,129,0.015),transparent_70%)] opacity-50 pointer-events-none" />

            <div className="text-center relative z-10 w-full max-w-lg mx-auto">
              <div className={`w-16 h-16 md:w-24 md:h-24 bg-zinc-900/40 border border-white/5 rounded-[2rem] md:rounded-[2.5rem] flex items-center justify-center mx-auto mb-8 backdrop-blur-3xl group hover:border-emerald-500/20 transition-all duration-700 ${status.step === 'coding' || isLiveSyncing ? 'animate-pulse border-emerald-500/30' : ''}`}>
                <BoxSelect className={`w-6 h-6 md:w-10 md:h-10 transition-colors ${status.step === 'coding' || isLiveSyncing ? 'text-emerald-500' : 'text-zinc-800 group-hover:text-emerald-500'}`} />
              </div>

              {game ? (
                <div className="animate-in fade-in slide-in-from-bottom-4 duration-700 px-2">
                  <div className="inline-flex items-center gap-2 px-3 py-1 rounded-full bg-emerald-500/5 border border-emerald-500/10 mb-4">
                    <Activity className="w-3 h-3 text-emerald-500" />
                    <span className="text-[7px] font-black uppercase tracking-widest text-emerald-400">Project Linked</span>
                  </div>
                  <h3 className="text-[14px] md:text-[18px] font-black uppercase tracking-[0.4em] text-white italic mb-2 truncate max-w-md mx-auto">{game.title}</h3>
                  <p className="text-[8px] text-zinc-600 font-bold uppercase tracking-[0.2em] mb-8">Active Mechanical Substrate</p>

                  <div className="grid grid-cols-2 gap-px bg-white/5 rounded-2xl overflow-hidden border border-white/5 max-w-sm mx-auto">
                    <div className="bg-zinc-950 p-4 flex flex-col items-center gap-1">
                      <span className="text-[7px] text-zinc-600 uppercase font-black tracking-widest">Logic Nodes</span>
                      <span className="text-[14px] text-zinc-300 font-mono font-bold">{assets.filter(a => a.type === 'dialogue').length}</span>
                    </div>
                    <div className="bg-zinc-950 p-4 flex flex-col items-center gap-1">
                      <span className="text-[7px] text-zinc-600 uppercase font-black tracking-widest">3D Modules</span>
                      <span className="text-[14px] text-zinc-300 font-mono font-bold">{assets.filter(a => a.type !== 'dialogue').length}</span>
                    </div>
                  </div>
                </div>
              ) : (
                <div className="opacity-40 group cursor-default">
                  <h3 className="text-[10px] md:text-[11px] font-black uppercase tracking-[0.6em] text-zinc-700 italic group-hover:text-emerald-500/50 transition-colors">Idle Neural State</h3>
                  <p className="text-[7px] font-bold text-zinc-800 uppercase tracking-widest mt-4">Synthesize reality via the Architect</p>
                </div>
              )}
            </div>

            <div className="absolute bottom-4 left-6 md:bottom-8 md:left-8 flex flex-col gap-1 pointer-events-none">
              <span className="text-[6px] md:text-[7px] font-black text-zinc-800 uppercase tracking-widest">Logic Stream</span>
              <div className="flex items-center gap-2">
                <div className={`w-1 h-1 md:w-1.5 md:h-1.5 rounded-full ${status.step === 'ready' ? 'bg-emerald-500 shadow-[0_0_10px_rgba(16,185,129,0.5)]' : status.step === 'idle' ? 'bg-zinc-900' : 'bg-yellow-500 animate-pulse'}`} />
                <span className="text-[7px] md:text-[9px] font-black text-zinc-500 uppercase tracking-widest">{status.message || 'Waiting...'}</span>
              </div>
            </div>
          </div>

          <div className={`h-[150px] md:h-[200px] flex flex-col bg-[#030304] ${activeMobileView === 'logs' ? 'flex h-full' : 'hidden md:flex'}`}>
            <div className="px-5 py-3 border-b border-white/5 flex items-center justify-between bg-zinc-950/40">
              <div className="flex items-center gap-2">
                <Terminal className="w-3.5 h-3.5 text-zinc-600" />
                <h2 className="text-[9px] font-black uppercase tracking-[0.3em] text-zinc-600">Architectural Console</h2>
              </div>
              <div className="flex gap-1.5">
                <div className="w-1.5 h-1.5 rounded-full bg-zinc-800" />
                <div className="w-1.5 h-1.5 rounded-full bg-zinc-800" />
                <div className="w-1.5 h-1.5 rounded-full bg-zinc-800" />
              </div>
            </div>
            <div className="flex-1 p-4 md:p-6 font-mono text-[9px] md:text-[10px] text-zinc-600 overflow-y-auto no-scrollbar space-y-1.5">
              {logs.map((log, i) => (
                <p key={i} className={`flex gap-3 ${log.includes('CRITICAL') ? 'text-red-500/70' : log.includes('Build') || log.includes('integrated') || log.includes('Auto-Sync') ? 'text-emerald-500/60' : ''}`}>
                  <span className="opacity-20 shrink-0">[{new Date().toLocaleTimeString([], { hour12: false })}]</span>
                  <span className="truncate">{log}</span>
                </p>
              ))}
              {(status.step !== 'idle' && status.step !== 'ready' || isLiveSyncing) && (
                <p className="text-blue-500 animate-pulse flex gap-3">
                  <span className="opacity-20 shrink-0">[{new Date().toLocaleTimeString([], { hour12: false })}]</span>
                  <span>> SYNTHESIZING LOGICAL STRUCTURES...</span>
                </p>
              )}
            </div>
          </div>
        </div>

        {/* Right Sidebar: AI Architect */}
        <div className={`
          fixed inset-y-0 right-0 z-40 w-full md:w-[400px] lg:w-[500px] border-l border-white/5 bg-zinc-950/95 md:bg-zinc-950/30 backdrop-blur-3xl md:backdrop-blur-none
          flex flex-col shrink-0 transition-transform duration-300 transform
          ${isRightSidebarOpen ? 'translate-x-0' : 'translate-x-full md:translate-x-0'}
          md:static md:z-0
          ${activeMobileView === 'chat' ? 'translate-x-0 flex' : ''}
        `}>
          <div className="flex-1 flex flex-col overflow-hidden pt-14 md:pt-0">
            <AIChat 
              history={chatHistory} 
              onSendMessage={processGeneration} 
              isProcessing={status.step !== 'idle' && status.step !== 'ready' && status.step !== 'error'} 
            />
          </div>
        </div>
      </main>

      {/* Mobile Footer Navigation */}
      <footer className="h-14 border-t border-white/5 bg-black px-4 flex items-center justify-around md:hidden shrink-0 z-50">
        <button onClick={() => setActiveMobileView('staging')} className={`flex flex-col items-center gap-1.5 transition-colors ${activeMobileView === 'staging' ? 'text-emerald-500' : 'text-zinc-600'}`}>
          <Monitor className="w-4 h-4" />
          <span className="text-[8px] font-black uppercase tracking-widest">Simulation</span>
        </button>
        <button onClick={() => setActiveMobileView('chat')} className={`flex flex-col items-center gap-1.5 transition-colors ${activeMobileView === 'chat' ? 'text-emerald-500' : 'text-zinc-600'}`}>
          <MessageSquareCode className="w-4 h-4" />
          <span className="text-[8px] font-black uppercase tracking-widest">Architect</span>
        </button>
        <button onClick={() => setActiveMobileView('logs')} className={`flex flex-col items-center gap-1.5 transition-colors ${activeMobileView === 'logs' ? 'text-emerald-500' : 'text-zinc-600'}`}>
          <Terminal className="w-4 h-4" />
          <span className="text-[8px] font-black uppercase tracking-widest">Console</span>
        </button>
      </footer>

      {/* Desktop Info Bar */}
      <footer className="h-8 border-t border-white/5 bg-black px-6 hidden md:flex items-center justify-between text-[8px] font-bold tracking-[0.4em] text-zinc-800 uppercase shrink-0">
        <div className="flex gap-10">
           <span className="flex items-center gap-2 text-emerald-500/20">
            <Sparkles className="w-3 h-3" />
            Logical Synthesis Engine v5.1.0_PRO
           </span>
        </div>
        <div className="flex items-center gap-6">
           <span className="opacity-30">Active Buffers: {assets.length}</span>
           <div className="w-px h-3 bg-white/5" />
           <span className="opacity-30">Render: WebGL 2.0 / 60FPS Target</span>
        </div>
      </footer>
    </div>
  );
};

export default App;

