import { GoogleGenAI, Type } from "@google/genai";
import { GameAsset, ChatMessage } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const generateGame = async (
  prompt: string,
  assets: GameAsset[],
  history: ChatMessage[] = [],
  currentCode: string = ""
): Promise<{ code: string; title: string; explanation: string }> => {

  const assetMetadata = assets.map(a => ({
    name: a.name,
    type: a.type,
    mimeType: a.mimeType,
    isOptimized: !!a.isOptimized,
    logicContext: a.type === 'dialogue' ? a.content : undefined
  }));

  const isRefinement = history.length > 0 && currentCode !== "";

  const systemInstruction = `
    You are the "Core Neural Architect" of ForgeAI Studio—a world-class expert in Three.js, ECS (Entity Component System), and Real-time Physics simulations.

    CORE OPERATING MANDATE:
    Every response must be a masterclass in architectural reasoning. You do not just "code"; you solve mechanical puzzles.

    LOGICAL THINKING PROTOCOLS:
    1. GENRE RECOGNITION & BLUEPRINTING: Identify genre-specific requirements (e.g., camera offsets for 3rd person, raycasting for platformers).
    2. PHYSICS ENGINE CORE (MANDATORY):
       - GRAVITY: Implement a consistent downward force (e.g., Vector3(0, -9.8, 0)) applied to dynamic entities.
       - COLLISION SYSTEM: Use THREE.Raycaster for precise environmental interaction. 
       - GROUND DETECTION: Entities must detect ground surfaces ('environment' assets) to stop falling and enable jumping.
       - KINEMATIC RESOLUTION: Calculate new positions based on velocity, acceleration, and friction (dt-based).
    3. DEEP ASSET SYNERGY: 
       - Map models and animations correctly. 
       - PERFORMANCE: If an asset is marked as "isOptimized: true", leverage higher-fidelity shaders or more complex logic. If not, use simplified proxy geometry for collisions and standard materials to maintain 60FPS.
    4. ADVANCED CONTROL SURFACE: Support Keyboard/Mouse/Touch with a unified input map.
    5. PERSISTENCE ENGINE: Use window.PERSISTED_STATE and window.saveState(data) for state persistence.

    MANDATORY EXPLANATION STRUCTURE:
    Your "explanation" field MUST follow this strict four-part technical dev log format:

    [GENRE ANALYSIS]: Classify game type and architectural blueprint.
    [MECHANICAL DERIVATION]: Provide specific physics parameters used in the code, including:
       - The exact Gravity Vector (e.g., THREE.Vector3(0, -9.81, 0)).
       - Friction and Restitution coefficients used for movement and collisions.
       - Detailed Collision Detection methods (e.g., Raycasting for ground, Sphere-casting for obstacles, or AABB checks).
    [LOGIC NODE BINDING]: Explain translation of "Logic Nodes" into functional code.
    [ASSET MAPPING]: Detail 3D integration, including performance considerations for optimized vs raw assets.

    ENGINE CONSTRAINTS:
    - Include Three.js (0.160.0) and OrbitControls via CDN.
    - Always implement a 'dispose()' or 'cleanup()' method.
    - Use Delta Time (dt) for all movement and physics calculations.
  `;

  const userPrompt = isRefinement 
    ? `ARCHITECTURAL REFINEMENT PROTOCOL:
       Input Instructions: ${prompt}
       Current Substrate Status: ${currentCode}
       Available Buffers: ${JSON.stringify(assetMetadata)}

       MANDATE: Evolve the physics and logic. Ensure gravity and environmental collisions are robust. Provide the mandatory four-part report with specific physics parameters.`
    : `SYSTEM INITIALIZATION SEED:
       Project Description: ${prompt}
       Available Buffers: ${JSON.stringify(assetMetadata)}

       MANDATE: Synthesize a full-scale 3D simulation with a functional physics engine. Provide the mandatory four-part report with specific physics parameters.`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: userPrompt,
    config: {
      systemInstruction,
      thinkingConfig: { thinkingBudget: 32768 },
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          code: { type: Type.STRING },
          title: { type: Type.STRING },
          explanation: { type: Type.STRING }
        },
        required: ['code', 'title', 'explanation']
      }
    }
  });

  try {
    const result = JSON.parse(response.text || '{}');
    return {
      code: result.code || currentCode,
      title: result.title || 'Studio Synthesis',
      explanation: result.explanation || 'Logic synthesis complete.'
    };
  } catch (e) {
    console.error("Architectural Collision:", e);
    throw new Error("Logic synthesis failure. The engine requires a structured architectural report.");
  }
};

