  title: string;
  assets: GameAsset[];
  onExit: () => void;
}

export const GameRunner: React.FC<GameRunnerProps> = ({ code, title, assets, onExit }) => {
  const iframeRef = useRef<HTMLIFrameElement>(null);
  const [isMounting, setIsMounting] = useState(true);
  const [showSaveIndicator, setShowSaveIndicator] = useState(false);
  const [debugEnabled, setDebugEnabled] = useState(false);

  // Storage key based on game title to avoid collisions between different projects
  const persistenceKey = useMemo(() => `forge_studio_state_${btoa(title).substring(0, 16)}`, [title]);

  // Simulate a brief mounting phase for immersion
  useEffect(() => {
    const timer = setTimeout(() => setIsMounting(false), 2000);
    return () => clearTimeout(timer);
  }, []);

  // Handle debug toggle
  const toggleDebug = () => {
    const newState = !debugEnabled;
    setDebugEnabled(newState);
    if (iframeRef.current?.contentWindow) {
      iframeRef.current.contentWindow.postMessage({ type: 'FORGE_TOGGLE_DEBUG', payload: newState }, '*');
    }
  };

  // Listen for messages from the game iframe to persist state
  useEffect(() => {
    const handleMessage = (event: MessageEvent) => {
      if (event.data) {
        if (event.data.type === 'FORGE_SAVE_STATE') {
          const stateToSave = event.data.payload;
          localStorage.setItem(persistenceKey, JSON.stringify(stateToSave));

          // Brief visual feedback for saving
          setShowSaveIndicator(true);
          setTimeout(() => setShowSaveIndicator(false), 1500);
        }
        if (event.data.type === 'FORGE_RUNTIME_READY') {
          // Sync current debug state to newly loaded runtime
          if (iframeRef.current?.contentWindow) {
            iframeRef.current.contentWindow.postMessage({ type: 'FORGE_TOGGLE_DEBUG', payload: debugEnabled }, '*');
          }
        }
      }
    };

    window.addEventListener('message', handleMessage);
    return () => window.removeEventListener('message', handleMessage);
  }, [persistenceKey, debugEnabled]);

  const combinedSrcDoc = useMemo(() => {
    const assetMap = assets.reduce((acc, asset) => {
      acc[asset.name] = asset.content;
      return acc;
    }, {} as Record<string, string>);

    // Retrieve current persisted state
    const savedStateStr = localStorage.getItem(persistenceKey);
    const savedState = savedStateStr ? JSON.parse(savedStateStr) : null;

    const bootstrapScript = `
      <script>
        (function() {
          const rawAssets = ${JSON.stringify(assetMap)};
          const blobUrls = {};

          // Persistence & Debug API
          window.PERSISTED_STATE = ${JSON.stringify(savedState)};
          window.DEBUG_PHYSICS = false; // Initial state

          window.saveState = function(data) {
            window.parent.postMessage({ type: 'FORGE_SAVE_STATE', payload: data }, '*');
          };

          window.addEventListener('message', (event) => {
            if (event.data && event.data.type === 'FORGE_TOGGLE_DEBUG') {
              window.DEBUG_PHYSICS = event.data.payload;
            }
          });

          // Inform parent that we are ready to receive state
          window.parent.postMessage({ type: 'FORGE_RUNTIME_READY' }, '*');

          function base64ToBlob(base64, mime) {
            const split = base64.split(',');
            const data = split[1] || split[0];
            const byteString = atob(data);
            const ab = new ArrayBuffer(byteString.length);
            const ia = new Uint8Array(ab);
            for (let i = 0; i < byteString.length; i++) {
              ia[i] = byteString.charCodeAt(i);
            }
            return new Blob([ab], { type: mime });
          }

          window.getAssetUrl = function(name) {
            if (blobUrls[name]) return blobUrls[name];
            const data = rawAssets[name];
            if (!data) return "";
            let mime = 'application/octet-stream';
            if (data.includes('data:')) {
              mime = data.split(':')[1].split(';')[0];
            }
            const blob = base64ToBlob(data, mime);
            const url = URL.createObjectURL(blob);
            blobUrls[name] = url;
