          <h2 className="text-[11px] font-black text-white uppercase tracking-[0.6em] mb-2">Mounting Reality...</h2>
          <p className="text-[8px] text-zinc-600 font-bold uppercase tracking-[0.3em]">{title}</p>
        </div>
      )}

      {/* Status Bar */}
      <div className="absolute bottom-8 left-8 right-8 z-[1060] flex items-center justify-between pointer-events-none">
        {/* Save Indicator */}
        <div className={`flex items-center gap-3 bg-zinc-900/80 backdrop-blur-xl border border-white/10 px-4 py-2 rounded-full transition-all duration-500 ${showSaveIndicator ? 'opacity-100 translate-y-0' : 'opacity-0 translate-y-4'}`}>
          <Save className="w-3.5 h-3.5 text-emerald-500" />
          <span className="text-[9px] font-black uppercase tracking-widest text-zinc-400">Syncing Substrate State</span>
        </div>

        {/* Debug Controls */}
        <div className="flex gap-2 pointer-events-auto">
