      <div className="flex flex-col gap-2">
        <div className="flex items-center justify-between">
          <div className="flex items-center gap-2">
            <div className="p-1.5 rounded-md bg-zinc-900 border border-white/5">
              <Icon className="w-3.5 h-3.5 text-emerald-500" />
            </div>
            <div className="flex flex-col">
              <span className="text-[10px] font-black uppercase tracking-wider text-zinc-300">{label}</span>
              <div className="flex items-center gap-1">
                <span className="text-[7px] text-zinc-600 font-bold uppercase tracking-tight">
                  {limit ? `${currentAssets.length}/${limit} Slots` : 'Unlimited'}
                </span>
              </div>
            </div>
          </div>
          <label className={`cursor-pointer px-3 py-1.5 rounded-lg border text-[9px] font-black uppercase transition-all flex items-center gap-1.5 ${
            isFull 
              ? 'bg-zinc-950 border-white/5 text-zinc-700 cursor-not-allowed' 
              : 'bg-zinc-900 border-white/10 text-zinc-400 hover:border-emerald-500/50 hover:text-emerald-500'
          }`}>
            <Plus className="w-3 h-3" />
            Add
            {!isFull && (
              <input 
                type="file" 
                multiple
                className="hidden" 
                onChange={(e) => handleFileUpload(e, type)}
                accept={accept}
              />
            )}
          </label>
        </div>

        <div className="space-y-1.5 ml-1.5 pl-3 border-l border-white/5">
          {currentAssets.map(asset => (
            <div key={asset.id} className="flex flex-col gap-1 bg-zinc-900/40 px-2.5 py-2 rounded-lg border border-white/5 group/item hover:border-emerald-500/20 transition-all relative">
              <div className="flex items-center justify-between gap-2">
                <div className="flex flex-col gap-1 truncate flex-1">
                  <span className="truncate text-[9px] text-zinc-400 font-mono tracking-tight">{asset.name}</span>

                  {/* Category Badge & Trigger */}
                  <div className="relative">
                    <button 
                      onClick={() => setActiveCategoryPicker(activeCategoryPicker === asset.id ? null : asset.id)}
                      className="flex items-center gap-1 text-[7px] font-black uppercase tracking-wider text-zinc-600 hover:text-emerald-500 transition-colors group/cat"
                    >
                      <Tag className="w-2 h-2" />
                      <span>{asset.category || 'Uncategorized'}</span>
                      <ChevronDown className="w-2 h-2 opacity-0 group-hover/cat:opacity-100 transition-opacity" />
                    </button>

                    {activeCategoryPicker === asset.id && (
                      <div className="absolute top-full left-0 z-[60] mt-1 bg-zinc-900 border border-white/10 rounded-lg shadow-2xl overflow-hidden py-1 w-32 grid grid-cols-1">
                        {CATEGORIES.map(cat => (
                          <button
                            key={cat}
                            onClick={() => updateAssetCategory(asset.id, cat)}
                            className={`px-3 py-1.5 text-[8px] font-black uppercase tracking-widest text-left transition-colors ${asset.category === cat ? 'bg-emerald-500 text-black' : 'text-zinc-500 hover:bg-white/5 hover:text-white'}`}
                          >
                            {cat}
