          <MessageSquare className="w-3.5 h-3.5 text-yellow-500/50" />
          <span className="text-[10px] font-black uppercase tracking-wider text-zinc-400">Gameplay Logic Nodes</span>
        </div>
        <div className="relative">
          <input 
            type="text" 
            value={dialogueInput}
            onChange={(e) => setDialogueInput(e.target.value)}
