interface AIChatProps {
  history: ChatMessage[];
  onSendMessage: (msg: string) => void;
  isProcessing: boolean;
}

export const AIChat: React.FC<AIChatProps> = ({ history, onSendMessage, isProcessing }) => {
  const [input, setInput] = useState('');
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [history, isProcessing]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (input.trim() && !isProcessing) {
      onSendMessage(input);
      setInput('');
    }
  };

  // Helper to format the AI's structured response
  const formatReport = (text: string) => {
    return text.split('\n').map((line, i) => {
      if (line.startsWith('[') && line.includes(']')) {
        return (
          <div key={i} className="flex items-center gap-2 mt-4 mb-1">
            <ChevronRight className="w-3 h-3 text-emerald-500" />
            <span className="text-[8px] font-black uppercase tracking-[0.2em] text-emerald-500/80">
              {line.replace('[', '').replace(']', '')}
            </span>
          </div>
        );
      }
      return <p key={i} className="mb-1">{line}</p>;
    });
  };

  return (
    <div className="flex flex-col h-full bg-transparent font-sans md:border-l border-white/5">
      {/* Chat Header */}
      <div className="hidden md:flex px-5 py-4 border-b border-white/5 items-center justify-between bg-zinc-950/60 backdrop-blur-md">
        <div className="flex items-center gap-2.5">
          <div className="p-1.5 rounded-lg bg-emerald-500/10 border border-emerald-500/20">
            <BrainCircuit className="w-4 h-4 text-emerald-400" />
          </div>
          <div className="flex flex-col">
            <h2 className="text-[10px] font-black uppercase tracking-[0.2em] text-zinc-200">Neural Architect</h2>
            <span className="text-[6px] text-zinc-500 uppercase tracking-widest font-bold">Mechanical Core 5.1</span>
          </div>
        </div>
      </div>

