              {/* Suggestions Chips */}
              {msg.role === 'ai' && msg.suggestions && msg.suggestions.length > 0 && !isProcessing && (
                <div className="flex flex-wrap gap-2 animate-in fade-in slide-in-from-left-2 duration-500 delay-300">
                  {msg.suggestions.map((suggestion, sIdx) => (
                    <button
                      key={sIdx}
                      onClick={() => onSendMessage(suggestion)}
                      className="group flex items-center gap-2 px-3 py-1.5 bg-zinc-900/50 border border-emerald-500/20 rounded-full hover:bg-emerald-500/10 hover:border-emerald-500/50 transition-all active:scale-95"
