            className="w-full bg-zinc-900/30 border border-white/10 rounded-2xl py-4 px-5 pr-14 text-[13px] text-zinc-300 placeholder:text-zinc-700 focus:outline-none focus:border-emerald-500/30 transition-all font-medium"
