                  <div className="grid grid-cols-2 gap-px bg-white/5 rounded-2xl overflow-hidden border border-white/5 max-w-sm mx-auto">
                    <div className="bg-zinc-950 p-4 flex flex-col items-center gap-1">
                      <span className="text-[7px] text-zinc-600 uppercase font-black tracking-widest">Logic Nodes</span>
                      <span className="text-[14px] text-zinc-300 font-mono font-bold">{assets.filter(a => a.type === 'dialogue').length}</span>
