import { GoogleGenAI, Type } from "@google/genai";
import { GameAsset, ChatMessage } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const generateGame = async (
  prompt: string,
  assets: GameAsset[],
  history: ChatMessage[] = [],
  currentCode: string = ""
): Promise<{ code: string; title: string; explanation: string; suggestions: string[] }> => {

  const assetMetadata = assets.map(a => ({
    name: a.name,
    type: a.type,
    mimeType: a.mimeType,
    category: a.category,
    isOptimized: !!a.isOptimized,
    logicContext: a.type === 'dialogue' ? a.content : undefined
  }));

  const isRefinement = history.length > 0 && currentCode !== "";

  const systemInstruction = `
    You are the "Core Neural Architect" of ForgeAI Studio—a world-class expert in Three.js, ECS (Entity Component System), and Real-time Physics simulations.

    CORE OPERATING MANDATE:
    Every response must be a masterclass in architectural reasoning. You do not just "code"; you solve mechanical puzzles.

    LOGICAL THINKING PROTOCOLS:
    1. GENRE RECOGNITION & BLUEPRINTING: Identify genre-specific requirements (e.g., camera offsets for 3rd person, raycasting for platformers).
    2. PHYSICS ENGINE CORE (MANDATORY):
       - ARCHITECTURE: Implement a Robust Verlet Integration system (Position-based dynamics).
       - STATE: Each dynamic entity must track 'position', 'previousPosition', and 'acceleration'.
       - KINEMATIC RESOLUTION: Calculate new positions as: pos + (pos - prevPos) * damping + acc * dt * dt.
       - SUB-STEPPING: Use a minimum of 4 sub-steps per frame to ensure stability and prevent tunneling through thin collisions.
       - COLLISION RESOLUTION: Use Constraint-based resolution. When a collision is detected, project the entity's position out of the collision volume immediately rather than just modifying velocity.
       - GRAVITY: Implement a consistent downward force applied to acceleration.
    3. DEEP ASSET SYNERGY: 
       - Map models and animations correctly using provided categories (Hero, Enemy, Prop, Level Geometry, etc.).
       - PERFORMANCE: Use simplified proxy geometry (spheres/boxes) for physics checks even if the visual model is complex.
