import React, { useMemo, useRef, useState, useEffect } from 'react';
import { GameAsset } from '../types';
import { Power, Loader2, Save, Bug, BugOff, AlertTriangle, RefreshCcw, Home } from 'lucide-react';

interface GameRunnerProps {
  code: string;
  title: string;
  assets: GameAsset[];
  onExit: () => void;
}

export const GameRunner: React.FC<GameRunnerProps> = ({ code, title, assets, onExit }) => {
  const iframeRef = useRef<HTMLIFrameElement>(null);
  const [isMounting, setIsMounting] = useState(true);
  const [showSaveIndicator, setShowSaveIndicator] = useState(false);
  const [debugEnabled, setDebugEnabled] = useState(false);
  const [runtimeError, setRuntimeError] = useState<{ message: string; type: string } | null>(null);

  // Storage key based on game title to avoid collisions between different projects
  const persistenceKey = useMemo(() => `forge_studio_state_${btoa(title).substring(0, 16)}`, [title]);

  // Simulate a brief mounting phase for immersion
  useEffect(() => {
    const timer = setTimeout(() => setIsMounting(false), 2000);
    return () => clearTimeout(timer);
  }, []);

  // Handle debug toggle
  const toggleDebug = () => {
    const newState = !debugEnabled;
    setDebugEnabled(newState);
    if (iframeRef.current?.contentWindow) {
      iframeRef.current.contentWindow.postMessage({ type: 'FORGE_TOGGLE_DEBUG', payload: newState }, '*');
    }
  };

  // Listen for messages from the game iframe
  useEffect(() => {
    const handleMessage = (event: MessageEvent) => {
      if (event.data) {
        if (event.data.type === 'FORGE_SAVE_STATE') {
          const stateToSave = event.data.payload;
          localStorage.setItem(persistenceKey, JSON.stringify(stateToSave));

          // Brief visual feedback for saving
          setShowSaveIndicator(true);
          setTimeout(() => setShowSaveIndicator(false), 1500);
        }
        if (event.data.type === 'FORGE_RUNTIME_READY') {
          // Sync current debug state to newly loaded runtime
          if (iframeRef.current?.contentWindow) {
            iframeRef.current.contentWindow.postMessage({ type: 'FORGE_TOGGLE_DEBUG', payload: debugEnabled }, '*');
          }
        }
        if (event.data.type === 'FORGE_RUNTIME_ERROR') {
          console.error("Simulation Runtime Crash:", event.data.payload);
          setRuntimeError(event.data.payload);
        }
      }
    };

    window.addEventListener('message', handleMessage);
    return () => window.removeEventListener('message', handleMessage);
  }, [persistenceKey, debugEnabled]);

  const combinedSrcDoc = useMemo(() => {
    const assetMap = assets.reduce((acc, asset) => {
      acc[asset.name] = asset.content;
      return acc;
    }, {} as Record<string, string>);

    // Retrieve current persisted state
    const savedStateStr = localStorage.getItem(persistenceKey);
    const savedState = savedStateStr ? JSON.parse(savedStateStr) : null;

    const bootstrapScript = `
      <script>
        (function() {
          // Global Error Interception
          window.onerror = function(message, source, lineno, colno, error) {
            window.parent.postMessage({ 
              type: 'FORGE_RUNTIME_ERROR', 
              payload: { message: message, type: 'Logical Kernel Panic' } 
            }, '*');
            return true;
          };

          window.onunhandledrejection = function(event) {
            window.parent.postMessage({ 
              type: 'FORGE_RUNTIME_ERROR', 
              payload: { message: event.reason?.message || 'Asynchronous logical collision', type: 'Unhandled Promise' } 
            }, '*');
          };

          const rawAssets = ${JSON.stringify(assetMap)};
          const blobUrls = {};

          // Time-stepping Subsystem for Physics Stability
          let lastTime = performance.now();
          window.getDeltaTime = function() {
            const now = performance.now();
            let dt = (now - lastTime) / 1000;
            lastTime = now;

            // Clamping DT to prevent "Physics Explosions" during frame drops (max 10fps worth of motion)
            // Clamping at 0.1s is essential for Verlet stability.
            if (dt > 0.1) dt = 0.1;
            return dt;
          };

          // Persistence & Debug API
          window.PERSISTED_STATE = ${JSON.stringify(savedState)};
          window.DEBUG_PHYSICS = false; // Initial state

          window.saveState = function(data) {
            window.parent.postMessage({ type: 'FORGE_SAVE_STATE', payload: data }, '*');
          };

          window.addEventListener('message', (event) => {
            if (event.data && event.data.type === 'FORGE_TOGGLE_DEBUG') {
              window.DEBUG_PHYSICS = event.data.payload;
            }
          });

          // Inform parent that we are ready to receive state
          window.parent.postMessage({ type: 'FORGE_RUNTIME_READY' }, '*');

          function base64ToBlob(base64, mime) {
            const split = base64.split(',');
            const data = split[1] || split[0];
            const byteString = atob(data);
            const ab = new ArrayBuffer(byteString.length);
            const ia = new Uint8Array(ab);
            for (let i = 0; i < byteString.length; i++) {
              ia[i] = byteString.charCodeAt(i);
            }
            return new Blob([ab], { type: mime });
          }

          window.getAssetUrl = function(name) {
            if (blobUrls[name]) return blobUrls[name];
            const data = rawAssets[name];
            if (!data) return "";
            let mime = 'application/octet-stream';
            if (data.includes('data:')) {
              mime = data.split(':')[1].split(';')[0];
            }
            const blob = base64ToBlob(data, mime);
            const url = URL.createObjectURL(blob);
            blobUrls[name] = url;
            return url;
          };
        })();
      </script>
      <style>
        body { margin: 0; background: #000; overflow: hidden; width: 100vw; height: 100vh; font-family: sans-serif; }
        canvas { display: block; width: 100%; height: 100%; object-fit: contain; }
      </style>
    `;

    if (code.includes('<head>')) {
      return code.replace('<head>', `<head>${bootstrapScript}`);
    }
    return bootstrapScript + code;
  }, [code, assets, persistenceKey]);

  return (
    <div className="fixed inset-0 w-full h-full bg-black flex flex-col z-[1000] overflow-hidden cursor-auto select-none">

      {/* Immersive Loading Screen */}
      {isMounting && !runtimeError && (
        <div className="absolute inset-0 z-[1100] bg-black flex flex-col items-center justify-center transition-opacity duration-1000">
          <div className="relative mb-8">
            <Loader2 className="w-10 h-10 text-emerald-500 animate-spin" />
            <div className="absolute inset-0 bg-emerald-500/20 blur-xl rounded-full animate-pulse" />
          </div>
          <h2 className="text-[11px] font-black text-white uppercase tracking-[0.6em] mb-2">Mounting Reality...</h2>
          <p className="text-[8px] text-zinc-600 font-bold uppercase tracking-[0.3em]">{title}</p>
        </div>
      )}

      {/* Robust Error Overlay */}
      {runtimeError && (
        <div className="absolute inset-0 z-[1200] bg-zinc-950 flex flex-col items-center justify-center p-8 animate-in fade-in duration-500">
          <div className="absolute inset-0 opacity-10 pointer-events-none">
            <div className="h-full w-full bg-[radial-gradient(circle_at_50%_50%,rgba(239,68,68,0.15),transparent_70%)]" />
          </div>

          <div className="w-20 h-20 bg-red-500/10 border border-red-500/20 rounded-3xl flex items-center justify-center mb-10 shadow-[0_0_50px_rgba(239,68,68,0.1)]">
            <AlertTriangle className="w-8 h-8 text-red-500" />
          </div>

          <div className="text-center max-w-xl mx-auto mb-12">
            <h2 className="text-[11px] font-black text-red-500 uppercase tracking-[0.5em] mb-4">Simulation Destabilized</h2>
            <p className="text-zinc-400 text-sm font-medium leading-relaxed mb-6">
              The neural substrate encountered a critical collision. This usually happens when the synthesized logic attempts an operation outside the bounds of the current physics engine or asset buffer.
            </p>
            <div className="p-4 rounded-xl bg-red-500/5 border border-red-500/10 font-mono text-left">
              <div className="flex items-center gap-2 mb-2">
                <span className="text-[9px] font-black text-red-500/50 uppercase tracking-widest">{runtimeError.type}</span>
              </div>
              <p className="text-[10px] text-zinc-500 leading-normal break-words italic">"{runtimeError.message}"</p>
            </div>
          </div>

          <div className="flex gap-4">
            <button 
              onClick={() => window.location.reload()}
              className="flex items-center gap-3 px-6 py-3 rounded-2xl bg-zinc-900 border border-white/5 text-zinc-300 hover:text-white hover:border-white/20 transition-all font-black text-[9px] uppercase tracking-widest"
            >
              <RefreshCcw className="w-4 h-4" />
              Re-Initialize Core
            </button>
            <button 
              onClick={onExit}
              className="flex items-center gap-3 px-8 py-3 rounded-2xl bg-red-500 text-black hover:bg-red-400 transition-all font-black text-[9px] uppercase tracking-widest shadow-[0_0_30px_rgba(239,68,68,0.2)]"
            >
              <Home className="w-4 h-4" />
              Return to Editor
            </button>
          </div>
        </div>
      )}

      {/* Status Bar */}
      {!runtimeError && (
        <div className="absolute bottom-8 left-8 right-8 z-[1060] flex items-center justify-between pointer-events-none">
          {/* Save Indicator */}
          <div className={`flex items-center gap-3 bg-zinc-900/80 backdrop-blur-xl border border-white/10 px-4 py-2 rounded-full transition-all duration-500 ${showSaveIndicator ? 'opacity-100 translate-y-0' : 'opacity-0 translate-y-4'}`}>
            <Save className="w-3.5 h-3.5 text-emerald-500" />
            <span className="text-[9px] font-black uppercase tracking-widest text-zinc-400">Syncing Substrate State</span>
          </div>

          {/* Debug Controls */}
          <div className="flex gap-2 pointer-events-auto">
            <button 
              onClick={toggleDebug}
              className={`flex items-center gap-2 px-4 py-2 rounded-full border transition-all ${debugEnabled ? 'bg-emerald-500/20 border-emerald-500/50 text-emerald-400' : 'bg-zinc-900/80 border-white/10 text-zinc-500 hover:border-white/20'}`}
            >
              {debugEnabled ? <Bug className="w-3.5 h-3.5" /> : <BugOff className="w-3.5 h-3.5" />}
              <span className="text-[9px] font-black uppercase tracking-widest">
                {debugEnabled ? 'Debug Overlays: On' : 'Debug Overlays: Off'}
              </span>
            </button>
          </div>
        </div>
      )}

      {/* Subtle Exit Control (Appears on Hover at Top) */}
      {!runtimeError && (
        <div className="absolute top-0 left-0 right-0 h-20 z-[1050] flex justify-center opacity-0 hover:opacity-100 transition-opacity duration-300 group">
          <button 
            onClick={onExit}
            className="mt-6 flex items-center gap-3 bg-black/80 backdrop-blur-3xl border border-white/10 px-6 py-2.5 rounded-2xl hover:bg-white hover:text-black hover:border-white transition-all transform hover:scale-105 active:scale-95 shadow-2xl pointer-events-auto"
          >
            <Power className="w-4 h-4" />
            <span className="text-[9px] font-black uppercase tracking-[0.2em]">Exit Simulation</span>
          </button>
        </div>
      )}

      {/* Pure Game Iframe */}
      <iframe
        ref={iframeRef}
        srcDoc={combinedSrcDoc}
        title="Forge Runtime"
        className={`w-full h-full border-none transition-opacity duration-1000 ${isMounting || runtimeError ? 'opacity-0' : 'opacity-100'}`}
        sandbox="allow-scripts allow-modals allow-pointer-lock"
      />
    </div>
  );
};

import { GoogleGenAI, Type } from "@google/genai";
import { GameAsset, ChatMessage } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const generateGame = async (
  prompt: string,
  assets: GameAsset[],
  history: ChatMessage[] = [],
  currentCode: string = ""
): Promise<{ code: string; title: string; explanation: string; suggestions: string[] }> => {

  const assetMetadata = assets.map(a => ({
    name: a.name,
    type: a.type,
    mimeType: a.mimeType,
    category: a.category,
    isOptimized: !!a.isOptimized,
    logicContext: a.type === 'dialogue' ? a.content : undefined
  }));

  const isRefinement = history.length > 0 && currentCode !== "";

  const systemInstruction = `
    You are the "Core Neural Architect" of ForgeAI Studio—a world-class expert in Three.js, ECS (Entity Component System), and Real-time Physics simulations.

    CORE OPERATING MANDATE:
    Every response must be a masterclass in architectural reasoning. You do not just "code"; you solve mechanical puzzles.

    LOGICAL THINKING PROTOCOLS:
    1. GENRE RECOGNITION & BLUEPRINTING: Identify genre-specific requirements (e.g., camera offsets for 3rd person, raycasting for platformers).
    2. PHYSICS ENGINE CORE (MANDATORY):
       - ARCHITECTURE: Implement a Robust Verlet Integration system (Position-based dynamics).
       - STATE: Each dynamic entity must track 'position', 'previousPosition', and 'acceleration'.
       - KINEMATIC RESOLUTION: Calculate new positions as: pos + (pos - prevPos) * damping + acc * dt * dt.
       - SUB-STEPPING: Use a minimum of 4 sub-steps per frame to ensure stability.
       - PHYSICAL MATERIAL MATRIX: Leverage 'window.PHYSICS_MATERIALS' (defined in runtime) to apply distinct friction and restitution based on asset categories:
         - 'Level Geometry': High friction (0.9), low restitution (0.1) for solid footing.
         - 'Prop': Medium friction (0.5), higher restitution (0.6) for bouncy, interactive objects.
         - 'Hero'/'Enemy': High friction (0.8) for precise movement control.
         - 'Hazard': Low friction (0.1) for slippery surfaces.
       - COLLISION RESOLUTION: Use Constraint-based resolution. Project positions out of collision volumes and adjust 'previousPosition' to simulate restitution/bounce.
    3. DEEP ASSET SYNERGY: 
       - Map models correctly using categories. Use window.getAssetUrl(name) to load assets.
    4. ADVANCED CONTROL SURFACE: Support Keyboard/Mouse/Touch.
    5. DEBUG VISUALIZATION (MANDATORY): Check 'window.DEBUG_PHYSICS' to render bounding volumes and normals.
    6. PERSISTENCE ENGINE: Use window.PERSISTED_STATE and window.saveState(data).

    MANDATORY EXPLANATION STRUCTURE:
    Your "explanation" field MUST follow this strict format: [GENRE ANALYSIS], [MECHANICAL DERIVATION], [LOGIC NODE BINDING], [ASSET MAPPING].
    In [MECHANICAL DERIVATION], detail how you mapped category-specific friction and restitution values to the Verlet integrator.

    PROACTIVE SUGGESTIONS (MANDATORY):
    Provide 2-3 improvement ideas (e.g., "Add procedural wind affectors?", "Implement destructible props?").

    RESPONSE FORMAT:
    Return a JSON object with: code, title, explanation, suggestions.

    ENGINE CONSTRAINTS:
    - Include Three.js (0.160.0) and OrbitControls via CDN.
    - Use window.getDeltaTime() (clamped at 0.1s).
    - Always implement a 'dispose()' or 'cleanup()' method.
  `;

  const userPrompt = isRefinement 
    ? `ARCHITECTURAL REFINEMENT PROTOCOL:
       Input Instructions: ${prompt}
       Current Substrate Status: ${currentCode}
       Available Buffers: ${JSON.stringify(assetMetadata)}

       MANDATE: Evolve the physics and logic. Implement category-specific physical materials (friction/restitution) within the Verlet simulation.`
    : `SYSTEM INITIALIZATION SEED:
       Project Description: ${prompt}
       Available Buffers: ${JSON.stringify(assetMetadata)}

       MANDATE: Synthesize a full-scale 3D simulation with a Verlet-based physics kernel using category-specific physical materials (friction/restitution).`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: userPrompt,
    config: {
      systemInstruction,
      thinkingConfig: { thinkingBudget: 32768 },
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          code: { type: Type.STRING },
          title: { type: Type.STRING },
          explanation: { type: Type.STRING },
          suggestions: {
            type: Type.ARRAY,
            items: { type: Type.STRING }
          }
        },
        required: ['code', 'title', 'explanation', 'suggestions']
      }
    }
  });

  try {
    const result = JSON.parse(response.text || '{}');
    return {
      code: result.code || currentCode,
      title: result.title || 'Studio Synthesis',
      explanation: result.explanation || 'Logic synthesis complete.',
      suggestions: result.suggestions || []
    };
  } catch (e) {
    console.error("Architectural Collision:", e);
    throw new Error("Logic synthesis failure. The engine requires a structured architectural report.");
  }
};

