import React, { useState, useCallback, useEffect, useRef } from 'react';
import { AssetUploader } from './components/AssetUploader';
import { GameRunner } from './components/GameRunner';
import { AIChat } from './components/AIChat';
import { generateGame } from './services/gemini';
import { GameAsset, GenerationStatus, GeneratedGame, ChatMessage } from './types';
import { Box, Activity, Layers, Monitor, Terminal, Sparkles, Play, BoxSelect, Menu, X, MessageSquareCode, BrainCircuit, RefreshCw, Cpu } from 'lucide-react';

type ViewMode = 'editor' | 'preview';

const App: React.FC = () => {
  const [viewMode, setViewMode] = useState<ViewMode>('editor');
  const [assets, setAssets] = useState<GameAsset[]>([]);
  const [status, setStatus] = useState<GenerationStatus>({ step: 'idle', message: '' });
  const [game, setGame] = useState<GeneratedGame | null>(null);
  const [chatHistory, setChatHistory] = useState<ChatMessage[]>([]);
  const [logs, setLogs] = useState<string[]>([
    'Initializing ForgeAI Studio core...', 
    'Neural substrate calibration complete.',
    'Physics Subsystem: High-precision Verlet Active.'
  ]);
  const [isLeftSidebarOpen, setIsLeftSidebarOpen] = useState(false);
  const [isRightSidebarOpen, setIsRightSidebarOpen] = useState(false);
  const [activeMobileView, setActiveMobileView] = useState<'staging' | 'chat' | 'logs'>('staging');
  const [isLiveSyncing, setIsLiveSyncing] = useState(false);

  const prevAssetsCount = useRef(0);
  const autoSyncTimer = useRef<ReturnType<typeof setTimeout> | null>(null);

  const addLog = (msg: string) => {
    setLogs(prev => [...prev.slice(-15), msg]);
  };

  const processGeneration = useCallback(async (instruction: string, isAutoSync: boolean = false) => {
    if (!isAutoSync) {
      setStatus({ step: 'analyzing', message: 'Architecting Logical Model...' });
      addLog(`Analyzing mechanical intent: "${instruction.slice(0, 30)}..."`);
      setChatHistory(prev => [...prev, { role: 'user', text: instruction }]);
    } else {
      setIsLiveSyncing(true);
      addLog(`Auto-Sync: Harmonizing buffers...`);
    }

    try {
      const result = await generateGame(
        instruction, 
        assets, 
        chatHistory, 
        game?.code || ""
      );

      if (!isAutoSync) {
        setStatus({ step: 'coding', message: 'Synthesizing 3D Substrate...' });
        const aiMessage: ChatMessage = { 
          role: 'ai', 
          text: result.explanation,
          suggestions: result.suggestions,
          isApplying: true 
        };
        setChatHistory(prev => [...prev, aiMessage]);

        await new Promise(resolve => setTimeout(resolve, 2000));

        setChatHistory(prev => prev.map((m, idx) => 
          idx === prev.length - 1 ? { ...m, isApplying: false } : m
        ));
      }

      setGame({ code: result.code, title: result.title });
      setStatus({ step: 'ready', message: 'Architecture Verified.' });
      setIsLiveSyncing(false);

      addLog(`Substrate ${isAutoSync ? 'synchronized' : 'generated'}: "${result.title}"`);

    } catch (error: any) {
      console.error(error);
      setStatus({ step: 'error', message: 'Synthesis Failure.' });
      setIsLiveSyncing(false);
      if (!isAutoSync) {
        setChatHistory(prev => [...prev, { role: 'ai', text: 'Structural paradox detected. The architect requires refined mechanical parameters.' }]);
      }
      addLog(`Error: Collision in logic synthesis.`);
    }
  }, [assets, chatHistory, game]);

  useEffect(() => {
    if (game && assets.length !== prevAssetsCount.current) {
      if (autoSyncTimer.current) clearTimeout(autoSyncTimer.current);
      autoSyncTimer.current = setTimeout(() => {
        const lastUserPrompt = chatHistory.filter(m => m.role === 'user').pop()?.text || "Synchronize simulation with updated buffers.";
        processGeneration(`SYNC: ${lastUserPrompt}`, true);
      }, 5000); 
    }
    prevAssetsCount.current = assets.length;
  }, [assets, game, chatHistory, processGeneration]);

  const enterPreview = () => {
    if (game) setViewMode('preview');
  };

  const exitPreview = () => setViewMode('editor');

  if (viewMode === 'preview' && game) {
    return (
      <div className="fixed inset-0 z-[500] bg-[#0F172A]">
        <GameRunner code={game.code} title={game.title} assets={assets} onExit={exitPreview} />
      </div>
    );
  }

  return (
    <div className="flex flex-col h-screen max-h-screen bg-[#F8FAFC] text-[#0F172A] overflow-hidden font-sans relative selection:bg-[#4F46E5]/10 selection:text-[#4F46E5]">
      {/* LUXURY HEADER */}
      <header className="h-16 border-b border-[#E2E8F0] bg-white shadow-sm flex items-center justify-between px-6 shrink-0 z-50">
        <div className="flex items-center gap-6">
          <button 
            onClick={() => setIsLeftSidebarOpen(!isLeftSidebarOpen)}
            className="md:hidden p-2 hover:bg-[#F1F5F9] rounded-lg transition-colors text-[#64748B]"
          >
            {isLeftSidebarOpen ? <X className="w-5 h-5" /> : <Menu className="w-5 h-5" />}
          </button>

          <div className="flex items-center gap-3">
            <div className="bg-[#4F46E5] p-1.5 rounded-lg shadow-md shadow-indigo-100">
              <Box className="w-4 h-4 text-white" />
            </div>
            <div className="flex flex-col">
              <h1 className="text-sm font-bold tracking-tight text-[#0F172A]">
                STUDIO <span className="text-[#4F46E5]">FORGE</span>
              </h1>
              <span className="text-[8px] text-[#94A3B8] font-bold uppercase tracking-[0.2em] -mt-0.5">Neural Engine v5.1</span>
            </div>
          </div>

          <div className="h-6 w-px bg-[#E2E8F0] hidden sm:block" />

          <div className="hidden lg:flex items-center gap-5">
            <div className="flex items-center gap-2 px-3 py-1 rounded-full bg-[#F1F5F9] border border-[#E2E8F0]">
              <BrainCircuit className={`w-3.5 h-3.5 ${status.step === 'ready' ? 'text-[#4F46E5]' : status.step !== 'idle' ? 'text-[#C9A24D] animate-pulse' : 'text-[#94A3B8]'}`} />
              <span className="text-[10px] font-bold uppercase tracking-wider text-[#64748B]">System: {status.step === 'ready' ? 'Optimal' : 'Standby'}</span>
            </div>
            <div className="flex items-center gap-2 px-3 py-1 rounded-full bg-[#F8FAFC] border border-[#C9A24D]/30">
              <Cpu className="w-3.5 h-3.5 text-[#C9A24D]" />
              <span className="text-[10px] font-bold uppercase tracking-wider text-[#C9A24D]">Reasoning: Max</span>
            </div>
            {isLiveSyncing && (
              <div className="flex items-center gap-1.5 text-[#4F46E5] animate-pulse">
                <RefreshCw className="w-3 h-3 animate-spin" />
                <span className="text-[9px] font-bold">LIVE SYNCING</span>
              </div>
            )}
          </div>
        </div>

        <div className="flex items-center gap-3">
          {game && (
            <button 
              onClick={enterPreview}
              className="flex items-center gap-2 px-5 py-2 rounded-xl bg-[#4F46E5] text-white font-bold text-[11px] uppercase tracking-wider hover:bg-[#4338CA] transition-all shadow-lg shadow-indigo-100 hover:shadow-indigo-200 active:scale-95"
            >
              <Play className="w-3.5 h-3.5 fill-current" />
              <span>Launch Engine</span>
            </button>
          )}
          <button 
            onClick={() => setIsRightSidebarOpen(!isRightSidebarOpen)}
            className="md:hidden p-2 hover:bg-[#F1F5F9] rounded-lg transition-colors text-[#64748B]"
          >
            <MessageSquareCode className="w-5 h-5" />
          </button>
        </div>
      </header>

      <main className="flex-1 flex overflow-hidden">
        {/* Left Sidebar: Asset Matrix */}
        <aside className={`
          fixed inset-y-0 left-0 z-40 w-[280px] md:w-[320px] border-r border-[#E2E8F0] bg-[#FFFFFF] shadow-xl md:shadow-none
          flex flex-col shrink-0 transition-transform duration-300 transform
          ${isLeftSidebarOpen ? 'translate-x-0' : '-translate-x-full md:translate-x-0'}
          md:static md:z-0
        `}>
          <div className="p-6 overflow-y-auto flex-1 no-scrollbar space-y-8">
            <section>
              <div className="flex items-center justify-between mb-6">
                <div className="flex items-center gap-2.5">
                  <div className="w-1.5 h-4 bg-[#4F46E5] rounded-full" />
                  <h2 className="text-[11px] font-bold uppercase tracking-[0.2em] text-[#64748B]">Asset Matrix</h2>
                </div>
                <span className="text-[9px] font-bold text-[#94A3B8] uppercase">{assets.length} Active</span>
              </div>
              <AssetUploader assets={assets} onAssetsChange={setAssets} />
            </section>
          </div>
        </aside>

        {/* Center: Staging Area */}
        <div className={`flex-1 flex flex-col bg-[#F8FAFC] transition-all overflow-hidden ${activeMobileView === 'staging' || activeMobileView === 'logs' ? 'flex' : 'hidden md:flex'}`}>
          <div className={`flex-1 relative flex flex-col items-center justify-center p-8 ${activeMobileView === 'staging' ? 'flex' : 'hidden md:flex'}`}>
            <div className="absolute inset-0 bg-[radial-gradient(circle_at_50%_50%,rgba(79,70,229,0.03),transparent_70%)] pointer-events-none" />

            <div className="text-center relative z-10 w-full max-w-lg">
              <div className={`w-20 h-20 md:w-28 md:h-28 bg-white border border-[#E2E8F0] rounded-[2.5rem] flex items-center justify-center mx-auto mb-10 shadow-2xl shadow-slate-200 group hover:border-[#4F46E5]/30 transition-all duration-700 ${status.step === 'coding' || isLiveSyncing ? 'animate-pulse border-[#4F46E5]/20' : ''}`}>
                <BoxSelect className={`w-8 h-8 md:w-12 md:h-12 transition-colors ${status.step === 'coding' || isLiveSyncing ? 'text-[#4F46E5]' : 'text-[#CBD5E1] group-hover:text-[#4F46E5]'}`} />
              </div>

              {game ? (
                <div className="animate-in fade-in slide-in-from-bottom-4 duration-700">
                  <div className="inline-flex items-center gap-2 px-3 py-1.5 rounded-full bg-[#EEF2FF] border border-[#E0E7FF] mb-6">
                    <Activity className="w-3.5 h-3.5 text-[#4F46E5]" />
                    <span className="text-[9px] font-bold uppercase tracking-widest text-[#4F46E5]">Substrate Ready</span>
                  </div>
                  <h3 className="text-xl md:text-2xl font-bold tracking-tight text-[#0F172A] mb-2">{game.title}</h3>
                  <p className="text-[10px] text-[#64748B] font-medium uppercase tracking-[0.1em] mb-10">Active Synthesis Session</p>

                  <div className="grid grid-cols-2 gap-4 max-w-sm mx-auto">
                    <div className="bg-white p-5 rounded-2xl border border-[#E2E8F0] shadow-sm flex flex-col items-center gap-1.5">
                      <span className="text-[9px] text-[#94A3B8] uppercase font-bold tracking-widest">Logic Units</span>
                      <span className="text-lg text-[#0F172A] font-bold">{assets.filter(a => a.type === 'dialogue').length}</span>
                    </div>
                    <div className="bg-white p-5 rounded-2xl border border-[#E2E8F0] shadow-sm flex flex-col items-center gap-1.5">
                      <span className="text-[9px] text-[#94A3B8] uppercase font-bold tracking-widest">3D Buffers</span>
                      <span className="text-lg text-[#0F172A] font-bold">{assets.filter(a => a.type !== 'dialogue').length}</span>
                    </div>
                  </div>
                </div>
              ) : (
                <div className="opacity-60 cursor-default">
                  <h3 className="text-[11px] font-bold uppercase tracking-[0.5em] text-[#94A3B8]">Neural Staging Idle</h3>
                  <p className="text-xs text-[#64748B] mt-6 leading-relaxed">Synthesize architectural logic via the assistant to begin.</p>
                </div>
              )}
            </div>

            <div className="absolute bottom-10 left-10 flex flex-col gap-2">
