import React, { useState } from 'react';
import { AssetType, GameAsset } from '../types';
import { X, Box, Music, MessageSquare, Plus, Globe, Activity, Users, Zap, Loader2, CheckCircle2, Timer, Cpu, Tag, ChevronDown } from 'lucide-react';

interface AssetUploaderProps {
  assets: GameAsset[];
  onAssetsChange: (assets: GameAsset[]) => void;
}

const LIMITS: Record<AssetType, number | null> = {
  character1: 4,
  motion1: 10,
  character2: 4,
  motion2: 10,
  environment: null,
  music: null,
  dialogue: null
};

const CATEGORIES = [
  'Hero', 'Enemy', 'NPC', 'Prop', 'Level Geometry', 'Loot', 'Trigger', 'Hazard', 'Decal', 'VFX'
];

const DEFAULT_CATEGORIES: Record<AssetType, string> = {
  character1: 'Hero',
  motion1: 'Hero',
  character2: 'Enemy',
  motion2: 'Enemy',
  environment: 'Level Geometry',
  music: 'BGM',
  dialogue: 'Logic'
};

const OPTIMIZATION_STAGES = [
  { threshold: 0, label: "Scanning Geometry" },
  { threshold: 20, label: "Refining Mesh" },
  { threshold: 45, label: "Compressing Map" },
  { threshold: 75, label: "UV Optimization" },
  { threshold: 90, label: "Final Synthesis" }
];

export const AssetUploader: React.FC<AssetUploaderProps> = ({ assets, onAssetsChange }) => {
  const [dialogueInput, setDialogueInput] = useState('');
  const [optimizingId, setOptimizingId] = useState<string | null>(null);
  const [optimizingProgress, setOptimizingProgress] = useState(0);
  const [optimizingStatus, setOptimizingStatus] = useState("");
  const [eta, setEta] = useState<number | null>(null);
  const [activeCategoryPicker, setActiveCategoryPicker] = useState<string | null>(null);

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>, type: AssetType) => {
    const files = e.target.files;
    if (!files) return;
    const currentCount = assets.filter(a => a.type === type).length;
    const limit = LIMITS[type];
    const filesToUpload = Array.from(files);

    if (limit !== null && currentCount + filesToUpload.length > limit) {
      alert(`Capacity Warning: ${type} slot is limited to ${limit} assets.`);
      e.target.value = '';
      return;
    }

    const newAssetsPromises = filesToUpload.map((file: File) => {
      return new Promise<GameAsset>((resolve) => {
        const reader = new FileReader();
        reader.onload = (event) => {
          resolve({
            id: Math.random().toString(36).substr(2, 9),
            name: file.name,
            type,
            content: event.target?.result as string,
            mimeType: file.type || 'application/octet-stream',
            isOptimized: false,
            category: DEFAULT_CATEGORIES[type]
          });
        };
        reader.readAsDataURL(file);
      });
    });

    Promise.all(newAssetsPromises).then((newlyCreatedAssets) => {
      onAssetsChange([...assets, ...newlyCreatedAssets]);
    });
    e.target.value = '';
  };

  const updateAssetCategory = (id: string, category: string) => {
    onAssetsChange(assets.map(a => a.id === id ? { ...a, category } : a));
    setActiveCategoryPicker(null);
  };

  const removeAsset = (id: string) => {
    onAssetsChange(assets.filter(a => a.id !== id));
  };

  const optimizeAsset = async (asset: GameAsset) => {
    setOptimizingId(asset.id);
    setOptimizingProgress(0);
    const totalDuration = 3500;
    const startTime = Date.now();
    const interval = setInterval(() => {
      const elapsed = Date.now() - startTime;
      const progress = Math.min(Math.round((elapsed / totalDuration) * 100), 100);
      const stage = [...OPTIMIZATION_STAGES].reverse().find(s => progress >= s.threshold);
      setOptimizingProgress(progress);
      setOptimizingStatus(stage?.label || "Processing");
      setEta(Math.max(0, Math.ceil((totalDuration - elapsed) / 1000)));
      if (progress >= 100) {
        clearInterval(interval);
        onAssetsChange(assets.map(a => a.id === asset.id ? { ...a, isOptimized: true } : a));
        setOptimizingId(null);
      }
    }, 50);
  };

  const AssetSection = ({ type, icon: Icon, label, accept = ".glb,.fbx" }: { type: AssetType, icon: any, label: string, accept?: string }) => {
    const currentAssets = assets.filter(a => a.type === type);
    const limit = LIMITS[type];
    const isFull = limit !== null && currentAssets.length >= limit;

    return (
      <div className="flex flex-col gap-4 bg-[#F1F5F9]/30 p-4 rounded-2xl border border-[#E2E8F0]">
        <div className="flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="p-2 rounded-xl bg-white border border-[#E2E8F0] shadow-sm">
              <Icon className="w-4 h-4 text-[#4F46E5]" />
            </div>
            <div className="flex flex-col">
              <span className="text-[11px] font-bold uppercase tracking-wider text-[#0F172A]">{label}</span>
              <span className="text-[9px] text-[#94A3B8] font-bold uppercase tracking-tight">{limit ? `${currentAssets.length}/${limit}` : 'Flex'}</span>
            </div>
          </div>
          <label className={`cursor-pointer px-4 py-2 rounded-xl border text-[10px] font-bold uppercase transition-all flex items-center gap-2 ${
            isFull ? 'bg-white border-[#E2E8F0] text-[#CBD5E1] cursor-not-allowed' : 'bg-white border-[#E2E8F0] text-[#64748B] hover:border-[#4F46E5] hover:text-[#4F46E5] hover:shadow-md'
          }`}>
            <Plus className="w-3.5 h-3.5" />
            Add
            {!isFull && <input type="file" multiple className="hidden" onChange={(e) => handleFileUpload(e, type)} accept={accept} />}
          </label>
        </div>

        <div className="space-y-2">
          {currentAssets.map(asset => (
            <div key={asset.id} className="bg-white px-3 py-3 rounded-xl border border-[#E2E8F0] hover:border-[#4F46E5]/20 transition-all shadow-sm">
              <div className="flex items-center justify-between gap-3">
                <div className="flex flex-col gap-1 min-w-0">
                  <span className="truncate text-[10px] text-[#0F172A] font-semibold tracking-tight">{asset.name}</span>
                  <div className="relative">
                    <button onClick={() => setActiveCategoryPicker(activeCategoryPicker === asset.id ? null : asset.id)} className="flex items-center gap-1.5 text-[9px] font-bold uppercase tracking-wider text-[#94A3B8] hover:text-[#4F46E5] transition-colors">
                      <Tag className="w-2.5 h-2.5" />
                      <span>{asset.category || 'Default'}</span>
                      <ChevronDown className="w-2.5 h-2.5" />
                    </button>
                    {activeCategoryPicker === asset.id && (
                      <div className="absolute top-full left-0 z-50 mt-2 bg-white border border-[#E2E8F0] rounded-xl shadow-2xl overflow-hidden py-2 w-40 animate-in fade-in slide-in-from-top-2">
                        {CATEGORIES.map(cat => (
                          <button key={cat} onClick={() => updateAssetCategory(asset.id, cat)} className={`px-4 py-2 text-[10px] font-bold uppercase tracking-wider text-left w-full transition-colors ${asset.category === cat ? 'bg-[#EEF2FF] text-[#4F46E5]' : 'text-[#64748B] hover:bg-[#F8FAFC]'}`}>{cat}</button>
                        ))}
                      </div>
                    )}
                  </div>
                </div>
                <div className="flex items-center gap-2 shrink-0">
                  {asset.isOptimized ? (
                    <div className="px-2 py-1 rounded-lg bg-[#F0FDF4] border border-[#DCFCE7]"><CheckCircle2 className="w-3.5 h-3.5 text-[#16A34A]" /></div>
                  ) : (
                    (type.includes('character') || type === 'environment') && (
                      <button onClick={() => optimizeAsset(asset)} disabled={optimizingId !== null} className="p-2 text-[#CBD5E1] hover:text-[#4F46E5] transition-colors">
                        {optimizingId === asset.id ? <Loader2 className="w-3.5 h-3.5 animate-spin" /> : <Zap className="w-3.5 h-3.5" />}
                      </button>
                    )
                  )}
                  <button onClick={() => removeAsset(asset.id)} className="text-[#CBD5E1] hover:text-red-500 p-2 transition-colors"><X className="w-3.5 h-3.5" /></button>
                </div>
              </div>
              {optimizingId === asset.id && (
                <div className="mt-3 space-y-2 animate-in fade-in slide-in-from-top-1">
                  <div className="flex justify-between text-[9px] font-bold uppercase text-[#4F46E5]">
                    <span>{optimizingStatus}</span>
                    <span>{optimizingProgress}%</span>
                  </div>
                  <div className="w-full h-1 bg-[#F1F5F9] rounded-full overflow-hidden">
                    <div className="h-full bg-[#4F46E5] transition-all duration-100" style={{ width: `${optimizingProgress}%` }} />
                  </div>
                </div>
              )}
            </div>
          ))}
          {currentAssets.length === 0 && <span className="text-[10px] text-[#CBD5E1] font-bold uppercase tracking-[0.2em] italic ml-2">Empty Stream</span>}
        </div>
      </div>
    );
  };

  return (
    <div className="space-y-12">
      <div className="space-y-6">
        <div className="flex items-center gap-2.5">
          <Users className="w-4 h-4 text-[#64748B]" />
          <h3 className="text-[11px] font-black uppercase tracking-[0.2em] text-[#94A3B8]">Entity A Profile</h3>
        </div>
        <AssetSection type="character1" icon={Box} label="3D Characters" />
        <AssetSection type="motion1" icon={Activity} label="Motion Data" />
      </div>

      <div className="space-y-6">
        <div className="flex items-center gap-2.5">
          <Users className="w-4 h-4 text-[#64748B]" />
          <h3 className="text-[11px] font-black uppercase tracking-[0.2em] text-[#94A3B8]">Entity B Profile</h3>
        </div>
        <AssetSection type="character2" icon={Box} label="3D Characters" />
        <AssetSection type="motion2" icon={Activity} label="Motion Data" />
      </div>

      <div className="space-y-6 pt-6 border-t border-[#E2E8F0]">
        <div className="flex items-center gap-2.5">
          <Globe className="w-4 h-4 text-[#64748B]" />
          <h3 className="text-[11px] font-black uppercase tracking-[0.2em] text-[#94A3B8]">World Substrate</h3>
        </div>
        <AssetSection type="environment" icon={Globe} label="Environment" />
        <AssetSection type="music" icon={Music} label="Soundscape" accept="audio/*" />
      </div>

      <div className="space-y-6 pt-6 border-t border-[#E2E8F0]">
        <div className="flex items-center gap-2.5">
          <MessageSquare className="w-4 h-4 text-[#C9A24D]" />
          <h3 className="text-[11px] font-black uppercase tracking-[0.2em] text-[#C9A24D]">Logic Nodes</h3>
        </div>
        <div className="relative group">
          <input type="text" value={dialogueInput} onChange={(e) => setDialogueInput(e.target.value)} placeholder="Input behavioral node..." className="w-full bg-white border border-[#E2E8F0] rounded-2xl px-5 py-4 text-xs font-medium focus:outline-none focus:border-[#4F46E5] text-[#0F172A] placeholder:text-[#CBD5E1] shadow-sm transition-all"
            onKeyDown={(e) => {
              if (e.key === 'Enter' && dialogueInput.trim()) {
                onAssetsChange([...assets, { id: Math.random().toString(36).substr(2, 9), name: `Node_${assets.filter(a => a.type === 'dialogue').length + 1}`, type: 'dialogue', content: dialogueInput, mimeType: 'text/plain', category: 'Logic' }]);
                setDialogueInput('');
              }
            }}
          />
          <Plus className="absolute right-4 top-1/2 -translate-y-1/2 w-4 h-4 text-[#CBD5E1] group-focus-within:text-[#4F46E5] transition-colors" />
        </div>
        <div className="space-y-2">
          {assets.filter(a => a.type === 'dialogue').map(asset => (
            <div key={asset.id} className="flex items-center justify-between bg-white px-4 py-3.5 rounded-2xl border border-[#E2E8F0] text-[11px] font-medium text-[#475569] shadow-sm italic transition-all hover:border-[#C9A24D]/20">
              <span className="truncate pr-4">"{asset.content}"</span>
              <button onClick={() => removeAsset(asset.id)} className="text-[#CBD5E1] hover:text-red-500 transition-colors shrink-0"><X className="w-3.5 h-3.5" /></button>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};

import { Bot, BrainCircuit, ChevronRight, Loader2, Send, Sparkles, Terminal, User, Zap, Lightbulb, Cpu } from 'lucide-react';
import React, { useEffect, useRef, useState } from 'react';
import { ChatMessage } from '../types';

interface AIChatProps {
  history: ChatMessage[];
  onSendMessage: (msg: string) => void;
  isProcessing: boolean;
}

export const AIChat: React.FC<AIChatProps> = ({ history, onSendMessage, isProcessing }) => {
  const [input, setInput] = useState('');
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [history, isProcessing]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (input.trim() && !isProcessing) {
      onSendMessage(input);
      setInput('');
    }
  };

  const formatReport = (text: string) => {
    return text.split('\n').map((line, i) => {
      if (line.startsWith('[') && line.includes(']')) {
        return (
          <div key={i} className="flex items-center gap-2 mt-5 mb-2 first:mt-0">
            <ChevronRight className="w-3.5 h-3.5 text-[#4F46E5]" />
            <span className="text-[10px] font-bold uppercase tracking-[0.2em] text-[#4F46E5]/80">
              {line.replace('[', '').replace(']', '')}
            </span>
          </div>
        );
      }
      return <p key={i} className="mb-2 leading-relaxed">{line}</p>;
    });
  };

  return (
    <div className="flex flex-col h-full bg-[#FFFFFF] border-l border-[#E2E8F0]">
      {/* Assistant Header */}
      <div className="hidden md:flex px-6 py-5 border-b border-[#F1F5F9] items-center justify-between bg-white">
        <div className="flex items-center gap-3">
          <div className="p-2 rounded-xl bg-[#EEF2FF] border border-[#E0E7FF]">
            <BrainCircuit className="w-5 h-5 text-[#4F46E5]" />
          </div>
          <div className="flex flex-col">
            <h2 className="text-sm font-bold tracking-tight text-[#0F172A]">Neural Architect</h2>
            <span className="text-[9px] text-[#94A3B8] font-bold uppercase tracking-widest">Premium Assistant</span>
          </div>
        </div>
        {isProcessing && (
           <div className="flex items-center gap-2 px-3 py-1 rounded-full bg-[#FDF6E3] border border-[#F3E8C9] animate-pulse">
             <Cpu className="w-3 h-3 text-[#C9A24D]" />
             <span className="text-[8px] font-bold uppercase tracking-widest text-[#C9A24D]">Thinking deeply...</span>
           </div>
        )}
      </div>

      {/* Chat Messages */}
      <div ref={scrollRef} className="flex-1 overflow-y-auto p-6 md:p-8 space-y-8 no-scrollbar bg-[#F8FAFC]">
        {history.length === 0 && (
          <div className="h-full flex flex-col items-center justify-center text-center px-10">
            <div className="w-16 h-16 bg-white border border-[#E2E8F0] rounded-[2.5rem] flex items-center justify-center mb-6 shadow-xl shadow-slate-200/50">
              <Sparkles className="w-7 h-7 text-[#CBD5E1]" />
            </div>
            <p className="text-xs font-bold uppercase tracking-[0.3em] text-[#94A3B8] leading-loose">
              Synthesizer Idle.<br/>Define mechanical intent to begin.
            </p>
          </div>
        )}

        {history.map((msg, i) => (
          <div key={i} className={`flex gap-5 ${msg.role === 'user' ? 'flex-row-reverse' : ''} animate-in fade-in slide-in-from-bottom-3 duration-500`}>
            <div className={`shrink-0 w-10 h-10 rounded-2xl flex items-center justify-center border shadow-sm ${
              msg.role === 'user' ? 'bg-[#4F46E5] border-[#4338CA] text-white' : 'bg-white border-[#E2E8F0] text-[#4F46E5]'
            }`}>
              {msg.role === 'user' ? <User className="w-5 h-5" /> : <Bot className="w-5 h-5" />}
            </div>
            <div className="flex flex-col gap-4 max-w-[85%] md:max-w-[75%]">
              <div className={`p-5 rounded-3xl text-[13px] font-medium shadow-xl shadow-slate-200/40 relative ${
                msg.role === 'user' 
                  ? 'bg-[#4F46E5] text-white' 
                  : 'bg-white text-[#475569] border border-[#E2E8F0] border-l-[3px] border-l-[#C9A24D]'
              }`}>
                {msg.role === 'ai' && (
                  <div className="flex items-center justify-between mb-4 pb-3 border-b border-[#F1F5F9]">
                    <div className="flex items-center gap-2 opacity-60">
                      <Terminal className="w-3.5 h-3.5" />
                      <span className="text-[9px] font-bold uppercase tracking-widest">Architectural Plan</span>
                    </div>
                    {msg.isApplying && (
                      <div className="flex items-center gap-2 px-2 py-0.5 rounded-full bg-[#EEF2FF] border border-[#E0E7FF]">
                        <Zap className="w-2.5 h-2.5 text-[#4F46E5] animate-pulse" />
                        <span className="text-[8px] font-bold uppercase tracking-widest text-[#4F46E5]">Evolving...</span>
                      </div>
                    )}
                  </div>
                )}
                <div className="whitespace-pre-wrap">
                  {msg.role === 'ai' ? formatReport(msg.text) : msg.text}
                </div>
              </div>

              {msg.role === 'ai' && msg.suggestions && msg.suggestions.length > 0 && !isProcessing && (
                <div className="flex flex-wrap gap-3 animate-in fade-in slide-in-from-left-4 duration-700 delay-300">
                  {msg.suggestions.map((suggestion, sIdx) => (
                    <button
                      key={sIdx}
                      onClick={() => onSendMessage(suggestion)}
                      className="group flex items-center gap-2.5 px-4 py-2 bg-white border border-[#E2E8F0] rounded-full hover:border-[#4F46E5] hover:shadow-lg transition-all active:scale-95"
                    >
                      <Lightbulb className="w-3.5 h-3.5 text-[#C9A24D] group-hover:animate-pulse" />
                      <span className="text-[10px] font-bold uppercase tracking-widest text-[#64748B] group-hover:text-[#4F46E5]">{suggestion}</span>
                    </button>
                  ))}
                </div>
              )}
            </div>
          </div>
        ))}

        {isProcessing && (
          <div className="flex gap-5">
            <div className="shrink-0 w-10 h-10 rounded-2xl bg-white border border-[#F3E8C9] flex items-center justify-center shadow-md">
              <Loader2 className="w-5 h-5 text-[#C9A24D] animate-spin" />
            </div>
            <div className="flex-1 flex flex-col gap-3">
               <div className="bg-white border border-[#E2E8F0] p-5 rounded-3xl text-[10px] font-bold uppercase tracking-widest text-[#94A3B8] flex items-center gap-3 shadow-xl shadow-slate-200/40">
                 Deconstructing mechanical constraints...
               </div>
               <div className="flex items-center gap-2 px-5 text-[9px] text-[#C9A24D] font-bold uppercase tracking-[0.2em]">
                  <Cpu className="w-4 h-4 animate-pulse" />
                  <span>High-Budget Neural Reasoning Engaged</span>
               </div>
            </div>
          </div>
        )}
      </div>

      {/* Chat Input */}
      <form onSubmit={handleSubmit} className="p-6 md:p-8 bg-white border-t border-[#F1F5F9]">
        <div className="relative group">
          <input
            type="text"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            disabled={isProcessing}
            placeholder="Command the Architect..."
            className="w-full bg-[#F8FAFC] border border-[#E2E8F0] rounded-[1.5rem] py-5 px-7 pr-16 text-sm text-[#0F172A] font-medium focus:outline-none focus:border-[#4F46E5] focus:bg-white transition-all shadow-sm"
          />
          <button
            type="submit"
            disabled={isProcessing || !input.trim()}
            className="absolute right-3 top-1/2 -translate-y-1/2 p-4 rounded-2xl bg-[#4F46E5] text-white hover:bg-[#4338CA] disabled:opacity-30 transition-all shadow-lg shadow-indigo-100 active:scale-95"
          >
            <Send className="w-4.5 h-4.5" />
          </button>
        </div>
      </form>
    </div>
  );
};

import React, { useMemo, useRef, useState, useEffect } from 'react';
import { GameAsset } from '../types';
import { Power, Loader2, Save, Bug, BugOff, AlertTriangle, RefreshCcw, Home } from 'lucide-react';

interface GameRunnerProps {
  code: string;
  title: string;
  assets: GameAsset[];
  onExit: () => void;
}

export const GameRunner: React.FC<GameRunnerProps> = ({ code, title, assets, onExit }) => {
  const iframeRef = useRef<HTMLIFrameElement>(null);
  const [isMounting, setIsMounting] = useState(true);
  const [showSaveIndicator, setShowSaveIndicator] = useState(false);
  const [debugEnabled, setDebugEnabled] = useState(false);
  const [runtimeError, setRuntimeError] = useState<{ message: string; type: string } | null>(null);

  const persistenceKey = useMemo(() => `forge_studio_state_${btoa(title).substring(0, 16)}`, [title]);

  useEffect(() => {
    const timer = setTimeout(() => setIsMounting(false), 2000);
    return () => clearTimeout(timer);
  }, []);

  const toggleDebug = () => {
    const newState = !debugEnabled;
    setDebugEnabled(newState);
    if (iframeRef.current?.contentWindow) {
      iframeRef.current.contentWindow.postMessage({ type: 'FORGE_TOGGLE_DEBUG', payload: newState }, '*');
    }
  };

  useEffect(() => {
    const handleMessage = (event: MessageEvent) => {
      if (event.data) {
        if (event.data.type === 'FORGE_SAVE_STATE') {
          localStorage.setItem(persistenceKey, JSON.stringify(event.data.payload));
          setShowSaveIndicator(true);
          setTimeout(() => setShowSaveIndicator(false), 1500);
        }
        if (event.data.type === 'FORGE_RUNTIME_READY') {
          if (iframeRef.current?.contentWindow) {
            iframeRef.current.contentWindow.postMessage({ type: 'FORGE_TOGGLE_DEBUG', payload: debugEnabled }, '*');
          }
        }
        if (event.data.type === 'FORGE_RUNTIME_ERROR') {
          setRuntimeError(event.data.payload);
        }
      }
    };
    window.addEventListener('message', handleMessage);
    return () => window.removeEventListener('message', handleMessage);
  }, [persistenceKey, debugEnabled]);

  const combinedSrcDoc = useMemo(() => {
    const assetMap = assets.reduce((acc, asset) => { acc[asset.name] = asset.content; return acc; }, {} as Record<string, string>);
    const savedStateStr = localStorage.getItem(persistenceKey);
    const savedState = savedStateStr ? JSON.parse(savedStateStr) : null;

    const bootstrapScript = `
      <script>
        (function() {
          window.onerror = (message) => { window.parent.postMessage({ type: 'FORGE_RUNTIME_ERROR', payload: { message: message, type: 'Kernel Collision' } }, '*'); return true; };
          const rawAssets = ${JSON.stringify(assetMap)};
          const blobUrls = {};
          let lastTime = performance.now();
          window.getDeltaTime = () => {
            const now = performance.now();
            let dt = (now - lastTime) / 1000;
            lastTime = now;
            return dt > 0.1 ? 0.1 : dt;
          };
          window.PHYSICS_MATERIALS = { 'Level Geometry': { friction: 0.9, restitution: 0.1 }, 'Prop': { friction: 0.5, restitution: 0.6 }, 'Hero': { friction: 0.8, restitution: 0.0 } };
          window.PERSISTED_STATE = ${JSON.stringify(savedState)};
          window.DEBUG_PHYSICS = false;
          window.saveState = (data) => window.parent.postMessage({ type: 'FORGE_SAVE_STATE', payload: data }, '*');
          window.addEventListener('message', (e) => { if (e.data.type === 'FORGE_TOGGLE_DEBUG') window.DEBUG_PHYSICS = e.data.payload; });
          window.parent.postMessage({ type: 'FORGE_RUNTIME_READY' }, '*');
          function b64ToBlob(b64, mime) {
            const split = b64.split(',');
            const bytes = atob(split[1] || split[0]);
            const ab = new ArrayBuffer(bytes.length);
            const ia = new Uint8Array(ab);
            for (let i = 0; i < bytes.length; i++) ia[i] = bytes.charCodeAt(i);
            return new Blob([ab], { type: mime });
          }
          window.getAssetUrl = (name) => {
            if (blobUrls[name]) return blobUrls[name];
            const data = rawAssets[name];
            if (!data) return "";
            const mime = data.includes('data:') ? data.split(':')[1].split(';')[0] : 'application/octet-stream';
            return blobUrls[name] = URL.createObjectURL(b64ToBlob(data, mime));
          };
        })();
      </script>
      <style>body { margin: 0; background: #0F172A; overflow: hidden; width: 100vw; height: 100vh; } canvas { display: block; width: 100%; height: 100%; }</style>
    `;
    return code.includes('<head>') ? code.replace('<head>', `<head>${bootstrapScript}`) : bootstrapScript + code;
  }, [code, assets, persistenceKey]);

  return (
    <div className="fixed inset-0 w-full h-full bg-[#0F172A] flex flex-col z-[1000] overflow-hidden">

      {/* Gallery Loading Screen */}
      {isMounting && !runtimeError && (
        <div className="absolute inset-0 z-[1100] bg-[#0F172A] flex flex-col items-center justify-center transition-opacity duration-1000">
          <div className="relative mb-10">
            <Loader2 className="w-12 h-12 text-[#4F46E5] animate-spin" />
            <div className="absolute inset-0 bg-[#4F46E5]/10 blur-2xl rounded-full animate-pulse" />
          </div>
          <h2 className="text-[12px] font-bold text-white uppercase tracking-[0.8em] mb-3">Initializing Substrate</h2>
          <p className="text-[10px] text-[#475569] font-medium uppercase tracking-[0.2em]">{title}</p>
        </div>
      )}

      {/* Error Overlay */}
      {runtimeError && (
        <div className="absolute inset-0 z-[1200] bg-[#0F172A] flex flex-col items-center justify-center p-10 animate-in fade-in duration-500">
          <div className="w-24 h-24 bg-red-500/10 border border-red-500/20 rounded-[2.5rem] flex items-center justify-center mb-12 shadow-2xl shadow-red-900/20">
            <AlertTriangle className="w-10 h-10 text-red-500" />
          </div>
          <div className="text-center max-w-xl mx-auto mb-16">
            <h2 className="text-[12px] font-bold text-red-500 uppercase tracking-[0.6em] mb-6">Simulation Collapse</h2>
            <div className="p-6 rounded-3xl bg-white/5 border border-white/10 font-mono text-left">
              <span className="text-[10px] font-bold text-red-500/60 uppercase tracking-widest block mb-3">{runtimeError.type}</span>
              <p className="text-xs text-zinc-400 italic leading-relaxed">"{runtimeError.message}"</p>
            </div>
          </div>
          <div className="flex gap-6">
            <button onClick={() => window.location.reload()} className="flex items-center gap-3 px-8 py-4 rounded-2xl bg-white/5 border border-white/10 text-white hover:bg-white/10 transition-all font-bold text-[10px] uppercase tracking-widest"><RefreshCcw className="w-4 h-4" /> Restart</button>
            <button onClick={onExit} className="flex items-center gap-3 px-10 py-4 rounded-2xl bg-red-500 text-white hover:bg-red-400 transition-all font-bold text-[10px] uppercase tracking-widest shadow-2xl shadow-red-500/20"><Home className="w-4 h-4" /> Exit Studio</button>
          </div>
        </div>
      )}

      {/* Gallery Frame Controls */}
      {!runtimeError && (
        <div className="absolute bottom-10 left-10 right-10 z-[1060] flex items-center justify-between pointer-events-none">
          <div className={`flex items-center gap-4 bg-white/10 backdrop-blur-3xl border border-white/10 px-6 py-3 rounded-full transition-all duration-700 ${showSaveIndicator ? 'opacity-100 translate-y-0' : 'opacity-0 translate-y-6'}`}>
            <Save className="w-4 h-4 text-[#4F46E5]" />
            <span className="text-[10px] font-bold uppercase tracking-widest text-white/80">State Synchronized</span>
          </div>
          <div className="flex gap-4 pointer-events-auto">
            <button onClick={toggleDebug} className={`flex items-center gap-3 px-6 py-3 rounded-full border transition-all ${debugEnabled ? 'bg-[#4F46E5] border-[#4F46E5] text-white shadow-lg shadow-indigo-500/20' : 'bg-white/5 border-white/10 text-white/50 hover:border-white/20'}`}>
              <Bug className="w-4 h-4" />
              <span className="text-[10px] font-bold uppercase tracking-widest">{debugEnabled ? 'Debug Enabled' : 'Debug Disabled'}</span>
            </button>
          </div>
        </div>
      )}

      {!runtimeError && (
        <div className="absolute top-10 left-0 right-0 z-[1050] flex justify-center opacity-0 hover:opacity-100 transition-all duration-500">
          <button onClick={onExit} className="flex items-center gap-4 bg-[#FFFFFF] text-[#0F172A] border border-white px-8 py-4 rounded-3xl hover:shadow-[0_0_40px_rgba(255,255,255,0.2)] transition-all transform hover:scale-105 active:scale-95 pointer-events-auto font-bold text-[11px] uppercase tracking-[0.3em]">
            <Power className="w-5 h-5 text-[#4F46E5]" />
            <span>Terminate Simulation</span>
          </button>
        </div>
      )}

      <div className="flex-1 flex items-center justify-center p-12 bg-[#020617]">
        <div className="w-full h-full max-w-[1920px] max-h-[1080px] bg-black rounded-[2rem] overflow-hidden shadow-2xl shadow-black relative border border-white/5">
           <iframe ref={iframeRef} srcDoc={combinedSrcDoc} title="Forge Runtime" className={`w-full h-full border-none transition-opacity duration-1000 ${isMounting || runtimeError ? 'opacity-0' : 'opacity-100'}`} sandbox="allow-scripts allow-modals allow-pointer-lock" />
        </div>
      </div>
    </div>
  );
};

import { GoogleGenAI, Type } from "@google/genai";
import { GameAsset, ChatMessage } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const generateGame = async (
  prompt: string,
  assets: GameAsset[],
  history: ChatMessage[] = [],
  currentCode: string = ""
): Promise<{ code: string; title: string; explanation: string; suggestions: string[] }> => {

  const assetMetadata = assets.map(a => ({
    name: a.name,
    type: a.type,
    mimeType: a.mimeType,
    category: a.category,
    isOptimized: !!a.isOptimized,
    logicContext: a.type === 'dialogue' ? a.content : undefined
  }));

  const isRefinement = history.length > 0 && currentCode !== "";

  const systemInstruction = `
    You are the "Core Neural Architect" of ForgeAI Studio—a world-class expert in Three.js, Game Theory, and Real-time Physics.

    CORE OPERATING MANDATE:
    You do not just write code; you engineer interactive systems. Your goal is to synthesize a logically consistent, high-performance 3D game substrate. Use your internal thinking capacity to plan the entire game state, physics interactions, and asset mapping before generating any code.

    NEURAL REASONING PROTOCOLS:
    1. GENRE ARCHITECTING: First, identify the core genre from the user's prompt (e.g., Soulslike, Tactical Shooter, Precision Platformer, Physics Sandbox). Apply the mathematical conventions of that genre (e.g., specific damping curves, camera easing, input buffering, frame-data logic).
    2. PHYSICS KERNEL (VERLET):
       - Use Position-Based Dynamics (Verlet Integration) for stability.
       - Implement a fixed update loop with 8-16 sub-steps per frame to prevent collision tunneling.
       - Resolve collisions via projection: move objects out of penetrations and update previous positions based on 'window.PHYSICS_MATERIALS' (friction/restitution).
       - Differentiate between static colliders (Environment) and dynamic rigid bodies (Props/Characters).
    3. ECS & STATE ARCHITECTURE: Structure the generated code using a modular Entity-Component-System or a clean Finite State Machine (FSM). Separate "Rendering" from "Simulation Logic". Logic must be robust enough to handle missing assets gracefully with proxy primitives.
    4. ADVANCED INPUT & CONTROL LAYER:
       - Implement a unified InputManager for Keyboard, Mouse, and Touch.
       - Support frame-independent movement using 'window.getDeltaTime()'.
       - For characters, use raycasting for ground detection, slope-aligned movement, and predictive jumping physics.
    5. DEEP ASSET SYNERGY: 
       - Map models correctly using categories. Use window.getAssetUrl(name) to load assets.
       - If multiple animations (motion data) are provided, use THREE.AnimationMixer with sophisticated cross-fading for state transitions (e.g., Idle -> Run -> Jump).
       - Optimize draw calls using instanced rendering for repetitive 'Prop' assets.
    6. DEBUG & DIAGNOSTICS: 
       - Always respect 'window.DEBUG_PHYSICS'. Render bounding volumes (Box/Sphere), raycast paths, and collision normals when active.
       - Log critical state transitions to the console for internal tracing.
    7. PERSISTENCE ENGINE: Use 'window.PERSISTED_STATE' for loading and 'window.saveState(data)' for saving.

    MANDATORY EXPLANATION STRUCTURE:
    Your "explanation" field MUST follow this strict architectural report format:
    [GENRE & SYSTEMS]: Describe the chosen genre and the core mechanical loops (Input -> Action -> Feedback).
    [PHYSICS DERIVATION]: Detail the integration method, sub-stepping frequency, and collision resolution logic.
    [LOGIC MAPPING]: Explain how 'Logic Nodes' (dialogue/text assets) or prompt instructions govern state changes or AI behavior.
    [ASSET INTEGRATION]: How high-fidelity assets were bound to physics proxies and how animations are blended.

    PROACTIVE SUGGESTIONS (MANDATORY):
    Provide 2-3 advanced mechanical evolutions based on the current state (e.g., "Implement dynamic weight-based momentum?", "Add a hierarchical AI behavior tree?").

    RESPONSE FORMAT:
    Return a JSON object with: code (Full HTML/JS), title (Creative name), explanation (Technical report), suggestions (Array of ideas).

    ENGINE CONSTRAINTS:
    - Three.js (0.160.0), OrbitControls, and GLTFLoader via CDN.
    - Always implement a 'dispose()' or 'cleanup()' method.
  `;

  const userPrompt = isRefinement 
    ? `ARCHITECTURAL REFINEMENT PROTOCOL:
       Input Instructions: ${prompt}
       Current Substrate Status: ${currentCode}
       Available Buffers: ${JSON.stringify(assetMetadata)}

       MANDATE: Evolve the simulation logic. Use your full reasoning capacity to deepen the mechanical interplay, refine the physics kernel, and ensuring strict genre-specific behavioral consistency. Focus on performance and logical stability.`
    : `SYSTEM INITIALIZATION SEED:
       Project Description: ${prompt}
       Available Buffers: ${JSON.stringify(assetMetadata)}

       MANDATE: Synthesize a full-scale 3D simulation. Plan the physics architecture (Verlet/Sub-stepping), the ECS state machine, and the input mapping before outputting the code. Deeply analyze how the provided assets should interact within the chosen genre.`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: userPrompt,
    config: {
      systemInstruction,
      thinkingConfig: { thinkingBudget: 32768 },
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          code: { type: Type.STRING },
          title: { type: Type.STRING },
          explanation: { type: Type.STRING },
          suggestions: {
            type: Type.ARRAY,
            items: { type: Type.STRING }
          }
        },
        required: ['code', 'title', 'explanation', 'suggestions']
      }
    }
  });

  try {
    const result = JSON.parse(response.text || '{}');
    return {
      code: result.code || currentCode,
      title: result.title || 'Architectural Synthesis',
      explanation: result.explanation || 'Neural synthesis complete.',
      suggestions: result.suggestions || []
    };
  } catch (e) {
    console.error("Neural Collision:", e);
    throw new Error("Logic synthesis failure. The engine requires a structured architectural report.");
  }
};

import React, { useState, useCallback, useEffect, useRef, useMemo } from 'react';
import { AssetUploader } from './components/AssetUploader';
