import React, { useMemo, useRef, useState, useEffect } from 'react';
import { GameAsset } from '../types';
import { Power, Loader2, Save, Bug, BugOff, AlertTriangle, RefreshCcw, Home } from 'lucide-react';

interface GameRunnerProps {
  code: string;
  title: string;
  assets: GameAsset[];
  onExit: () => void;
}

export const GameRunner: React.FC<GameRunnerProps> = ({ code, title, assets, onExit }) => {
  const iframeRef = useRef<HTMLIFrameElement>(null);
  const [isMounting, setIsMounting] = useState(true);
  const [showSaveIndicator, setShowSaveIndicator] = useState(false);
  const [debugEnabled, setDebugEnabled] = useState(false);
  const [runtimeError, setRuntimeError] = useState<{ message: string; type: string } | null>(null);

  const persistenceKey = useMemo(() => `forge_studio_state_${btoa(title).substring(0, 16)}`, [title]);

  useEffect(() => {
    const timer = setTimeout(() => setIsMounting(false), 2000);
    return () => clearTimeout(timer);
  }, []);

  const toggleDebug = () => {
    const newState = !debugEnabled;
    setDebugEnabled(newState);
    if (iframeRef.current?.contentWindow) {
      iframeRef.current.contentWindow.postMessage({ type: 'FORGE_TOGGLE_DEBUG', payload: newState }, '*');
    }
  };

  useEffect(() => {
    const handleMessage = (event: MessageEvent) => {
      if (event.data) {
        if (event.data.type === 'FORGE_SAVE_STATE') {
          localStorage.setItem(persistenceKey, JSON.stringify(event.data.payload));
          setShowSaveIndicator(true);
          setTimeout(() => setShowSaveIndicator(false), 1500);
        }
        if (event.data.type === 'FORGE_RUNTIME_READY') {
          if (iframeRef.current?.contentWindow) {
            iframeRef.current.contentWindow.postMessage({ type: 'FORGE_TOGGLE_DEBUG', payload: debugEnabled }, '*');
          }
        }
        if (event.data.type === 'FORGE_RUNTIME_ERROR') {
          setRuntimeError(event.data.payload);
        }
      }
    };
    window.addEventListener('message', handleMessage);
    return () => window.removeEventListener('message', handleMessage);
  }, [persistenceKey, debugEnabled]);

  const combinedSrcDoc = useMemo(() => {
    const assetMap = assets.reduce((acc, asset) => { acc[asset.name] = asset.content; return acc; }, {} as Record<string, string>);
    const savedStateStr = localStorage.getItem(persistenceKey);
    const savedState = savedStateStr ? JSON.parse(savedStateStr) : null;

    const bootstrapScript = `
      <script>
        (function() {
          window.onerror = (message) => { window.parent.postMessage({ type: 'FORGE_RUNTIME_ERROR', payload: { message: message, type: 'Kernel Collision' } }, '*'); return true; };
          const rawAssets = ${JSON.stringify(assetMap)};
          const assetCache = new Map();
          let lastTime = performance.now();
          window.getDeltaTime = () => {
            const now = performance.now();
            let dt = (now - lastTime) / 1000;
            lastTime = now;
            return dt > 0.1 ? 0.1 : dt;
          };
          window.PHYSICS_MATERIALS = { 'Level Geometry': { friction: 0.9, restitution: 0.1 }, 'Prop': { friction: 0.5, restitution: 0.6 }, 'Hero': { friction: 0.8, restitution: 0.0 } };
          window.PERSISTED_STATE = ${JSON.stringify(savedState)};
          window.DEBUG_PHYSICS = false;
          window.saveState = (data) => window.parent.postMessage({ type: 'FORGE_SAVE_STATE', payload: data }, '*');
          window.addEventListener('message', (e) => { if (e.data.type === 'FORGE_TOGGLE_DEBUG') window.DEBUG_PHYSICS = e.data.payload; });
          window.parent.postMessage({ type: 'FORGE_RUNTIME_READY' }, '*');

          function b64ToBlob(b64, mime) {
            try {
              const split = b64.split(',');
              const bytes = atob(split[1] || split[0]);
              const ab = new ArrayBuffer(bytes.length);
              const ia = new Uint8Array(ab);
              for (let i = 0; i < bytes.length; i++) ia[i] = bytes.charCodeAt(i);
              return new Blob([ab], { type: mime });
            } catch (e) {
              console.error("Blob Extraction Failure:", e);
              return null;
            }
          }

          window.getAssetUrl = (name) => {
            if (assetCache.has(name)) return assetCache.get(name);
            const data = rawAssets[name];
            if (!data) return "";

            try {
              const mime = data.includes('data:') ? data.split(':')[1].split(';')[0] : 'application/octet-stream';
              const blob = b64ToBlob(data, mime);
              if (!blob) return "";
              const url = URL.createObjectURL(blob);
              assetCache.set(name, url);
              return url;
            } catch (e) {
              console.error("Asset Synthesis Error:", e);
              return "";
            }
          };

          // Explicit Memory Cleanup
          window.addEventListener('pagehide', () => {
            assetCache.forEach(url => URL.revokeObjectURL(url));
            assetCache.clear();
          });
        })();
      </script>
      <style>body { margin: 0; background: #0F172A; overflow: hidden; width: 100vw; height: 100vh; } canvas { display: block; width: 100%; height: 100%; }</style>
    `;
    return code.includes('<head>') ? code.replace('<head>', `<head>${bootstrapScript}`) : bootstrapScript + code;
  }, [code, assets, persistenceKey]);

  return (
    <div className="fixed inset-0 w-full h-full bg-[#0F172A] flex flex-col z-[1000] overflow-hidden">

      {/* Gallery Loading Screen */}
      {isMounting && !runtimeError && (
        <div className="absolute inset-0 z-[1100] bg-[#0F172A] flex flex-col items-center justify-center transition-opacity duration-1000">
          <div className="relative mb-10">
            <div className="w-16 h-16 border-4 border-[#4F46E5]/20 border-t-[#4F46E5] rounded-full animate-spin" />
            <div className="absolute inset-0 bg-[#4F46E5]/10 blur-2xl rounded-full animate-pulse" />
          </div>
          <h2 className="text-[12px] font-bold text-white uppercase tracking-[0.8em] mb-3">Initializing Substrate</h2>
          <p className="text-[10px] text-[#475569] font-medium uppercase tracking-[0.2em]">{title}</p>
        </div>
      )}

      {/* Error Overlay */}
      {runtimeError && (
        <div className="absolute inset-0 z-[1200] bg-[#0F172A] flex flex-col items-center justify-center p-10 animate-in fade-in duration-500">
          <div className="w-24 h-24 bg-red-500/10 border border-red-500/20 rounded-[2.5rem] flex items-center justify-center mb-12 shadow-2xl shadow-red-900/20">
            <AlertTriangle className="w-10 h-10 text-red-500" />
          </div>
          <div className="text-center max-w-xl mx-auto mb-16">
            <h2 className="text-[12px] font-bold text-red-500 uppercase tracking-[0.6em] mb-6">Simulation Collapse</h2>
            <div className="p-6 rounded-3xl bg-white/5 border border-white/10 font-mono text-left">
              <span className="text-[10px] font-bold text-red-500/60 uppercase tracking-widest block mb-3">{runtimeError.type}</span>
              <p className="text-xs text-zinc-400 italic leading-relaxed">"{runtimeError.message}"</p>
            </div>
          </div>
          <div className="flex gap-6">
            <button onClick={() => window.location.reload()} className="flex items-center gap-3 px-8 py-4 rounded-2xl bg-white/5 border border-white/10 text-white hover:bg-white/10 transition-all font-bold text-[10px] uppercase tracking-widest"><RefreshCcw className="w-4 h-4" /> Restart</button>
            <button onClick={onExit} className="flex items-center gap-3 px-10 py-4 rounded-2xl bg-red-500 text-white hover:bg-red-400 transition-all font-bold text-[10px] uppercase tracking-widest shadow-2xl shadow-red-500/20"><Home className="w-4 h-4" /> Exit Studio</button>
          </div>
        </div>
      )}

      {/* Gallery Frame Controls */}
      {!runtimeError && (
        <div className="absolute bottom-10 left-10 right-10 z-[1060] flex items-center justify-between pointer-events-none">
          <div className={`flex items-center gap-4 bg-white/10 backdrop-blur-3xl border border-white/10 px-6 py-3 rounded-full transition-all duration-700 ${showSaveIndicator ? 'opacity-100 translate-y-0' : 'opacity-0 translate-y-6'}`}>
            <Save className="w-4 h-4 text-[#4F46E5]" />
            <span className="text-[10px] font-bold uppercase tracking-widest text-white/80">State Synchronized</span>
          </div>
          <div className="flex gap-4 pointer-events-auto">
            <button onClick={toggleDebug} className={`flex items-center gap-3 px-6 py-3 rounded-full border transition-all ${debugEnabled ? 'bg-[#4F46E5] border-[#4F46E5] text-white shadow-lg shadow-indigo-500/20' : 'bg-white/5 border-white/10 text-white/50 hover:border-white/20'}`}>
              <Bug className="w-4 h-4" />
              <span className="text-[10px] font-bold uppercase tracking-widest">{debugEnabled ? 'Debug Enabled' : 'Debug Disabled'}</span>
            </button>
          </div>
        </div>
      )}

      {!runtimeError && (
        <div className="absolute top-10 left-0 right-0 z-[1050] flex justify-center opacity-0 hover:opacity-100 transition-all duration-500">
          <button onClick={onExit} className="flex items-center gap-4 bg-[#FFFFFF] text-[#0F172A] border border-white px-8 py-4 rounded-3xl hover:shadow-[0_0_40px_rgba(255,255,255,0.2)] transition-all transform hover:scale-105 active:scale-95 pointer-events-auto font-bold text-[11px] uppercase tracking-[0.3em]">
            <Power className="w-5 h-5 text-[#4F46E5]" />
            <span>Terminate Simulation</span>
          </button>
        </div>
      )}

      <div className="flex-1 flex items-center justify-center p-12 bg-[#020617]">
        <div className="w-full h-full max-w-[1920px] max-h-[1080px] bg-black rounded-[2rem] overflow-hidden shadow-2xl shadow-black relative border border-white/5">
           <iframe ref={iframeRef} srcDoc={combinedSrcDoc} title="Forge Runtime" className={`w-full h-full border-none transition-opacity duration-1000 ${isMounting || runtimeError ? 'opacity-0' : 'opacity-100'}`} sandbox="allow-scripts allow-modals allow-pointer-lock" />
        </div>
      </div>
    </div>
  );
};

export type AssetType = 
  | 'character1' 
  | 'motion1' 
  | 'character2' 
  | 'motion2' 
  | 'environment' 
  | 'music' 
  | 'dialogue';

export type AIModelMode = 'fast' | 'thinking';

export interface GameAsset {
  id: string;
  name: string;
  type: AssetType;
  content: string; // Base64 for files, text for dialogue
  mimeType: string;
  isOptimized?: boolean;
  category?: string;
}

export interface ChatMessage {
  role: 'user' | 'ai';
  text: string;
  isApplying?: boolean;
  suggestions?: string[];
}

export interface GenerationStatus {
  step: 'idle' | 'analyzing' | 'coding' | 'compiling' | 'ready' | 'error';
  message: string;
}

export interface GeneratedGame {
  code: string; // HTML/JS combo
  title: string;
}

import { GoogleGenAI, Type } from "@google/genai";
import { GameAsset, ChatMessage, AIModelMode } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const generateGame = async (
  prompt: string,
  assets: GameAsset[],
  history: ChatMessage[] = [],
  currentCode: string = "",
  mode: AIModelMode = 'thinking'
): Promise<{ code: string; title: string; explanation: string; suggestions: string[] }> => {

  const assetMetadata = assets.map(a => ({
    name: a.name,
    type: a.type,
    mimeType: a.mimeType,
    category: a.category,
    isOptimized: !!a.isOptimized,
    logicContext: a.type === 'dialogue' ? a.content : undefined
  }));

  const isRefinement = history.length > 0 && currentCode !== "";

  const systemInstruction = `
    You are the "Core Neural Architect" of ForgeAI Studio—a world-class expert in Three.js, Game Theory, and Real-time Physics.

    CORE OPERATING MANDATE:
    You do not just write code; you engineer interactive systems. Your goal is to synthesize a logically consistent, high-performance 3D game substrate. Use your internal thinking capacity to plan the entire game state, physics interactions, and asset mapping before generating any code.

    NEURAL REASONING PROTOCOLS:
    1. GENRE ARCHITECTING: Identify the core genre (e.g., Soulslike, FPS, Platformer). Apply genre-specific conventions: input buffering, camera easing, and frame-data logic.
    2. PHYSICS KERNEL (VERLET):
       - Use Position-Based Dynamics (Verlet Integration) for stability.
       - Implement a fixed update loop with 8-16 sub-steps per frame.
       - Resolve collisions via projection using 'window.PHYSICS_MATERIALS'.
    3. ECS & STATE ARCHITECTURE: Modular code with Entity-Component-System or FSM. Separate rendering from simulation logic.
    4. ADVANCED INPUT LAYER: Unified Keyboard/Mouse/Touch support. Frame-independent movement via 'window.getDeltaTime()'.
    5. DEEP ASSET SYNERGY: 
       - Load assets via 'window.getAssetUrl(name)'.
       - Handle animations with 'THREE.AnimationMixer' and sophisticated blending.
    6. DEBUG & PERSISTENCE: Support 'window.DEBUG_PHYSICS' and 'window.PERSISTED_STATE'/'window.saveState(data)'.

    MANDATORY EXPLANATION STRUCTURE:
    Your "explanation" field MUST follow this strict format:
    [GENRE ANALYSIS]: Detailed breakdown of the chosen genre and its inherent mechanical requirements.
    [MECHANICAL DERIVATION]: Technical explanation of the physics kernel, integration method, and collision logic.
    [LOGIC NODE BINDING]: How provided instructions and text assets govern the simulation's state machine.
    [ASSET MAPPING]: Description of how high-fidelity buffers were integrated and animated.

    PROACTIVE SUGGESTIONS (MANDATORY):
    Provide 2-3 advanced mechanical evolutions.

    RESPONSE FORMAT:
    Return a JSON object with: code (Full HTML/JS), title, explanation, suggestions.

    ENGINE CONSTRAINTS:
    - Three.js (0.160.0), OrbitControls, and GLTFLoader via CDN.
    - Always implement a 'dispose()' or 'cleanup()' method.
  `;

  const userPrompt = isRefinement 
    ? `ARCHITECTURAL REFINEMENT PROTOCOL:
       Input Instructions: ${prompt}
       Current Substrate Status: ${currentCode}
       Available Buffers: ${JSON.stringify(assetMetadata)}

       MANDATE: Evolve the simulation logic. Refine the physics kernel and deepening the mechanical interplay while maintaining strict genre consistency.`
    : `SYSTEM INITIALIZATION SEED:
       Project Description: ${prompt}
       Available Buffers: ${JSON.stringify(assetMetadata)}

       MANDATE: Synthesize a full-scale 3D simulation. Architect the physics and state machine before generating code.`;

  const modelName = mode === 'thinking' ? 'gemini-3-pro-preview' : 'gemini-2.5-flash-lite-latest';
  const config: any = {
    systemInstruction,
    responseMimeType: "application/json",
    responseSchema: {
      type: Type.OBJECT,
      properties: {
        code: { type: Type.STRING },
        title: { type: Type.STRING },
        explanation: { type: Type.STRING },
        suggestions: {
          type: Type.ARRAY,
          items: { type: Type.STRING }
        }
      },
      required: ['code', 'title', 'explanation', 'suggestions']
    }
  };

  if (mode === 'thinking') {
    config.thinkingConfig = { thinkingBudget: 32768 };
  }

  const response = await ai.models.generateContent({
    model: modelName,
    contents: userPrompt,
    config,
  });

  try {
    const result = JSON.parse(response.text || '{}');
    return {
      code: result.code || currentCode,
      title: result.title || 'Architectural Synthesis',
      explanation: result.explanation || 'Neural synthesis complete.',
      suggestions: result.suggestions || []
    };
  } catch (e) {
    console.error("Neural Collision:", e);
    throw new Error("Logic synthesis failure. The engine requires a structured architectural report.");
  }
};

import React, { useState, useCallback, useEffect, useRef, useMemo } from 'react';
import { AssetUploader } from './components/AssetUploader';
import { GameRunner } from './components/GameRunner';
import { AIChat } from './components/AIChat';
import { generateGame } from './services/gemini';
import { GameAsset, GenerationStatus, GeneratedGame, ChatMessage, AIModelMode } from './types';
import { Box, Activity, Layers, Monitor, Terminal, Sparkles, Play, BoxSelect, Menu, X, MessageSquareCode, BrainCircuit, RefreshCw, Cpu, Zap, Maximize2, Bolt } from 'lucide-react';

type ViewMode = 'editor' | 'preview';

const App: React.FC = () => {
  const [viewMode, setViewMode] = useState<ViewMode>('editor');
  const [assets, setAssets] = useState<GameAsset[]>([]);
  const [status, setStatus] = useState<GenerationStatus>({ step: 'idle', message: '' });
  const [game, setGame] = useState<GeneratedGame | null>(null);
  const [chatHistory, setChatHistory] = useState<ChatMessage[]>([]);
  const [aiMode, setAiMode] = useState<AIModelMode>('thinking');
  const [logs, setLogs] = useState<string[]>([
    'Initializing ForgeAI Studio core...', 
    'Neural substrate calibration complete.',
    'Physics Subsystem: High-precision Verlet Active.'
  ]);
  const [isLeftSidebarOpen, setIsLeftSidebarOpen] = useState(false);
  const [isRightSidebarOpen, setIsRightSidebarOpen] = useState(false);
  const [activeMobileView, setActiveMobileView] = useState<'staging' | 'chat' | 'logs'>('staging');
  const [isLiveSyncing, setIsLiveSyncing] = useState(false);

  const prevAssetsCount = useRef(0);
  const autoSyncTimer = useRef<ReturnType<typeof setTimeout> | null>(null);
  const iframeRef = useRef<HTMLIFrameElement>(null);

  const addLog = (msg: string) => {
    setLogs(prev => [...prev.slice(-15), msg]);
  };

  const processGeneration = useCallback(async (instruction: string, isAutoSync: boolean = false) => {
    if (!isAutoSync) {
      setStatus({ step: 'analyzing', message: 'Architecting Logical Model...' });
      addLog(`Analyzing mechanical intent: "${instruction.slice(0, 30)}..."`);
      setChatHistory(prev => [...prev, { role: 'user', text: instruction }]);
    } else {
      setIsLiveSyncing(true);
      addLog(`Auto-Sync: Harmonizing buffers...`);
    }

    try {
      const result = await generateGame(
        instruction, 
        assets, 
        chatHistory, 
        game?.code || "",
        aiMode
      );

      if (!isAutoSync) {
        setStatus({ step: 'coding', message: 'Synthesizing 3D Substrate...' });
        const aiMessage: ChatMessage = { 
          role: 'ai', 
          text: result.explanation,
          suggestions: result.suggestions,
          isApplying: true 
        };
        setChatHistory(prev => [...prev, aiMessage]);

        await new Promise(resolve => setTimeout(resolve, 2000));

        setChatHistory(prev => prev.map((m, idx) => 
          idx === prev.length - 1 ? { ...m, isApplying: false } : m
        ));
      }

      setGame({ code: result.code, title: result.title });
      setStatus({ step: 'ready', message: 'Architecture Verified.' });
      setIsLiveSyncing(false);

      addLog(`Substrate ${isAutoSync ? 'synchronized' : 'generated'}: "${result.title}"`);

    } catch (error: any) {
      console.error(error);
      setStatus({ step: 'error', message: 'Synthesis Failure.' });
      setIsLiveSyncing(false);
      if (!isAutoSync) {
        setChatHistory(prev => [...prev, { role: 'ai', text: 'Structural paradox detected. The architect requires refined mechanical parameters.' }]);
      }
      addLog(`Error: Collision in logic synthesis.`);
    }
  }, [assets, chatHistory, game, aiMode]);

  useEffect(() => {
    if (game && assets.length !== prevAssetsCount.current) {
      if (autoSyncTimer.current) clearTimeout(autoSyncTimer.current);
      autoSyncTimer.current = setTimeout(() => {
        const lastUserPrompt = chatHistory.filter(m => m.role === 'user').pop()?.text || "Synchronize simulation with updated buffers.";
        processGeneration(`SYNC: ${lastUserPrompt}`, true);
      }, 5000); 
    }
    prevAssetsCount.current = assets.length;
  }, [assets, game, chatHistory, processGeneration]);

  const enterPreview = () => {
    if (game) setViewMode('preview');
  };

  const exitPreview = () => setViewMode('editor');

  const integratedSrcDoc = useMemo(() => {
    if (!game) return "";
    const assetMap = assets.reduce((acc, asset) => { acc[asset.name] = asset.content; return acc; }, {} as Record<string, string>);
    const persistenceKey = `forge_studio_state_${btoa(game.title).substring(0, 16)}`;
    const savedStateStr = localStorage.getItem(persistenceKey);
    const savedState = savedStateStr ? JSON.parse(savedStateStr) : null;

    const bootstrapScript = `
      <script>
        (function() {
          window.onerror = (message) => { window.parent.postMessage({ type: 'FORGE_RUNTIME_ERROR', payload: { message: message, type: 'Integrated Crash' } }, '*'); return true; };
          const rawAssets = ${JSON.stringify(assetMap)};
          const assetCache = new Map();
          let lastTime = performance.now();
          window.getDeltaTime = () => {
            const now = performance.now();
            let dt = (now - lastTime) / 1000;
            lastTime = now;
            return dt > 0.1 ? 0.1 : dt;
          };
          window.PHYSICS_MATERIALS = { 'Level Geometry': { friction: 0.9, restitution: 0.1 }, 'Prop': { friction: 0.5, restitution: 0.6 }, 'Hero': { friction: 0.8, restitution: 0.0 } };
          window.PERSISTED_STATE = ${JSON.stringify(savedState)};
          window.DEBUG_PHYSICS = false;
          window.saveState = (data) => window.parent.postMessage({ type: 'FORGE_SAVE_STATE', payload: data }, '*');

          function b64ToBlob(b64, mime) {
            try {
              const split = b64.split(',');
              const bytes = atob(split[1] || split[0]);
              const ab = new ArrayBuffer(bytes.length);
              const ia = new Uint8Array(ab);
              for (let i = 0; i < bytes.length; i++) ia[i] = bytes.charCodeAt(i);
              return new Blob([ab], { type: mime });
            } catch (e) {
              console.error("Blob Synthesis Failure:", e);
              return null;
            }
          }

          window.getAssetUrl = (name) => {
            if (assetCache.has(name)) return assetCache.get(name);
            const data = rawAssets[name];
            if (!data) return "";

            try {
              const mime = data.includes('data:') ? data.split(':')[1].split(';')[0] : 'application/octet-stream';
              const blob = b64ToBlob(data, mime);
              if (!blob) return "";
              const url = URL.createObjectURL(blob);
              assetCache.set(name, url);
              return url;
            } catch (e) {
              console.error("Asset Loader Paradox:", e);
              return "";
            }
          };

          // Explicit Memory Management
          window.addEventListener('pagehide', () => {
            assetCache.forEach(url => URL.revokeObjectURL(url));
            assetCache.clear();
          });
        })();
      </script>
      <style>body { margin: 0; background: #0F172A; overflow: hidden; width: 100%; height: 100%; } canvas { display: block; width: 100%; height: 100%; }</style>
    `;
    return game.code.includes('<head>') ? game.code.replace('<head>', `<head>${bootstrapScript}`) : bootstrapScript + game.code;
  }, [game, assets]);

  if (viewMode === 'preview' && game) {
    return (
      <div className="fixed inset-0 z-[500] bg-[#0F172A]">
        <GameRunner code={game.code} title={game.title} assets={assets} onExit={exitPreview} />
      </div>
    );
  }

  return (
