          </button>

          <div className="flex items-center gap-3">
            <div className="bg-[#4F46E5] p-1.5 rounded-lg shadow-md shadow-indigo-100">
              <Box className="w-4 h-4 text-white" />
            </div>
            <div className="flex flex-col">
              <h1 className="text-sm font-bold tracking-tight text-[#0F172A]">
                STUDIO <span className="text-[#4F46E5]">FORGE</span>
              </h1>
              <span className="text-[8px] text-[#94A3B8] font-bold uppercase tracking-[0.2em] -mt-0.5">Neural Engine v5.1</span>
            </div>
          </div>

          <div className="h-6 w-px bg-[#E2E8F0] hidden sm:block" />

          <div className="hidden lg:flex items-center gap-5">
            {/* Mode Switcher */}
