                </div>
              </div>

              {msg.role === 'ai' && msg.suggestions && msg.suggestions.length > 0 && !isProcessing && (
                <div className="flex flex-wrap gap-3 animate-in fade-in slide-in-from-left-4 duration-700 delay-300">
                  {msg.suggestions.map((suggestion, sIdx) => (
                    <button
                      key={sIdx}
                      onClick={() => onSendMessage(suggestion)}
                      className="group flex items-center gap-2.5 px-4 py-2 bg-white border border-[#E2E8F0] rounded-full hover:border-[#4F46E5] hover:shadow-lg transition-all active:scale-95"
                    >
                      <Lightbulb className="w-3.5 h-3.5 text-[#C9A24D] group-hover:animate-pulse" />
                      <span className="text-[10px] font-bold uppercase tracking-widest text-[#64748B] group-hover:text-[#4F46E5]">{suggestion}</span>
                    </button>
                  ))}
                </div>
              )}
            </div>
          </div>
        ))}

        {isProcessing && (
          <div className="flex gap-5">
            <div className="shrink-0 w-10 h-10 rounded-2xl bg-white border border-[#F3E8C9] flex items-center justify-center shadow-md">
              <Loader2 className="w-5 h-5 text-[#C9A24D] animate-spin" />
            </div>
            <div className="flex-1 flex flex-col gap-3">
               <div className="bg-white border border-[#E2E8F0] p-5 rounded-3xl text-[10px] font-bold uppercase tracking-widest text-[#94A3B8] flex items-center gap-3 shadow-xl shadow-slate-200/40">
                 {aiMode === 'thinking' ? 'Deconstructing complex mechanical constraints...' : 'Synchronizing logical buffers...'}
               </div>
               <div className="flex items-center gap-2 px-5 text-[9px] text-[#C9A24D] font-bold uppercase tracking-[0.2em]">
                  {aiMode === 'thinking' ? (
                    <>
                      <Cpu className="w-4 h-4 animate-pulse" />
                      <span>High-Budget Neural Reasoning Engaged</span>
                    </>
                  ) : (
                    <>
                      <Bolt className="w-4 h-4 animate-pulse text-[#4F46E5]" />
                      <span className="text-[#4F46E5]">Low-Latency Stream Active</span>
                    </>
                  )}
               </div>
            </div>
          </div>
        )}
      </div>

      {/* Chat Input */}
      <form onSubmit={handleSubmit} className="p-6 md:p-8 bg-white border-t border-[#F1F5F9]">
        <div className="relative group">
          <input
            type="text"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            disabled={isProcessing}
            placeholder={aiMode === 'thinking' ? "Command the Architect (Thinking Mode)..." : "Quick command (Fast Mode)..."}
            className="w-full bg-[#F8FAFC] border border-[#E2E8F0] rounded-[1.5rem] py-5 px-7 pr-16 text-sm text-[#0F172A] font-medium focus:outline-none focus:border-[#4F46E5] focus:bg-white transition-all shadow-sm"
          />
          <button
            type="submit"
            disabled={isProcessing || !input.trim()}
            className={`absolute right-3 top-1/2 -translate-y-1/2 p-4 rounded-2xl text-white disabled:opacity-30 transition-all shadow-lg active:scale-95 ${aiMode === 'thinking' ? 'bg-[#C9A24D] shadow-[#C9A24D]/20 hover:bg-[#B18E3F]' : 'bg-[#4F46E5] shadow-indigo-100 hover:bg-[#4338CA]'}`}
          >
            <Send className="w-4.5 h-4.5" />
          </button>
        </div>
        <div className="mt-3 flex justify-center gap-4 md:hidden">
            <button onClick={() => onModeChange('fast')} className={`px-4 py-1 rounded-full text-[10px] font-bold uppercase tracking-widest ${aiMode === 'fast' ? 'bg-[#4F46E5] text-white' : 'text-[#94A3B8] border border-[#E2E8F0]'}`}>Fast</button>
            <button onClick={() => onModeChange('thinking')} className={`px-4 py-1 rounded-full text-[10px] font-bold uppercase tracking-widest ${aiMode === 'thinking' ? 'bg-[#C9A24D] text-white' : 'text-[#94A3B8] border border-[#E2E8F0]'}`}>Think</button>
        </div>
      </form>
    </div>
  );
};

import React, { useState, useCallback, useEffect, useRef, useMemo } from 'react';
import { AssetUploader } from './components/AssetUploader';
import { GameRunner } from './components/GameRunner';
import { AIChat } from './components/AIChat';
import { generateGame } from './services/gemini';
import { GameAsset, GenerationStatus, GeneratedGame, ChatMessage, AIModelMode } from './types';
import { Box, Activity, Layers, Monitor, Terminal, Sparkles, Play, BoxSelect, Menu, X, MessageSquareCode, BrainCircuit, RefreshCw, Cpu, Zap, Maximize2, Bolt, Download } from 'lucide-react';

type ViewMode = 'editor' | 'preview';

const App: React.FC = () => {
  const [viewMode, setViewMode] = useState<ViewMode>('editor');
  const [assets, setAssets] = useState<GameAsset[]>([]);
  const [status, setStatus] = useState<GenerationStatus>({ step: 'idle', message: '' });
  const [game, setGame] = useState<GeneratedGame | null>(null);
  const [chatHistory, setChatHistory] = useState<ChatMessage[]>([]);
  const [aiMode, setAiMode] = useState<AIModelMode>('thinking');
  const [logs, setLogs] = useState<string[]>([
    'Initializing ForgeAI Studio core...', 
    'Neural substrate calibration complete.',
    'Physics Subsystem: High-precision Verlet Active.'
  ]);
  const [isLeftSidebarOpen, setIsLeftSidebarOpen] = useState(false);
  const [isRightSidebarOpen, setIsRightSidebarOpen] = useState(false);
  const [activeMobileView, setActiveMobileView] = useState<'staging' | 'chat' | 'logs'>('staging');
  const [isLiveSyncing, setIsLiveSyncing] = useState(false);

  const prevAssetsCount = useRef(0);
  const autoSyncTimer = useRef<ReturnType<typeof setTimeout> | null>(null);
  const iframeRef = useRef<HTMLIFrameElement>(null);

  const addLog = (msg: string) => {
    setLogs(prev => [...prev.slice(-15), msg]);
  };

  const processGeneration = useCallback(async (instruction: string, isAutoSync: boolean = false) => {
    if (!isAutoSync) {
      setStatus({ step: 'analyzing', message: 'Architecting Logical Model...' });
      addLog(`Analyzing mechanical intent: "${instruction.slice(0, 30)}..."`);
      setChatHistory(prev => [...prev, { role: 'user', text: instruction }]);
    } else {
      setIsLiveSyncing(true);
      addLog(`Auto-Sync: Harmonizing buffers...`);
    }

    try {
      const result = await generateGame(
        instruction, 
        assets, 
        chatHistory, 
        game?.code || "",
        aiMode
      );

      if (!isAutoSync) {
        setStatus({ step: 'coding', message: 'Synthesizing 3D Substrate...' });
        const aiMessage: ChatMessage = { 
          role: 'ai', 
          text: result.explanation,
          suggestions: result.suggestions,
          isApplying: true 
        };
        setChatHistory(prev => [...prev, aiMessage]);

        await new Promise(resolve => setTimeout(resolve, 2000));

        setChatHistory(prev => prev.map((m, idx) => 
          idx === prev.length - 1 ? { ...m, isApplying: false } : m
        ));
      }

      setGame({ code: result.code, title: result.title });
      setStatus({ step: 'ready', message: 'Architecture Verified.' });
      setIsLiveSyncing(false);

      addLog(`Substrate ${isAutoSync ? 'synchronized' : 'generated'}: "${result.title}"`);

    } catch (error: any) {
      console.error(error);
      setStatus({ step: 'error', message: 'Synthesis Failure.' });
      setIsLiveSyncing(false);
      if (!isAutoSync) {
        setChatHistory(prev => [...prev, { role: 'ai', text: 'Structural paradox detected. The architect requires refined mechanical parameters.' }]);
      }
      addLog(`Error: Collision in logic synthesis.`);
    }
  }, [assets, chatHistory, game, aiMode]);

  useEffect(() => {
    if (game && assets.length !== prevAssetsCount.current) {
      if (autoSyncTimer.current) clearTimeout(autoSyncTimer.current);
      autoSyncTimer.current = setTimeout(() => {
        const lastUserPrompt = chatHistory.filter(m => m.role === 'user').pop()?.text || "Synchronize simulation with updated buffers.";
        processGeneration(`SYNC: ${lastUserPrompt}`, true);
      }, 5000); 
    }
    prevAssetsCount.current = assets.length;
  }, [assets, game, chatHistory, processGeneration]);

  const enterPreview = () => {
    if (game) setViewMode('preview');
  };

  const exitPreview = () => setViewMode('editor');

  const integratedSrcDoc = useMemo(() => {
    if (!game) return "";
    const assetMap = assets.reduce((acc, asset) => { acc[asset.name] = asset.content; return acc; }, {} as Record<string, string>);
    const persistenceKey = `forge_studio_state_${btoa(game.title).substring(0, 16)}`;
    const savedStateStr = localStorage.getItem(persistenceKey);
    const savedState = savedStateStr ? JSON.parse(savedStateStr) : null;

    const bootstrapScript = `
      <script>
        (function() {
          window.onerror = (message) => { window.parent.postMessage({ type: 'FORGE_RUNTIME_ERROR', payload: { message: message, type: 'Integrated Crash' } }, '*'); return true; };
          const rawAssets = ${JSON.stringify(assetMap)};
          const assetCache = new Map();
          let lastTime = performance.now();
          window.getDeltaTime = () => {
            const now = performance.now();
            let dt = (now - lastTime) / 1000;
            lastTime = now;
            return dt > 0.1 ? 0.1 : dt;
          };
          window.PHYSICS_MATERIALS = { 'Level Geometry': { friction: 0.9, restitution: 0.1 }, 'Prop': { friction: 0.5, restitution: 0.6 }, 'Hero': { friction: 0.8, restitution: 0.0 } };
          window.PERSISTED_STATE = ${JSON.stringify(savedState)};
          window.DEBUG_PHYSICS = false;
          window.saveState = (data) => window.parent.postMessage({ type: 'FORGE_SAVE_STATE', payload: data }, '*');

          function b64ToBlob(b64, mime) {
            try {
              const split = b64.split(',');
              const bytes = atob(split[1] || split[0]);
              const ab = new ArrayBuffer(bytes.length);
              const ia = new Uint8Array(ab);
              for (let i = 0; i < bytes.length; i++) ia[i] = bytes.charCodeAt(i);
              return new Blob([ab], { type: mime });
            } catch (e) {
              console.error("Blob Synthesis Failure:", e);
              return null;
            }
          }

          window.getAssetUrl = (name) => {
            if (assetCache.has(name)) return assetCache.get(name);
            const data = rawAssets[name];
            if (!data) return "";

            try {
              const mime = data.includes('data:') ? data.split(':')[1].split(';')[0] : 'application/octet-stream';
              const blob = b64ToBlob(data, mime);
              if (!blob) return "";
              const url = URL.createObjectURL(blob);
              assetCache.set(name, url);
              return url;
            } catch (e) {
              console.error("Asset Loader Paradox:", e);
              return "";
            }
          };

          // Explicit Memory Management
          window.addEventListener('pagehide', () => {
            assetCache.forEach(url => URL.revokeObjectURL(url));
            assetCache.clear();
          });
        })();
      </script>
      <style>body { margin: 0; background: #0F172A; overflow: hidden; width: 100%; height: 100%; } canvas { display: block; width: 100%; height: 100%; }</style>
    `;
    const finalDoc = game.code.includes('<head>') ? game.code.replace('<head>', `<head>${bootstrapScript}`) : bootstrapScript + game.code;
    return finalDoc.startsWith('<!DOCTYPE html>') ? finalDoc : `<!DOCTYPE html>${finalDoc}`;
  }, [game, assets]);

  const downloadGame = () => {
    if (!game) return;
    const blob = new Blob([integratedSrcDoc], { type: 'text/html' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `${game.title.replace(/\s+/g, '_').toLowerCase()}.html`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
    addLog(`Substrate Exported: ${game.title}.html`);
  };

  if (viewMode === 'preview' && game) {
    return (
      <div className="fixed inset-0 z-[500] bg-[#0F172A]">
        <GameRunner code={game.code} title={game.title} assets={assets} onExit={exitPreview} />
      </div>
    );
  }

  return (
    <div className="flex flex-col h-screen max-h-screen bg-[#F8FAFC] text-[#0F172A] overflow-hidden font-sans relative selection:bg-[#4F46E5]/10 selection:text-[#4F46E5]">
      {/* LUXURY HEADER */}
      <header className="h-16 border-b border-[#E2E8F0] bg-white shadow-sm flex items-center justify-between px-6 shrink-0 z-50">
        <div className="flex items-center gap-6">
          <button 
            onClick={() => setIsLeftSidebarOpen(!isLeftSidebarOpen)}
            className="md:hidden p-2 hover:bg-[#F1F5F9] rounded-lg transition-colors text-[#64748B]"
          >
            {isLeftSidebarOpen ? <X className="w-5 h-5" /> : <Menu className="w-5 h-5" />}
          </button>

          <div className="flex items-center gap-3">
            <div className="bg-[#4F46E5] p-1.5 rounded-lg shadow-md shadow-indigo-100">
              <Box className="w-4 h-4 text-white" />
            </div>
            <div className="flex flex-col">
              <h1 className="text-sm font-bold tracking-tight text-[#0F172A]">
                STUDIO <span className="text-[#4F46E5]">FORGE</span>
              </h1>
              <span className="text-[8px] text-[#94A3B8] font-bold uppercase tracking-[0.2em] -mt-0.5">Neural Engine v5.1</span>
            </div>
          </div>

          <div className="h-6 w-px bg-[#E2E8F0] hidden sm:block" />

          <div className="hidden lg:flex items-center gap-5">
            {/* Mode Switcher */}
            <div className="flex bg-[#F1F5F9] p-1 rounded-xl border border-[#E2E8F0]">
              <button 
                onClick={() => setAiMode('fast')}
                className={`flex items-center gap-2 px-3 py-1 rounded-lg transition-all ${aiMode === 'fast' ? 'bg-white text-[#4F46E5] shadow-sm' : 'text-[#94A3B8] hover:text-[#64748B]'}`}
              >
                <Bolt className="w-3.5 h-3.5" />
                <span className="text-[10px] font-bold uppercase tracking-wider">Fast</span>
              </button>
              <button 
                onClick={() => setAiMode('thinking')}
                className={`flex items-center gap-2 px-3 py-1 rounded-lg transition-all ${aiMode === 'thinking' ? 'bg-white text-[#C9A24D] shadow-sm' : 'text-[#94A3B8] hover:text-[#64748B]'}`}
              >
                <Cpu className="w-3.5 h-3.5" />
                <span className="text-[10px] font-bold uppercase tracking-wider">Thinking</span>
              </button>
            </div>

            <div className="flex items-center gap-2 px-3 py-1 rounded-full bg-[#F1F5F9] border border-[#E2E8F0]">
              <BrainCircuit className={`w-3.5 h-3.5 ${status.step === 'ready' ? 'text-[#4F46E5]' : status.step !== 'idle' ? 'text-[#C9A24D] animate-pulse' : 'text-[#94A3B8]'}`} />
              <span className="text-[10px] font-bold uppercase tracking-wider text-[#64748B]">System: {status.step === 'ready' ? 'Optimal' : 'Standby'}</span>
            </div>
            {isLiveSyncing && (
              <div className="flex items-center gap-1.5 text-[#4F46E5] animate-pulse">
                <RefreshCw className="w-3 h-3 animate-spin" />
                <span className="text-[9px] font-bold">LIVE SYNCING</span>
              </div>
            )}
          </div>
        </div>

        <div className="flex items-center gap-2">
          {game && (
            <>
              <button 
                onClick={downloadGame}
                className="hidden sm:flex items-center gap-2 px-4 py-2 rounded-xl border border-[#E2E8F0] bg-white text-[#64748B] font-bold text-[11px] uppercase tracking-wider hover:bg-[#F8FAFC] hover:border-[#4F46E5]/20 transition-all shadow-sm active:scale-95"
                title="Download Standalone HTML"
              >
                <Download className="w-3.5 h-3.5 text-[#4F46E5]" />
                <span className="hidden md:inline">Export Source</span>
              </button>
              <button 
                onClick={enterPreview}
                className="flex items-center gap-2 px-5 py-2 rounded-xl bg-[#4F46E5] text-white font-bold text-[11px] uppercase tracking-wider hover:bg-[#4338CA] transition-all shadow-lg shadow-indigo-100 hover:shadow-indigo-200 active:scale-95"
              >
                <Maximize2 className="w-3.5 h-3.5" />
                <span>Full Preview</span>
              </button>
            </>
          )}
          <button 
            onClick={() => setIsRightSidebarOpen(!isRightSidebarOpen)}
            className="md:hidden p-2 hover:bg-[#F1F5F9] rounded-lg transition-colors text-[#64748B]"
          >
            <MessageSquareCode className="w-5 h-5" />
          </button>
        </div>
      </header>

      <main className="flex-1 flex overflow-hidden">
        {/* Left Sidebar: Asset Matrix */}
        <aside className={`
          fixed inset-y-0 left-0 z-40 w-[280px] md:w-[320px] border-r border-[#E2E8F0] bg-[#FFFFFF] shadow-xl md:shadow-none
          flex flex-col shrink-0 transition-transform duration-300 transform
          ${isLeftSidebarOpen ? 'translate-x-0' : '-translate-x-full md:translate-x-0'}
          md:static md:z-0
        `}>
          <div className="p-6 overflow-y-auto flex-1 no-scrollbar space-y-8">
            <section>
              <div className="flex items-center justify-between mb-6">
                <div className="flex items-center gap-2.5">
                  <div className="w-1.5 h-4 bg-[#4F46E5] rounded-full" />
                  <h2 className="text-[11px] font-bold uppercase tracking-[0.2em] text-[#64748B]">Asset Matrix</h2>
                </div>
                <span className="text-[9px] font-bold text-[#94A3B8] uppercase">{assets.length} Active</span>
              </div>
              <AssetUploader assets={assets} onAssetsChange={setAssets} />
            </section>
          </div>
        </aside>

        {/* Center: Live Integrated Staging Area - Dominant Game Preview */}
        <div className={`flex-1 flex flex-col bg-[#F8FAFC] transition-all overflow-hidden ${activeMobileView === 'staging' || activeMobileView === 'logs' ? 'flex' : 'hidden md:flex'}`}>
          <div className={`h-[70vh] relative flex flex-col items-center justify-center p-0 border-b border-[#E2E8F0] bg-[#0F172A] overflow-hidden ${activeMobileView === 'staging' ? 'flex' : 'hidden md:flex'}`}>

            {game ? (
              <div className="w-full h-full relative group p-6 md:p-10">
                <div className="w-full h-full bg-black rounded-[2rem] overflow-hidden shadow-2xl relative border border-[#C9A24D]/30 group-hover:border-[#C9A24D]/60 transition-colors duration-500">
                   <iframe 
                     ref={iframeRef} 
                     srcDoc={integratedSrcDoc} 
                     title="Integrated Runtime" 
                     className="w-full h-full border-none" 
                     sandbox="allow-scripts allow-modals allow-pointer-lock" 
                   />

                   {/* Luxury Overlays for Integrated Preview */}
                   <div className="absolute top-6 left-6 flex items-center gap-3 pointer-events-none">
                      <div className="px-4 py-2 bg-black/40 backdrop-blur-md border border-white/10 rounded-xl flex items-center gap-2.5">
                        <div className="w-2 h-2 rounded-full bg-[#4F46E5] animate-pulse" />
                        <span className="text-[9px] font-bold uppercase tracking-widest text-white/90">Neural Link Active</span>
                      </div>
                      <div className="px-4 py-2 bg-black/40 backdrop-blur-md border border-white/10 rounded-xl flex items-center gap-2.5">
                        <span className="text-[9px] font-bold uppercase tracking-widest text-white/60">{game.title}</span>
                      </div>
                   </div>
                </div>

                {/* Visual Hint for Fullscreen */}
                <button 
                  onClick={enterPreview}
                  className="absolute bottom-14 right-14 p-4 rounded-2xl bg-white text-[#0F172A] opacity-0 group-hover:opacity-100 transition-all shadow-2xl hover:scale-110 active:scale-95"
                >
                  <Maximize2 className="w-5 h-5" />
                </button>
              </div>
            ) : (
              <div className="flex flex-col items-center justify-center text-center p-12 animate-in fade-in duration-1000">
                <div className="relative mb-12">
                   <div className="w-32 h-32 md:w-40 md:h-40 bg-white/5 border border-white/10 rounded-[3rem] flex items-center justify-center shadow-2xl">
                     <BoxSelect className="w-12 h-12 md:w-16 md:h-16 text-white/20 animate-pulse" />
                   </div>
                   <div className="absolute inset-0 bg-[#C9A24D]/5 blur-[60px] rounded-full" />
                </div>
                <h3 className="text-white text-[12px] font-bold uppercase tracking-[0.8em] mb-4">Awaiting Neural Synthesis</h3>
                <p className="text-white/40 text-[10px] font-medium uppercase tracking-[0.2em] max-w-xs leading-relaxed">
                  Provide mechanical intent or structural buffers via the Architect to materialize the simulation substrate here.
                </p>
                <div className="mt-12 flex items-center gap-6 opacity-30">
                   <div className="h-px w-12 bg-white/20" />
                   <Sparkles className="w-4 h-4 text-[#C9A24D]" />
                   <div className="h-px w-12 bg-white/20" />
                </div>
              </div>
            )}

            {/* Status indicators in the dark preview area */}
            <div className="absolute bottom-6 left-10 flex flex-col gap-2">
              <span className="text-[9px] font-bold text-white/20 uppercase tracking-[0.2em]">Substrate Pulse</span>
              <div className="flex items-center gap-2.5">
                <div className={`w-2 h-2 rounded-full ${status.step === 'ready' ? 'bg-[#4F46E5] shadow-[0_0_12px_rgba(79,70,229,0.8)]' : status.step === 'idle' ? 'bg-white/10' : 'bg-[#C9A24D] animate-pulse'}`} />
                <span className="text-[10px] font-bold text-white/40 uppercase tracking-widest">{status.message || 'Standby'}</span>
              </div>
            </div>
          </div>

          {/* Luxury Console (Bottom 30%) */}
          <div className={`flex-1 bg-white flex flex-col ${activeMobileView === 'logs' ? 'flex h-full' : 'hidden md:flex'}`}>
            <div className="px-6 py-4 flex items-center justify-between bg-[#F8FAFC]/50 border-b border-[#F1F5F9]">
              <div className="flex items-center gap-2.5">
                <Terminal className="w-3.5 h-3.5 text-[#64748B]" />
                <h2 className="text-[10px] font-bold uppercase tracking-[0.2em] text-[#64748B]">Architect Console</h2>
              </div>
              <div className="flex items-center gap-4">
                 {isLiveSyncing && (
                    <div className="flex items-center gap-2 px-3 py-1 bg-[#EEF2FF] border border-[#E0E7FF] rounded-full">
                       <RefreshCw className="w-2.5 h-2.5 text-[#4F46E5] animate-spin" />
                       <span className="text-[8px] font-bold text-[#4F46E5] uppercase tracking-widest">Auto-Sync</span>
                    </div>
                 )}
                <div className="flex gap-2">
                  <div className="w-2 h-2 rounded-full bg-[#E2E8F0]" />
                  <div className="w-2 h-2 rounded-full bg-[#E2E8F0]" />
                </div>
              </div>
            </div>
            <div className="flex-1 p-6 font-mono text-[11px] text-[#64748B] overflow-y-auto no-scrollbar space-y-2">
              {logs.map((log, i) => (
                <p key={i} className={`flex gap-4 ${log.includes('Error') ? 'text-red-500' : log.includes('Substrate') ? 'text-[#4F46E5]' : ''}`}>
                  <span className="opacity-40 shrink-0 font-bold">[{new Date().toLocaleTimeString([], { hour12: false })}]</span>
                  <span>{log}</span>
                </p>
              ))}
              {(status.step !== 'idle' && status.step !== 'ready' || isLiveSyncing) && (
                <p className="text-[#C9A24D] animate-pulse flex gap-4">
                  <span className="opacity-40 shrink-0 font-bold">[{new Date().toLocaleTimeString([], { hour12: false })}]</span>
                  <span className="flex items-center gap-2">
                    <Zap className="w-3 h-3" />
                    Neural Core evolving substrate...
                  </span>
                </p>
              )}
            </div>
          </div>
        </div>

        {/* Right Sidebar: AI Architect */}
        <aside className={`
          fixed inset-y-0 right-0 z-40 w-full md:w-[450px] lg:w-[500px] border-l border-[#E2E8F0] bg-white shadow-2xl md:shadow-none
          flex flex-col shrink-0 transition-transform duration-300 transform
