  code: string;
  title: string;
  assets: GameAsset[];
  onExit: () => void;
}

export const GameRunner: React.FC<GameRunnerProps> = ({ code, title, assets, onExit }) => {
  const iframeRef = useRef<HTMLIFrameElement>(null);
  const [isMounting, setIsMounting] = useState(true);
  const [showSaveIndicator, setShowSaveIndicator] = useState(false);
  const [debugEnabled, setDebugEnabled] = useState(false);
  const [runtimeError, setRuntimeError] = useState<{ message: string; type: string } | null>(null);

  const persistenceKey = useMemo(() => `forge_studio_state_${btoa(title).substring(0, 16)}`, [title]);

  useEffect(() => {
    const timer = setTimeout(() => setIsMounting(false), 2500);
    return () => clearTimeout(timer);
  }, []);

  const toggleDebug = () => {
    const newState = !debugEnabled;
    setDebugEnabled(newState);
    if (iframeRef.current?.contentWindow) {
      iframeRef.current.contentWindow.postMessage({ type: 'FORGE_TOGGLE_DEBUG', payload: newState }, '*');
    }
  };

  useEffect(() => {
    const handleMessage = (event: MessageEvent) => {
      if (event.data) {
        if (event.data.type === 'FORGE_SAVE_STATE') {
          localStorage.setItem(persistenceKey, JSON.stringify(event.data.payload));
          setShowSaveIndicator(true);
          setTimeout(() => setShowSaveIndicator(false), 1500);
        }
        if (event.data.type === 'FORGE_RUNTIME_READY') {
          if (iframeRef.current?.contentWindow) {
            iframeRef.current.contentWindow.postMessage({ type: 'FORGE_TOGGLE_DEBUG', payload: debugEnabled }, '*');
          }
        }
        if (event.data.type === 'FORGE_RUNTIME_ERROR') {
          setRuntimeError(event.data.payload);
        }
      }
    };
    window.addEventListener('message', handleMessage);
    return () => window.removeEventListener('message', handleMessage);
  }, [persistenceKey, debugEnabled]);

  const combinedSrcDoc = useMemo(() => {
    const assetMap = assets.reduce((acc, asset) => { acc[asset.name] = asset.content; return acc; }, {} as Record<string, string>);
    const savedStateStr = localStorage.getItem(persistenceKey);
    const savedState = savedStateStr ? JSON.parse(savedStateStr) : null;

    const bootstrapScript = `
      <script>
        (function() {
          window.onerror = (message) => { 
            window.parent.postMessage({ type: 'FORGE_RUNTIME_ERROR', payload: { message: message, type: 'Kernel Collision' } }, '*'); 
            return true; 
          };
          const rawAssets = ${JSON.stringify(assetMap)};
          const assetCache = new Map();
          let lastTime = performance.now();

          window.getDeltaTime = () => {
            const now = performance.now();
            let dt = (now - lastTime) / 1000;
            lastTime = now;
            return Math.min(dt, 0.1);
          };

          window.PHYSICS_MATERIALS = { 
            'Level Geometry': { friction: 0.9, restitution: 0.1 }, 
            'Prop': { friction: 0.5, restitution: 0.6 }, 
            'Hero': { friction: 0.8, restitution: 0.0 } 
          };

          window.PERSISTED_STATE = ${JSON.stringify(savedState)};
          window.DEBUG_PHYSICS = false;
          window.saveState = (data) => window.parent.postMessage({ type: 'FORGE_SAVE_STATE', payload: data }, '*');

          window.addEventListener('message', (e) => { 
            if (e.data.type === 'FORGE_TOGGLE_DEBUG') window.DEBUG_PHYSICS = e.data.payload; 
          });

          window.parent.postMessage({ type: 'FORGE_RUNTIME_READY' }, '*');

          function b64ToBlob(b64, mime) {
            try {
              const split = b64.split(',');
              const bytes = atob(split[1] || split[0]);
              const ab = new ArrayBuffer(bytes.length);
              const ia = new Uint8Array(ab);
              for (let i = 0; i < bytes.length; i++) ia[i] = bytes.charCodeAt(i);
              return new Blob([ab], { type: mime });
            } catch (e) {
              console.error("Blob Extraction Failure:", e);
              return null;
            }
          }

          window.getAssetUrl = (name) => {
            if (assetCache.has(name)) return assetCache.get(name);
            const data = rawAssets[name];
            if (!data) return "";
            try {
              const mime = data.includes('data:') ? data.split(':')[1].split(';')[0] : 'application/octet-stream';
              const blob = b64ToBlob(data, mime);
              if (!blob) return "";
              const url = URL.createObjectURL(blob);
              assetCache.set(name, url);
              return url;
            } catch (e) {
              return "";
            }
          };

          window.addEventListener('pagehide', () => {
            assetCache.forEach(url => URL.revokeObjectURL(url));
            assetCache.clear();
          });
        })();
      </script>
      <style>
        body { margin: 0; background: #000; overflow: hidden; width: 100vw; height: 100vh; display: flex; flex-direction: column; align-items: center; justify-content: center; }
        canvas { display: block; width: 100%; height: 100%; }
        #orientation-hint { display: none; position: fixed; inset: 0; background: #000; color: #fff; z-index: 9999; flex-direction: column; align-items: center; justify-content: center; text-align: center; p: 20px; font-family: sans-serif; }
        @media screen and (orientation: portrait) and (max-width: 600px) {
          /* Optional: hint for landscape games */
          /* #orientation-hint { display: flex; } */
        }
      </style>
      <div id="orientation-hint">
        <svg xmlns="http://www.w3.org/2000/svg" width="48" height="48" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" class="lucide lucide-rotate-cw"><path d="M21 12a9 9 0 1 1-9-9c2.52 0 4.93 1 6.74 2.74L21 8"/><path d="M21 3v5h-5"/></svg>
        <p style="margin-top: 20px; font-weight: bold; text-transform: uppercase; letter-spacing: 0.2em; font-size: 12px;">Please Rotate Your Device</p>
      </div>
    `;
    return code.includes('<head>') ? code.replace('<head>', `<head>${bootstrapScript}`) : bootstrapScript + code;
  }, [code, assets, persistenceKey]);

  return (
    <div className="fixed inset-0 w-full h-full bg-[#020617] flex flex-col z-[1000] overflow-hidden">

      {/* Standalone Loader Overlay */}
      {isMounting && !runtimeError && (
        <div className="absolute inset-0 z-[1100] bg-[#020617] flex flex-col items-center justify-center transition-opacity duration-1000">
          <div className="relative mb-12">
            <div className="w-20 h-20 border-[3px] border-[#4F46E5]/10 border-t-[#4F46E5] rounded-full animate-spin" />
            <div className="absolute inset-0 bg-[#4F46E5]/10 blur-3xl rounded-full animate-pulse" />
          </div>
          <div className="flex flex-col items-center gap-4">
             <h2 className="text-[14px] font-bold text-white uppercase tracking-[1em] ml-[1em]">INITIALIZING</h2>
             <div className="flex items-center gap-3">
               <div className="h-px w-10 bg-white/20" />
               <p className="text-[10px] text-white/40 font-bold uppercase tracking-[0.3em]">{title}</p>
               <div className="h-px w-10 bg-white/20" />
             </div>
          </div>
          <div className="absolute bottom-16 flex items-center gap-10 opacity-20">
             <div className="flex items-center gap-2">
               <Monitor className="w-3.5 h-3.5 text-white" />
               <span className="text-[8px] font-bold text-white uppercase tracking-widest">Desktop Optimized</span>
             </div>
             <div className="flex items-center gap-2">
               <Smartphone className="w-3.5 h-3.5 text-white" />
               <span className="text-[8px] font-bold text-white uppercase tracking-widest">Touch Optimized</span>
             </div>
          </div>
        </div>
      )}

      {/* Standalone Error Page */}
      {runtimeError && (
        <div className="absolute inset-0 z-[1200] bg-[#020617] flex flex-col items-center justify-center p-8 text-center">
          <div className="w-32 h-32 bg-red-500/5 border border-red-500/20 rounded-[3rem] flex items-center justify-center mb-12 shadow-[0_0_100px_rgba(239,68,68,0.1)]">
            <AlertTriangle className="w-12 h-12 text-red-500" />
          </div>
          <h2 className="text-[16px] font-bold text-red-500 uppercase tracking-[0.5em] mb-6">Simulation Collapse</h2>
          <div className="max-w-md bg-white/5 border border-white/10 rounded-3xl p-6 font-mono text-[11px] text-zinc-400 text-left mb-12">
            <span className="text-red-500/60 font-bold mb-2 block">KERNEL_ERROR_ID: {runtimeError.type}</span>
            <p className="leading-relaxed opacity-80">{runtimeError.message}</p>
