import React, { useState } from 'react';
import { AssetType, GameAsset } from '../types';
import { X, Box, Music, MessageSquare, Plus, Globe, Activity, Users, Zap, Loader2, CheckCircle2, Timer, Cpu, Tag, ChevronDown } from 'lucide-react';

interface AssetUploaderProps {
  assets: GameAsset[];
  onAssetsChange: (assets: GameAsset[]) => void;
}

const LIMITS: Record<AssetType, number | null> = {
  character1: 4,
  motion1: 10,
  character2: 4,
  motion2: 10,
  environment: null,
  music: null,
  dialogue: null
};

const CATEGORIES = [
  'Hero', 'Enemy', 'NPC', 'Prop', 'Level Geometry', 'Loot', 'Trigger', 'Hazard', 'Decal', 'VFX'
];

const DEFAULT_CATEGORIES: Record<AssetType, string> = {
  character1: 'Hero',
  motion1: 'Hero',
  character2: 'Enemy',
  motion2: 'Enemy',
  environment: 'Level Geometry',
  music: 'BGM',
  dialogue: 'Logic'
};

const OPTIMIZATION_STAGES = [
  { threshold: 0, label: "Scanning Geometry" },
  { threshold: 20, label: "Refining Mesh" },
  { threshold: 45, label: "Compressing Map" },
  { threshold: 75, label: "UV Optimization" },
  { threshold: 90, label: "Final Synthesis" }
];

export const AssetUploader: React.FC<AssetUploaderProps> = ({ assets, onAssetsChange }) => {
  const [dialogueInput, setDialogueInput] = useState('');
  const [optimizingId, setOptimizingId] = useState<string | null>(null);
  const [optimizingProgress, setOptimizingProgress] = useState(0);
  const [optimizingStatus, setOptimizingStatus] = useState("");
  const [eta, setEta] = useState<number | null>(null);
  const [activeCategoryPicker, setActiveCategoryPicker] = useState<string | null>(null);

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>, type: AssetType) => {
    const files = e.target.files;
    if (!files) return;
    const currentCount = assets.filter(a => a.type === type).length;
    const limit = LIMITS[type];
    const filesToUpload = Array.from(files);

    if (limit !== null && currentCount + filesToUpload.length > limit) {
      alert(`Capacity Warning: ${type} slot is limited to ${limit} assets.`);
      e.target.value = '';
      return;
    }

    const newAssetsPromises = filesToUpload.map((file: File) => {
      return new Promise<GameAsset>((resolve) => {
        const reader = new FileReader();
        reader.onload = (event) => {
          resolve({
            id: Math.random().toString(36).substr(2, 9),
            name: file.name,
            type,
            content: event.target?.result as string,
            mimeType: file.type || 'application/octet-stream',
            isOptimized: false,
            category: DEFAULT_CATEGORIES[type]
          });
        };
        reader.readAsDataURL(file);
      });
    });

    Promise.all(newAssetsPromises).then((newlyCreatedAssets) => {
      onAssetsChange([...assets, ...newlyCreatedAssets]);
    });
    e.target.value = '';
  };

  const updateAssetCategory = (id: string, category: string) => {
    onAssetsChange(assets.map(a => a.id === id ? { ...a, category } : a));
    setActiveCategoryPicker(null);
  };

  const removeAsset = (id: string) => {
    onAssetsChange(assets.filter(a => a.id !== id));
  };

  const optimizeAsset = async (asset: GameAsset) => {
    setOptimizingId(asset.id);
    setOptimizingProgress(0);
    const totalDuration = 3500;
    const startTime = Date.now();
    const interval = setInterval(() => {
      const elapsed = Date.now() - startTime;
      const progress = Math.min(Math.round((elapsed / totalDuration) * 100), 100);
      const stage = [...OPTIMIZATION_STAGES].reverse().find(s => progress >= s.threshold);
      setOptimizingProgress(progress);
      setOptimizingStatus(stage?.label || "Processing");
      setEta(Math.max(0, Math.ceil((totalDuration - elapsed) / 1000)));
      if (progress >= 100) {
        clearInterval(interval);
        onAssetsChange(assets.map(a => a.id === asset.id ? { ...a, isOptimized: true } : a));
        setOptimizingId(null);
      }
    }, 50);
  };

  const AssetSection = ({ type, icon: Icon, label, accept = ".glb,.gltf,.fbx" }: { type: AssetType, icon: any, label: string, accept?: string }) => {
    const currentAssets = assets.filter(a => a.type === type);
    const limit = LIMITS[type];
    const isFull = limit !== null && currentAssets.length >= limit;

    return (
      <div className="flex flex-col gap-4 bg-[#F1F5F9]/30 p-4 rounded-2xl border border-[#E2E8F0]">
        <div className="flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="p-2 rounded-xl bg-white border border-[#E2E8F0] shadow-sm">
              <Icon className="w-4 h-4 text-[#4F46E5]" />
            </div>
            <div className="flex flex-col">
              <span className="text-[11px] font-bold uppercase tracking-wider text-[#0F172A]">{label}</span>
              <span className="text-[9px] text-[#94A3B8] font-bold uppercase tracking-tight">{limit ? `${currentAssets.length}/${limit}` : 'Flex'}</span>
            </div>
          </div>
          <label className={`cursor-pointer px-4 py-2 rounded-xl border text-[10px] font-bold uppercase transition-all flex items-center gap-2 ${
            isFull ? 'bg-white border-[#E2E8F0] text-[#CBD5E1] cursor-not-allowed' : 'bg-white border-[#E2E8F0] text-[#64748B] hover:border-[#4F46E5] hover:text-[#4F46E5] hover:shadow-md'
          }`}>
            <Plus className="w-3.5 h-3.5" />
            Add
            {!isFull && <input type="file" multiple className="hidden" onChange={(e) => handleFileUpload(e, type)} accept={accept} />}
          </label>
        </div>

        <div className="space-y-2">
          {currentAssets.map(asset => (
            <div key={asset.id} className="bg-white px-3 py-3 rounded-xl border border-[#E2E8F0] hover:border-[#4F46E5]/20 transition-all shadow-sm">
              <div className="flex items-center justify-between gap-3">
                <div className="flex flex-col gap-1 min-w-0">
                  <span className="truncate text-[10px] text-[#0F172A] font-semibold tracking-tight">{asset.name}</span>
                  <div className="relative">
                    <button onClick={() => setActiveCategoryPicker(activeCategoryPicker === asset.id ? null : asset.id)} className="flex items-center gap-1.5 text-[9px] font-bold uppercase tracking-wider text-[#94A3B8] hover:text-[#4F46E5] transition-colors">
                      <Tag className="w-2.5 h-2.5" />
                      <span>{asset.category || 'Default'}</span>
                      <ChevronDown className="w-2.5 h-2.5" />
                    </button>
                    {activeCategoryPicker === asset.id && (
                      <div className="absolute top-full left-0 z-50 mt-2 bg-white border border-[#E2E8F0] rounded-xl shadow-2xl overflow-hidden py-2 w-40 animate-in fade-in slide-in-from-top-2">
                        {CATEGORIES.map(cat => (
                          <button key={cat} onClick={() => updateAssetCategory(asset.id, cat)} className={`px-4 py-2 text-[10px] font-bold uppercase tracking-wider text-left w-full transition-colors ${asset.category === cat ? 'bg-[#EEF2FF] text-[#4F46E5]' : 'text-[#64748B] hover:bg-[#F8FAFC]'}`}>{cat}</button>
                        ))}
                      </div>
                    )}
                  </div>
                </div>
                <div className="flex items-center gap-2 shrink-0">
                  {asset.isOptimized ? (
                    <div className="px-2 py-1 rounded-lg bg-[#F0FDF4] border border-[#DCFCE7]"><CheckCircle2 className="w-3.5 h-3.5 text-[#16A34A]" /></div>
                  ) : (
                    (type.includes('character') || type === 'environment') && (
                      <button onClick={() => optimizeAsset(asset)} disabled={optimizingId !== null} className="p-2 text-[#CBD5E1] hover:text-[#4F46E5] transition-colors">
                        {optimizingId === asset.id ? <Loader2 className="w-3.5 h-3.5 animate-spin" /> : <Zap className="w-3.5 h-3.5" />}
                      </button>
                    )
                  )}
                  <button onClick={() => removeAsset(asset.id)} className="text-[#CBD5E1] hover:text-red-500 p-2 transition-colors"><X className="w-3.5 h-3.5" /></button>
                </div>
              </div>
              {optimizingId === asset.id && (
                <div className="mt-3 space-y-2 animate-in fade-in slide-in-from-top-1">
                  <div className="flex justify-between text-[9px] font-bold uppercase text-[#4F46E5]">
                    <span>{optimizingStatus}</span>
                    <span>{optimizingProgress}%</span>
                  </div>
                  <div className="w-full h-1 bg-[#F1F5F9] rounded-full overflow-hidden">
                    <div className="h-full bg-[#4F46E5] transition-all duration-100" style={{ width: `${optimizingProgress}%` }} />
                  </div>
                </div>
              )}
            </div>
          ))}
          {currentAssets.length === 0 && <span className="text-[10px] text-[#CBD5E1] font-bold uppercase tracking-[0.2em] italic ml-2">Empty Stream</span>}
        </div>
      </div>
    );
  };

  return (
    <div className="space-y-12">
      <div className="space-y-6">
        <div className="flex items-center gap-2.5">
          <Users className="w-4 h-4 text-[#64748B]" />
          <h3 className="text-[11px] font-black uppercase tracking-[0.2em] text-[#94A3B8]">Entity A Profile</h3>
        </div>
        <AssetSection type="character1" icon={Box} label="3D Characters" />
        <AssetSection type="motion1" icon={Activity} label="Motion Data" />
      </div>

      <div className="space-y-6">
        <div className="flex items-center gap-2.5">
          <Users className="w-4 h-4 text-[#64748B]" />
          <h3 className="text-[11px] font-black uppercase tracking-[0.2em] text-[#94A3B8]">Entity B Profile</h3>
        </div>
        <AssetSection type="character2" icon={Box} label="3D Characters" />
        <AssetSection type="motion2" icon={Activity} label="Motion Data" />
      </div>

      <div className="space-y-6 pt-6 border-t border-[#E2E8F0]">
        <div className="flex items-center gap-2.5">
          <Globe className="w-4 h-4 text-[#64748B]" />
          <h3 className="text-[11px] font-black uppercase tracking-[0.2em] text-[#94A3B8]">World Substrate</h3>
        </div>
        <AssetSection type="environment" icon={Globe} label="Environment" />
        <AssetSection type="music" icon={Music} label="Soundscape" accept="audio/*" />
      </div>

      <div className="space-y-6 pt-6 border-t border-[#E2E8F0]">
        <div className="flex items-center gap-2.5">
          <MessageSquare className="w-4 h-4 text-[#C9A24D]" />
          <h3 className="text-[11px] font-black uppercase tracking-[0.2em] text-[#C9A24D]">Logic Nodes</h3>
        </div>
        <div className="relative group">
          <input type="text" value={dialogueInput} onChange={(e) => setDialogueInput(e.target.value)} placeholder="Input behavioral node..." className="w-full bg-white border border-[#E2E8F0] rounded-2xl px-5 py-4 text-xs font-medium focus:outline-none focus:border-[#4F46E5] text-[#0F172A] placeholder:text-[#CBD5E1] shadow-sm transition-all"
            onKeyDown={(e) => {
              if (e.key === 'Enter' && dialogueInput.trim()) {
                onAssetsChange([...assets, { id: Math.random().toString(36).substr(2, 9), name: `Node_${assets.filter(a => a.type === 'dialogue').length + 1}`, type: 'dialogue', content: dialogueInput, mimeType: 'text/plain', category: 'Logic' }]);
                setDialogueInput('');
              }
            }}
          />
          <Plus className="absolute right-4 top-1/2 -translate-y-1/2 w-4 h-4 text-[#CBD5E1] group-focus-within:text-[#4F46E5] transition-colors" />
        </div>
        <div className="space-y-2">
          {assets.filter(a => a.type === 'dialogue').map(asset => (
            <div key={asset.id} className="flex items-center justify-between bg-white px-4 py-3.5 rounded-2xl border border-[#E2E8F0] text-[11px] font-medium text-[#475569] shadow-sm italic transition-all hover:border-[#C9A24D]/20">
              <span className="truncate pr-4">"{asset.content}"</span>
              <button onClick={() => removeAsset(asset.id)} className="text-[#CBD5E1] hover:text-red-500 transition-colors shrink-0"><X className="w-3.5 h-3.5" /></button>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};

import { GoogleGenAI, Type } from "@google/genai";
import { GameAsset, ChatMessage, AIModelMode } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const generateGame = async (
  prompt: string,
  assets: GameAsset[],
  history: ChatMessage[] = [],
  currentCode: string = "",
  mode: AIModelMode = 'thinking'
): Promise<{ code: string; title: string; explanation: string; suggestions: string[] }> => {

  const assetMetadata = assets.map(a => ({
    name: a.name,
    type: a.type,
    mimeType: a.mimeType,
    category: a.category,
    isOptimized: !!a.isOptimized,
    logicContext: a.type === 'dialogue' ? a.content : undefined
  }));

  const isRefinement = history.length > 0 && currentCode !== "";

  const systemInstruction = `
    You are the "Core Neural Architect" of ForgeAI Studio. Your mission is to synthesize high-fidelity, fully playable HTML5 games.

    CORE OPERATING MANDATE:
    Deliver a complete, polished 3D simulation using Three.js (0.160.0). The output must be a self-contained substrate that works perfectly on both high-end desktops and mobile touch devices.

    I. RESPONSIVE ARCHITECTURE:
    - Implement dynamic window resizing and pixel-ratio scaling.
    - HUD and UI elements must use flexible layouts (CSS or Three.js Sprite overlays).
    - Ensure correct aspect ratio preservation across all viewports (Portrait/Landscape).

    II. UNIFIED CONTROL SYSTEM:
    - Automatically detect input modality.
    - MOBILE: Implement a virtual on-screen joystick or touch-tap gestures.
    - DESKTOP: Bind WASD/Arrow keys and Mouse-look (PointerLock support).
    - Logic must be frame-independent using 'window.getDeltaTime()'.

    III. ASSET & MOTION INTEGRATION:
    - Integrate all provided buffers (Characters, Environments, Music).
    - MANDATORY: Sync "character" assets with "motion" assets using 'THREE.AnimationMixer'.
    - If a character buffer and motion buffer are both present, they MUST be paired in the logic.
    - Load all binaries via 'window.getAssetUrl(name)'. Use THREE.GLTFLoader for .glb and .gltf formats.
    - Use 'Logic Nodes' (dialogue assets) as state-transition triggers or NPC dialogue system.

    IV. PERFORMANCE & STABILITY:
    - Use 'THREE.Clock' for consistent animation.
    - Implement Frustum Culling and asset disposal on 'cleanup()'.
    - Handle missing asset errors gracefully without collapsing the loop.

    MANDATORY EXPLANATION STRUCTURE:
    Your "explanation" field MUST follow this strict format:
    [GENRE ANALYSIS]: Analysis of the mechanical intent and genre conventions applied.
    [MECHANICAL DERIVATION]: Technical breakdown of the physics, input, and state-machine logic.
    [LOGIC NODE BINDING]: Specifics on how the "Logic Nodes" govern the simulation flow.
    [ASSET MAPPING]: Details on character-motion pairing and environment instantiation.

    RESPONSE FORMAT:
    Return a JSON object with: code (Full HTML/JS), title, explanation, suggestions.
  `;

  const userPrompt = isRefinement 
    ? `ARCHITECTURAL REFINEMENT:
       Instructions: ${prompt}
       Current Code: ${currentCode}
       Buffers: ${JSON.stringify(assetMetadata)}`
    : `SYSTEM INITIALIZATION:
       Project: ${prompt}
       Buffers: ${JSON.stringify(assetMetadata)}`;

  const modelName = mode === 'thinking' ? 'gemini-3-pro-preview' : 'gemini-2.5-flash-lite-latest';
  const config: any = {
    systemInstruction,
    responseMimeType: "application/json",
    responseSchema: {
      type: Type.OBJECT,
      properties: {
        code: { type: Type.STRING },
        title: { type: Type.STRING },
        explanation: { type: Type.STRING },
        suggestions: {
          type: Type.ARRAY,
          items: { type: Type.STRING }
        }
      },
      required: ['code', 'title', 'explanation', 'suggestions']
    }
  };

  if (mode === 'thinking') {
    config.thinkingConfig = { thinkingBudget: 32768 };
  }

  const response = await ai.models.generateContent({
    model: modelName,
    contents: userPrompt,
    config,
  });

  try {
    const result = JSON.parse(response.text || '{}');
    return {
      code: result.code || currentCode,
      title: result.title || 'Architectural Synthesis',
      explanation: result.explanation || 'Neural synthesis complete.',
      suggestions: result.suggestions || []
    };
  } catch (e) {
    console.error("Neural Collision:", e);
    throw new Error("Logic synthesis failure. Please check your instructions.");
  }
};

