  const assetMetadata = assets.map(a => ({ name: a.name, type: a.type, category: a.category }));

  return executeWithNeuralResilience(async (ai) => {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: `As a Lead Game Architect, analyze these assets: ${JSON.stringify(assetMetadata)}. 
      Generate a detailed Game Design Brainstorm report. 
      Include:
      - [CORE CONCEPT]: A unique hook based on the assets.
      - [MECHANICAL SYNERGY]: How Entity A and B assets should interact.
      - [WORLD LOGIC]: How the environment governs play.
      - [TECHNICAL ROADMAP]: Recommended state machine structure.
      Keep it professional, concise, and inspiring.`,
      config: {
        thinkingConfig: { thinkingBudget: 16000 },
        temperature: 0.9
      }
    });

    return response.text || "Neural core unable to synthesize inspiration at this time.";
  });
};

import React, { useState, useCallback, useEffect, useRef, useMemo } from 'react';
import { AssetUploader } from './components/AssetUploader';
import { GameRunner } from './components/GameRunner';
import { AIChat } from './components/AIChat';
import { generateGame, brainstormGame } from './services/gemini';
import { GameAsset, GenerationStatus, GeneratedGame, ChatMessage, AIModelMode } from './types';
import { Box, Activity, Layers, Monitor, Terminal, Sparkles, Play, BoxSelect, Menu, X, MessageSquareCode, BrainCircuit, RefreshCw, Cpu, Zap, Maximize2, Bolt, Download, ShieldCheck } from 'lucide-react';

type ViewMode = 'editor' | 'preview';

const App: React.FC = () => {
  const [viewMode, setViewMode] = useState<ViewMode>('editor');
  const [assets, setAssets] = useState<GameAsset[]>([]);
  const [status, setStatus] = useState<GenerationStatus>({ step: 'idle', message: '' });
  const [game, setGame] = useState<GeneratedGame | null>(null);
  const [chatHistory, setChatHistory] = useState<ChatMessage[]>([]);
  const [aiMode, setAiMode] = useState<AIModelMode>('thinking');
  const [logs, setLogs] = useState<string[]>([
    'Initializing ForgeAI Studio core...', 
    'Neural substrate calibration complete.',
    'Physics Subsystem: High-precision Verlet Active.'
  ]);
  const [isLeftSidebarOpen, setIsLeftSidebarOpen] = useState(false);
  const [isRightSidebarOpen, setIsRightSidebarOpen] = useState(false);
  const [activeMobileView, setActiveMobileView] = useState<'staging' | 'chat' | 'logs'>('staging');
  const [isLiveSyncing, setIsLiveSyncing] = useState(false);

  const prevAssetsCount = useRef(0);
  const autoSyncTimer = useRef<ReturnType<typeof setTimeout> | null>(null);
  const iframeRef = useRef<HTMLIFrameElement>(null);

  const addLog = (msg: string) => {
    setLogs(prev => [...prev.slice(-15), msg]);
  };

  const processGeneration = useCallback(async (instruction: string, isAutoSync: boolean = false) => {
    if (!isAutoSync) {
      setStatus({ step: 'analyzing', message: 'Architecting Logical Model...' });
      addLog(`Analyzing mechanical intent: "${instruction.slice(0, 30)}..."`);
      setChatHistory(prev => [...prev, { role: 'user', text: instruction }]);
    } else {
      setIsLiveSyncing(true);
      addLog(`Auto-Sync: Harmonizing buffers...`);
    }

    try {
      const result = await generateGame(
        instruction, 
        assets, 
        chatHistory, 
        game?.code || "",
        aiMode
      );

      if (!isAutoSync) {
        setStatus({ step: 'coding', message: 'Synthesizing 3D Substrate...' });
        const aiMessage: ChatMessage = { 
          role: 'ai', 
          text: result.explanation,
          suggestions: result.suggestions,
          isApplying: true 
        };
        setChatHistory(prev => [...prev, aiMessage]);

        await new Promise(resolve => setTimeout(resolve, 2000));

        setChatHistory(prev => prev.map((m, idx) => 
          idx === prev.length - 1 ? { ...m, isApplying: false } : m
        ));
      }

      setGame({ code: result.code, title: result.title });
      setStatus({ step: 'ready', message: 'Architecture Verified.' });
      setIsLiveSyncing(false);

      addLog(`Substrate ${isAutoSync ? 'synchronized' : 'generated'}: "${result.title}"`);

    } catch (error: any) {
      console.error(error);
      const errorMsg = error?.message || "Synthesis Failure";

      setStatus({ step: 'error', message: 'Synthesis Failure.' });
      setIsLiveSyncing(false);

      if (!isAutoSync) {
        let helpText = 'Structural paradox detected. The architect requires refined mechanical parameters.';
        if (errorMsg.includes('429')) helpText = 'Neural bandwidth exhausted (Rate Limit). Please wait a moment for the quota to reset.';
        if (errorMsg.includes('404')) helpText = 'Model link severed. Please ensure your API key is correctly configured for Pro models.';

        setChatHistory(prev => [...prev, { role: 'ai', text: helpText }]);
      }
      addLog(`Error: ${errorMsg}`);
    }
  }, [assets, chatHistory, game, aiMode]);

  const handleInspiration = async () => {
    if (status.step !== 'idle' && status.step !== 'ready') return;
    setStatus({ step: 'analyzing', message: 'Neural Brainstorming...' });
    addLog("Architecting design inspiration report...");

    try {
      const report = await brainstormGame(assets);
      setChatHistory(prev => [...prev, { 
        role: 'ai', 
        text: report,
        suggestions: ["Build this concept", "Refine mechanics", "Change theme"] 
      }]);
      setStatus({ step: 'ready', message: 'Inspiration Synthesized.' });
    } catch (e: any) {
      addLog(`Inspiration Error: ${e.message}`);
      setStatus({ step: 'error', message: 'Logic Sync Failure' });
    }
  };

  useEffect(() => {
    if (game && assets.length !== prevAssetsCount.current) {
      if (autoSyncTimer.current) clearTimeout(autoSyncTimer.current);
      autoSyncTimer.current = setTimeout(() => {
        const lastUserPrompt = chatHistory.filter(m => m.role === 'user').pop()?.text || "Synchronize simulation with updated buffers.";
        processGeneration(`SYNC: ${lastUserPrompt}`, true);
      }, 5000); 
    }
    prevAssetsCount.current = assets.length;
  }, [assets, game, chatHistory, processGeneration]);

  const enterPreview = () => {
    if (game) setViewMode('preview');
  };

  const exitPreview = () => setViewMode('editor');

  const integratedSrcDoc = useMemo(() => {
    if (!game) return "";
    const assetMap = assets.reduce((acc, asset) => { acc[asset.name] = asset.content; return acc; }, {} as Record<string, string>);
    const persistenceKey = `forge_studio_state_${btoa(game.title).substring(0, 16)}`;
    const savedStateStr = localStorage.getItem(persistenceKey);
    const savedState = savedStateStr ? JSON.parse(savedStateStr) : null;

    const bootstrapScript = `
      <script>
        (function() {
          window.onerror = (message) => { window.parent.postMessage({ type: 'FORGE_RUNTIME_ERROR', payload: { message: message, type: 'Integrated Crash' } }, '*'); return true; };
          const rawAssets = ${JSON.stringify(assetMap)};
          const assetCache = new Map();
          let lastTime = performance.now();
          window.getDeltaTime = () => {
            const now = performance.now();
            let dt = (now - lastTime) / 1000;
            lastTime = now;
            return dt > 0.1 ? 0.1 : dt;
          };
          window.PHYSICS_MATERIALS = { 'Level Geometry': { friction: 0.9, restitution: 0.1 }, 'Prop': { friction: 0.5, restitution: 0.6 }, 'Hero': { friction: 0.8, restitution: 0.0 } };
          window.PERSISTED_STATE = ${JSON.stringify(savedState)};
          window.DEBUG_PHYSICS = false;
          window.saveState = (data) => window.parent.postMessage({ type: 'FORGE_SAVE_STATE', payload: data }, '*');

          function b64ToBlob(b64, mime) {
            try {
              const split = b64.split(',');
              const bytes = atob(split[1] || split[0]);
              const ab = new ArrayBuffer(bytes.length);
              const ia = new Uint8Array(ab);
              for (let i = 0; i < bytes.length; i++) ia[i] = bytes.charCodeAt(i);
              return new Blob([ab], { type: mime });
            } catch (e) {
              console.error("Blob Synthesis Failure:", e);
              return null;
            }
          }

          window.getAssetUrl = (name) => {
            if (assetCache.has(name)) return assetCache.get(name);
            const data = rawAssets[name];
            if (!data) return "";

            try {
              const mime = data.includes('data:') ? data.split(':')[1].split(';')[0] : 'application/octet-stream';
              const blob = b64ToBlob(data, mime);
              if (!blob) return "";
              const url = URL.createObjectURL(blob);
              assetCache.set(name, url);
              return url;
            } catch (e) {
              console.error("Asset Loader Paradox:", e);
              return "";
            }
          };

          // Explicit Memory Management
          window.addEventListener('pagehide', () => {
            assetCache.forEach(url => URL.revokeObjectURL(url));
            assetCache.clear();
          });
        })();
      </script>
      <style>body { margin: 0; background: #0F172A; overflow: hidden; width: 100%; height: 100%; } canvas { display: block; width: 100%; height: 100%; }</style>
    `;
    const finalDoc = game.code.includes('<head>') ? game.code.replace('<head>', `<head>${bootstrapScript}`) : bootstrapScript + game.code;
    return finalDoc.startsWith('<!DOCTYPE html>') ? finalDoc : `<!DOCTYPE html>${finalDoc}`;
  }, [game, assets]);

  const downloadGame = () => {
    if (!game) return;
    const blob = new Blob([integratedSrcDoc], { type: 'text/html' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `${game.title.replace(/\s+/g, '_').toLowerCase()}.html`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
    addLog(`Substrate Exported: ${game.title}.html`);
  };

  const handleKeySelectionManual = async () => {
    if ((window as any).aistudio?.openSelectKey) {
      await (window as any).aistudio.openSelectKey();
      addLog("API Key selection triggered manually.");
    }
  };

  if (viewMode === 'preview' && game) {
    return (
      <div className="fixed inset-0 z-[500] bg-[#0F172A]">
        <GameRunner code={game.code} title={game.title} assets={assets} onExit={exitPreview} />
      </div>
    );
  }

  return (
    <div className="flex flex-col h-screen max-h-screen bg-[#F8FAFC] text-[#0F172A] overflow-hidden font-sans relative selection:bg-[#4F46E5]/10 selection:text-[#4F46E5]">
      {/* LUXURY HEADER */}
      <header className="h-16 border-b border-[#E2E8F0] bg-white shadow-sm flex items-center justify-between px-6 shrink-0 z-50">
        <div className="flex items-center gap-6">
          <button 
            onClick={() => setIsLeftSidebarOpen(!isLeftSidebarOpen)}
            className="md:hidden p-2 hover:bg-[#F1F5F9] rounded-lg transition-colors text-[#64748B]"
          >
            {isLeftSidebarOpen ? <X className="w-5 h-5" /> : <Menu className="w-5 h-5" />}
          </button>

          <div className="flex items-center gap-3">
            <div className="bg-[#4F46E5] p-1.5 rounded-lg shadow-md shadow-indigo-100">
              <Box className="w-4 h-4 text-white" />
            </div>
            <div className="flex flex-col">
              <h1 className="text-sm font-bold tracking-tight text-[#0F172A]">
                STUDIO <span className="text-[#4F46E5]">FORGE</span>
              </h1>
              <span className="text-[8px] text-[#94A3B8] font-bold uppercase tracking-[0.2em] -mt-0.5">Neural Engine v5.1</span>
            </div>
          </div>

          <div className="h-6 w-px bg-[#E2E8F0] hidden sm:block" />

          <div className="hidden lg:flex items-center gap-5">
            {/* Mode Switcher */}
            <div className="flex bg-[#F1F5F9] p-1 rounded-xl border border-[#E2E8F0]">
              <button 
                onClick={() => setAiMode('fast')}
                className={`flex items-center gap-2 px-3 py-1 rounded-lg transition-all ${aiMode === 'fast' ? 'bg-white text-[#4F46E5] shadow-sm' : 'text-[#94A3B8] hover:text-[#64748B]'}`}
              >
                <Bolt className="w-3.5 h-3.5" />
                <span className="text-[10px] font-bold uppercase tracking-wider">Fast</span>
              </button>
              <button 
                onClick={() => setAiMode('thinking')}
                className={`flex items-center gap-2 px-3 py-1 rounded-lg transition-all ${aiMode === 'thinking' ? 'bg-white text-[#C9A24D] shadow-sm' : 'text-[#94A3B8] hover:text-[#64748B]'}`}
              >
                <Cpu className="w-3.5 h-3.5" />
                <span className="text-[10px] font-bold uppercase tracking-wider">Thinking</span>
              </button>
            </div>

            <div className="flex items-center gap-2 px-3 py-1 rounded-full bg-[#F1F5F9] border border-[#E2E8F0]">
              <BrainCircuit className={`w-3.5 h-3.5 ${status.step === 'ready' ? 'text-[#4F46E5]' : status.step !== 'idle' ? 'text-[#C9A24D] animate-pulse' : 'text-[#94A3B8]'}`} />
              <span className="text-[10px] font-bold uppercase tracking-wider text-[#64748B]">System: {status.step === 'ready' ? 'Optimal' : 'Standby'}</span>
            </div>
            {isLiveSyncing && (
              <div className="flex items-center gap-1.5 text-[#4F46E5] animate-pulse">
                <RefreshCw className="w-3 h-3 animate-spin" />
                <span className="text-[9px] font-bold">LIVE SYNCING</span>
              </div>
            )}
          </div>
        </div>

        <div className="flex items-center gap-2">
          <button 
            onClick={handleKeySelectionManual}
            className="hidden lg:flex items-center gap-2 px-4 py-2 rounded-xl border border-[#E2E8F0] bg-white text-[#64748B] font-bold text-[11px] uppercase tracking-wider hover:bg-[#F8FAFC] transition-all"
            title="Setup AI Key for Pro models"
          >
            <ShieldCheck className="w-3.5 h-3.5 text-emerald-500" />
            <span>Key Config</span>
          </button>
          {game && (
            <>
              <button 
