                className="hidden sm:flex items-center gap-2 px-4 py-2 rounded-xl border border-[#E2E8F0] bg-white text-[#64748B] font-bold text-[11px] uppercase tracking-wider hover:bg-[#F8FAFC] hover:border-[#4F46E5]/20 transition-all shadow-sm active:scale-95"
                title="Download Standalone HTML"
              >
                <Download className="w-3.5 h-3.5 text-[#4F46E5]" />
