          <MessageSquareCode className="w-5 h-5" />
          <span className="text-[9px] font-bold uppercase tracking-widest">Architect</span>
        </button>
        <button onClick={() => setActiveMobileView('logs')} className={`flex flex-col items-center gap-1.5 ${activeMobileView === 'logs' ? 'text-[#4F46E5]' : 'text-[#94A3B8]'}`}>
          <Terminal className="w-5 h-5" />
          <span className="text-[9px] font-bold uppercase tracking-widest">Logs</span>
        </button>
      </footer>
    </div>
  );
};

export default App;

import React, { useState, useCallback, useEffect, useRef, useMemo } from 'react';
import { AssetUploader } from './components/AssetUploader';
