import { AIChat } from './components/AIChat';
import { generateGame, brainstormGame } from './services/gemini';
import { GameAsset, GenerationStatus, GeneratedGame, ChatMessage, AIModelMode } from './types';
import { Box, Activity, Layers, Monitor, Terminal, Sparkles, Play, BoxSelect, Menu, X, MessageSquareCode, BrainCircuit, RefreshCw, Cpu, Zap, Maximize2, Bolt, Download, ShieldCheck } from 'lucide-react';

type ViewMode = 'editor' | 'preview';

const App: React.FC = () => {
  const [viewMode, setViewMode] = useState<ViewMode>('editor');
  const [assets, setAssets] = useState<GameAsset[]>([]);
  const [status, setStatus] = useState<GenerationStatus>({ step: 'idle', message: '' });
  const [game, setGame] = useState<GeneratedGame | null>(null);
  const [chatHistory, setChatHistory] = useState<ChatMessage[]>([]);
  const [aiMode, setAiMode] = useState<AIModelMode>('thinking');
  const [logs, setLogs] = useState<string[]>([
    'Initializing ForgeAI Studio core...', 
    'Neural substrate calibration complete.',
    'Physics Subsystem: High-precision Verlet Active.'
  ]);
  const [isLeftSidebarOpen, setIsLeftSidebarOpen] = useState(false);
  const [isRightSidebarOpen, setIsRightSidebarOpen] = useState(false);
  const [activeMobileView, setActiveMobileView] = useState<'staging' | 'chat' | 'logs'>('staging');
  const [isLiveSyncing, setIsLiveSyncing] = useState(false);

  const prevAssetsCount = useRef(0);
  const autoSyncTimer = useRef<ReturnType<typeof setTimeout> | null>(null);
  const iframeRef = useRef<HTMLIFrameElement>(null);

  const addLog = (msg: string) => {
    setLogs(prev => [...prev.slice(-15), msg]);
  };

  const processGeneration = useCallback(async (instruction: string, isAutoSync: boolean = false) => {
    if (!isAutoSync) {
      setStatus({ step: 'analyzing', message: 'Architecting Logical Model...' });
      addLog(`Analyzing mechanical intent: "${instruction.slice(0, 30)}..."`);
      setChatHistory(prev => [...prev, { role: 'user', text: instruction }]);
    } else {
      setIsLiveSyncing(true);
      addLog(`Auto-Sync: Harmonizing buffers...`);
    }

    try {
      const result = await generateGame(
        instruction, 
        assets, 
        chatHistory, 
        game?.code || "",
        aiMode
      );

      if (!isAutoSync) {
        setStatus({ step: 'coding', message: 'Synthesizing 3D Substrate...' });
        const aiMessage: ChatMessage = { 
          role: 'ai', 
          text: result.explanation,
          suggestions: result.suggestions,
          isApplying: true 
        };
        setChatHistory(prev => [...prev, aiMessage]);

        await new Promise(resolve => setTimeout(resolve, 2000));

        setChatHistory(prev => prev.map((m, idx) => 
          idx === prev.length - 1 ? { ...m, isApplying: false } : m
        ));
      }

      setGame({ code: result.code, title: result.title });
      setStatus({ step: 'ready', message: 'Architecture Verified.' });
      setIsLiveSyncing(false);

      addLog(`Substrate ${isAutoSync ? 'synchronized' : 'generated'}: "${result.title}"`);

    } catch (error: any) {
      console.error(error);
      const errorMsg = error?.message || "Synthesis Failure";

      setStatus({ step: 'error', message: 'Synthesis Failure.' });
      setIsLiveSyncing(false);

      if (!isAutoSync) {
        let helpText = 'Structural paradox detected. The architect requires refined mechanical parameters.';
        if (errorMsg.includes('429')) helpText = 'Neural bandwidth exhausted (Rate Limit). Please wait a moment for the quota to reset.';
        if (errorMsg.includes('404')) helpText = 'Model link severed. Please ensure your API key is correctly configured for Pro models.';

        setChatHistory(prev => [...prev, { role: 'ai', text: helpText }]);
      }
      addLog(`Error: ${errorMsg}`);
    }
  }, [assets, chatHistory, game, aiMode]);

  const handleInspiration = async () => {
    if (status.step !== 'idle' && status.step !== 'ready') return;
    setStatus({ step: 'analyzing', message: 'Neural Brainstorming...' });
    addLog("Architecting design inspiration report...");

    try {
      const report = await brainstormGame(assets);
      setChatHistory(prev => [...prev, { 
        role: 'ai', 
        text: report,
        suggestions: ["Build this concept", "Refine mechanics", "Change theme"] 
      }]);
      setStatus({ step: 'ready', message: 'Inspiration Synthesized.' });
    } catch (e: any) {
      addLog(`Inspiration Error: ${e.message}`);
      setStatus({ step: 'error', message: 'Logic Sync Failure' });
    }
  };

  useEffect(() => {
    if (game && assets.length !== prevAssetsCount.current) {
      if (autoSyncTimer.current) clearTimeout(autoSyncTimer.current);
      autoSyncTimer.current = setTimeout(() => {
        const lastUserPrompt = chatHistory.filter(m => m.role === 'user').pop()?.text || "Synchronize simulation with updated buffers.";
        processGeneration(`SYNC: ${lastUserPrompt}`, true);
      }, 5000); 
    }
    prevAssetsCount.current = assets.length;
  }, [assets, game, chatHistory, processGeneration]);

  const enterPreview = () => {
    if (game) setViewMode('preview');
  };

  const exitPreview = () => setViewMode('editor');

  const integratedSrcDoc = useMemo(() => {
    if (!game) return "";
    const assetMap = assets.reduce((acc, asset) => { acc[asset.name] = asset.content; return acc; }, {} as Record<string, string>);
    const persistenceKey = `forge_studio_state_${btoa(game.title).substring(0, 16)}`;
    const savedStateStr = localStorage.getItem(persistenceKey);
    const savedState = savedStateStr ? JSON.parse(savedStateStr) : null;

    const bootstrapScript = `
      <script>
        (function() {
          window.onerror = (message) => { window.parent.postMessage({ type: 'FORGE_RUNTIME_ERROR', payload: { message: message, type: 'Integrated Crash' } }, '*'); return true; };
          const rawAssets = ${JSON.stringify(assetMap)};
          const assetCache = new Map();
          let lastTime = performance.now();
          window.getDeltaTime = () => {
            const now = performance.now();
            let dt = (now - lastTime) / 1000;
            lastTime = now;
            return dt > 0.1 ? 0.1 : dt;
          };
          window.PHYSICS_MATERIALS = { 'Level Geometry': { friction: 0.9, restitution: 0.1 }, 'Prop': { friction: 0.5, restitution: 0.6 }, 'Hero': { friction: 0.8, restitution: 0.0 } };
          window.PERSISTED_STATE = ${JSON.stringify(savedState)};
          window.DEBUG_PHYSICS = false;
          window.saveState = (data) => window.parent.postMessage({ type: 'FORGE_SAVE_STATE', payload: data }, '*');

          function b64ToBlob(b64, mime) {
            try {
              const split = b64.split(',');
              const bytes = atob(split[1] || split[0]);
              const ab = new ArrayBuffer(bytes.length);
              const ia = new Uint8Array(ab);
              for (let i = 0; i < bytes.length; i++) ia[i] = bytes.charCodeAt(i);
              return new Blob([ab], { type: mime });
            } catch (e) {
              console.error("Blob Synthesis Failure:", e);
              return null;
            }
          }

          window.getAssetUrl = (name) => {
            if (assetCache.has(name)) return assetCache.get(name);
            const data = rawAssets[name];
            if (!data) return "";

            try {
              const mime = data.includes('data:') ? data.split(':')[1].split(';')[0] : 'application/octet-stream';
              const blob = b64ToBlob(data, mime);
              if (!blob) return "";
              const url = URL.createObjectURL(blob);
              assetCache.set(name, url);
              return url;
            } catch (e) {
              console.error("Asset Loader Paradox:", e);
              return "";
            }
          };

          // Explicit Memory Management
          window.addEventListener('pagehide', () => {
            assetCache.forEach(url => URL.revokeObjectURL(url));
            assetCache.clear();
          });
        })();
      </script>
      <style>body { margin: 0; background: #0F172A; overflow: hidden; width: 100%; height: 100%; } canvas { display: block; width: 100%; height: 100%; }</style>
    `;
    const finalDoc = game.code.includes('<head>') ? game.code.replace('<head>', `<head>${bootstrapScript}`) : bootstrapScript + game.code;
    return finalDoc.startsWith('<!DOCTYPE html>') ? finalDoc : `<!DOCTYPE html>${finalDoc}`;
  }, [game, assets]);

  const downloadGame = () => {
    if (!game) return;
    const blob = new Blob([integratedSrcDoc], { type: 'text/html' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `${game.title.replace(/\s+/g, '_').toLowerCase()}.html`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
    addLog(`Substrate Exported: ${game.title}.html`);
  };

  const handleKeySelectionManual = async () => {
    if ((window as any).aistudio?.openSelectKey) {
      await (window as any).aistudio.openSelectKey();
      addLog("API Key selection triggered manually.");
    }
  };

  if (viewMode === 'preview' && game) {
    return (
      <div className="fixed inset-0 z-[500] bg-[#0F172A]">
        <GameRunner code={game.code} title={game.title} assets={assets} onExit={exitPreview} />
      </div>
    );
  }

  return (
    <div className="flex flex-col h-screen max-h-screen bg-[#F8FAFC] text-[#0F172A] overflow-hidden font-sans relative selection:bg-[#4F46E5]/10 selection:text-[#4F46E5]">
      {/* LUXURY HEADER */}
      <header className="h-16 border-b border-[#E2E8F0] bg-white shadow-sm flex items-center justify-between px-4 md:px-6 shrink-0 z-50">
        <div className="flex items-center gap-3 md:gap-6">
          <button 
            onClick={() => setIsLeftSidebarOpen(!isLeftSidebarOpen)}
            className="md:hidden p-2 hover:bg-[#F1F5F9] rounded-lg transition-colors text-[#64748B]"
            aria-label="Toggle Asset Sidebar"
          >
            {isLeftSidebarOpen ? <X className="w-5 h-5" /> : <Menu className="w-5 h-5" />}
          </button>

          <div className="flex items-center gap-3">
            <div className="bg-[#4F46E5] p-1.5 rounded-lg shadow-md shadow-indigo-100">
              <Box className="w-4 h-4 text-white" />
            </div>
            <div className="flex flex-col">
              <h1 className="text-xs md:text-sm font-bold tracking-tight text-[#0F172A] whitespace-nowrap">
                STUDIO <span className="text-[#4F46E5]">FORGE</span>
              </h1>
              <span className="text-[7px] md:text-[8px] text-[#94A3B8] font-bold uppercase tracking-[0.2em] -mt-0.5">Neural Engine v5.1</span>
            </div>
          </div>

          <div className="h-6 w-px bg-[#E2E8F0] hidden sm:block" />

          <div className="hidden lg:flex items-center gap-5">
            <div className="flex bg-[#F1F5F9] p-1 rounded-xl border border-[#E2E8F0]">
              <button 
                onClick={() => setAiMode('fast')}
                className={`flex items-center gap-2 px-3 py-1 rounded-lg transition-all ${aiMode === 'fast' ? 'bg-white text-[#4F46E5] shadow-sm' : 'text-[#94A3B8] hover:text-[#64748B]'}`}
              >
                <Bolt className="w-3.5 h-3.5" />
                <span className="text-[10px] font-bold uppercase tracking-wider">Fast</span>
              </button>
              <button 
                onClick={() => setAiMode('thinking')}
                className={`flex items-center gap-2 px-3 py-1 rounded-lg transition-all ${aiMode === 'thinking' ? 'bg-white text-[#C9A24D] shadow-sm' : 'text-[#94A3B8] hover:text-[#64748B]'}`}
              >
                <Cpu className="w-3.5 h-3.5" />
                <span className="text-[10px] font-bold uppercase tracking-wider">Thinking</span>
              </button>
            </div>

            <div className="flex items-center gap-2 px-3 py-1 rounded-full bg-[#F1F5F9] border border-[#E2E8F0]">
              <BrainCircuit className={`w-3.5 h-3.5 ${status.step === 'ready' ? 'text-[#4F46E5]' : status.step !== 'idle' ? 'text-[#C9A24D] animate-pulse' : 'text-[#94A3B8]'}`} />
              <span className="text-[10px] font-bold uppercase tracking-wider text-[#64748B]">System: {status.step === 'ready' ? 'Optimal' : 'Standby'}</span>
            </div>
          </div>
        </div>

        <div className="flex items-center gap-1.5 md:gap-2">
          <button 
            onClick={handleKeySelectionManual}
            className="hidden sm:flex items-center gap-2 px-3 md:px-4 py-2 rounded-xl border border-[#E2E8F0] bg-white text-[#64748B] font-bold text-[10px] md:text-[11px] uppercase tracking-wider hover:bg-[#F8FAFC] transition-all"
            title="Setup AI Key for Pro models"
          >
            <ShieldCheck className="w-3.5 h-3.5 text-emerald-500" />
            <span className="hidden md:inline">Key Config</span>
          </button>
          {game && (
            <>
              <button 
                onClick={downloadGame}
                className="hidden sm:flex items-center gap-2 px-4 py-2 rounded-xl border border-[#E2E8F0] bg-white text-[#64748B] font-bold text-[11px] uppercase tracking-wider hover:bg-[#F8FAFC] hover:border-[#4F46E5]/20 transition-all shadow-sm active:scale-95"
                title="Export HTML"
              >
                <Download className="w-3.5 h-3.5 text-[#4F46E5]" />
                <span className="hidden md:inline">Export</span>
              </button>
              <button 
                onClick={enterPreview}
                className="flex items-center gap-2 px-3 md:px-5 py-2 rounded-xl bg-[#4F46E5] text-white font-bold text-[10px] md:text-[11px] uppercase tracking-wider hover:bg-[#4338CA] transition-all shadow-lg shadow-indigo-100 hover:shadow-indigo-200 active:scale-95"
              >
                <Maximize2 className="w-3.5 h-3.5" />
                <span>Preview</span>
              </button>
            </>
          )}
          <button 
            onClick={() => setIsRightSidebarOpen(!isRightSidebarOpen)}
            className="md:hidden p-2 hover:bg-[#F1F5F9] rounded-lg transition-colors text-[#64748B]"
            aria-label="Toggle Architect Sidebar"
          >
            <MessageSquareCode className="w-5 h-5" />
          </button>
        </div>
      </header>

      <main className="flex-1 flex overflow-hidden relative">
        {/* Left Sidebar: Asset Matrix */}
        <aside className={`
          fixed inset-y-0 left-0 z-[60] w-[280px] md:w-[320px] border-r border-[#E2E8F0] bg-[#FFFFFF] shadow-2xl md:shadow-none
          flex flex-col shrink-0 transition-transform duration-300 ease-in-out transform
          ${isLeftSidebarOpen ? 'translate-x-0' : '-translate-x-full md:translate-x-0'}
          md:static md:z-0
        `}>
          <div className="p-6 overflow-y-auto flex-1 no-scrollbar space-y-8">
            <section>
              <div className="flex items-center justify-between mb-6">
                <div className="flex items-center gap-2.5">
                  <div className="w-1.5 h-4 bg-[#4F46E5] rounded-full" />
                  <h2 className="text-[11px] font-bold uppercase tracking-[0.2em] text-[#64748B]">Asset Matrix</h2>
                </div>
                <span className="text-[9px] font-bold text-[#94A3B8] uppercase">{assets.length} Active</span>
              </div>
              <AssetUploader assets={assets} onAssetsChange={setAssets} />
            </section>
          </div>
          {/* Mobile close button for sidebar */}
          <button 
            onClick={() => setIsLeftSidebarOpen(false)}
            className="md:hidden absolute top-4 right-4 p-2 text-[#94A3B8] hover:text-[#0F172A]"
          >
            <X className="w-5 h-5" />
          </button>
        </aside>

        {/* Center: Live Integrated Staging Area */}
        <div className={`flex-1 flex flex-col bg-[#F8FAFC] transition-all overflow-hidden relative ${activeMobileView === 'staging' || activeMobileView === 'logs' ? 'flex' : 'hidden md:flex'}`}>

          {/* Staging Area (Preview Iframe) */}
          <div className={`flex-[3] relative flex flex-col items-center justify-center p-0 border-b border-[#E2E8F0] bg-[#0F172A] overflow-hidden ${activeMobileView === 'staging' ? 'flex' : 'hidden md:flex'}`}>

            {game ? (
              <div className="w-full h-full relative group p-4 md:p-8 lg:p-10">
                <div className="w-full h-full bg-black rounded-3xl md:rounded-[2rem] overflow-hidden shadow-2xl relative border border-[#C9A24D]/30 group-hover:border-[#C9A24D]/60 transition-colors duration-500">
                   <iframe 
                     ref={iframeRef} 
                     srcDoc={integratedSrcDoc} 
                     title="Integrated Runtime" 
                     className="w-full h-full border-none" 
                     sandbox="allow-scripts allow-modals allow-pointer-lock" 
                   />

                   {/* Luxury Overlays for Integrated Preview */}
                   <div className="absolute top-4 left-4 md:top-6 md:left-6 flex flex-wrap items-center gap-2 pointer-events-none">
                      <div className="px-3 md:px-4 py-1.5 md:py-2 bg-black/40 backdrop-blur-md border border-white/10 rounded-xl flex items-center gap-2 md:gap-2.5">
                        <div className="w-1.5 h-1.5 md:w-2 md:h-2 rounded-full bg-[#4F46E5] animate-pulse" />
                        <span className="text-[8px] md:text-[9px] font-bold uppercase tracking-widest text-white/90">Link Active</span>
                      </div>
                      <div className="px-3 md:px-4 py-1.5 md:py-2 bg-black/40 backdrop-blur-md border border-white/10 rounded-xl flex items-center gap-2 md:gap-2.5">
                        <span className="text-[8px] md:text-[9px] font-bold uppercase tracking-widest text-white/60 truncate max-w-[120px] md:max-w-none">{game.title}</span>
                      </div>
                   </div>
                </div>

                {/* Visual Hint for Fullscreen */}
                <button 
                  onClick={enterPreview}
                  className="absolute bottom-10 right-10 md:bottom-14 md:right-14 p-3 md:p-4 rounded-2xl bg-white text-[#0F172A] opacity-0 group-hover:opacity-100 transition-all shadow-2xl hover:scale-110 active:scale-95 hidden md:block"
                >
                  <Maximize2 className="w-5 h-5" />
                </button>
              </div>
            ) : (
              <div className="flex flex-col items-center justify-center text-center p-8 animate-in fade-in duration-1000">
                <div className="relative mb-8 md:mb-12">
                   <div className="w-24 h-24 md:w-40 md:h-40 bg-white/5 border border-white/10 rounded-[2rem] md:rounded-[3rem] flex items-center justify-center shadow-2xl">
                     <BoxSelect className="w-10 h-10 md:w-16 md:h-16 text-white/20 animate-pulse" />
                   </div>
                   <div className="absolute inset-0 bg-[#C9A24D]/5 blur-[60px] rounded-full" />
                </div>
                <h3 className="text-white text-[10px] md:text-[12px] font-bold uppercase tracking-[0.6em] md:tracking-[0.8em] mb-4">Awaiting Neural Synthesis</h3>
                <p className="text-white/40 text-[9px] md:text-[10px] font-medium uppercase tracking-[0.15em] md:tracking-[0.2em] max-w-xs leading-relaxed">
                  Provide mechanical intent or structural buffers via the Architect to materialize the simulation substrate here.
                </p>
                <div className="mt-8 md:mt-12 flex items-center gap-6 opacity-30">
                   <div className="h-px w-8 md:w-12 bg-white/20" />
                   <Sparkles className="w-4 h-4 text-[#C9A24D]" />
                   <div className="h-px w-8 md:w-12 bg-white/20" />
                </div>
              </div>
            )}

            {/* Status indicators in the dark preview area */}
            <div className="absolute bottom-4 left-6 md:bottom-6 md:left-10 flex flex-col gap-1 md:gap-2 pointer-events-none">
              <span className="text-[7px] md:text-[9px] font-bold text-white/20 uppercase tracking-[0.2em]">Substrate Pulse</span>
              <div className="flex items-center gap-2 md:gap-2.5">
                <div className={`w-1.5 h-1.5 md:w-2 md:h-2 rounded-full ${status.step === 'ready' ? 'bg-[#4F46E5] shadow-[0_0_12px_rgba(79,70,229,0.8)]' : status.step === 'idle' ? 'bg-white/10' : 'bg-[#C9A24D] animate-pulse'}`} />
                <span className="text-[8px] md:text-[10px] font-bold text-white/40 uppercase tracking-widest truncate max-w-[150px]">{status.message || 'Standby'}</span>
              </div>
            </div>
          </div>

          {/* Luxury Console (Lower Section) */}
          <div className={`flex-1 min-h-[150px] bg-white flex flex-col ${activeMobileView === 'logs' ? 'flex absolute inset-0 z-[55]' : 'hidden md:flex'}`}>
            <div className="px-6 py-3 flex items-center justify-between bg-[#F8FAFC]/50 border-b border-[#F1F5F9] shrink-0">
              <div className="flex items-center gap-2.5">
                <Terminal className="w-3.5 h-3.5 text-[#64748B]" />
                <h2 className="text-[10px] font-bold uppercase tracking-[0.2em] text-[#64748B]">Architect Console</h2>
              </div>
              <div className="flex items-center gap-3">
                 {isLiveSyncing && (
                    <div className="flex items-center gap-1.5 px-2 py-0.5 bg-[#EEF2FF] border border-[#E0E7FF] rounded-full">
                       <RefreshCw className="w-2.5 h-2.5 text-[#4F46E5] animate-spin" />
                       <span className="text-[7px] font-bold text-[#4F46E5] uppercase tracking-widest">Live Sync</span>
                    </div>
                 )}
                 <div className="flex gap-1.5">
                    <div className="w-1.5 h-1.5 rounded-full bg-[#E2E8F0]" />
                    <div className="w-1.5 h-1.5 rounded-full bg-[#E2E8F0]" />
                 </div>
                 {activeMobileView === 'logs' && (
                    <button onClick={() => setActiveMobileView('staging')} className="md:hidden p-1 text-[#64748B] hover:text-[#0F172A]">
                      <X className="w-4 h-4" />
                    </button>
                 )}
              </div>
            </div>
            <div className="flex-1 p-4 md:p-6 font-mono text-[10px] md:text-[11px] text-[#64748B] overflow-y-auto no-scrollbar space-y-2">
              {logs.map((log, i) => (
                <p key={i} className={`flex gap-3 md:gap-4 ${log.includes('Error') ? 'text-red-500' : log.includes('Substrate') ? 'text-[#4F46E5]' : ''}`}>
                  <span className="opacity-40 shrink-0 font-bold whitespace-nowrap">[{new Date().toLocaleTimeString([], { hour12: false, hour: '2-digit', minute: '2-digit', second: '2-digit' })}]</span>
                  <span className="break-all md:break-normal">{log}</span>
                </p>
              ))}
              {(status.step !== 'idle' && status.step !== 'ready' || isLiveSyncing) && (
                <p className="text-[#C9A24D] animate-pulse flex gap-3 md:gap-4">
                  <span className="opacity-40 shrink-0 font-bold whitespace-nowrap">[{new Date().toLocaleTimeString([], { hour12: false, hour: '2-digit', minute: '2-digit', second: '2-digit' })}]</span>
                  <span className="flex items-center gap-2">
                    <Zap className="w-3 h-3" />
                    Neural Core evolving substrate...
                  </span>
                </p>
              )}
            </div>
          </div>
        </div>

        {/* Right Sidebar: AI Architect */}
        <aside className={`
          fixed inset-y-0 right-0 z-[60] w-full md:w-[450px] lg:w-[500px] border-l border-[#E2E8F0] bg-white shadow-2xl md:shadow-none
          flex flex-col shrink-0 transition-transform duration-300 ease-in-out transform
          ${isRightSidebarOpen || activeMobileView === 'chat' ? 'translate-x-0 flex' : 'translate-x-full md:translate-x-0'}
          md:static md:z-0
        `}>
          <AIChat 
            history={chatHistory} 
            onSendMessage={processGeneration} 
            onInspiration={handleInspiration}
            isProcessing={status.step !== 'idle' && status.step !== 'ready' && status.step !== 'error'} 
            aiMode={aiMode}
            onModeChange={setAiMode}
          />
          {/* Mobile close button for architect */}
          <button 
            onClick={() => {
                setIsRightSidebarOpen(false);
                if (activeMobileView === 'chat') setActiveMobileView('staging');
            }}
            className="md:hidden absolute top-4 right-4 p-2 text-[#94A3B8] hover:text-[#0F172A] z-[70]"
          >
            <X className="w-5 h-5" />
          </button>
        </aside>

        {/* Backdrop for mobile sidebars */}
        {(isLeftSidebarOpen || isRightSidebarOpen) && (
          <div 
            className="fixed inset-0 bg-black/20 backdrop-blur-sm z-50 md:hidden"
            onClick={() => {
              setIsLeftSidebarOpen(false);
              setIsRightSidebarOpen(false);
