import React, { useState } from 'react';
import { AssetType, GameAsset } from '../types';
import { X, Box, Music, MessageSquare, Plus, Globe, Activity, Users, Zap, Loader2, CheckCircle2, Timer, Cpu, Tag, ChevronDown } from 'lucide-react';

interface AssetUploaderProps {
  assets: GameAsset[];
  onAssetsChange: (assets: GameAsset[]) => void;
}

const LIMITS: Record<AssetType, number | null> = {
  character1: 4,
  motion1: 10,
  character2: 4,
  motion2: 10,
  environment: null,
  music: null,
  dialogue: null
};

const CATEGORIES = [
  'Hero', 'Enemy', 'NPC', 'Prop', 'Level Geometry', 'Loot', 'Trigger', 'Hazard', 'Decal', 'VFX'
];

const DEFAULT_CATEGORIES: Record<AssetType, string> = {
  character1: 'Hero',
  motion1: 'Hero',
  character2: 'Enemy',
  motion2: 'Enemy',
  environment: 'Level Geometry',
  music: 'BGM',
  dialogue: 'Logic'
};

const OPTIMIZATION_STAGES = [
  { threshold: 0, label: "Scanning Geometry" },
  { threshold: 20, label: "Refining Mesh" },
  { threshold: 45, label: "Compressing Map" },
  { threshold: 75, label: "UV Optimization" },
  { threshold: 90, label: "Final Synthesis" }
];

export const AssetUploader: React.FC<AssetUploaderProps> = ({ assets, onAssetsChange }) => {
  const [dialogueInput, setDialogueInput] = useState('');
  const [optimizingId, setOptimizingId] = useState<string | null>(null);
  const [optimizingProgress, setOptimizingProgress] = useState(0);
  const [optimizingStatus, setOptimizingStatus] = useState("");
  const [activeCategoryPicker, setActiveCategoryPicker] = useState<string | null>(null);

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>, type: AssetType) => {
    const files = e.target.files;
    if (!files) return;
    const currentCount = assets.filter(a => a.type === type).length;
    const limit = LIMITS[type];
    const filesToUpload = Array.from(files);

    if (limit !== null && currentCount + filesToUpload.length > limit) {
      alert(`Capacity Warning: ${type} slot is limited to ${limit} assets.`);
      e.target.value = '';
      return;
    }

    const newAssetsPromises = filesToUpload.map((file: File) => {
      return new Promise<GameAsset>((resolve) => {
        const reader = new FileReader();
        reader.onload = (event) => {
          resolve({
            id: Math.random().toString(36).substr(2, 9),
            name: file.name,
            type,
            content: event.target?.result as string,
            mimeType: file.type || 'application/octet-stream',
            isOptimized: false,
            category: DEFAULT_CATEGORIES[type]
          });
        };
        reader.readAsDataURL(file);
      });
    });

    Promise.all(newAssetsPromises).then((newlyCreatedAssets) => {
      onAssetsChange([...assets, ...newlyCreatedAssets]);
    });
    e.target.value = '';
  };

  const updateAssetCategory = (id: string, category: string) => {
    onAssetsChange(assets.map(a => a.id === id ? { ...a, category } : a));
    setActiveCategoryPicker(null);
  };

  const removeAsset = (id: string) => {
    onAssetsChange(assets.filter(a => a.id !== id));
  };

  const optimizeAsset = async (asset: GameAsset) => {
    setOptimizingId(asset.id);
    setOptimizingProgress(0);
    const totalDuration = 3500;
    const startTime = Date.now();
    const interval = setInterval(() => {
      const elapsed = Date.now() - startTime;
      const progress = Math.min(Math.round((elapsed / totalDuration) * 100), 100);
      const stage = [...OPTIMIZATION_STAGES].reverse().find(s => progress >= s.threshold);
      setOptimizingProgress(progress);
      setOptimizingStatus(stage?.label || "Processing");
      if (progress >= 100) {
        clearInterval(interval);
        onAssetsChange(assets.map(a => a.id === asset.id ? { ...a, isOptimized: true } : a));
        setOptimizingId(null);
      }
    }, 50);
  };

  const AssetSection = ({ type, icon: Icon, label, accept = ".glb,.gltf,.fbx" }: { type: AssetType, icon: any, label: string, accept?: string }) => {
    const currentAssets = assets.filter(a => a.type === type);
    const limit = LIMITS[type];
    const isFull = limit !== null && currentAssets.length >= limit;

    return (
      <div className="flex flex-col gap-3 bg-[#F1F5F9]/30 p-3 md:p-4 rounded-2xl border border-[#E2E8F0]">
        <div className="flex items-center justify-between">
          <div className="flex items-center gap-2.5">
            <div className="p-1.5 md:p-2 rounded-xl bg-white border border-[#E2E8F0] shadow-sm">
              <Icon className="w-3.5 h-3.5 text-[#4F46E5]" />
            </div>
            <div className="flex flex-col">
              <span className="text-[10px] md:text-[11px] font-bold uppercase tracking-wider text-[#0F172A]">{label}</span>
              <span className="text-[8px] md:text-[9px] text-[#94A3B8] font-bold uppercase tracking-tight">{limit ? `${currentAssets.length}/${limit}` : 'Flex'}</span>
            </div>
          </div>
          <label className={`cursor-pointer px-3 md:px-4 py-1.5 md:py-2 rounded-xl border text-[9px] md:text-[10px] font-bold uppercase transition-all flex items-center gap-1.5 ${
            isFull ? 'bg-white border-[#E2E8F0] text-[#CBD5E1] cursor-not-allowed' : 'bg-white border-[#E2E8F0] text-[#64748B] hover:border-[#4F46E5] hover:text-[#4F46E5] hover:shadow-md'
          }`}>
            <Plus className="w-3 h-3 md:w-3.5 md:h-3.5" />
            Add
            {!isFull && <input type="file" multiple className="hidden" onChange={(e) => handleFileUpload(e, type)} accept={accept} />}
          </label>
        </div>

        <div className="space-y-2">
          {currentAssets.map(asset => (
            <div key={asset.id} className="bg-white px-3 py-2.5 rounded-xl border border-[#E2E8F0] hover:border-[#4F46E5]/20 transition-all shadow-sm">
              <div className="flex items-center justify-between gap-2">
                <div className="flex flex-col gap-0.5 min-w-0">
                  <span className="truncate text-[9px] md:text-[10px] text-[#0F172A] font-semibold tracking-tight">{asset.name}</span>
                  <div className="relative">
                    <button onClick={() => setActiveCategoryPicker(activeCategoryPicker === asset.id ? null : asset.id)} className="flex items-center gap-1 text-[8px] md:text-[9px] font-bold uppercase tracking-wider text-[#94A3B8] hover:text-[#4F46E5] transition-colors">
                      <Tag className="w-2 h-2 md:w-2.5 md:h-2.5" />
                      <span className="truncate max-w-[80px]">{asset.category || 'Default'}</span>
                      <ChevronDown className="w-2 h-2 md:w-2.5 md:h-2.5" />
                    </button>
                    {activeCategoryPicker === asset.id && (
                      <div className="absolute top-full left-0 z-50 mt-1 bg-white border border-[#E2E8F0] rounded-xl shadow-2xl overflow-hidden py-1 w-32 md:w-40 animate-in fade-in slide-in-from-top-1">
                        {CATEGORIES.map(cat => (
                          <button key={cat} onClick={() => updateAssetCategory(asset.id, cat)} className={`px-3 py-1.5 text-[8px] md:text-[10px] font-bold uppercase tracking-wider text-left w-full transition-colors ${asset.category === cat ? 'bg-[#EEF2FF] text-[#4F46E5]' : 'text-[#64748B] hover:bg-[#F8FAFC]'}`}>{cat}</button>
                        ))}
                      </div>
                    )}
                  </div>
                </div>
                <div className="flex items-center gap-1 md:gap-2 shrink-0">
                  {asset.isOptimized ? (
                    <div className="px-1.5 py-0.5 rounded-lg bg-[#F0FDF4] border border-[#DCFCE7]"><CheckCircle2 className="w-3 h-3 text-[#16A34A]" /></div>
                  ) : (
                    (type.includes('character') || type === 'environment') && (
                      <button onClick={() => optimizeAsset(asset)} disabled={optimizingId !== null} className="p-1.5 text-[#CBD5E1] hover:text-[#4F46E5] transition-colors">
                        {optimizingId === asset.id ? <Loader2 className="w-3 h-3 animate-spin" /> : <Zap className="w-3 h-3" />}
                      </button>
                    )
                  )}
                  <button onClick={() => removeAsset(asset.id)} className="text-[#CBD5E1] hover:text-red-500 p-1.5 transition-colors"><X className="w-3 h-3" /></button>
                </div>
              </div>
              {optimizingId === asset.id && (
                <div className="mt-2.5 space-y-1.5 animate-in fade-in slide-in-from-top-1">
                  <div className="flex justify-between text-[8px] font-bold uppercase text-[#4F46E5]">
                    <span>{optimizingStatus}</span>
                    <span>{optimizingProgress}%</span>
                  </div>
                  <div className="w-full h-1 bg-[#F1F5F9] rounded-full overflow-hidden">
                    <div className="h-full bg-[#4F46E5] transition-all duration-100" style={{ width: `${optimizingProgress}%` }} />
                  </div>
                </div>
              )}
            </div>
          ))}
          {currentAssets.length === 0 && <span className="text-[9px] md:text-[10px] text-[#CBD5E1] font-bold uppercase tracking-[0.2em] italic ml-1">Stream Empty</span>}
        </div>
      </div>
    );
  };

  return (
    <div className="space-y-8 md:space-y-12">
      <div className="space-y-4 md:space-y-6">
        <div className="flex items-center gap-2">
          <Users className="w-3.5 h-3.5 text-[#64748B]" />
          <h3 className="text-[10px] font-black uppercase tracking-[0.2em] text-[#94A3B8]">Entity A Profile</h3>
        </div>
        <AssetSection type="character1" icon={Box} label="3D Characters" />
        <AssetSection type="motion1" icon={Activity} label="Motion Data" />
      </div>

      <div className="space-y-4 md:space-y-6">
        <div className="flex items-center gap-2">
          <Users className="w-3.5 h-3.5 text-[#64748B]" />
          <h3 className="text-[10px] font-black uppercase tracking-[0.2em] text-[#94A3B8]">Entity B Profile</h3>
        </div>
        <AssetSection type="character2" icon={Box} label="3D Characters" />
        <AssetSection type="motion2" icon={Activity} label="Motion Data" />
      </div>

      <div className="space-y-4 md:space-y-6 pt-4 md:pt-6 border-t border-[#E2E8F0]">
        <div className="flex items-center gap-2">
          <Globe className="w-3.5 h-3.5 text-[#64748B]" />
          <h3 className="text-[10px] font-black uppercase tracking-[0.2em] text-[#94A3B8]">World Substrate</h3>
        </div>
        <AssetSection type="environment" icon={Globe} label="Environment" accept=".glb,.gltf,.fbx" />
        <AssetSection type="music" icon={Music} label="Soundscape" accept="audio/*" />
      </div>

      <div className="space-y-4 md:space-y-6 pt-4 md:pt-6 border-t border-[#E2E8F0]">
        <div className="flex items-center gap-2">
          <MessageSquare className="w-3.5 h-3.5 text-[#C9A24D]" />
          <h3 className="text-[10px] font-black uppercase tracking-[0.2em] text-[#C9A24D]">Logic Nodes</h3>
        </div>
        <div className="relative group">
          <input 
            type="text" 
            value={dialogueInput} 
            onChange={(e) => setDialogueInput(e.target.value)} 
            placeholder="Input behavioral node..." 
            className="w-full bg-white border border-[#E2E8F0] rounded-xl md:rounded-2xl px-4 py-3 md:py-4 text-[11px] md:text-xs font-medium focus:outline-none focus:border-[#4F46E5] text-[#0F172A] placeholder:text-[#CBD5E1] shadow-sm transition-all"
            onKeyDown={(e) => {
              if (e.key === 'Enter' && dialogueInput.trim()) {
                onAssetsChange([...assets, { id: Math.random().toString(36).substr(2, 9), name: `Node_${assets.filter(a => a.type === 'dialogue').length + 1}`, type: 'dialogue', content: dialogueInput, mimeType: 'text/plain', category: 'Logic' }]);
                setDialogueInput('');
              }
            }}
          />
          <Plus className="absolute right-3.5 top-1/2 -translate-y-1/2 w-3.5 h-3.5 text-[#CBD5E1] group-focus-within:text-[#4F46E5] transition-colors" />
        </div>
        <div className="space-y-2">
          {assets.filter(a => a.type === 'dialogue').map(asset => (
            <div key={asset.id} className="flex items-center justify-between bg-white px-3 md:px-4 py-2.5 md:py-3.5 rounded-xl md:rounded-2xl border border-[#E2E8F0] text-[10px] md:text-[11px] font-medium text-[#475569] shadow-sm italic transition-all hover:border-[#C9A24D]/20">
              <span className="truncate pr-3">"{asset.content}"</span>
              <button onClick={() => removeAsset(asset.id)} className="text-[#CBD5E1] hover:text-red-500 transition-colors shrink-0"><X className="w-3 h-3 md:w-3.5 md:h-3.5" /></button>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};

import { Bot, BrainCircuit, ChevronRight, Loader2, Send, Sparkles, Terminal, User, Zap, Lightbulb, Cpu, Bolt, Brain } from 'lucide-react';
import React, { useEffect, useRef, useState } from 'react';
import { ChatMessage, AIModelMode } from '../types';

interface AIChatProps {
  history: ChatMessage[];
  onSendMessage: (msg: string) => void;
  onInspiration: () => void;
  isProcessing: boolean;
  aiMode: AIModelMode;
  onModeChange: (mode: AIModelMode) => void;
}

export const AIChat: React.FC<AIChatProps> = ({ history, onSendMessage, onInspiration, isProcessing, aiMode, onModeChange }) => {
  const [input, setInput] = useState('');
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [history, isProcessing]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (input.trim() && !isProcessing) {
      onSendMessage(input);
      setInput('');
    }
  };

  const formatReport = (text: string) => {
    return text.split('\n').map((line, i) => {
      if (line.startsWith('[') && line.includes(']')) {
        return (
          <div key={i} className="flex items-center gap-2 mt-4 md:mt-5 mb-2 first:mt-0">
            <ChevronRight className="w-3 h-3 md:w-3.5 md:h-3.5 text-[#4F46E5]" />
            <span className="text-[9px] md:text-[10px] font-bold uppercase tracking-[0.15em] md:tracking-[0.2em] text-[#4F46E5]/80">
              {line.replace('[', '').replace(']', '')}
            </span>
          </div>
        );
      }
      return <p key={i} className="mb-2 leading-relaxed break-words">{line}</p>;
    });
  };

  return (
    <div className="flex flex-col h-full bg-[#FFFFFF] border-l border-[#E2E8F0] relative">
      {/* Assistant Header */}
      <div className="flex px-4 md:px-6 py-4 md:py-5 border-b border-[#F1F5F9] items-center justify-between bg-white shrink-0">
        <div className="flex items-center gap-2.5 md:gap-3">
          <div className="p-1.5 md:p-2 rounded-xl bg-[#EEF2FF] border border-[#E0E7FF]">
            <BrainCircuit className="w-4 h-4 md:w-5 md:h-5 text-[#4F46E5]" />
          </div>
          <div className="flex flex-col">
            <h2 className="text-xs md:text-sm font-bold tracking-tight text-[#0F172A]">Neural Architect</h2>
            <div className="flex items-center gap-1">
               {aiMode === 'fast' ? (
                 <>
                   <Bolt className="w-2 h-2 md:w-2.5 md:h-2.5 text-[#4F46E5]" />
                   <span className="text-[7px] md:text-[8px] text-[#4F46E5] font-bold uppercase tracking-widest">Fast Engine</span>
                 </>
               ) : (
                 <>
                   <Cpu className="w-2 h-2 md:w-2.5 md:h-2.5 text-[#C9A24D]" />
                   <span className="text-[7px] md:text-[8px] text-[#C9A24D] font-bold uppercase tracking-widest">Think Engine</span>
                 </>
               )}
            </div>
          </div>
        </div>
        <div className="flex items-center gap-1.5 md:gap-2">
          {isProcessing && (
             <div className="hidden sm:flex items-center gap-1.5 px-2 md:px-3 py-1 rounded-full bg-[#FDF6E3] border border-[#F3E8C9] animate-pulse">
               <span className="text-[7px] md:text-[8px] font-bold uppercase tracking-widest text-[#C9A24D]">Working...</span>
             </div>
          )}
          <div className="flex bg-[#F1F5F9] p-0.5 md:p-1 rounded-lg border border-[#E2E8F0]">
            <button 
              onClick={() => onModeChange('fast')}
              title="Fast Engine (Lite)"
              className={`p-1 rounded-md transition-all ${aiMode === 'fast' ? 'bg-white text-[#4F46E5] shadow-sm' : 'text-[#94A3B8]'}`}
            >
              <Bolt className="w-3 h-3 md:w-3.5 md:h-3.5" />
            </button>
            <button 
              onClick={() => onModeChange('thinking')}
              title="Deep Thinking (Pro)"
              className={`p-1 rounded-md transition-all ${aiMode === 'thinking' ? 'bg-white text-[#C9A24D] shadow-sm' : 'text-[#94A3B8]'}`}
