        {isProcessing && (
          <div className="flex gap-3 md:gap-5">
            <div className="shrink-0 w-8 h-8 md:w-10 md:h-10 rounded-xl md:rounded-2xl bg-white border border-[#F3E8C9] flex items-center justify-center shadow-md">
              <Loader2 className="w-4 h-4 md:w-5 md:h-5 text-[#C9A24D] animate-spin" />
            </div>
            <div className="flex-1 flex flex-col gap-2">
               <div className="bg-white border border-[#E2E8F0] p-4 rounded-2xl text-[9px] md:text-[10px] font-bold uppercase tracking-widest text-[#94A3B8] flex items-center gap-2 shadow-sm">
                 <RefreshCw className="w-3 h-3 animate-spin text-[#C9A24D]" />
