        </div>
        <div className="flex items-center gap-2">
          <button onClick={handleKeySelectionManual} className="hidden sm:flex items-center gap-2 px-3 py-1.5 rounded-lg border text-[10px] font-bold uppercase hover:bg-slate-50">
