        </div>

        <aside className={`fixed md:static inset-y-0 right-0 w-full md:w-[400px] bg-white border-l z-50 transition-transform duration-300 ${isRightSidebarOpen || activeMobileView === 'chat' ? 'translate-x-0' : 'translate-x-full md:translate-x-0'}`}>
          <AIChat 
            history={chatHistory} 
            onSendMessage={processGeneration} 
            onInspiration={handleInspiration}
