      </main>

      <footer className="h-14 border-t bg-white flex items-center justify-around md:hidden shrink-0">
        <button onClick={() => setActiveMobileView('staging')} className={`flex flex-col items-center gap-1 ${activeMobileView === 'staging' ? 'text-indigo-600' : 'text-slate-400'}`}>
