        </button>
        <button onClick={() => setActiveMobileView('chat')} className={`flex flex-col items-center gap-1 ${activeMobileView === 'chat' ? 'text-indigo-600' : 'text-slate-400'}`}>
          <MessageSquareCode className="w-5 h-5" /><span className="text-[8px] font-bold uppercase">Architect</span>
