        <button onClick={() => setActiveMobileView('logs')} className={`flex flex-col items-center gap-1 ${activeMobileView === 'logs' ? 'text-indigo-600' : 'text-slate-400'}`}>
          <Terminal className="w-5 h-5" /><span className="text-[8px] font-bold uppercase">Console</span>
        </button>
      </footer>
    </div>
  );
};

export default App;

