import React, { useState, useCallback, useEffect, useRef, useMemo } from 'react';
import { AssetUploader } from './components/AssetUploader';
import { GameRunner } from './components/GameRunner';
import { AIChat } from './components/AIChat';
import { generateGame, brainstormGame } from './services/gemini';
import { GameAsset, GenerationStatus, GeneratedGame, ChatMessage, AIModelMode } from './types';
import { Box, Monitor, Sparkles, BoxSelect, Menu, X, MessageSquareCode, BrainCircuit, RefreshCw, Cpu, Zap, Maximize2, Bolt, Download, ShieldCheck } from 'lucide-react';

type ViewMode = 'editor' | 'preview';

const App: React.FC = () => {
  const [viewMode, setViewMode] = useState<ViewMode>('editor');
  const [assets, setAssets] = useState<GameAsset[]>([]);
  const [status, setStatus] = useState<GenerationStatus>({ step: 'idle', message: '' });
  const [game, setGame] = useState<GeneratedGame | null>(null);
  const [chatHistory, setChatHistory] = useState<ChatMessage[]>([]);
  const [aiMode, setAiMode] = useState<AIModelMode>('thinking');
  const [isLeftSidebarOpen, setIsLeftSidebarOpen] = useState(false);
  const [isRightSidebarOpen, setIsRightSidebarOpen] = useState(false);
  const [activeMobileView, setActiveMobileView] = useState<'staging' | 'chat'>('staging');
  const [isLiveSyncing, setIsLiveSyncing] = useState(false);

  const prevAssetsCount = useRef(0);
  const autoSyncTimer = useRef<ReturnType<typeof setTimeout> | null>(null);
  const iframeRef = useRef<HTMLIFrameElement>(null);

  const processGeneration = useCallback(async (instruction: string, isAutoSync: boolean = false) => {
    if (!isAutoSync) {
      setStatus({ step: 'analyzing', message: 'Architecting...' });
      setChatHistory(prev => [...prev, { role: 'user', text: instruction }]);
    } else {
      setIsLiveSyncing(true);
    }

    try {
      const result = await generateGame(instruction, assets, chatHistory, game?.code || "", aiMode);
      setGame({ code: result.code, title: result.title });
      if (!isAutoSync) {
        setChatHistory(prev => [...prev, { role: 'ai', text: result.explanation, suggestions: result.suggestions }]);
      }
      setStatus({ step: 'ready', message: 'Ready.' });
      setIsLiveSyncing(false);
    } catch (error: any) {
      console.error(error);
      setStatus({ step: 'error', message: 'Error' });
      setIsLiveSyncing(false);
    }
  }, [assets, chatHistory, game, aiMode]);

  const handleInspiration = async () => {
    if (status.step !== 'idle' && status.step !== 'ready') return;
    setStatus({ step: 'analyzing', message: 'Brainstorming...' });
    try {
      const report = await brainstormGame(assets);
      setChatHistory(prev => [...prev, { role: 'ai', text: report }]);
      setStatus({ step: 'ready', message: 'Report Ready' });
    } catch (e: any) {
      setStatus({ step: 'ready', message: 'Ready' });
    }
  };

  const handleKeySelectionManual = async () => {
    if ((window as any).aistudio?.openSelectKey) {
      await (window as any).aistudio.openSelectKey();
    }
  };

  const integratedSrcDoc = useMemo(() => {
    if (!game) return "";
    const assetMap = assets.reduce((acc, asset) => { acc[asset.name] = asset.content; return acc; }, {} as Record<string, string>);
    return `
      <!DOCTYPE html>
      <html>
        <head>
          <script>
            window.getAssetUrl = (name) => {
              const data = ${JSON.stringify(assetMap)}[name];
              if (!data) return "";
              const blob = new Blob([Uint8Array.from(atob(data.split(',')[1] || data), c => c.charCodeAt(0))], { type: 'application/octet-stream' });
              return URL.createObjectURL(blob);
            };
          </script>
          <style>body { margin: 0; background: #000; overflow: hidden; height: 100vh; }</style>
        </head>
        <body>${game.code}</body>
      </html>
    `;
  }, [game, assets]);

  if (viewMode === 'preview' && game) {
    return <GameRunner code={game.code} title={game.title} assets={assets} onExit={() => setViewMode('editor')} />;
  }

  return (
    <div className="flex flex-col h-screen bg-[#F8FAFC] overflow-hidden">
      <header className="h-14 border-b bg-white flex items-center justify-between px-4 shrink-0 z-[100]">
        <div className="flex items-center gap-4">
          <button onClick={() => setIsLeftSidebarOpen(!isLeftSidebarOpen)} className="md:hidden p-2 text-slate-500"><Menu className="w-5 h-5" /></button>
          <div className="flex items-center gap-2">
            <Box className="w-5 h-5 text-indigo-600" />
            <span className="font-bold text-sm tracking-tight">FORGE STUDIO</span>
          </div>
        </div>
        <div className="flex items-center gap-2">
          <button onClick={handleKeySelectionManual} className="hidden sm:flex items-center gap-2 px-3 py-1.5 rounded-lg border text-[10px] font-bold uppercase hover:bg-slate-50">
            <ShieldCheck className="w-3.5 h-3.5 text-emerald-500" /> Key
          </button>
          {game && (
            <button onClick={() => setViewMode('preview')} className="bg-indigo-600 text-white px-4 py-1.5 rounded-lg text-[10px] font-bold uppercase shadow-lg hover:bg-indigo-700 transition-all">Preview</button>
          )}
          <button onClick={() => setIsRightSidebarOpen(!isRightSidebarOpen)} className="md:hidden p-2 text-slate-500"><MessageSquareCode className="w-5 h-5" /></button>
        </div>
      </header>

      <main className="flex-1 flex overflow-hidden relative">
        <aside className={`fixed md:static inset-y-0 left-0 w-[280px] bg-white border-r z-50 transition-transform duration-300 ${isLeftSidebarOpen ? 'translate-x-0' : '-translate-x-full md:translate-x-0'}`}>
          <div className="p-4 h-full overflow-y-auto no-scrollbar">
            <AssetUploader assets={assets} onAssetsChange={setAssets} />
          </div>
        </aside>

        <div className="flex-1 flex flex-col bg-[#F1F5F9] relative overflow-hidden">
          <div className={`flex-1 relative bg-[#0F172A] ${activeMobileView === 'staging' ? 'flex' : 'hidden md:flex'}`}>
            {game ? <iframe srcDoc={integratedSrcDoc} className="w-full h-full border-none" /> : (
              <div className="flex-1 flex flex-col items-center justify-center text-white/20 uppercase tracking-[0.5em] text-[10px]">
                <BoxSelect className="w-12 h-12 mb-4 opacity-10 animate-pulse" />
                Awaiting Neural Link
              </div>
            )}

            {/* Status indicators in the dark preview area */}
            <div className="absolute bottom-4 left-6 flex flex-col gap-1 pointer-events-none">
              <span className="text-[7px] font-bold text-white/20 uppercase tracking-[0.2em]">Substrate Pulse</span>
              <div className="flex items-center gap-2">
                <div className={`w-1.5 h-1.5 rounded-full ${status.step === 'ready' ? 'bg-[#4F46E5] shadow-[0_0_12px_rgba(79,70,229,0.8)]' : status.step === 'idle' ? 'bg-white/10' : 'bg-[#C9A24D] animate-pulse'}`} />
                <span className="text-[8px] font-bold text-white/40 uppercase tracking-widest">{status.message || 'Standby'}</span>
              </div>
            </div>

            {isLiveSyncing && (
              <div className="absolute top-4 right-4 flex items-center gap-2 px-3 py-1 bg-black/40 backdrop-blur-md border border-white/10 rounded-full">
                <RefreshCw className="w-3 h-3 text-indigo-400 animate-spin" />
                <span className="text-[8px] font-bold text-white/80 uppercase tracking-widest">Neural Sync</span>
              </div>
            )}
          </div>
        </div>

