            </div>
            <span className="font-black text-xs md:text-sm tracking-tighter text-slate-900 hidden sm:inline">FORGE STUDIO</span>
            <span className="font-black text-xs tracking-tighter text-slate-900 sm:hidden">FORGE</span>
          </div>
        </div>

        <div className="flex items-center gap-1.5 md:gap-3">
