              className="bg-indigo-600 text-white px-3 md:px-5 py-1.5 md:py-2 rounded-xl text-[10px] md:text-xs font-bold uppercase shadow-lg shadow-indigo-100 hover:bg-indigo-700 hover:shadow-indigo-200 transition-all active:scale-95"
            >
              <Maximize2 className="w-3.5 h-3.5 md:hidden" />
