import React, { useEffect, useRef, useState } from 'react';
import { ChatMessage, AIModelMode } from '../types';

interface AIChatProps {
  history: ChatMessage[];
  onSendMessage: (msg: string) => void;
  onInspiration: () => void;
  onLogicWeave: () => void;
  onAddAsset: (content: string) => void;
  isProcessing: boolean;
  aiMode: AIModelMode;
  onModeChange: (mode: AIModelMode) => void;
}

export const AIChat: React.FC<AIChatProps> = ({ 
  history, 
  onSendMessage, 
  onInspiration, 
  onLogicWeave,
  onAddAsset,
  isProcessing, 
  aiMode, 
  onModeChange 
}) => {
  const [input, setInput] = useState('');
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [history, isProcessing]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (input.trim() && !isProcessing) {
      onSendMessage(input);
      setInput('');
    }
  };

  const formatReport = (text: string) => {
    return text.split('\n').map((line, i) => {
      if (line.startsWith('[') && line.includes(']')) {
        return (
          <div key={i} className="flex items-center gap-2 mt-5 mb-2.5 first:mt-0">
            <ChevronRight className="w-3.5 h-3.5 text-indigo-600" />
            <span className="text-[10px] font-black uppercase tracking-widest text-indigo-600">
              {line.replace('[', '').replace(']', '')}
            </span>
          </div>
        );
      }
      return <p key={i} className="mb-2.5 leading-relaxed break-words font-medium text-slate-700">{line}</p>;
    });
  };

  return (
    <div className="flex flex-col h-full bg-white relative">
      {/* Assistant Header */}
      <div className="px-5 md:px-6 py-4 md:py-5 border-b border-slate-100 flex items-center justify-between shrink-0 bg-white/80 backdrop-blur-md sticky top-0 z-[55]">
        <div className="flex items-center gap-3">
          <div className="p-2 rounded-xl bg-indigo-50 border border-indigo-100 shadow-sm shrink-0">
            <BrainCircuit className="w-5 h-5 text-indigo-600" />
          </div>
          <div className="flex flex-col min-w-0">
            <h2 className="text-sm font-black tracking-tight text-slate-900 truncate">Neural Architect</h2>
            <div className="flex items-center gap-1.5">
               {aiMode === 'fast' ? (
                 <>
                   <Bolt className="w-2.5 h-2.5 text-indigo-600" />
                   <span className="text-[8px] text-indigo-600 font-black uppercase tracking-widest">Flash Engine</span>
                 </>
               ) : (
                 <>
                   <Cpu className="w-2.5 h-2.5 text-amber-500" />
                   <span className="text-[8px] text-amber-500 font-black uppercase tracking-widest">Think Engine</span>
                 </>
               )}
            </div>
          </div>
        </div>

        <div className="flex bg-slate-50 p-1 rounded-xl border border-slate-100">
          <button 
            onClick={() => onModeChange('fast')}
            title="Fast Mode"
            className={`p-1.5 rounded-lg transition-all ${aiMode === 'fast' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-400 hover:text-slate-600'}`}
          >
            <Bolt className="w-4 h-4" />
          </button>
          <button 
            onClick={() => onModeChange('thinking')}
            title="Reasoning Mode"
            className={`p-1.5 rounded-lg transition-all ${aiMode === 'thinking' ? 'bg-white text-amber-500 shadow-sm' : 'text-slate-400 hover:text-slate-600'}`}
          >
            <Cpu className="w-4 h-4" />
          </button>
        </div>
      </div>

      {/* Chat Messages */}
      <div ref={scrollRef} className="flex-1 overflow-y-auto p-5 md:p-8 space-y-8 no-scrollbar bg-slate-50/30">
        {history.length === 0 && (
          <div className="h-full flex flex-col items-center justify-center text-center px-8">
            <div className="w-16 h-16 bg-white border border-slate-100 rounded-[2rem] flex items-center justify-center mb-8 shadow-xl shadow-indigo-100/50">
              <Sparkles className="w-8 h-8 text-slate-200" />
            </div>
            <p className="text-[10px] md:text-xs font-black uppercase tracking-[0.3em] text-slate-300 leading-loose">
              Architect Offline.<br/>Buffers Required.
            </p>
          </div>
        )}

        {history.map((msg, i) => (
          <div key={i} className={`flex gap-4 md:gap-6 ${msg.role === 'user' ? 'flex-row-reverse' : ''} animate-in fade-in slide-in-from-bottom-4 duration-500`}>
            <div className={`shrink-0 w-9 h-9 md:w-11 md:h-11 rounded-2xl flex items-center justify-center border shadow-sm ${
              msg.role === 'user' ? 'bg-indigo-600 border-indigo-700 text-white' : 'bg-white border-slate-200 text-indigo-600'
            }`}>
              {msg.role === 'user' ? <User className="w-5 h-5" /> : <Bot className="w-5 h-5" />}
            </div>
            <div className={`flex flex-col gap-3 md:gap-4 max-w-[85%] md:max-w-[80%] ${msg.role === 'user' ? 'items-end' : 'items-start'}`}>
              <div className={`p-5 md:p-6 rounded-[1.75rem] text-xs md:text-sm shadow-xl shadow-slate-200/40 relative ${
                msg.role === 'user' 
                  ? 'bg-indigo-600 text-white rounded-tr-none' 
                  : 'bg-white text-slate-700 border border-slate-100 rounded-tl-none border-l-[3px] border-l-amber-400'
              }`}>
                {msg.role === 'ai' && (
                  <div className="flex items-center justify-between mb-4 pb-2.5 border-b border-slate-50">
                    <div className="flex items-center gap-2 opacity-40">
                      <Terminal className="w-3.5 h-3.5" />
                      <span className="text-[8px] font-black uppercase tracking-widest">Substrate Analysis</span>
                    </div>
                    {msg.isApplying && (
                      <div className="flex items-center gap-1.5 px-2.5 py-1 rounded-full bg-indigo-50 border border-indigo-100">
                        <Zap className="w-2.5 h-2.5 text-indigo-600 animate-pulse" />
                        <span className="text-[7px] font-black uppercase tracking-widest text-indigo-600">Active</span>
                      </div>
                    )}
                  </div>
                )}
                <div className="whitespace-pre-wrap">
                  {msg.role === 'ai' ? formatReport(msg.text) : msg.text}
                </div>

                {msg.role === 'ai' && msg.proposedLogicNodes && msg.proposedLogicNodes.length > 0 && (
                  <div className="mt-6 pt-4 border-t border-slate-100 space-y-3">
                    <div className="flex items-center gap-2 mb-2 text-indigo-600">
                      <Workflow className="w-4 h-4" />
                      <span className="text-[10px] font-black uppercase tracking-[0.2em]">Logic Proposals</span>
                    </div>
                    {msg.proposedLogicNodes.map((node, nIdx) => (
                      <div key={nIdx} className="group/node bg-slate-50 border border-slate-100 p-3 rounded-xl flex items-center justify-between gap-3 hover:border-indigo-200 transition-all">
                        <span className="text-[10px] md:text-[11px] font-bold text-slate-600 line-clamp-2 italic">"{node}"</span>
                        <button 
                          onClick={() => onAddAsset(node)}
                          title="Add to Project"
                          className="shrink-0 p-1.5 bg-white border border-slate-200 rounded-lg text-slate-400 hover:text-indigo-600 hover:border-indigo-200 hover:shadow-sm transition-all active:scale-90"
                        >
                          <Plus className="w-3.5 h-3.5" />
                        </button>
                      </div>
                    ))}
                  </div>
                )}
              </div>

              {msg.role === 'ai' && msg.suggestions && msg.suggestions.length > 0 && !isProcessing && (
                <div className="flex flex-wrap gap-2 animate-in fade-in slide-in-from-left-4 duration-700">
                  {msg.suggestions.map((suggestion, sIdx) => (
                    <button
                      key={sIdx}
                      onClick={() => onSendMessage(suggestion)}
                      className="group flex items-center gap-2 px-4 py-2 bg-white border border-slate-200 rounded-full hover:border-indigo-600 hover:shadow-lg transition-all active:scale-95"
                    >
                      <Lightbulb className="w-3.5 h-3.5 text-amber-500 group-hover:animate-pulse" />
                      <span className="text-[10px] font-black uppercase tracking-widest text-slate-500 group-hover:text-indigo-600">{suggestion}</span>
                    </button>
                  ))}
                </div>
              )}
            </div>
          </div>
        ))}

        {isProcessing && (
          <div className="flex gap-4 md:gap-6">
            <div className="shrink-0 w-9 h-9 md:w-11 md:h-11 rounded-2xl bg-white border border-amber-100 flex items-center justify-center shadow-md">
              <Loader2 className="w-5 h-5 text-amber-500 animate-spin" />
            </div>
            <div className="flex-1 flex flex-col gap-3">
               <div className="bg-white border border-slate-100 p-5 rounded-2xl text-[10px] font-black uppercase tracking-widest text-slate-400 flex items-center gap-3 shadow-sm">
                 <RefreshCw className="w-4 h-4 animate-spin text-amber-400" />
                 Synthesizing logical substrate...
               </div>
            </div>
          </div>
        )}
      </div>

      {/* Chat Input Area */}
      <form onSubmit={handleSubmit} className="p-5 md:p-8 bg-white border-t border-slate-100 shrink-0 sticky bottom-0 z-50">
        <div className="flex gap-2 mb-4 md:mb-5">
           <button 
             type="button"
             onClick={onInspiration}
             disabled={isProcessing}
             className="flex-1 group flex items-center justify-center gap-2 px-3 py-3 bg-amber-50 border border-amber-100 rounded-xl hover:bg-amber-100 hover:border-amber-200 transition-all active:scale-95 shadow-sm"
           >
              <Brain className="w-3.5 h-3.5 text-amber-600" />
              <span className="text-[9px] font-black uppercase tracking-widest text-amber-700">Brainstorm</span>
           </button>
           <button 
             type="button"
             onClick={onLogicWeave}
             disabled={isProcessing}
             className="flex-1 group flex items-center justify-center gap-2 px-3 py-3 bg-indigo-50 border border-indigo-100 rounded-xl hover:bg-indigo-100 hover:border-indigo-200 transition-all active:scale-95 shadow-sm"
           >
              <Workflow className="w-3.5 h-3.5 text-indigo-600" />
              <span className="text-[9px] font-black uppercase tracking-widest text-indigo-700">Logic Weaver</span>
           </button>
        </div>

        <div className="relative flex items-center">
          <input
            type="text"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            disabled={isProcessing}
            placeholder={isProcessing ? "Synthesizing..." : "Prompt Architect..."}
            className="w-full bg-slate-50 border border-slate-200 rounded-2xl md:rounded-[1.75rem] py-4.5 md:py-5 px-6 md:px-8 pr-16 md:pr-20 text-xs md:text-sm text-slate-900 font-bold focus:outline-none focus:border-indigo-600 focus:bg-white transition-all shadow-inner placeholder:text-slate-300"
          />
          <button
            type="submit"
            disabled={isProcessing || !input.trim()}
            className={`absolute right-2.5 md:right-3 p-3 md:p-4 rounded-xl md:rounded-2xl text-white disabled:opacity-20 transition-all shadow-xl active:scale-90 ${aiMode === 'thinking' ? 'bg-amber-500 shadow-amber-200 hover:bg-amber-600' : 'bg-indigo-600 shadow-indigo-200 hover:bg-indigo-700'}`}
          >
            <Send className="w-4.5 h-4.5" />
          </button>
        </div>
      </form>
    </div>
  );
};

import React, { useState, useCallback, useEffect, useRef, useMemo } from 'react';
import { AssetUploader } from './components/AssetUploader';
import { GameRunner } from './components/GameRunner';
import { AIChat } from './components/AIChat';
import { generateGame, brainstormGame, generateLogicNodes } from './services/gemini';
import { GameAsset, GenerationStatus, GeneratedGame, ChatMessage, AIModelMode } from './types';
import { Box, Monitor, Sparkles, BoxSelect, Menu, X, MessageSquareCode, BrainCircuit, RefreshCw, Cpu, Zap, Maximize2, Bolt, Download, ShieldCheck } from 'lucide-react';

type ViewMode = 'editor' | 'preview';

const App: React.FC = () => {
  const [viewMode, setViewMode] = useState<ViewMode>('editor');
  const [assets, setAssets] = useState<GameAsset[]>([]);
  const [status, setStatus] = useState<GenerationStatus>({ step: 'idle', message: '' });
  const [game, setGame] = useState<GeneratedGame | null>(null);
  const [chatHistory, setChatHistory] = useState<ChatMessage[]>([]);
  const [aiMode, setAiMode] = useState<AIModelMode>('thinking');
  const [isLeftSidebarOpen, setIsLeftSidebarOpen] = useState(false);
  const [isRightSidebarOpen, setIsRightSidebarOpen] = useState(false);
  const [activeMobileView, setActiveMobileView] = useState<'staging' | 'chat'>('staging');
  const [isLiveSyncing, setIsLiveSyncing] = useState(false);

  const prevAssetsCount = useRef(0);
  const autoSyncTimer = useRef<ReturnType<typeof setTimeout> | null>(null);
  const iframeRef = useRef<HTMLIFrameElement>(null);

  const processGeneration = useCallback(async (instruction: string, isAutoSync: boolean = false) => {
    if (!isAutoSync) {
      setStatus({ step: 'analyzing', message: 'Architecting...' });
      setChatHistory(prev => [...prev, { role: 'user', text: instruction }]);
    } else {
      setIsLiveSyncing(true);
    }

    try {
      const result = await generateGame(instruction, assets, chatHistory, game?.code || "", aiMode);
      setGame({ code: result.code, title: result.title });
      if (!isAutoSync) {
        setChatHistory(prev => [...prev, { 
          role: 'ai', 
          text: result.explanation, 
          suggestions: result.suggestions,
          proposedLogicNodes: result.proposedLogicNodes 
        }]);
      }
      setStatus({ step: 'ready', message: 'Ready.' });
      setIsLiveSyncing(false);
    } catch (error: any) {
      console.error(error);
      setStatus({ step: 'error', message: 'Error' });
      setIsLiveSyncing(false);
    }
  }, [assets, chatHistory, game, aiMode]);

  const handleInspiration = async () => {
    if (status.step !== 'idle' && status.step !== 'ready') return;
    setStatus({ step: 'analyzing', message: 'Brainstorming...' });
    try {
      const report = await brainstormGame(assets);
      setChatHistory(prev => [...prev, { role: 'ai', text: report }]);
      setStatus({ step: 'ready', message: 'Report Ready' });
    } catch (e: any) {
      setStatus({ step: 'ready', message: 'Ready' });
    }
  };

  const handleLogicWeave = async () => {
    if (status.step !== 'idle' && status.step !== 'ready') return;
    setStatus({ step: 'analyzing', message: 'Weaving Logic...' });
    try {
      const lastPrompt = chatHistory.filter(m => m.role === 'user').pop()?.text || "General Gameplay Logic";
      const nodes = await generateLogicNodes(lastPrompt, assets);
      setChatHistory(prev => [...prev, { 
        role: 'ai', 
        text: "I have synthesized a set of complex behavioral blueprints for your simulation. Review and integrate them below.",
        proposedLogicNodes: nodes 
      }]);
      setStatus({ step: 'ready', message: 'Logic Synthesized' });
    } catch (e: any) {
      setStatus({ step: 'ready', message: 'Ready' });
    }
  };

  const addAssetFromAI = (content: string) => {
    const newAsset: GameAsset = {
      id: Math.random().toString(36).substr(2, 9),
      name: `Logic_${assets.filter(a => a.type === 'dialogue').length + 1}`,
      type: 'dialogue',
      content: content,
      mimeType: 'text/plain',
      category: 'Logic'
    };
    setAssets(prev => [...prev, newAsset]);
  };

  const handleKeySelectionManual = async () => {
    if ((window as any).aistudio?.openSelectKey) {
      await (window as any).aistudio.openSelectKey();
    }
  };

  const integratedSrcDoc = useMemo(() => {
    if (!game) return "";
    const assetMap = assets.reduce((acc, asset) => { acc[asset.name] = asset.content; return acc; }, {} as Record<string, string>);
    return `
      <!DOCTYPE html>
      <html>
        <head>
          <meta name="viewport" content="width=device-width, initial-scale=1.0, maximum-scale=1.0, user-scalable=no">
          <script>
            window.getAssetUrl = (name) => {
              const data = ${JSON.stringify(assetMap)}[name];
              if (!data) return "";
              try {
                const parts = data.split(',');
                const mime = parts[0].match(/:(.*?);/)[1];
                const bstr = atob(parts[1]);
                let n = bstr.length;
                const u8arr = new Uint8Array(n);
                while(n--) u8arr[n] = bstr.charCodeAt(n);
                const blob = new Blob([u8arr], { type: mime });
                return URL.createObjectURL(blob);
              } catch(e) { return ""; }
            };
          </script>
          <style>
            body { margin: 0; background: #000; overflow: hidden; height: 100vh; width: 100vw; }
            canvas { display: block; width: 100% !important; height: 100% !important; }
          </style>
        </head>
        <body>${game.code}</body>
      </html>
    `;
  }, [game, assets]);

  if (viewMode === 'preview' && game) {
    return <GameRunner code={game.code} title={game.title} assets={assets} onExit={() => setViewMode('editor')} />;
  }

  return (
    <div className="flex flex-col h-screen bg-[#F8FAFC] overflow-hidden">
      <header className="h-14 md:h-16 border-b bg-white flex items-center justify-between px-4 md:px-6 shrink-0 z-[100]">
        <div className="flex items-center gap-2 md:gap-4">
          <button 
            onClick={() => setIsLeftSidebarOpen(!isLeftSidebarOpen)} 
            className="md:hidden p-2 text-slate-500 hover:bg-slate-50 rounded-lg transition-colors"
          >
            <Menu className="w-5 h-5" />
          </button>
          <div className="flex items-center gap-2">
            <div className="bg-indigo-600 p-1.5 rounded-lg shadow-sm shadow-indigo-100">
              <Box className="w-4 h-4 md:w-5 md:h-5 text-white" />
            </div>
            <span className="font-black text-xs md:text-sm tracking-tighter text-slate-900 hidden sm:inline uppercase">TEXT2GAME STUDIO</span>
            <span className="font-black text-xs tracking-tighter text-slate-900 sm:hidden uppercase">TEXT2GAME</span>
          </div>
        </div>

        <div className="flex items-center gap-1.5 md:gap-3">
          <button 
            onClick={handleKeySelectionManual} 
            className="flex items-center gap-2 px-2.5 md:px-4 py-1.5 md:py-2 rounded-xl border border-slate-200 text-[10px] md:text-xs font-bold uppercase hover:bg-slate-50 hover:border-slate-300 transition-all text-slate-600"
          >
            <ShieldCheck className="w-3.5 h-3.5 text-emerald-500" />
            <span className="hidden lg:inline">Config Key</span>
          </button>

          {game && (
            <button 
              onClick={() => setViewMode('preview')} 
              className="bg-indigo-600 text-white px-3 md:px-5 py-1.5 md:py-2 rounded-xl text-[10px] md:text-xs font-bold uppercase shadow-lg shadow-indigo-100 hover:bg-indigo-700 hover:shadow-indigo-200 transition-all active:scale-95"
            >
              <Maximize2 className="w-3.5 h-3.5 md:hidden" />
              <span className="hidden md:inline">Live Preview</span>
            </button>
          )}

          <button 
            onClick={() => {
              setIsRightSidebarOpen(!isRightSidebarOpen);
              if (!isRightSidebarOpen) setActiveMobileView('chat');
            }} 
            className="md:hidden p-2 text-slate-500 hover:bg-slate-50 rounded-lg transition-colors"
          >
            <MessageSquareCode className="w-5 h-5" />
          </button>
        </div>
      </header>

      <main className="flex-1 flex overflow-hidden relative">
        <aside className={`
          fixed md:static inset-y-0 left-0 w-[280px] bg-white border-r z-50 transition-transform duration-300 ease-in-out
          ${isLeftSidebarOpen ? 'translate-x-0 shadow-2xl md:shadow-none' : '-translate-x-full md:translate-x-0'}
        `}>
          <div className="p-4 h-full overflow-y-auto no-scrollbar scroll-smooth">
            <div className="md:hidden flex items-center justify-between mb-6 pb-2 border-b border-slate-100">
              <span className="text-[10px] font-black uppercase tracking-widest text-slate-400">Asset Matrix</span>
              <button onClick={() => setIsLeftSidebarOpen(false)} className="p-1 text-slate-400"><X className="w-4 h-4" /></button>
            </div>
            <AssetUploader assets={assets} onAssetsChange={setAssets} />
          </div>
        </aside>

        <div className="flex-1 flex flex-col bg-[#F1F5F9] relative overflow-hidden transition-all duration-300">
          <div className={`flex-1 relative bg-[#0F172A] ${activeMobileView === 'staging' ? 'flex' : 'hidden md:flex'}`}>
            {game ? (
              <div className="w-full h-full relative group">
                <iframe 
                  srcDoc={integratedSrcDoc} 
                  className="w-full h-full border-none shadow-2xl" 
                  sandbox="allow-scripts allow-modals allow-pointer-lock"
                />
                <button 
                  onClick={() => setViewMode('preview')}
                  className="absolute bottom-6 right-6 p-3 bg-white/10 backdrop-blur-md border border-white/20 text-white rounded-2xl opacity-0 group-hover:opacity-100 transition-opacity hover:bg-white/20"
                >
                  <Maximize2 className="w-5 h-5" />
                </button>
              </div>
            ) : (
              <div className="flex-1 flex flex-col items-center justify-center text-center p-8">
                <div className="w-20 h-20 md:w-24 md:h-24 bg-white/5 border border-white/10 rounded-[2rem] flex items-center justify-center mb-6 animate-pulse">
                  <BoxSelect className="w-8 h-8 md:w-10 md:h-10 text-white/10" />
                </div>
                <h3 className="text-white/20 font-black uppercase tracking-[0.4em] text-[10px] md:text-xs mb-2">Awaiting Neural Link</h3>
                <p className="text-white/10 text-[9px] font-bold uppercase tracking-widest max-w-[200px] leading-relaxed">Synthesis occurs once buffers are architected</p>
              </div>
            )}

            <div className="absolute bottom-6 left-6 flex flex-col gap-1.5 pointer-events-none">
              <span className="text-[8px] font-black text-white/20 uppercase tracking-[0.2em]">Substrate Pulse</span>
              <div className="flex items-center gap-2.5 bg-black/40 backdrop-blur-md px-3 py-1.5 rounded-xl border border-white/5">
                <div className={`w-2 h-2 rounded-full ${status.step === 'ready' ? 'bg-[#4F46E5] shadow-[0_0_12px_rgba(79,70,229,0.8)]' : status.step === 'idle' ? 'bg-white/10' : 'bg-[#C9A24D] animate-pulse'}`} />
                <span className="text-[9px] font-black text-white/60 uppercase tracking-widest">{status.message || 'Standby'}</span>
              </div>
            </div>

            {isLiveSyncing && (
              <div className="absolute top-6 right-6 flex items-center gap-2.5 px-4 py-2 bg-indigo-600/20 backdrop-blur-md border border-indigo-500/30 rounded-2xl animate-in fade-in slide-in-from-top-4 duration-500">
                <RefreshCw className="w-3.5 h-3.5 text-indigo-400 animate-spin" />
                <span className="text-[9px] font-black text-indigo-100 uppercase tracking-widest">Neural Sync</span>
              </div>
            )}
          </div>
        </div>

        <aside className={`
          fixed md:static inset-y-0 right-0 w-full md:w-[380px] lg:w-[450px] bg-white border-l z-50 transition-transform duration-300 ease-in-out
          ${isRightSidebarOpen || activeMobileView === 'chat' ? 'translate-x-0' : 'translate-x-full md:translate-x-0'}
        `}>
          <div className="h-full relative">
            <AIChat 
              history={chatHistory} 
              onSendMessage={processGeneration} 
              onInspiration={handleInspiration}
              onLogicWeave={handleLogicWeave}
              onAddAsset={addAssetFromAI}
              isProcessing={status.step !== 'idle' && status.step !== 'ready' && status.step !== 'error'} 
              aiMode={aiMode}
              onModeChange={setAiMode}
            />
            <button 
              onClick={() => {
                setIsRightSidebarOpen(false);
                if (activeMobileView === 'chat') setActiveMobileView('staging');
              }} 
              className="md:hidden absolute top-4 right-4 p-2 text-slate-400 hover:text-slate-600 z-[60]"
            >
              <X className="w-5 h-5" />
            </button>
          </div>
        </aside>

        {(isLeftSidebarOpen || (isRightSidebarOpen && activeMobileView !== 'chat')) && (
          <div 
            className="fixed inset-0 bg-slate-900/40 backdrop-blur-sm z-40 md:hidden"
            onClick={() => {
              setIsLeftSidebarOpen(false);
              setIsRightSidebarOpen(false);
            }}
          />
        )}
      </main>

      <footer className="h-14 border-t bg-white flex items-center justify-around md:hidden shrink-0 shadow-[0_-1px_10px_rgba(0,0,0,0.02)] z-[100]">
        <button 
          onClick={() => setActiveMobileView('staging')} 
          className={`flex flex-col items-center gap-1 transition-all ${activeMobileView === 'staging' ? 'text-indigo-600' : 'text-slate-400'}`}
        >
          <Monitor className="w-5 h-5" />
          <span className="text-[9px] font-black uppercase tracking-tighter">Staging</span>
        </button>
        <button 
          onClick={() => setActiveMobileView('chat')} 
          className={`flex flex-col items-center gap-1 transition-all ${activeMobileView === 'chat' ? 'text-indigo-600' : 'text-slate-400'}`}
        >
          <div className="relative">
            <MessageSquareCode className="w-5 h-5" />
            {isLiveSyncing && <span className="absolute -top-1 -right-1 w-2.5 h-2.5 bg-indigo-600 rounded-full animate-pulse border-2 border-white" />}
          </div>
          <span className="text-[9px] font-black uppercase tracking-tighter">Architect</span>
        </button>
      </footer>
    </div>
  );
};

export default App;

{
  "name": "TEXT2GAME",
  "description": "An AI-powered game development platform where you upload assets and prompts to generate fully playable web games instantly.",
  "requestFramePermissions": [
    "camera",
    "microphone"
  ]
}

import React, { useState, useCallback, useEffect, useRef, useMemo } from 'react';
import { AssetUploader } from './components/AssetUploader';
import { GameRunner } from './components/GameRunner';
import { AIChat } from './components/AIChat';
import { generateGame, brainstormGame, generateLogicNodes } from './services/gemini';
import { GameAsset, GenerationStatus, GeneratedGame, ChatMessage, AIModelMode } from './types';
import { Box, Monitor, Sparkles, BoxSelect, Menu, X, MessageSquareCode, BrainCircuit, RefreshCw, Cpu, Zap, Maximize2, Bolt, Download, ShieldCheck } from 'lucide-react';

type ViewMode = 'editor' | 'preview';

const App: React.FC = () => {
  const [viewMode, setViewMode] = useState<ViewMode>('editor');
  const [assets, setAssets] = useState<GameAsset[]>([]);
  const [status, setStatus] = useState<GenerationStatus>({ step: 'idle', message: '' });
  const [game, setGame] = useState<GeneratedGame | null>(null);
  const [chatHistory, setChatHistory] = useState<ChatMessage[]>([]);
  const [aiMode, setAiMode] = useState<AIModelMode>('thinking');
  const [isLeftSidebarOpen, setIsLeftSidebarOpen] = useState(false);
  const [isRightSidebarOpen, setIsRightSidebarOpen] = useState(false);
  const [activeMobileView, setActiveMobileView] = useState<'staging' | 'chat'>('staging');
  const [isLiveSyncing, setIsLiveSyncing] = useState(false);

  const prevAssetsCount = useRef(0);
  const autoSyncTimer = useRef<ReturnType<typeof setTimeout> | null>(null);
  const iframeRef = useRef<HTMLIFrameElement>(null);

  const processGeneration = useCallback(async (instruction: string, isAutoSync: boolean = false) => {
    if (!isAutoSync) {
      setStatus({ step: 'analyzing', message: 'Architecting...' });
      setChatHistory(prev => [...prev, { role: 'user', text: instruction }]);
    } else {
      setIsLiveSyncing(true);
    }

    try {
      const result = await generateGame(instruction, assets, chatHistory, game?.code || "", aiMode);
      setGame({ code: result.code, title: result.title });
      if (!isAutoSync) {
        setChatHistory(prev => [...prev, { 
          role: 'ai', 
          text: result.explanation, 
          suggestions: result.suggestions,
          proposedLogicNodes: result.proposedLogicNodes 
        }]);
      }
      setStatus({ step: 'ready', message: 'Ready.' });
      setIsLiveSyncing(false);
    } catch (error: any) {
      console.error(error);
      setStatus({ step: 'error', message: 'Error' });
      setIsLiveSyncing(false);
    }
  }, [assets, chatHistory, game, aiMode]);

  const handleInspiration = async () => {
    if (status.step !== 'idle' && status.step !== 'ready') return;
    setStatus({ step: 'analyzing', message: 'Brainstorming...' });
    try {
      const report = await brainstormGame(assets);
      setChatHistory(prev => [...prev, { role: 'ai', text: report }]);
      setStatus({ step: 'ready', message: 'Report Ready' });
    } catch (e: any) {
      setStatus({ step: 'ready', message: 'Ready' });
    }
  };

  const handleLogicWeave = async () => {
    if (status.step !== 'idle' && status.step !== 'ready') return;
    setStatus({ step: 'analyzing', message: 'Weaving Logic...' });
    try {
      const lastPrompt = chatHistory.filter(m => m.role === 'user').pop()?.text || "General Gameplay Logic";
      const nodes = await generateLogicNodes(lastPrompt, assets);
      setChatHistory(prev => [...prev, { 
        role: 'ai', 
        text: "I have synthesized a set of complex behavioral blueprints for your simulation. Review and integrate them below.",
        proposedLogicNodes: nodes 
      }]);
      setStatus({ step: 'ready', message: 'Logic Synthesized' });
    } catch (e: any) {
      setStatus({ step: 'ready', message: 'Ready' });
    }
  };

  const addAssetFromAI = (content: string) => {
    const newAsset: GameAsset = {
      id: Math.random().toString(36).substr(2, 9),
      name: `Logic_${assets.filter(a => a.type === 'dialogue').length + 1}`,
      type: 'dialogue',
      content: content,
      mimeType: 'text/plain',
      category: 'Logic'
    };
    setAssets(prev => [...prev, newAsset]);
  };

  const handleDownload = () => {
    if (!game) return;

    const assetMap = assets.reduce((acc, asset) => {
      acc[asset.name] = asset.content;
      return acc;
    }, {} as Record<string, string>);

    const portableHtml = `
<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <title>${game.title}</title>
  <meta name="viewport" content="width=device-width, initial-scale=1.0, maximum-scale=1.0, user-scalable=no">
  <script>
    window.getAssetUrl = (name) => {
      const data = ${JSON.stringify(assetMap)}[name];
      if (!data) return "";
      try {
        const parts = data.split(',');
        const mime = parts[0].match(/:(.*?);/)[1];
        const bstr = atob(parts[1]);
        let n = bstr.length;
        const u8arr = new Uint8Array(n);
        while(n--) u8arr[n] = bstr.charCodeAt(n);
        const blob = new Blob([u8arr], { type: mime });
        return URL.createObjectURL(blob);
      } catch(e) { return ""; }
    };
  </script>
  <style>
    body { margin: 0; background: #000; overflow: hidden; height: 100vh; width: 100vw; }
    canvas { display: block; width: 100% !important; height: 100% !important; }
  </style>
</head>
<body>
  ${game.code}
</body>
</html>
    `;

    const blob = new Blob([portableHtml], { type: 'text/html' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `${game.title.replace(/\s+/g, '_').toLowerCase()}.html`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  };

  const handleKeySelectionManual = async () => {
    if ((window as any).aistudio?.openSelectKey) {
      await (window as any).aistudio.openSelectKey();
    }
  };

  const integratedSrcDoc = useMemo(() => {
    if (!game) return "";
    const assetMap = assets.reduce((acc, asset) => { acc[asset.name] = asset.content; return acc; }, {} as Record<string, string>);
    return `
      <!DOCTYPE html>
      <html>
        <head>
          <meta name="viewport" content="width=device-width, initial-scale=1.0, maximum-scale=1.0, user-scalable=no">
          <script>
            window.getAssetUrl = (name) => {
              const data = ${JSON.stringify(assetMap)}[name];
              if (!data) return "";
              try {
                const parts = data.split(',');
                const mime = parts[0].match(/:(.*?);/)[1];
                const bstr = atob(parts[1]);
                let n = bstr.length;
                const u8arr = new Uint8Array(n);
                while(n--) u8arr[n] = bstr.charCodeAt(n);
                const blob = new Blob([u8arr], { type: mime });
                return URL.createObjectURL(blob);
              } catch(e) { return ""; }
            };
          </script>
          <style>
            body { margin: 0; background: #000; overflow: hidden; height: 100vh; width: 100vw; }
            canvas { display: block; width: 100% !important; height: 100% !important; }
          </style>
        </head>
        <body>${game.code}</body>
      </html>
    `;
  }, [game, assets]);

  if (viewMode === 'preview' && game) {
