              />
            )}

            {/* Import View - Hidden file input */}
            <input
              type="file"
              ref={fileInputRef}
              onChange={handleFileChange}
              accept=".json"
              className="hidden"
            />
          </div>
        </div>
      </div>
    </div>
  );
};

// Helper for unique IDs
const getNextProjectId = () => `unsaved_${Math.random().toString(36).substr(2, 9)}`;

