 * Saves or updates an existing project.
 * @param projectId The ID of the project to save.
 * @param projectName The new name for the project.
 * @param state The current ProjectState to save.
 */
export const saveProject = (
  projectId: string,
  projectName: string,
  state: ProjectState
): ProjectMetadata => {
  const now = Date.now();
  let allMetadata = loadAllProjectMetadata();
  const index = allMetadata.findIndex((p) => p.id === projectId);

  let metadataToSave: ProjectMetadata;

  if (index !== -1) {
    // Update existing project
    metadataToSave = {
      ...allMetadata[index],
      name: projectName,
      lastModified: now,
      isDirty: false,
    };
    allMetadata[index] = metadataToSave;
  } else {
    // This case should ideally not happen if projectId is managed correctly,
    // but acts as a safeguard to create if not found.
    metadataToSave = {
      id: projectId,
      name: projectName,
      createdAt: now,
      lastModified: now,
      versionCount: 0, // Will be updated by addProjectVersion
      isDirty: false,
    };
    allMetadata.push(metadataToSave);
  }

  saveProjectState(projectId, state);
  addProjectVersion(projectId, state); // Add a new version on explicit save
  saveAllProjectMetadata(allMetadata);

  return metadataToSave;
};

/**
 * Loads a project by its ID.
 * @param projectId The ID of the project to load.
 */
export const loadProject = (projectId: string): Project | null => {
  const metadata = loadAllProjectMetadata().find((p) => p.id === projectId);
  if (!metadata) return null;

  const state = loadProjectState(projectId);
  if (!state) return null; // State could be missing or corrupted

  const versions = loadProjectVersions(projectId);

  return { metadata, state, versions };
};

/**
 * Deletes a project by its ID.
 * @param projectId The ID of the project to delete.
 */
export const deleteProject = (projectId: string): void => {
  let allMetadata = loadAllProjectMetadata();
  const updatedMetadata = allMetadata.filter((p) => p.id !== projectId);
  saveAllProjectMetadata(updatedMetadata);
  deleteProjectData(projectId); // Clear actual project data and versions
};

/**
 * Duplicates a project.
 * @param sourceProjectId The ID of the project to duplicate.
 * @param newName The name for the new duplicated project.
 */
export const duplicateProject = (
  sourceProjectId: string,
  newName: string
): Project | null => {
  const sourceProject = loadProject(sourceProjectId);
  if (!sourceProject) return null;

  const now = Date.now();
  const newProjectId = getNextProjectId();

  const newMetadata: ProjectMetadata = {
    ...sourceProject.metadata,
    id: newProjectId,
    name: newName,
    createdAt: now,
    lastModified: now,
    isDirty: true,
  };

  saveProjectState(newProjectId, sourceProject.state);
  // Duplicate versions as well
  const duplicatedVersions = sourceProject.versions.map((v) => ({
    ...v,
    id: Math.random().toString(36).substr(2, 9), // New ID for version
  }));
  saveProjectVersions(newProjectId, duplicatedVersions);
  newMetadata.versionCount = duplicatedVersions.length;

  let allMetadata = loadAllProjectMetadata();
  saveAllProjectMetadata([...allMetadata, newMetadata]);

  return { metadata: newMetadata, state: sourceProject.state, versions: duplicatedVersions };
};

/**
 * Exports a project to a JSON file.
 * @param project The Project object to export.
 */
export const exportProject = (project: Project): void => {
  const exportData = {
    metadata: project.metadata,
    state: project.state,
    versions: project.versions,
  };
  const filename = `${project.metadata.name.replace(/\s+/g, '_').toLowerCase()}.json`;
  const blob = new Blob([JSON.stringify(exportData, null, 2)], {
    type: 'application/json',
  });
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url;
  a.download = filename;
  document.body.appendChild(a);
  a.click();
  document.body.removeChild(a);
  URL.revokeObjectURL(url);
};

/**
 * Imports a project from a JSON file.
 * @param file The JSON File object to import.
 */
export const importProject = async (file: File): Promise<Project | null> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = async (event) => {
      try {
        const importedData = JSON.parse(event.target?.result as string);
        if (
          !importedData ||
          !importedData.metadata ||
          !importedData.state
        ) {
          throw new Error('Invalid project file format.');
        }

        const now = Date.now();
        const newProjectId = getNextProjectId();

        const newMetadata: ProjectMetadata = {
          ...importedData.metadata,
          id: newProjectId, // Assign a new ID to avoid conflicts
          name: `${importedData.metadata.name} (Imported)`,
          createdAt: now,
          lastModified: now,
          isDirty: true,
        };

        saveProjectState(newProjectId, importedData.state);

        // Re-save versions, potentially re-compressing them if necessary
        const importedVersions = importedData.versions || [];
        saveProjectVersions(newProjectId, importedVersions.map(v => ({
            ...v,
            id: Math.random().toString(36).substr(2, 9), // New ID for each version
            state: compress(JSON.stringify(v.state)) // Ensure state is compressed
        })));
        newMetadata.versionCount = importedVersions.length;


        let allMetadata = loadAllProjectMetadata();
        saveAllProjectMetadata([...allMetadata, newMetadata]);

        resolve({ metadata: newMetadata, state: importedData.state, versions: importedVersions });
      } catch (error) {
        console.error('Error importing project:', error);
        reject(error);
      }
    };
    reader.onerror = (error) => reject(error);
    reader.readAsText(file);
  });
};

/**
 * Version History Management
 */

const MAX_VERSIONS = 10;

/**
 * Adds a new version to a project's history.
 * @param projectId The ID of the project.
 * @param state The current ProjectState to snapshot.
 * @param isInitial A boolean to indicate if it is the initial version (no trimming).
 */
export const addProjectVersion = (
  projectId: string,
  state: ProjectState,
  isInitial: boolean = false
): void => {
  let versions = loadProjectVersions(projectId);
  const now = Date.now();

  const newVersion: ProjectVersion = {
    id: Math.random().toString(36).substr(2, 9),
    timestamp: now,
    state: compress(JSON.stringify(state)),
    // thumbnail: captureThumbnail(state), // Future enhancement
  };

  versions.unshift(newVersion); // Add to the beginning (most recent first)

  if (!isInitial && versions.length > MAX_VERSIONS) {
    versions = versions.slice(0, MAX_VERSIONS); // Trim old versions
  }

  saveProjectVersions(projectId, versions);

  // Update metadata with new version count
  let allMetadata = loadAllProjectMetadata();
  const index = allMetadata.findIndex((p) => p.id === projectId);
  if (index !== -1) {
    allMetadata[index].versionCount = versions.length;
    saveAllProjectMetadata(allMetadata);
  }
};

/**
 * Restores a project state from a specific version.
 * @param projectId The ID of the project.
 * @param versionId The ID of the version to restore.
 */
export const restoreProjectVersion = (
  projectId: string,
  versionId: string
): ProjectState | null => {
  const versions = loadProjectVersions(projectId);
  const version = versions.find((v) => v.id === versionId);
  if (!version) return null;

  try {
    return JSON.parse(decompress(version.state));
  } catch (e) {
    console.error(`Failed to decompress and parse version ${versionId}:`, e);
    return null;
  }
};

/**
 * Sharing & Collaboration Utilities
 */

const SHARE_LINK_PREFIX = '#/share/';

/**
 * Generates a shareable URL fragment by compressing project state.
 * @param project The project to share.
 */
export const generateShareLink = (project: Project): string => {
  const shareableState: ProjectState = {
    assets: project.state.assets,
    game: project.state.game,
    chatHistory: [], // Don't share full chat history, just initial prompt
    aiMode: project.state.aiMode,
  };
  if (project.state.chatHistory.length > 0) {
    shareableState.chatHistory = [project.state.chatHistory[0]]; // Share only the initial prompt
  }

  const compressedState = compress(JSON.stringify(shareableState));
  const encodedState = encodeURIComponent(compressedState);
  return `${window.location.origin}${window.location.pathname}${SHARE_LINK_PREFIX}${encodedState}`;
};

/**
 * Copies the project state as JSON to the clipboard.
 * @param project The project to copy.
 */
export const copyProjectToClipboard = async (
  project: Project
): Promise<void> => {
  try {
    const clipboardData = {
      metadata: project.metadata,
      state: project.state,
      versions: project.versions,
    };
    await navigator.clipboard.writeText(JSON.stringify(clipboardData, null, 2));
    // Provide user feedback (e.g., a toast notification)
    alert('Project data copied to clipboard!');
  } catch (err) {
    console.error('Failed to copy project to clipboard:', err);
    alert('Failed to copy project data. Please try again or check browser permissions.');
  }
};

/**
 * Function to initialize a project from a share link.
 * Returns a ProjectState if valid data is found in the URL.
 */
export const loadProjectFromShareLink = (): ProjectState | null => {
  const hash = window.location.hash;
  if (hash.startsWith(SHARE_LINK_PREFIX)) {
    try {
      const encodedState = hash.substring(SHARE_LINK_PREFIX.length);
      const compressedState = decompress(encodedState); // This might need to be decoded from URI first, then decompressed
      const decompressedState = decompress(compressedState); // Double decompress if URL encodes compressed string
      const state = JSON.parse(decompressedState);
      // Clean URL hash after loading
      window.history.replaceState(null, '', window.location.pathname + window.location.search);
      return state;
    } catch (e) {
      console.error('Failed to load project from share link:', e);
      return null;
    }
  }
  return null;
};

import { useState, useCallback, useEffect, useRef, useLayoutEffect } from 'react';
import { UndoRedoState } from '../types';

/**
 * A custom hook for managing state with undo/redo capabilities.
 * It tracks changes to the `present` state and allows navigating through `past` and `future` states.
 *
 * @param initialState The initial state value.
 * @param maxHistory The maximum number of past states to keep. Defaults to 20.
 * @returns An array containing:
 *   - `state`: The current (present) state.
 *   - `setState`: A function to update the state, which also records a new history entry.
 *   - `undo`: A function to revert to the previous state.
 *   - `redo`: A function to re-apply a previously undone state.
 *   - `canUndo`: A boolean indicating if undo is possible.
 *   - `canRedo`: A boolean indicating if redo is possible.
 *   - `clearHistory`: A function to clear all past and future history.
 *   - `initializeState`: A function to set the state and clear history, for external loading.
 */
export function useUndoRedo<T>(initialState: T, maxHistory: number = 20) {
  const [state, setStateInternal] = useState<UndoRedoState<T>>({
    past: [],
    present: initialState,
    future: [],
  });

  const stateRef = useRef(state.present);
  // Keep stateRef up-to-date with the latest present state
  useLayoutEffect(() => {
    stateRef.current = state.present;
  }, [state.present]);

  // Set initial state without adding to past if it's identical
  const initializeState = useCallback((newState: T) => {
    setStateInternal(prevState => {
      // Only set if different from current present, to avoid empty first undo
      // Also, perform a deep comparison for objects
      if (JSON.stringify(prevState.present) === JSON.stringify(newState)) {
        return prevState;
      }
      return {
        past: [],
        present: newState,
        future: [],
      };
    });
  }, []);

  // Update function that adds to history
  const setState = useCallback(
    (newPresent: T | ((prev: T) => T), recordHistory = true) => {
      setStateInternal((prevState) => {
        const nextPresent = typeof newPresent === 'function'
          ? (newPresent as (prev: T) => T)(prevState.present)
          : newPresent;

        // Don't record history if the state hasn't actually changed,
        // or if explicitly told not to record history.
        if (!recordHistory || JSON.stringify(prevState.present) === JSON.stringify(nextPresent)) {
          return { ...prevState, present: nextPresent };
        }

        const newPast = [...prevState.past, prevState.present];
        // Trim history if it exceeds maxHistory
        if (newPast.length > maxHistory) {
          newPast.shift(); // Remove the oldest past state
        }

        return {
          past: newPast,
          present: nextPresent,
          future: [], // Clear future on new state
        };
      });
    },
    [maxHistory]
  );

  const undo = useCallback(() => {
    setStateInternal((prevState) => {
      if (prevState.past.length === 0) return prevState;

      const newPast = [...prevState.past];
      const newPresent = newPast.pop()!; // Guaranteed to exist by check above
      return {
        past: newPast,
        present: newPresent,
        future: [prevState.present, ...prevState.future],
      };
    });
  }, []);

  const redo = useCallback(() => {
    setStateInternal((prevState) => {
      if (prevState.future.length === 0) return prevState;

      const newFuture = [...prevState.future];
      const newPresent = newFuture.shift()!; // Guaranteed to exist by check above
      return {
        past: [...prevState.past, prevState.present],
        present: newPresent,
        future: newFuture,
      };
    });
  }, []);

  const clearHistory = useCallback(() => {
    setStateInternal(prevState => ({
      past: [],
      present: prevState.present,
      future: [],
    }));
  }, []);

  // Keyboard shortcuts for undo/redo
  useEffect(() => {
    const handleKeyDown = (event: KeyboardEvent) => {
      if (event.ctrlKey || event.metaKey) { // Ctrl for Windows/Linux, Cmd for macOS
        if (event.key === 'z' && !event.shiftKey) {
          event.preventDefault();
          undo();
        } else if (event.key === 'y' || (event.key === 'z' && event.shiftKey)) {
          event.preventDefault();
          redo();
        }
      }
    };

    window.addEventListener('keydown', handleKeyDown);
    return () => {
      window.removeEventListener('keydown', handleKeyDown);
    };
  }, [undo, redo]);

  return [
    state.present,
    setState,
    undo,
    redo,
    state.past.length > 0, // canUndo
    state.future.length > 0, // canRedo
    clearHistory,
    initializeState // Expose initializer for external loading
  ] as const;
}

import { useState, useEffect, useRef, useCallback } from 'react';
import { ProjectState } from '../types';
import { saveAutosavedProject, loadAutosavedProject, clearAutosavedProject } from '../services/storage';

const AUTOSAVE_INTERVAL_MS = 30000; // Auto-save every 30 seconds

/**
 * A custom hook to automatically save the current project state to local storage.
 * It also provides status indicators for saving.
 *
 * @param state The ProjectState object to be autosaved.
 * @param projectId The ID of the currently active project (can be null for unsaved new projects).
 * @param lastManualSaveTimestamp Timestamp of the last explicit manual save.
 * @returns An array containing:
 *   - `isSaving`: A boolean indicating if the project is currently being autosaved.
 *   - `autosaveStatusMessage`: A string indicating the status ("Saved", "Saving...", "Error").
 *   - `loadLastAutosave`: A function to load the last autosaved project.
 *   - `clearLastAutosave`: A function to clear the last autosaved project.
 */
export function useAutoSave(
  state: ProjectState,
  projectId: string | null,
  lastManualSaveTimestamp: number | null
) {
  const [isSaving, setIsSaving] = useState(false);
  const [autosaveStatusMessage, setAutosaveStatusMessage] = useState('Standby');
  const stateRef = useRef(state); // Use a ref to get the latest state inside useEffect
  const projectIdRef = useRef(projectId);
  const lastManualSaveTimestampRef = useRef(lastManualSaveTimestamp);

  // Update refs when props change
  useEffect(() => {
    stateRef.current = state;
    projectIdRef.current = projectId;
    lastManualSaveTimestampRef.current = lastManualSaveTimestamp;
  }, [state, projectId, lastManualSaveTimestamp]);

  const triggerAutoSave = useCallback(() => {
    if (!stateRef.current) return;

    // Only autosave if the state has changed since the last autosave,
    // AND if it's different from the last manual save.
    // This prevents autosaving an identical state immediately after a manual save.
    const lastAutosaveData = loadAutosavedProject();
    const currentSerializedState = JSON.stringify(stateRef.current);

    if (
      lastAutosaveData &&
      lastAutosaveData.projectId === projectIdRef.current &&
      JSON.stringify(JSON.parse(lastAutosaveData.state)) === currentSerializedState
    ) {
      // State hasn't changed since last autosave, or it's the same as what was just autosaved for this project.
      setAutosaveStatusMessage(`Saved ${new Date(lastAutosaveData.timestamp).toLocaleTimeString()}`);
      return;
    }

    if (
      lastManualSaveTimestampRef.current &&
      lastAutosaveData &&
      lastAutosaveData.timestamp < lastManualSaveTimestampRef.current &&
      lastAutosaveData.projectId === projectIdRef.current
    ) {
        // If autosave is older than last manual save for the *same* project,
        // and the current state is likely what was just manually saved,
        // we can assume it's up to date. This is an optimization, not strictly necessary.
        setAutosaveStatusMessage(`Saved ${new Date(lastManualSaveTimestampRef.current).toLocaleTimeString()}`);
        return;
    }


    setIsSaving(true);
    setAutosaveStatusMessage('Saving...');
    try {
      saveAutosavedProject(projectIdRef.current, stateRef.current);
      setAutosaveStatusMessage(`Saved ${new Date().toLocaleTimeString()}`);
    } catch (e) {
      console.error('Autosave failed:', e);
      setAutosaveStatusMessage('Error saving!');
    } finally {
      setIsSaving(false);
    }
  }, []);

  useEffect(() => {
    const intervalId = setInterval(triggerAutoSave, AUTOSAVE_INTERVAL_MS);

    // Initial save after component mounts or state is set the first time
    const timeoutId = setTimeout(triggerAutoSave, 500); // Small delay to avoid race conditions on initial render

    return () => {
      clearInterval(intervalId);
      clearTimeout(timeoutId);
    };
  }, [triggerAutoSave]);

  const loadLastAutosave = useCallback(() => {
    try {
      const autosaved = loadAutosavedProject();
      if (autosaved) {
        return autosaved.state;
      }
    } catch (e) {
      console.error('Failed to load autosaved project:', e);
      alert('Could not load autosaved project. It might be corrupted.');
      clearAutosavedProject();
    }
    return null;
  }, []);

  const clearLastAutosave = useCallback(() => {
    clearAutosavedProject();
    setAutosaveStatusMessage('Standby');
  }, []);

  return { isSaving, autosaveStatusMessage, loadLastAutosave, clearLastAutosave };
}

import React, { useState, useRef, useEffect } from 'react';
import {
  FolderOpen,
  Save,
  Plus,
  Copy,
  Trash2,
  Share2,
  Download,
  Upload,
  FlaskConical,
  Version, // Note: Not used in this component, but available
  ChevronDown,
} from 'lucide-react';
import { ProjectMetadata, ProjectTemplate } from '../types';
import { PROJECT_TEMPLATES } from '../services/projectManager';

interface ProjectDropdownProps {
  currentProjectName: string;
  isDirty: boolean;
  onNewProject: (template?: ProjectTemplate) => void;
  onSaveProject: () => void;
  onOpenProject: () => void; // Opens the ProjectManagerModal to load
  onDuplicateProject: () => void; // Placeholder for now, ProjectManagerModal handles details
  onDeleteProject: () => void;
  onExportProject: () => void;
  onImportProject: (file: File) => void;
  onShareProject: () => void;
  onCopyProject: () => void;
}

export const ProjectDropdown: React.FC<ProjectDropdownProps> = ({
  currentProjectName,
  isDirty,
  onNewProject,
  onSaveProject,
  onOpenProject,
  onDuplicateProject,
  onDeleteProject,
  onExportProject,
  onImportProject,
  onShareProject,
  onCopyProject,
}) => {
  const [isOpen, setIsOpen] = useState(false);
  const [showTemplates, setShowTemplates] = useState(false);
  const dropdownRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
        setIsOpen(false);
        setShowTemplates(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => {
      document.removeEventListener('mousedown', handleClickOutside);
    };
  }, [dropdownRef]);

  const handleImportClick = () => {
    fileInputRef.current?.click();
  };

  const handleFileChange = (event: React.ChangeEvent<HTMLInputElement>) => {
    if (event.target.files && event.target.files.length > 0) {
      onImportProject(event.target.files[0]);
    }
    event.target.value = ''; // Clear the input so same file can be imported again
  };

  return (
    <div className="relative" ref={dropdownRef}>
      <button
        onClick={() => setIsOpen(!isOpen)}
        className="flex items-center gap-2 px-3 py-1.5 rounded-xl border border-slate-200 text-[10px] md:text-xs font-bold uppercase hover:bg-slate-50 hover:border-slate-300 transition-all text-slate-600 relative"
      >
        <FolderOpen className="w-3.5 h-3.5 text-slate-500" />
        <span className="hidden lg:inline">{currentProjectName || 'Untitled'}</span>
        {isDirty && (
          <span className="absolute -top-1 -right-1 w-2.5 h-2.5 bg-amber-500 rounded-full animate-pulse border-2 border-white" />
        )}
        <ChevronDown className={`w-3.5 h-3.5 transition-transform duration-200 ${isOpen ? 'rotate-180' : ''}`} />
      </button>

      {isOpen && (
        <div className="absolute left-0 top-full mt-2 w-64 bg-white border border-slate-200 rounded-2xl shadow-xl z-50 animate-in fade-in slide-in-from-top-1 overflow-hidden py-1">
          <div className="px-4 py-2 text-[9px] font-black uppercase tracking-widest text-slate-400 border-b border-slate-100">
            Project Actions
          </div>
          <button
            onClick={() => {
              onNewProject();
              setIsOpen(false);
            }}
            className="flex items-center gap-3 px-4 py-2.5 w-full text-left text-[11px] font-bold text-slate-700 hover:bg-slate-50 transition-colors"
          >
            <Plus className="w-4 h-4 text-emerald-500" /> New Project
