          >
            <Upload className="w-4 h-4 text-yellow-500" /> Import JSON
          </button>
          <input
            type="file"
            ref={fileInputRef}
            onChange={handleFileChange}
            accept=".json"
            className="hidden"
          />
          <div className="h-px bg-slate-100 my-1" />
          <button
            onClick={() => {
              onShareProject();
              setIsOpen(false);
            }}
            className="flex items-center gap-3 px-4 py-2.5 w-full text-left text-[11px] font-bold text-slate-700 hover:bg-slate-50 transition-colors"
          >
            <Share2 className="w-4 h-4 text-teal-500" /> Share Link
          </button>
          <button
            onClick={() => {
              onCopyProject();
              setIsOpen(false);
            }}
            className="flex items-center gap-3 px-4 py-2.5 w-full text-left text-[11px] font-bold text-slate-700 hover:bg-slate-50 transition-colors"
          >
            <Copy className="w-4 h-4 text-cyan-500" /> Copy Data
          </button>
          <div className="h-px bg-slate-100 my-1" />
          <button
            onClick={() => {
              if (window.confirm('Are you sure you want to delete this project? This cannot be undone.')) {
                onDeleteProject();
                setIsOpen(false);
              }
            }}
            className="flex items-center gap-3 px-4 py-2.5 w-full text-left text-[11px] font-bold text-red-500 hover:bg-red-50 transition-colors"
          >
            <Trash2 className="w-4 h-4 text-red-500" /> Delete Project
          </button>
        </div>
      )}
    </div>
  );
};

import React from 'react';
import { ProjectVersion } from '../types';
import { History, Clock, RefreshCw } from 'lucide-react';

interface VersionHistoryProps {
  versions: ProjectVersion[];
  onRestoreVersion: (versionId: string) => void;
  currentProjectStateCompressed: string; // The compressed string of the current state for comparison
}

export const VersionHistory: React.FC<VersionHistoryProps> = ({ versions, onRestoreVersion, currentProjectStateCompressed }) => {
  if (versions.length === 0) {
    return (
      <div className="flex flex-col items-center justify-center p-6 text-center text-slate-400">
        <History className="w-8 h-8 mb-4 opacity-50" />
        <p className="text-[10px] font-black uppercase tracking-widest">No versions yet.</p>
        <p className="text-[9px] font-medium mt-1">Save your project to create a version snapshot.</p>
      </div>
    );
  }

  return (
    <div className="flex flex-col gap-3">
      <div className="flex items-center gap-2 text-indigo-600 px-2">
        <History className="w-4 h-4" />
        <h3 className="text-[10px] font-black uppercase tracking-widest">Version History</h3>
      </div>
      <div className="space-y-2 max-h-[400px] overflow-y-auto no-scrollbar pb-2">
        {versions.map((version, index) => {
          // Compare compressed states to determine if this version is currently active
          const isCurrent = version.state === currentProjectStateCompressed;
          return (
            <div
              key={version.id}
              className={`flex items-center justify-between gap-3 p-3 rounded-xl border transition-all ${
                isCurrent ? 'bg-indigo-50 border-indigo-200' : 'bg-white border-slate-100 hover:border-slate-200'
              }`}
            >
              <div className="flex flex-col gap-0.5">
                <span className={`text-[10px] font-bold ${isCurrent ? 'text-indigo-700' : 'text-slate-700'}`}>
                  Version {versions.length - index}
                </span>
                <div className="flex items-center gap-1 text-[9px] text-slate-500 font-medium">
                  <Clock className="w-3 h-3" />
                  {new Date(version.timestamp).toLocaleString()}
                </div>
              </div>
              <button
                onClick={() => onRestoreVersion(version.id)}
                disabled={isCurrent}
                title={isCurrent ? 'This is the current version' : 'Restore this version'}
                className={`px-3 py-1.5 rounded-lg text-[9px] font-black uppercase tracking-wider transition-all flex items-center gap-2 ${
                  isCurrent
                    ? 'bg-transparent text-indigo-400 cursor-default'
                    : 'bg-indigo-600 text-white hover:bg-indigo-700 active:scale-95'
                }`}
              >
                <RefreshCw className="w-3.5 h-3.5" /> {isCurrent ? 'Active' : 'Restore'}
              </button>
            </div>
          );
        })}
      </div>
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import {
  ProjectMetadata,
  ProjectState,
  ProjectTemplate,
  ProjectVersion, // Not directly used here, but versions are passed
} from '../types';
import {
  getAllProjectMetadata,
  createNewProject as pmCreateNewProject,
  saveProject as pmSaveProject,
  loadProject as pmLoadProject,
  deleteProject as pmDeleteProject,
  duplicateProject as pmDuplicateProject,
  exportProject as pmExportProject,
  importProject as pmImportProject,
  restoreProjectVersion,
  PROJECT_TEMPLATES,
} from '../services/projectManager';
import { X, Plus, FolderOpen, Save, Copy, Trash2, Download, Upload, FlaskConical, History, Search, FileCog } from 'lucide-react';
import { VersionHistory } from './VersionHistory';
import { compress } from '../services/storage';

interface ProjectManagerModalProps {
  isOpen: boolean;
  onClose: () => void;
  onProjectLoaded: (projectState: ProjectState, metadata: ProjectMetadata) => void;
  onProjectCreated: (projectState: ProjectState, metadata: ProjectMetadata) => void;
  currentProjectId: string | null;
  currentProjectState: ProjectState;
}

type ModalView = 'list' | 'new' | 'saveAs' | 'versions';

export const ProjectManagerModal: React.FC<ProjectManagerModalProps> = ({
  isOpen,
  onClose,
  onProjectLoaded,
  onProjectCreated,
  currentProjectId,
  currentProjectState,
}) => {
  const [allProjects, setAllProjects] = useState<ProjectMetadata[]>([]);
  const [modalView, setModalView] = useState<ModalView>('list');
  const [newProjectName, setNewProjectName] = useState('Untitled Project');
  const [saveAsName, setSaveAsName] = useState('');
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedProjectId, setSelectedProjectId] = useState<string | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Find current project metadata for display/default values
  const currentProjectMetadata = allProjects.find(p => p.id === currentProjectId);

  useEffect(() => {
    if (isOpen) {
      setAllProjects(getAllProjectMetadata());
      setModalView('list'); // Always start on project list
      // Set default name for "Save As" based on current project or a generic name
      setSaveAsName(currentProjectMetadata?.name || 'Untitled Project');
      setSelectedProjectId(currentProjectId); // Pre-select current project in list view
    }
  }, [isOpen, currentProjectId, currentProjectMetadata]);

  // Helper to re-fetch projects after any CUD operation
  const refreshProjects = () => {
    setAllProjects(getAllProjectMetadata());
  };

  const handleCreateNewProject = (template?: ProjectTemplate) => {
    const newProject = pmCreateNewProject(template);
    onProjectCreated(newProject.state, newProject.metadata);
    refreshProjects();
    onClose();
  };

  const handleLoadProject = (projectId: string) => {
    const project = pmLoadProject(projectId);
    if (project) {
      onProjectLoaded(project.state, project.metadata);
      onClose();
    } else {
      alert('Failed to load project. It might be corrupted or missing.');
      pmDeleteProject(projectId); // Clean up corrupted entry
      refreshProjects();
    }
  };

  const handleSaveAs = () => {
    if (!saveAsName.trim()) {
      alert('Project name cannot be empty.');
      return;
    }
    // If saving a new project (no currentProjectId yet), assign a temporary ID for saving
    const idToSave = currentProjectId || `temp_${Math.random().toString(36).substr(2, 9)}`;
    const savedMetadata = pmSaveProject(idToSave, saveAsName, currentProjectState);
    onProjectLoaded(currentProjectState, savedMetadata); // Update active project context with newly saved data
    refreshProjects();
    onClose();
  };

  const handleDuplicateProject = (projectId: string) => {
    const originalProjectName = allProjects.find(p => p.id === projectId)?.name || 'Untitled';
    const newName = window.prompt('Enter new name for duplicated project:', `Copy of ${originalProjectName}`);
    if (newName && newName.trim()) {
      const duplicatedProject = pmDuplicateProject(projectId, newName.trim());
      if (duplicatedProject) {
        refreshProjects();
        // Optionally load the duplicated project
        // onProjectLoaded(duplicatedProject.state, duplicatedProject.metadata);
        // onClose();
      } else {
        alert('Failed to duplicate project.');
      }
    }
  };

  const handleDeleteProject = (projectId: string) => {
    if (window.confirm('Are you sure you want to delete this project? This cannot be undone.')) {
      pmDeleteProject(projectId);
      refreshProjects();
      if (currentProjectId === projectId) {
        // If current project deleted, create a new blank one
        handleCreateNewProject(); // This will close the modal as well
      }
      setSelectedProjectId(null); // Clear selection after deletion
    }
  };

  const handleExportProject = (project: ProjectMetadata) => {
    const fullProject = pmLoadProject(project.id);
    if (fullProject) {
      pmExportProject(fullProject);
    } else {
      alert('Failed to load project data for export.');
    }
  };

  const handleImportClick = () => {
    fileInputRef.current?.click();
  };

  const handleFileChange = async (event: React.ChangeEvent<HTMLInputElement>) => {
    if (event.target.files && event.target.files.length > 0) {
      try {
        const importedProject = await pmImportProject(event.target.files[0]);
        if (importedProject) {
          onProjectCreated(importedProject.state, importedProject.metadata);
          refreshProjects();
          onClose();
        }
      } catch (error) {
        alert(`Failed to import project: ${error instanceof Error ? error.message : String(error)}`);
      }
    }
    event.target.value = ''; // Clear input for re-import
  };

  const handleRestoreVersion = (versionId: string) => {
    if (!selectedProjectId) return;
    const restoredState = restoreProjectVersion(selectedProjectId, versionId);
    if (restoredState) {
      const metadata = allProjects.find(p => p.id === selectedProjectId);
      if (metadata) {
        onProjectLoaded(restoredState, { ...metadata, isDirty: true }); // Mark as dirty since it's a restored state
        onClose();
      }
    } else {
      alert('Failed to restore version.');
    }
  };

  const filteredProjects = allProjects.filter(project =>
    project.name.toLowerCase().includes(searchTerm.toLowerCase())
  ).sort((a, b) => b.lastModified - a.lastModified); // Sort by most recent first

  if (!isOpen) return null;

  const currentProjectFull = currentProjectId ? pmLoadProject(currentProjectId) : null;
  const currentCompressedState = compress(JSON.stringify(currentProjectState));

  return (
    <div className="fixed inset-0 z-[1200] flex items-center justify-center bg-slate-900/60 backdrop-blur-sm p-4 md:p-8 animate-in fade-in">
      <div className="relative bg-white rounded-3xl shadow-2xl w-full max-w-4xl max-h-[90vh] overflow-hidden flex flex-col transition-all duration-300">
        {/* Modal Header */}
        <div className="flex items-center justify-between p-5 md:p-6 border-b border-slate-100 shrink-0">
          <div className="flex items-center gap-3">
            <FileCog className="w-6 h-6 text-indigo-600" />
            <h2 className="text-xl font-black tracking-tight text-slate-900">Project Manager</h2>
          </div>
          <button
            onClick={onClose}
            className="p-2 text-slate-400 hover:text-slate-600 hover:bg-slate-50 rounded-lg transition-colors"
          >
            <X className="w-5 h-5" />
          </button>
        </div>

        {/* Modal Content */}
        <div className="flex-1 flex overflow-hidden">
          {/* Left Panel: Navigation/New Project */}
          <div className="w-60 bg-slate-50 border-r border-slate-100 p-5 flex flex-col shrink-0">
            <div className="flex flex-col gap-2 mb-6">
              <button
                onClick={() => setModalView('list')}
                className={`flex items-center gap-3 px-4 py-2 rounded-xl text-sm font-bold transition-all ${
                  modalView === 'list' ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-700 hover:bg-slate-100'
                }`}
              >
                <FolderOpen className="w-4 h-4" /> My Projects
              </button>
              <button
                onClick={() => setModalView('new')}
                className={`flex items-center gap-3 px-4 py-2 rounded-xl text-sm font-bold transition-all ${
                  modalView === 'new' ? 'bg-emerald-600 text-white shadow-md' : 'text-slate-700 hover:bg-slate-100'
                }`}
              >
                <Plus className="w-4 h-4" /> New Project
              </button>
              <button
                onClick={() => setModalView('saveAs')}
                className={`flex items-center gap-3 px-4 py-2 rounded-xl text-sm font-bold transition-all ${
                  modalView === 'saveAs' ? 'bg-purple-600 text-white shadow-md' : 'text-slate-700 hover:bg-slate-100'
                }`}
              >
                <Save className="w-4 h-4" /> Save As
              </button>
              <button
                onClick={() => {
                  handleImportClick(); // Trigger file input immediately
                }}
                className={`flex items-center gap-3 px-4 py-2 rounded-xl text-sm font-bold transition-all ${
                  modalView === 'import' ? 'bg-yellow-600 text-white shadow-md' : 'text-slate-700 hover:bg-slate-100'
                }`}
              >
                <Upload className="w-4 h-4" /> Import Project
              </button>
            </div>

            {selectedProjectId && (
                <div className="mt-auto pt-6 border-t border-slate-200">
                    <button
                        onClick={() => setModalView('versions')}
                        className={`flex items-center gap-3 px-4 py-2 rounded-xl text-sm font-bold w-full transition-all ${
                        modalView === 'versions' ? 'bg-blue-600 text-white shadow-md' : 'text-slate-700 hover:bg-slate-100'
                        }`}
                    >
                        <History className="w-4 h-4" /> Version History
                    </button>
                </div>
            )}
          </div>

          {/* Right Panel: Content based on modalView */}
          <div className="flex-1 p-5 md:p-6 overflow-y-auto no-scrollbar">
            {/* Project List View */}
            {modalView === 'list' && (
              <>
                <div className="relative mb-6">
                  <Search className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400" />
                  <input
                    type="text"
                    placeholder="Search projects..."
                    value={searchTerm}
                    onChange={(e) => setSearchTerm(e.target.value)}
                    className="w-full pl-12 pr-4 py-3 bg-slate-50 border border-slate-200 rounded-xl text-sm focus:outline-none focus:border-indigo-600 transition-all"
                  />
                </div>

                <div className="space-y-3">
                  {filteredProjects.length === 0 ? (
                    <div className="text-center p-8 text-slate-400">
                      <FolderOpen className="w-10 h-10 mx-auto mb-4 opacity-50" />
                      <p className="text-sm font-bold">No projects found.</p>
                      <p className="text-xs text-slate-500">Try creating a new one!</p>
                    </div>
                  ) : (
                    filteredProjects.map((project) => (
                      <div
                        key={project.id}
                        className={`group flex flex-col md:flex-row items-start md:items-center justify-between p-4 rounded-xl border transition-all ${
                          selectedProjectId === project.id ? 'bg-indigo-50 border-indigo-200' : 'bg-white border-slate-100 hover:border-slate-200'
                        }`}
                        onClick={() => setSelectedProjectId(project.id)}
                      >
                        <div className="flex-1 flex items-start gap-4 mb-3 md:mb-0 cursor-pointer">
                          {/* Thumbnail placeholder */}
                          <div className="w-12 h-12 bg-slate-100 rounded-lg flex items-center justify-center text-slate-300">
                            <FileCog className="w-6 h-6" />
                          </div>
                          <div className="flex flex-col">
                            <h4 className="text-sm font-bold text-slate-900">{project.name}</h4>
                            <p className="text-xs text-slate-500">
                              Modified: {new Date(project.lastModified).toLocaleDateString()}
                            </p>
                            <p className="text-[10px] text-slate-400">Versions: {project.versionCount}</p>
                          </div>
                        </div>
                        <div className="flex flex-wrap md:flex-nowrap gap-2 ml-auto">
                          <button
                            onClick={(e) => { e.stopPropagation(); handleLoadProject(project.id); }}
                            className="px-3 py-1.5 rounded-lg bg-indigo-600 text-white text-[10px] font-bold uppercase hover:bg-indigo-700 transition-colors active:scale-95"
                          >
                            Load
                          </button>
                          <button
                            onClick={(e) => { e.stopPropagation(); handleDuplicateProject(project.id); }}
                            className="px-3 py-1.5 rounded-lg border border-slate-200 text-slate-600 text-[10px] font-bold uppercase hover:bg-slate-50 transition-colors active:scale-95"
                          >
                            <Copy className="w-3.5 h-3.5" />
                          </button>
                          <button
                            onClick={(e) => { e.stopPropagation(); handleExportProject(project); }}
                            className="px-3 py-1.5 rounded-lg border border-slate-200 text-slate-600 text-[10px] font-bold uppercase hover:bg-slate-50 transition-colors active:scale-95"
                          >
                            <Download className="w-3.5 h-3.5" />
                          </button>
                          <button
                            onClick={(e) => { e.stopPropagation(); handleDeleteProject(project.id); }}
                            className="px-3 py-1.5 rounded-lg border border-red-200 text-red-500 text-[10px] font-bold uppercase hover:bg-red-50 transition-colors active:scale-95"
                          >
                            <Trash2 className="w-3.5 h-3.5" />
                          </button>
                        </div>
                      </div>
                    ))
                  )}
                </div>
              </>
            )}

            {/* New Project View */}
            {modalView === 'new' && (
              <div className="space-y-6">
                <h3 className="text-lg font-bold text-slate-900">Create New Project</h3>
                <div className="flex flex-col gap-2">
                  <label htmlFor="new-project-name" className="text-sm font-medium text-slate-700">Project Name</label>
                  <input
                    id="new-project-name"
                    type="text"
                    value={newProjectName}
                    onChange={(e) => setNewProjectName(e.target.value)}
                    placeholder="My Awesome Game"
                    className="w-full px-4 py-3 border border-slate-200 rounded-xl text-sm focus:outline-none focus:border-emerald-600"
                  />
                </div>
                <button
                  onClick={() => handleCreateNewProject()}
                  className="w-full py-3 bg-emerald-600 text-white rounded-xl text-sm font-bold hover:bg-emerald-700 transition-colors active:scale-95"
                >
                  Create Blank Project
                </button>

                <div className="relative flex items-center py-4">
                  <div className="flex-grow border-t border-slate-200"></div>
                  <span className="flex-shrink mx-4 text-slate-400 text-xs uppercase font-bold tracking-widest">OR</span>
                  <div className="flex-grow border-t border-slate-200"></div>
                </div>

                <h3 className="text-lg font-bold text-slate-900 mb-4">Start from Template</h3>
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  {PROJECT_TEMPLATES.map((template) => (
                    <button
                      key={template.id}
                      onClick={() => handleCreateNewProject(template)}
                      className="flex flex-col items-start gap-2 p-4 border border-indigo-100 rounded-xl hover:bg-indigo-50 transition-colors text-left active:scale-95 shadow-sm"
                    >
                      <FlaskConical className="w-5 h-5 text-indigo-500" />
                      <h4 className="text-sm font-bold text-slate-900">{template.name}</h4>
                      <p className="text-xs text-slate-600 line-clamp-2">{template.description}</p>
                    </button>
                  ))}
                </div>
              </div>
            )}

            {/* Save As View */}
            {modalView === 'saveAs' && (
              <div className="space-y-6">
                <h3 className="text-lg font-bold text-slate-900">Save Project As</h3>
                <div className="flex flex-col gap-2">
                  <label htmlFor="save-as-name" className="text-sm font-medium text-slate-700">Project Name</label>
                  <input
                    id="save-as-name"
                    type="text"
                    value={saveAsName}
                    onChange={(e) => setSaveAsName(e.target.value)}
                    placeholder="My New Game Name"
                    className="w-full px-4 py-3 border border-slate-200 rounded-xl text-sm focus:outline-none focus:border-purple-600"
                  />
                </div>
                <button
                  onClick={handleSaveAs}
                  className="w-full py-3 bg-purple-600 text-white rounded-xl text-sm font-bold hover:bg-purple-700 transition-colors active:scale-95"
                >
                  Save Current Project
                </button>
              </div>
            )}

            {/* Version History View */}
            {modalView === 'versions' && selectedProjectId && currentProjectFull && (
              <VersionHistory
                versions={currentProjectFull.versions || []}
                onRestoreVersion={handleRestoreVersion}
                currentProjectStateCompressed={currentCompressedState} // Pass compressed for comparison
              />
            )}

            {/* Import View - Hidden file input */}
            <input
              type="file"
              ref={fileInputRef}
              onChange={handleFileChange}
              accept=".json"
              className="hidden"
            />
          </div>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useCallback, useEffect, useRef, useMemo } from 'react';
import { AssetUploader } from './components/AssetUploader';
import { GameRunner } from './components/GameRunner';
import { AIChat } from './components/AIChat';
import { generateGame, brainstormGame, generateLogicNodes } from './services/gemini';
import {
  GameAsset,
  GenerationStatus,
  GeneratedGame,
  ChatMessage,
  AIModelMode,
  ProjectState,
  ProjectMetadata,
  ProjectTemplate,
} from './types';
import {
  Box,
  Monitor,
  Sparkles,
  BoxSelect,
  Menu,
  X,
  MessageSquareCode,
  BrainCircuit,
  RefreshCw,
  Cpu,
  Zap,
  Maximize2,
  Bolt,
  Download,
  ShieldCheck,
  Undo2,
  Redo2,
  CloudLightning,
} from 'lucide-react';

import { useUndoRedo } from './hooks/useUndoRedo';
import { useAutoSave } from './hooks/useAutoSave';
import { loadAutosavedProject, clearAutosavedProject, compress } from './services/storage';
import {
  getAllProjectMetadata,
  saveProject as pmSaveProject,
  loadProject as pmLoadProject, // Import loadProject to get full project data for export/copy
  loadProjectFromShareLink,
  generateShareLink,
  copyProjectToClipboard,
  deleteProject as pmDeleteProject,
  exportProject as pmExportProject,
  importProject as pmImportProject,
  createNewProject as pmCreateNewProject, // Also need this for the initial blank project
} from './services/projectManager';
import { ProjectDropdown } from './components/ProjectDropdown';
import { ProjectManagerModal } from './components/ProjectManagerModal';

type ViewMode = 'editor' | 'preview';

// Initial project state when no project is loaded
const DEFAULT_INITIAL_PROJECT_STATE: ProjectState = {
  assets: [],
  game: null,
  chatHistory: [],
  aiMode: 'thinking',
};

const App: React.FC = () => {
  const [viewMode, setViewMode] = useState<ViewMode>('editor');
  const [status, setStatus] = useState<GenerationStatus>({ step: 'idle', message: '' });
  const [isLiveSyncing, setIsLiveSyncing] = useState(false);

  // Project Management States
  const [activeProjectId, setActiveProjectId] = useState<string | null>(null);
  const [activeProjectName, setActiveProjectName] = useState('Untitled Project');
  const [isDirty, setIsDirty] = useState(false); // Tracks unsaved changes to the current project
  const [lastManualSaveTimestamp, setLastManualSaveTimestamp] = useState<number | null>(null);
  const [showProjectManager, setShowProjectManager] = useState(false);
  const [showAutosaveRecoveryPrompt, setShowAutosaveRecoveryPrompt] = useState(false);

  // Undo/Redo State (manages the core project data)
  const [
    projectState,
    setProjectState,
    undo,
    redo,
    canUndo,
    canRedo,
    clearHistory,
    initializeUndoRedoState,
  ] = useUndoRedo<ProjectState>(DEFAULT_INITIAL_PROJECT_STATE);

  const { assets, game, chatHistory, aiMode } = projectState;

  // Auto-Save Hook
  const { autosaveStatusMessage, loadLastAutosave, clearLastAutosave } = useAutoSave(
    projectState,
    activeProjectId,
    lastManualSaveTimestamp
  );

  // Update dirty state when projectState changes (except on initial load/set)
  const isInitialProjectStateLoad = useRef(true);
  useEffect(() => {
    if (isInitialProjectStateLoad.current) {
      isInitialProjectStateLoad.current = false;
      return;
    }
    // Only set dirty if the project has been actively edited, not just loaded/initialized.
    // This is a simple heuristic; a more robust solution would track specific actions.
    setIsDirty(true); 
  }, [projectState]);

  // Handle initial load (share link, autosave, or new project)
  useEffect(() => {
    const handleInitialLoad = () => {
      const shareLinkState = loadProjectFromShareLink();
      if (shareLinkState) {
        initializeUndoRedoState(shareLinkState);
        setActiveProjectId(null); // Share link is always an unsaved new project
        setActiveProjectName('Shared Project');
        setIsDirty(true);
        clearAutosavedProject(); // Clear autosave if loading from share link
        return;
      }

      const autosaved = loadAutosavedProject();
      if (autosaved && autosaved.state && Date.now() - autosaved.timestamp < 24 * 60 * 60 * 1000) { // Autosave within 24 hours
        // Prompt user for autosave recovery
        setShowAutosaveRecoveryPrompt(true);
      } else {
        // No valid autosave, or too old, start fresh
        handleCreateNewProject(); // This will initialize a new project
      }
    };
    handleInitialLoad();
  }, []); // Run only once on mount

  const handleRecoverAutosave = useCallback(() => {
    const autosaved = loadAutosavedProject();
    if (autosaved) {
      initializeUndoRedoState(autosaved.state);
      setActiveProjectId(autosaved.projectId); // If autosave was for an existing project, load its ID
      setActiveProjectName(
        getAllProjectMetadata().find((p) => p.id === autosaved.projectId)?.name || 'Recovered Project'
      );
      setIsDirty(true); // Recovered state is dirty until explicitly saved
      clearAutosavedProject();
    }
    setShowAutosaveRecoveryPrompt(false);
  }, [initializeUndoRedoState, clearAutosavedProject]);

  const handleDiscardAutosave = useCallback(() => {
    clearAutosavedProject();
    handleCreateNewProject(); // Start a fresh project
    setShowAutosaveRecoveryPrompt(false);
  }, [clearAutosavedProject]);

  // Update specific parts of ProjectState
  const setAssets = useCallback(
    (newAssets: GameAsset[]) => setProjectState((prev) => ({ ...prev, assets: newAssets })),
    [setProjectState]
  );
  const setGame = useCallback(
    (newGame: GeneratedGame | null) => setProjectState((prev) => ({ ...prev, game: newGame })),
    [setProjectState]
  );
  const setChatHistory = useCallback(
    (newHistory: ChatMessage[]) => setProjectState((prev) => ({ ...prev, chatHistory: newHistory })),
    [setProjectState]
  );
  const setAiMode = useCallback(
    (newMode: AIModelMode) => setProjectState((prev) => ({ ...prev, aiMode: newMode })),
    [setProjectState]
  );

  const processGeneration = useCallback(
    async (instruction: string, isAutoSync: boolean = false) => {
      if (!isAutoSync) {
        setStatus({ step: 'analyzing', message: 'Architecting...' });
        setChatHistory([...chatHistory, { role: 'user', text: instruction }]);
      } else {
        setIsLiveSyncing(true);
      }

      try {
        const result = await generateGame(instruction, assets, chatHistory, game?.code || '', aiMode);
        setGame({ code: result.code, title: result.title });
        if (!isAutoSync) {
          setChatHistory([
            ...chatHistory,
            {
              role: 'ai',
              text: result.explanation,
              suggestions: result.suggestions,
              proposedLogicNodes: result.proposedLogicNodes,
            },
          ]);
        }
        setStatus({ step: 'ready', message: 'Ready.' });
        setIsLiveSyncing(false);
      } catch (error: any) {
        console.error(error);
        setStatus({ step: 'error', message: 'Error' });
        setIsLiveSyncing(false);
      }
    },
    [assets, chatHistory, game, aiMode, setChatHistory, setGame]
  );

  const handleInspiration = async () => {
    if (status.step !== 'idle' && status.step !== 'ready') return;
    setStatus({ step: 'analyzing', message: 'Brainstorming...' });
    try {
      const report = await brainstormGame(assets);
      setChatHistory([...chatHistory, { role: 'ai', text: report }]);
      setStatus({ step: 'ready', message: 'Report Ready' });
    } catch (e: any) {
      setStatus({ step: 'ready', message: 'Ready' });
    }
  };

  const handleLogicWeave = async () => {
    if (status.step !== 'idle' && status.step !== 'ready') return;
    setStatus({ step: 'analyzing', message: 'Weaving Logic...' });
    try {
      const lastPrompt = chatHistory.filter((m) => m.role === 'user').pop()?.text || 'General Gameplay Logic';
      const nodes = await generateLogicNodes(lastPrompt, assets);
      setChatHistory([
        ...chatHistory,
        {
          role: 'ai',
          text: 'I have synthesized a set of complex behavioral blueprints for your simulation. Review and integrate them below.',
          proposedLogicNodes: nodes,
        },
      ]);
      setStatus({ step: 'ready', message: 'Logic Synthesized' });
    } catch (e: any) {
      setStatus({ step: 'ready', message: 'Ready' });
    }
  };

  const addAssetFromAI = (content: string) => {
    const newAsset: GameAsset = {
      id: Math.random().toString(36).substr(2, 9),
      name: `Logic_${assets.filter((a) => a.type === 'dialogue').length + 1}`,
      type: 'dialogue',
      content: content,
      mimeType: 'text/plain',
      category: 'Logic',
    };
    setAssets([...assets, newAsset]);
  };

  const handleDownload = () => {
    if (!game) return;

    const assetMap = assets.reduce((acc, asset) => {
      acc[asset.name] = asset.content;
      return acc;
    }, {} as Record<string, string>);

    const portableHtml = `
<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <title>${game.title}</title>
  <meta name="viewport" content="width=device-width, initial-scale=1.0, maximum-scale=1.0, user-scalable=no">
  <script>
    window.getAssetUrl = (name) => {
      const data = ${JSON.stringify(assetMap)}[name];
      if (!data) return "";
      try {
        const parts = data.split(',');
        const mime = parts[0].match(/:(.*?);/)[1];
        const bstr = atob(parts[1]);
        let n = bstr.length;
        const u8arr = new Uint8Array(n);
        while(n--) u8arr[n] = bstr.charCodeAt(n);
        const blob = new Blob([u8arr], { type: mime });
        return URL.createObjectURL(blob);
      } catch(e) { return ""; }
    };
  </script>
  <style>
    body { margin: 0; background: #000; overflow: hidden; height: 100vh; width: 100vw; }
    canvas { display: block; width: 100% !important; height: 100% !important; }
  </style>
</head>
<body>
  ${game.code}
</body>
</html>
    `;

    const blob = new Blob([portableHtml], { type: 'text/html' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `${game.title.replace(/\s+/g, '_').toLowerCase()}.html`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  };

  const handleKeySelectionManual = async () => {
    if ((window as any).aistudio?.openSelectKey) {
      await (window as any).aistudio.openSelectKey();
    }
  };

  const integratedSrcDoc = useMemo(() => {
    if (!game) return '';
    const assetMap = assets.reduce((acc, asset) => {
      acc[asset.name] = asset.content;
      return acc;
    }, {} as Record<string, string>);
    return `
      <!DOCTYPE html>
      <html>
        <head>
          <meta name="viewport" content="width=device-width, initial-scale=1.0, maximum-scale=1.0, user-scalable=no">
          <script>
            window.getAssetUrl = (name) => {
              const data = ${JSON.stringify(assetMap)}[name];
              if (!data) return "";
              try {
                const parts = data.split(',');
                const mime = parts[0].match(/:(.*?);/)[1];
                const bstr = atob(parts[1]);
                let n = bstr.length;
                const u8arr = new Uint8Array(n);
                while(n--) u8arr[n] = bstr.charCodeAt(n);
                const blob = new Blob([u8arr], { type: mime });
                return URL.createObjectURL(blob);
              } catch(e) { return ""; }
            };
            window.FORGE_PROJECT_ID = "${activeProjectId || 'unsaved'}"; // Expose project ID for runtime persistence
          </script>
          <style>
            body { margin: 0; background: #000; overflow: hidden; height: 100vh; width: 100vw; }
            canvas { display: block; width: 100% !important; height: 100% !important; }
          </style>
        </head>
        <body>${game.code}</body>
      </html>
    `;
  }, [game, assets, activeProjectId]);

  // --- Project Management Handlers ---
  const handleCreateNewProject = useCallback(
    (template?: ProjectTemplate) => {
      if (isDirty && !window.confirm('You have unsaved changes. Are you sure you want to create a new project?')) {
        return;
      }
      const newProject = pmCreateNewProject(template);
      initializeUndoRedoState(newProject.state);
      setActiveProjectId(newProject.metadata.id);
      setActiveProjectName(newProject.metadata.name);
      setIsDirty(false); // New project is not dirty yet
      setLastManualSaveTimestamp(newProject.metadata.lastModified);
      clearHistory(); // Clear undo/redo history for the new project
    },
    [isDirty, initializeUndoRedoState, clearHistory]
  );

  const handleSaveProject = useCallback(() => {
    if (!activeProjectId) {
      // If no active project ID, it's a new unsaved project, so open modal to "Save As"
      setShowProjectManager(true); 
      return;
    }
    const savedMetadata = pmSaveProject(activeProjectId, activeProjectName, projectState);
    setActiveProjectName(savedMetadata.name); // In case name was changed in modal
    setIsDirty(false);
    setLastManualSaveTimestamp(savedMetadata.lastModified);
    alert('Project saved successfully!');
  }, [activeProjectId, activeProjectName, projectState]);

  const handleProjectLoaded = useCallback(
    (loadedState: ProjectState, metadata: ProjectMetadata) => {
      initializeUndoRedoState(loadedState);
      setActiveProjectId(metadata.id);
      setActiveProjectName(metadata.name);
      setIsDirty(false); // Just loaded, so not dirty
      setLastManualSaveTimestamp(metadata.lastModified);
      clearHistory(); // Clear undo/redo history for the new project
      setShowProjectManager(false);
    },
    [initializeUndoRedoState, clearHistory]
  );

  const handleProjectCreated = useCallback(
    (createdState: ProjectState, metadata: ProjectMetadata) => {
      initializeUndoRedoState(createdState);
      setActiveProjectId(metadata.id);
      setActiveProjectName(metadata.name);
      setIsDirty(false); // Just created, so not dirty
      setLastManualSaveTimestamp(metadata.lastModified);
      clearHistory(); // Clear undo/redo history for the new project
      setShowProjectManager(false);
    },
    [initializeUndoRedoState, clearHistory]
  );

  const handleDuplicateProject = useCallback(() => {
    if (!activeProjectId) {
      alert('No active project to duplicate. Please save or create one first.');
      return;
    }
    // Logic for duplication is handled within ProjectManagerModal,
    // this simply opens the modal. The user will be prompted for a new name there.
    setShowProjectManager(true); 
  }, [activeProjectId]);

  const handleDeleteProject = useCallback(() => {
    if (!activeProjectId) {
      alert('No active project to delete.');
      return;
    }
    if (window.confirm('Are you sure you want to delete the current project? This cannot be undone.')) {
      pmDeleteProject(activeProjectId);
      handleCreateNewProject(); // Automatically create a new project after deleting current
      alert('Project deleted.');
    }
  }, [activeProjectId, handleCreateNewProject]);


  const handleExportProject = useCallback(() => {
    if (!activeProjectId) {
      alert('No active project to export. Please save or create one first.');
      return;
    }
    const project = getAllProjectMetadata().find(p => p.id === activeProjectId);
    if (!project) {
        alert('Could not find current project metadata for export.');
        return;
    }
    const fullProject = pmLoadProject(activeProjectId);
    if (fullProject) {
        pmExportProject(fullProject);
    } else {
        alert('Failed to load full project data for export. It might be corrupted.');
    }
  }, [activeProjectId, projectState]); // projectState is here to ensure latest data is exported

  const handleImportProject = useCallback(async (file: File) => {
    try {
      if (isDirty && !window.confirm('You have unsaved changes. Import anyway?')) {
        return;
      }
      const importedProject = await pmImportProject(file);
      if (importedProject) {
        handleProjectCreated(importedProject.state, importedProject.metadata);
        alert('Project imported successfully!');
      }
    } catch (error) {
      alert(`Failed to import project: ${error instanceof Error ? error.message : String(error)}`);
    }
  }, [isDirty, handleProjectCreated]);

  const handleShareProject = useCallback(() => {
    if (!activeProjectId) {
      alert('Please save your project first to generate a shareable link.');
      return;
    }
    const project = getAllProjectMetadata().find(p => p.id === activeProjectId);
    if (!project) {
      alert('Could not find current project data for sharing.');
      return;
    }
    const fullProject = { metadata: project, state: projectState, versions: [] }; // Only current state is needed for sharing
    const shareLink = generateShareLink(fullProject);
    navigator.clipboard.writeText(shareLink);
    alert('Shareable link copied to clipboard!');
  }, [activeProjectId, projectState]);

  const handleCopyProject = useCallback(() => {
    if (!activeProjectId) {
      alert('No active project to copy. Please save or create one first.');
      return;
    }
    const project = getAllProjectMetadata().find(p => p.id === activeProjectId);
    if (!project) {
        alert('Could not find current project metadata for copy.');
        return;
    }
    const fullProject = pmLoadProject(activeProjectId); // Load full project for complete data copy
    if (fullProject) {
        copyProjectToClipboard(fullProject);
    } else {
        alert('Failed to load full project data for copy to clipboard. It might be corrupted.');
    }
  }, [activeProjectId, projectState]);

  if (viewMode === 'preview' && game) {
    return <GameRunner code={game.code} title={game.title} assets={assets} onExit={() => setViewMode('editor')} />;
  }

  return (
    <div className="flex flex-col h-screen bg-[#F8FAFC] overflow-hidden">
      <header className="h-14 md:h-16 border-b bg-white flex items-center justify-between px-4 md:px-6 shrink-0 z-[100]">
        <div className="flex items-center gap-2 md:gap-4">
          <button
            onClick={() => setIsLeftSidebarOpen(!isLeftSidebarOpen)}
            className="md:hidden p-2 text-slate-500 hover:bg-slate-50 rounded-lg transition-colors"
          >
            <Menu className="w-5 h-5" />
          </button>
          <div className="flex items-center gap-2">
            <div className="bg-indigo-600 p-1.5 rounded-lg shadow-sm shadow-indigo-100">
              <Box className="w-4 h-4 md:w-5 md:h-5 text-white" />
            </div>
            <span className="font-black text-xs md:text-sm tracking-tighter text-slate-900 hidden sm:inline uppercase">
              TEXT2GAME STUDIO
            </span>
            <span className="font-black text-xs tracking-tighter text-slate-900 sm:hidden uppercase">
              TEXT2GAME
            </span>
          </div>
        </div>

        <div className="flex items-center gap-1.5 md:gap-3">
          {/* Project Dropdown */}
          <ProjectDropdown
            currentProjectName={activeProjectName}
            isDirty={isDirty}
            onNewProject={handleCreateNewProject}
            onSaveProject={handleSaveProject}
            onOpenProject={() => setShowProjectManager(true)} // Opens the modal
            onDuplicateProject={handleDuplicateProject}
            onDeleteProject={handleDeleteProject}
            onExportProject={handleExportProject}
            onImportProject={handleImportProject}
            onShareProject={handleShareProject}
            onCopyProject={handleCopyProject}
          />

          {/* Undo/Redo Buttons */}
          <div className="hidden sm:flex items-center gap-1.5 bg-slate-50 p-1 rounded-xl border border-slate-100">
            <button
              onClick={undo}
              disabled={!canUndo}
              title="Undo (Ctrl+Z)"
              aria-label="Undo last action"
              className="p-1.5 rounded-lg text-slate-400 hover:bg-white hover:text-slate-600 disabled:opacity-30 disabled:hover:bg-transparent transition-colors"
            >
              <Undo2 className="w-4 h-4" />
            </button>
            <button
              onClick={redo}
              disabled={!canRedo}
              title="Redo (Ctrl+Y / Ctrl+Shift+Z)"
              aria-label="Redo last undone action"
              className="p-1.5 rounded-lg text-slate-400 hover:bg-white hover:text-slate-600 disabled:opacity-30 disabled:hover:bg-transparent transition-colors"
            >
              <Redo2 className="w-4 h-4" />
            </button>
          </div>

          {/* Autosave Status */}
          <div
            className="hidden lg:flex items-center gap-2 px-3 py-1.5 rounded-xl border border-slate-200 text-[10px] font-bold uppercase text-slate-500"
            title="Autosave Status"
          >
            <CloudLightning className={`w-3.5 h-3.5 ${autosaveStatusMessage.startsWith('Saving') ? 'text-indigo-400 animate-pulse' : autosaveStatusMessage.startsWith('Saved') ? 'text-emerald-500' : 'text-slate-400'}`} />
            {autosaveStatusMessage}
          </div>

          <button
            onClick={handleKeySelectionManual}
            className="flex items-center gap-2 px-2.5 md:px-4 py-1.5 md:py-2 rounded-xl border border-slate-200 text-[10px] md:text-xs font-bold uppercase hover:bg-slate-50 hover:border-slate-300 transition-all text-slate-600"
          >
            <ShieldCheck className="w-3.5 h-3.5 text-emerald-500" />
            <span className="hidden lg:inline">Config Key</span>
          </button>

          {game && (
            <div className="flex items-center gap-1.5 md:gap-2">
              <button
                onClick={handleDownload}
                title="Download Source"
                className="p-2 md:px-4 md:py-2 rounded-xl border border-slate-200 text-slate-600 hover:bg-slate-50 hover:border-slate-300 transition-all active:scale-95 flex items-center gap-2"
              >
                <Download className="w-4 h-4" />
                <span className="hidden lg:inline text-[10px] md:text-xs font-bold uppercase">Export</span>
              </button>

              <button
                onClick={() => setViewMode('preview')}
                className="bg-indigo-600 text-white px-3 md:px-5 py-1.5 md:py-2 rounded-xl text-[10px] md:text-xs font-bold uppercase shadow-lg shadow-indigo-100 hover:bg-indigo-700 hover:shadow-indigo-200 transition-all active:scale-95 flex items-center gap-2"
              >
                <Maximize2 className="w-3.5 h-3.5 md:w-4 md:h-4" />
                <span className="hidden md:inline">Live Preview</span>
              </button>
            </div>
          )}

          <button
            onClick={() => {
              setIsRightSidebarOpen(!isRightSidebarOpen);
              if (!isRightSidebarOpen) setActiveMobileView('chat');
            }}
            className="md:hidden p-2 text-slate-500 hover:bg-slate-50 rounded-lg transition-colors"
          >
            <MessageSquareCode className="w-5 h-5" />
          </button>
        </div>
      </header>

      <main className="flex-1 flex overflow-hidden relative">
        <aside
          className={`
          fixed md:static inset-y-0 left-0 w-[280px] bg-white border-r z-50 transition-transform duration-300 ease-in-out
          ${isLeftSidebarOpen ? 'translate-x-0 shadow-2xl md:shadow-none' : '-translate-x-full md:translate-x-0'}
        `}
        >
          <div className="p-4 h-full overflow-y-auto no-scrollbar scroll-smooth">
            <div className="md:hidden flex items-center justify-between mb-6 pb-2 border-b border-slate-100">
              <span className="text-[10px] font-black uppercase tracking-widest text-slate-400">Asset Matrix</span>
              <button onClick={() => setIsLeftSidebarOpen(false)} className="p-1 text-slate-400">
                <X className="w-4 h-4" />
              </button>
            </div>
            <AssetUploader assets={assets} onAssetsChange={setAssets} />
          </div>
        </aside>

        <div className="flex-1 flex flex-col bg-[#F1F5F9] relative overflow-hidden transition-all duration-300">
          <div className={`flex-1 relative bg-[#0F172A] ${activeMobileView === 'staging' ? 'flex' : 'hidden md:flex'}`}>
            {game ? (
              <div className="w-full h-full relative group">
                <iframe
                  srcDoc={integratedSrcDoc}
                  className="w-full h-full border-none shadow-2xl"
                  sandbox="allow-scripts allow-modals allow-pointer-lock"
                />
                <div className="absolute bottom-6 right-6 flex gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                  <button
                    onClick={handleDownload}
                    className="p-3 bg-white/10 backdrop-blur-md border border-white/20 text-white rounded-2xl hover:bg-white/20 transition-all"
                  >
                    <Download className="w-5 h-5" />
                  </button>
                  <button
                    onClick={() => setViewMode('preview')}
                    className="p-3 bg-white/10 backdrop-blur-md border border-white/20 text-white rounded-2xl hover:bg-white/20 transition-all"
                  >
                    <Maximize2 className="w-5 h-5" />
                  </button>
                </div>
              </div>
            ) : (
              <div className="flex-1 flex flex-col items-center justify-center text-center p-8">
                <div className="w-20 h-20 md:w-24 md:h-24 bg-white/5 border border-white/10 rounded-[2rem] flex items-center justify-center mb-6 animate-pulse">
                  <BoxSelect className="w-8 h-8 md:w-10 md:h-10 text-white/10" />
                </div>
                <h3 className="text-white/20 font-black uppercase tracking-[0.4em] text-[10px] md:text-xs mb-2">
                  Awaiting Neural Link
                </h3>
                <p className="text-white/10 text-[9px] font-bold uppercase tracking-widest max-w-[200px] leading-relaxed">
                  Synthesis occurs once buffers are architected
                </p>
              </div>
            )}

            <div className="absolute bottom-6 left-6 flex flex-col gap-1.5 pointer-events-none">
              <span className="text-[8px] font-black text-white/20 uppercase tracking-[0.2em]">Substrate Pulse</span>
              <div className="flex items-center gap-2.5 bg-black/40 backdrop-blur-md px-3 py-1.5 rounded-xl border border-white/5">
                <div
                  className={`w-2 h-2 rounded-full ${
                    status.step === 'ready'
                      ? 'bg-[#4F46E5] shadow-[0_0_12px_rgba(79,70,229,0.8)]'
                      : status.step === 'idle'
                      ? 'bg-white/10'
                      : 'bg-[#C9A24D] animate-pulse'
                  }`}
                />
                <span className="text-[9px] font-black text-white/60 uppercase tracking-widest">
                  {status.message || 'Standby'}
                </span>
              </div>
            </div>

            {isLiveSyncing && (
              <div className="absolute top-6 right-6 flex items-center gap-2.5 px-4 py-2 bg-indigo-600/20 backdrop-blur-md border border-indigo-500/30 rounded-2xl animate-in fade-in slide-in-from-top-4 duration-500">
                <RefreshCw className="w-3.5 h-3.5 text-indigo-400 animate-spin" />
                <span className="text-[9px] font-black text-indigo-100 uppercase tracking-widest">Neural Sync</span>
              </div>
            )}
          </div>
        </div>

        <aside
          className={`
          fixed md:static inset-y-0 right-0 w-full md:w-[380px] lg:w-[450px] bg-white border-l z-50 transition-transform duration-300 ease-in-out
          ${isRightSidebarOpen || activeMobileView === 'chat' ? 'translate-x-0' : 'translate-x-full md:translate-x-0'}
        `}
        >
          <div className="h-full relative">
            <AIChat
              history={chatHistory}
              onSendMessage={processGeneration}
              onInspiration={handleInspiration}
              onLogicWeave={handleLogicWeave}
              onAddAsset={addAssetFromAI}
              isProcessing={status.step !== 'idle' && status.step !== 'ready' && status.step !== 'error'}
              aiMode={aiMode}
              onModeChange={setAiMode}
            />
            <button
              onClick={() => {
                setIsRightSidebarOpen(false);
                if (activeMobileView === 'chat') setActiveMobileView('staging');
              }}
              className="md:hidden absolute top-4 right-4 p-2 text-slate-400 hover:text-slate-600 z-[60]"
            >
              <X className="w-5 h-5" />
            </button>
          </div>
        </aside>

        {(isLeftSidebarOpen || (isRightSidebarOpen && activeMobileView !== 'chat')) && (
          <div
            className="fixed inset-0 bg-slate-900/40 backdrop-blur-sm z-40 md:hidden"
            onClick={() => {
              setIsLeftSidebarOpen(false);
              setIsRightSidebarOpen(false);
            }}
          />
        )}
      </main>

      <footer className="h-14 border-t bg-white flex items-center justify-around md:hidden shrink-0 shadow-[0_-1px_10px_rgba(0,0,0,0.02)] z-[100]">
        <button
          onClick={() => setActiveMobileView('staging')}
          className={`flex flex-col items-center gap-1 transition-all ${
            activeMobileView === 'staging' ? 'text-indigo-600' : 'text-slate-400'
          }`}
        >
          <Monitor className="w-5 h-5" />
          <span className="text-[9px] font-black uppercase tracking-tighter">Staging</span>
        </button>
        <button
          onClick={() => setActiveMobileView('chat')}
          className={`flex flex-col items-center gap-1 transition-all ${
            activeMobileView === 'chat' ? 'text-indigo-600' : 'text-slate-400'
          }`}
        >
          <div className="relative">
            <MessageSquareCode className="w-5 h-5" />
            {isLiveSyncing && (
              <span className="absolute -top-1 -right-1 w-2.5 h-2.5 bg-indigo-600 rounded-full animate-pulse border-2 border-white" />
            )}
          </div>
          <span className="text-[9px] font-black uppercase tracking-tighter">Architect</span>
        </button>
      </footer>

      {/* Project Manager Modal */}
      <ProjectManagerModal
        isOpen={showProjectManager}
        onClose={() => setShowProjectManager(false)}
        onProjectLoaded={handleProjectLoaded}
        onProjectCreated={handleProjectCreated}
        currentProjectId={activeProjectId}
        currentProjectState={projectState}
      />

      {/* Autosave Recovery Prompt */}
      {showAutosaveRecoveryPrompt && (
        <div className="fixed inset-0 z-[1300] flex items-center justify-center bg-slate-900/70 backdrop-blur-sm p-4 animate-in fade-in">
          <div className="bg-white rounded-2xl p-8 shadow-2xl max-w-sm text-center">
            <h3 className="text-xl font-bold mb-4 text-slate-900">Recover Autosave?</h3>
            <p className="text-slate-700 mb-6">
              It looks like you have an unsaved project from your last session. Would you like to restore it?
            </p>
            <div className="flex gap-4">
              <button
                onClick={handleRecoverAutosave}
                className="flex-1 py-3 bg-indigo-600 text-white rounded-xl font-bold hover:bg-indigo-700 transition-colors active:scale-95"
              >
                Restore
              </button>
              <button
                onClick={handleDiscardAutosave}
                className="flex-1 py-3 bg-slate-100 text-slate-700 rounded-xl font-bold hover:bg-slate-200 transition-colors active:scale-95"
              >
                Discard
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useCallback, useEffect, useRef, useMemo } from 'react';
import { AssetUploader } from './components/AssetUploader';
import { GameRunner } from './components/GameRunner';
import { AIChat } from './components/AIChat';
import { generateGame, brainstormGame, generateLogicNodes } from './services/gemini';
import {
  GameAsset,
  GenerationStatus,
  GeneratedGame,
  ChatMessage,
  AIModelMode,
  ProjectState,
  ProjectMetadata,
  ProjectTemplate,
} from './types';
import {
  Box,
  Monitor,
  Sparkles,
  BoxSelect,
  Menu,
  X,
  MessageSquareCode,
  BrainCircuit,
  RefreshCw,
  Cpu,
  Zap,
  Maximize2,
  Bolt,
  Download,
  ShieldCheck,
  Undo2,
  Redo2,
  CloudLightning,
} from 'lucide-react';

import { useUndoRedo } from './hooks/useUndoRedo';
import { useAutoSave } from './hooks/useAutoSave';
import { loadAutosavedProject, clearAutosavedProject, compress } from './services/storage';
import {
  getAllProjectMetadata,
  saveProject as pmSaveProject,
  loadProject as pmLoadProject, // Import loadProject to get full project data for export/copy
  loadProjectFromShareLink,
  generateShareLink,
  copyProjectToClipboard,
  deleteProject as pmDeleteProject,
  exportProject as pmExportProject,
  importProject as pmImportProject,
  createNewProject as pmCreateNewProject, // Also need this for the initial blank project
} from './services/projectManager';
import { ProjectDropdown } from './components/ProjectDropdown';
import { ProjectManagerModal } from './components/ProjectManagerModal';

type ViewMode = 'editor' | 'preview';
// Define mobile view types
type MobileView = 'staging' | 'chat';

// Initial project state when no project is loaded
const DEFAULT_INITIAL_PROJECT_STATE: ProjectState = {
  assets: [],
  game: null,
  chatHistory: [],
  aiMode: 'thinking',
};

const App: React.FC = () => {
  const [viewMode, setViewMode] = useState<ViewMode>('editor');
  const [status, setStatus] = useState<GenerationStatus>({ step: 'idle', message: '' });
  const [isLiveSyncing, setIsLiveSyncing] = useState(false);

  // State for responsive layout
  const [isLeftSidebarOpen, setIsLeftSidebarOpen] = useState(false);
  const [isRightSidebarOpen, setIsRightSidebarOpen] = useState(false);
  const [activeMobileView, setActiveMobileView] = useState<MobileView>('staging');

  // Project Management States
  const [activeProjectId, setActiveProjectId] = useState<string | null>(null);
  const [activeProjectName, setActiveProjectName] = useState('Untitled Project');
  const [isDirty, setIsDirty] = useState(false); // Tracks unsaved changes to the current project
  const [lastManualSaveTimestamp, setLastManualSaveTimestamp] = useState<number | null>(null);
  const [showProjectManager, setShowProjectManager] = useState(false);
  const [showAutosaveRecoveryPrompt, setShowAutosaveRecoveryPrompt] = useState(false);

  // Undo/Redo State (manages the core project data)
  const [
    projectState,
    setProjectState,
    undo,
    redo,
    canUndo,
    canRedo,
    clearHistory,
    initializeUndoRedoState,
  ] = useUndoRedo<ProjectState>(DEFAULT_INITIAL_PROJECT_STATE);

  const { assets, game, chatHistory, aiMode } = projectState;

  // Auto-Save Hook
  const { autosaveStatusMessage, loadLastAutosave, clearLastAutosave } = useAutoSave(
    projectState,
    activeProjectId,
    lastManualSaveTimestamp
  );

  // Update dirty state when projectState changes (except on initial load/set)
  const isInitialProjectStateLoad = useRef(true);
  useEffect(() => {
    if (isInitialProjectStateLoad.current) {
      isInitialProjectStateLoad.current = false;
      return;
    }
    // Only set dirty if the project has been actively edited, not just loaded/initialized.
    // This is a simple heuristic; a more robust solution would track specific actions.
    setIsDirty(true); 
  }, [projectState]);

  // Handle initial load (share link, autosave, or new project)
  useEffect(() => {
    const handleInitialLoad = () => {
      const shareLinkState = loadProjectFromShareLink();
      if (shareLinkState) {
        initializeUndoRedoState(shareLinkState);
        setActiveProjectId(null); // Share link is always an unsaved new project
        setActiveProjectName('Shared Project');
        setIsDirty(true);
        clearAutosavedProject(); // Clear autosave if loading from share link
        return;
      }

      const autosaved = loadAutosavedProject();
      if (autosaved && autosaved.state && Date.now() - autosaved.timestamp < 24 * 60 * 60 * 1000) { // Autosave within 24 hours
        // Prompt user for autosave recovery
        setShowAutosaveRecoveryPrompt(true);
      } else {
        // No valid autosave, or too old, start fresh
        handleCreateNewProject(); // This will initialize a new project
      }
    };
    handleInitialLoad();
  }, []); // Run only once on mount

  const handleRecoverAutosave = useCallback(() => {
    const autosaved = loadAutosavedProject();
    if (autosaved) {
      initializeUndoRedoState(autosaved.state);
      setActiveProjectId(autosaved.projectId); // If autosave was for an existing project, load its ID
      setActiveProjectName(
        getAllProjectMetadata().find((p) => p.id === autosaved.projectId)?.name || 'Recovered Project'
      );
      setIsDirty(true); // Recovered state is dirty until explicitly saved
      clearAutosavedProject();
    }
    setShowAutosaveRecoveryPrompt(false);
  }, [initializeUndoRedoState, clearAutosavedProject]);

  const handleDiscardAutosave = useCallback(() => {
    clearAutosavedProject();
    handleCreateNewProject(); // Start a fresh project
    setShowAutosaveRecoveryPrompt(false);
  }, [clearAutosavedProject]);

  // Update specific parts of ProjectState
  const setAssets = useCallback(
    (newAssets: GameAsset[]) => setProjectState((prev) => ({ ...prev, assets: newAssets })),
    [setProjectState]
  );
  const setGame = useCallback(
    (newGame: GeneratedGame | null) => setProjectState((prev) => ({ ...prev, game: newGame })),
    [setProjectState]
  );
  const setChatHistory = useCallback(
    (newHistory: ChatMessage[]) => setProjectState((prev) => ({ ...prev, chatHistory: newHistory })),
    [setProjectState]
  );
  const setAiMode = useCallback(
    (newMode: AIModelMode) => setProjectState((prev) => ({ ...prev, aiMode: newMode })),
    [setProjectState]
  );

  const processGeneration = useCallback(
    async (instruction: string, isAutoSync: boolean = false) => {
      if (!isAutoSync) {
        setStatus({ step: 'analyzing', message: 'Architecting...' });
        setChatHistory([...chatHistory, { role: 'user', text: instruction }]);
      } else {
        setIsLiveSyncing(true);
      }

      try {
        const result = await generateGame(instruction, assets, chatHistory, game?.code || '', aiMode);
        setGame({ code: result.code, title: result.title });
        if (!isAutoSync) {
          setChatHistory([
            ...chatHistory,
            {
              role: 'ai',
              text: result.explanation,
              suggestions: result.suggestions,
              proposedLogicNodes: result.proposedLogicNodes,
            },
          ]);
        }
        setStatus({ step: 'ready', message: 'Ready.' });
        setIsLiveSyncing(false);
      } catch (error: any) {
        console.error(error);
        setStatus({ step: 'error', message: 'Error' });
        setIsLiveSyncing(false);
      }
    },
    [assets, chatHistory, game, aiMode, setChatHistory, setGame]
  );

  const handleInspiration = async () => {
    if (status.step !== 'idle' && status.step !== 'ready') return;
    setStatus({ step: 'analyzing', message: 'Brainstorming...' });
    try {
      const report = await brainstormGame(assets);
      setChatHistory([...chatHistory, { role: 'ai', text: report }]);
      setStatus({ step: 'ready', message: 'Report Ready' });
    } catch (e: any) {
      setStatus({ step: 'ready', message: 'Ready' });
    }
  };

  const handleLogicWeave = async () => {
    if (status.step !== 'idle' && status.step !== 'ready') return;
    setStatus({ step: 'analyzing', message: 'Weaving Logic...' });
    try {
      const lastPrompt = chatHistory.filter((m) => m.role === 'user').pop()?.text || 'General Gameplay Logic';
      const nodes = await generateLogicNodes(lastPrompt, assets);
      setChatHistory([
        ...chatHistory,
        {
          role: 'ai',
          text: 'I have synthesized a set of complex behavioral blueprints for your simulation. Review and integrate them below.',
          proposedLogicNodes: nodes,
        },
      ]);
      setStatus({ step: 'ready', message: 'Logic Synthesized' });
    } catch (e: any) {
      setStatus({ step: 'ready', message: 'Ready' });
    }
  };

  const addAssetFromAI = (content: string) => {
    const newAsset: GameAsset = {
      id: Math.random().toString(36).substr(2, 9),
      name: `Logic_${assets.filter((a) => a.type === 'dialogue').length + 1}`,
      type: 'dialogue',
      content: content,
      mimeType: 'text/plain',
      category: 'Logic',
    };
    setAssets([...assets, newAsset]);
  };

  const handleDownload = () => {
    if (!game) return;

    const assetMap = assets.reduce((acc, asset) => {
      acc[asset.name] = asset.content;
      return acc;
    }, {} as Record<string, string>);

    const portableHtml = `
<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <title>${game.title}</title>
  <meta name="viewport" content="width=device-width, initial-scale=1.0, maximum-scale=1.0, user-scalable=no">
  <script>
    window.getAssetUrl = (name) => {
      const data = ${JSON.stringify(assetMap)}[name];
      if (!data) return "";
      try {
        const parts = data.split(',');
        const mime = parts[0].match(/:(.*?);/)[1];
        const bstr = atob(parts[1]);
        let n = bstr.length;
        const u8arr = new Uint8Array(n);
        while(n--) u8arr[n] = bstr.charCodeAt(n);
        const blob = new Blob([u8arr], { type: mime });
        return URL.createObjectURL(blob);
      } catch(e) { return ""; }
    };
  </script>
  <style>
    body { margin: 0; background: #000; overflow: hidden; height: 100vh; width: 100vw; }
    canvas { display: block; width: 100% !important; height: 100% !important; }
  </style>
</head>
<body>
  ${game.code}
</body>
</html>
    `;

    const blob = new Blob([portableHtml], { type: 'text/html' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `${game.title.replace(/\s+/g, '_').toLowerCase()}.html`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  };

  const handleKeySelectionManual = async () => {
    if ((window as any).aistudio?.openSelectKey) {
      await (window as any).aistudio.openSelectKey();
    }
  };

  const integratedSrcDoc = useMemo(() => {
    if (!game) return '';
    const assetMap = assets.reduce((acc, asset) => {
      acc[asset.name] = asset.content;
      return acc;
    }, {} as Record<string, string>);
    return `
      <!DOCTYPE html>
      <html>
        <head>
          <meta name="viewport" content="width=device-width, initial-scale=1.0, maximum-scale=1.0, user-scalable=no">
          <script>
            window.getAssetUrl = (name) => {
              const data = ${JSON.stringify(assetMap)}[name];
              if (!data) return "";
              try {
                const parts = data.split(',');
                const mime = parts[0].match(/:(.*?);/)[1];
                const bstr = atob(parts[1]);
                let n = bstr.length;
                const u8arr = new Uint8Array(n);
                while(n--) u8arr[n] = bstr.charCodeAt(n);
                const blob = new Blob([u8arr], { type: mime });
                return URL.createObjectURL(blob);
              } catch(e) { return ""; }
            };
            window.FORGE_PROJECT_ID = "${activeProjectId || 'unsaved'}"; // Expose project ID for runtime persistence
          </script>
          <style>
            body { margin: 0; background: #000; overflow: hidden; height: 100vh; width: 100vw; }
            canvas { display: block; width: 100% !important; height: 100% !important; }
          </style>
        </head>
        <body>${game.code}</body>
      </html>
    `;
  }, [game, assets, activeProjectId]);

  // --- Project Management Handlers ---
  const handleCreateNewProject = useCallback(
    (template?: ProjectTemplate) => {
      if (isDirty && !window.confirm('You have unsaved changes. Are you sure you want to create a new project?')) {
        return;
      }
      const newProject = pmCreateNewProject(template);
      initializeUndoRedoState(newProject.state);
      setActiveProjectId(newProject.metadata.id);
      setActiveProjectName(newProject.metadata.name);
      setIsDirty(false); // New project is not dirty yet
      setLastManualSaveTimestamp(newProject.metadata.lastModified);
      clearHistory(); // Clear undo/redo history for the new project
    },
    [isDirty, initializeUndoRedoState, clearHistory]
  );

  const handleSaveProject = useCallback(() => {
    if (!activeProjectId) {
      // If no active project ID, it's a new unsaved project, so open modal to "Save As"
      setShowProjectManager(true); 
      return;
    }
    const savedMetadata = pmSaveProject(activeProjectId, activeProjectName, projectState);
    setActiveProjectName(savedMetadata.name); // In case name was changed in modal
    setIsDirty(false);
    setLastManualSaveTimestamp(savedMetadata.lastModified);
    alert('Project saved successfully!');
  }, [activeProjectId, activeProjectName, projectState]);

  const handleProjectLoaded = useCallback(
    (loadedState: ProjectState, metadata: ProjectMetadata) => {
      initializeUndoRedoState(loadedState);
      setActiveProjectId(metadata.id);
      setActiveProjectName(metadata.name);
      setIsDirty(false); // Just loaded, so not dirty
      setLastManualSaveTimestamp(metadata.lastModified);
      clearHistory(); // Clear undo/redo history for the new project
      setShowProjectManager(false);
    },
    [initializeUndoRedoState, clearHistory]
  );

  const handleProjectCreated = useCallback(
    (createdState: ProjectState, metadata: ProjectMetadata) => {
      initializeUndoRedoState(createdState);
      setActiveProjectId(metadata.id);
      setActiveProjectName(metadata.name);
      setIsDirty(false); // Just created, so not dirty
      setLastManualSaveTimestamp(metadata.lastModified);
      clearHistory(); // Clear undo/redo history for the new project
      setShowProjectManager(false);
    },
    [initializeUndoRedoState, clearHistory]
  );

  const handleDuplicateProject = useCallback(() => {
    if (!activeProjectId) {
      alert('No active project to duplicate. Please save or create one first.');
      return;
    }
    // Logic for duplication is handled within ProjectManagerModal,
    // this simply opens the modal. The user will be prompted for a new name there.
    setShowProjectManager(true); 
  }, [activeProjectId]);

  const handleDeleteProject = useCallback(() => {
    if (!activeProjectId) {
      alert('No active project to delete.');
      return;
    }
    if (window.confirm('Are you sure you want to delete the current project? This cannot be undone.')) {
      pmDeleteProject(activeProjectId);
      handleCreateNewProject(); // Automatically create a new project after deleting current
      alert('Project deleted.');
    }
  }, [activeProjectId, handleCreateNewProject]);


  const handleExportProject = useCallback(() => {
    if (!activeProjectId) {
      alert('No active project to export. Please save or create one first.');
      return;
    }
    const project = getAllProjectMetadata().find(p => p.id === activeProjectId);
    if (!project) {
        alert('Could not find current project metadata for export.');
        return;
    }
    const fullProject = pmLoadProject(activeProjectId);
    if (fullProject) {
        pmExportProject(fullProject);
    } else {
        alert('Failed to load full project data for export. It might be corrupted.');
    }
  }, [activeProjectId, projectState]); // projectState is here to ensure latest data is exported

  const handleImportProject = useCallback(async (file: File) => {
    try {
      if (isDirty && !window.confirm('You have unsaved changes. Import anyway?')) {
        return;
      }
      const importedProject = await pmImportProject(file);
      if (importedProject) {
        handleProjectCreated(importedProject.state, importedProject.metadata);
        alert('Project imported successfully!');
      }
    } catch (error) {
      alert(`Failed to import project: ${error instanceof Error ? error.message : String(error)}`);
    }
  }, [isDirty, handleProjectCreated]);

  const handleShareProject = useCallback(() => {
    if (!activeProjectId) {
      alert('Please save your project first to generate a shareable link.');
      return;
    }
    const project = getAllProjectMetadata().find(p => p.id === activeProjectId);
    if (!project) {
      alert('Could not find current project data for sharing.');
      return;
    }
    const fullProject = { metadata: project, state: projectState, versions: [] }; // Only current state is needed for sharing
    const shareLink = generateShareLink(fullProject);
    navigator.clipboard.writeText(shareLink);
    alert('Shareable link copied to clipboard!');
  }, [activeProjectId, projectState]);

  const handleCopyProject = useCallback(() => {
    if (!activeProjectId) {
      alert('No active project to copy. Please save or create one first.');
      return;
    }
    const project = getAllProjectMetadata().find(p => p.id === activeProjectId);
    if (!project) {
        alert('Could not find current project metadata for copy.');
        return;
    }
    const fullProject = pmLoadProject(activeProjectId); // Load full project for complete data copy
    if (fullProject) {
        copyProjectToClipboard(fullProject);
    } else {
        alert('Failed to load full project data for copy to clipboard. It might be corrupted.');
    }
  }, [activeProjectId, projectState]);

  if (viewMode === 'preview' && game) {
    return <GameRunner code={game.code} title={game.title} assets={assets} onExit={() => setViewMode('editor')} />;
  }

  return (
    <div className="flex flex-col h-screen bg-[#F8FAFC] overflow-hidden">
      <header className="h-14 md:h-16 border-b bg-white flex items-center justify-between px-4 md:px-6 shrink-0 z-[100]">
        <div className="flex items-center gap-2 md:gap-4">
          <button
            onClick={() => setIsLeftSidebarOpen(!isLeftSidebarOpen)}
            className="md:hidden p-2 text-slate-500 hover:bg-slate-50 rounded-lg transition-colors"
          >
            <Menu className="w-5 h-5" />
          </button>
          <div className="flex items-center gap-2">
            <div className="bg-indigo-600 p-1.5 rounded-lg shadow-sm shadow-indigo-100">
              <Box className="w-4 h-4 md:w-5 md:h-5 text-white" />
            </div>
            <span className="font-black text-xs md:text-sm tracking-tighter text-slate-900 hidden sm:inline uppercase">
              TEXT2GAME STUDIO
            </span>
            <span className="font-black text-xs tracking-tighter text-slate-900 sm:hidden uppercase">
              TEXT2GAME
            </span>
          </div>
        </div>

        <div className="flex items-center gap-1.5 md:gap-3">
          {/* Project Dropdown */}
          <ProjectDropdown
            currentProjectName={activeProjectName}
            isDirty={isDirty}
            onNewProject={handleCreateNewProject}
            onSaveProject={handleSaveProject}
            onOpenProject={() => setShowProjectManager(true)} // Opens the modal
            onDuplicateProject={handleDuplicateProject}
            onDeleteProject={handleDeleteProject}
            onExportProject={handleExportProject}
            onImportProject={handleImportProject}
            onShareProject={handleShareProject}
            onCopyProject={handleCopyProject}
          />

          {/* Undo/Redo Buttons */}
          <div className="hidden sm:flex items-center gap-1.5 bg-slate-50 p-1 rounded-xl border border-slate-100">
            <button
              onClick={undo}
              disabled={!canUndo}
              title="Undo (Ctrl+Z)"
              aria-label="Undo last action"
              className="p-1.5 rounded-lg text-slate-400 hover:bg-white hover:text-slate-600 disabled:opacity-30 disabled:hover:bg-transparent transition-colors"
            >
              <Undo2 className="w-4 h-4" />
            </button>
            <button
              onClick={redo}
              disabled={!canRedo}
              title="Redo (Ctrl+Y / Ctrl+Shift+Z)"
              aria-label="Redo last undone action"
              className="p-1.5 rounded-lg text-slate-400 hover:bg-white hover:text-slate-600 disabled:opacity-30 disabled:hover:bg-transparent transition-colors"
            >
              <Redo2 className="w-4 h-4" />
            </button>
          </div>

          {/* Autosave Status */}
          <div
            className="hidden lg:flex items-center gap-2 px-3 py-1.5 rounded-xl border border-slate-200 text-[10px] font-bold uppercase text-slate-500"
            title="Autosave Status"
          >
            <CloudLightning className={`w-3.5 h-3.5 ${autosaveStatusMessage.startsWith('Saving') ? 'text-indigo-400 animate-pulse' : autosaveStatusMessage.startsWith('Saved') ? 'text-emerald-500' : 'text-slate-400'}`} />
            {autosaveStatusMessage}
          </div>

          <button
            onClick={handleKeySelectionManual}
            className="flex items-center gap-2 px-2.5 md:px-4 py-1.5 md:py-2 rounded-xl border border-slate-200 text-[10px] md:text-xs font-bold uppercase hover:bg-slate-50 hover:border-slate-300 transition-all text-slate-600"
          >
            <ShieldCheck className="w-3.5 h-3.5 text-emerald-500" />
            <span className="hidden lg:inline">Config Key</span>
          </button>

          {game && (
            <div className="flex items-center gap-1.5 md:gap-2">
              <button
                onClick={handleDownload}
                title="Download Source"
                className="p-2 md:px-4 md:py-2 rounded-xl border border-slate-200 text-slate-600 hover:bg-slate-50 hover:border-slate-300 transition-all active:scale-95 flex items-center gap-2"
              >
                <Download className="w-4 h-4" />
                <span className="hidden lg:inline text-[10px] md:text-xs font-bold uppercase">Export</span>
              </button>

              <button
                onClick={() => setViewMode('preview')}
                className="bg-indigo-600 text-white px-3 md:px-5 py-1.5 md:py-2 rounded-xl text-[10px] md:text-xs font-bold uppercase shadow-lg shadow-indigo-100 hover:bg-indigo-700 hover:shadow-indigo-200 transition-all active:scale-95 flex items-center gap-2"
              >
                <Maximize2 className="w-3.5 h-3.5 md:w-4 md:h-4" />
                <span className="hidden md:inline">Live Preview</span>
              </button>
            </div>
          )}

          <button
            onClick={() => {
              setIsRightSidebarOpen(!isRightSidebarOpen);
              if (!isRightSidebarOpen) setActiveMobileView('chat');
            }}
            className="md:hidden p-2 text-slate-500 hover:bg-slate-50 rounded-lg transition-colors"
          >
            <MessageSquareCode className="w-5 h-5" />
          </button>
        </div>
      </header>

      <main className="flex-1 flex overflow-hidden relative">
        <aside
