import { useState, useEffect, useRef, useCallback } from 'react';
import { ProjectState } from '../types';
import { saveAutosavedProject, loadAutosavedProject, clearAutosavedProject } from '../services/storage';

const AUTOSAVE_INTERVAL_MS = 30000; // Auto-save every 30 seconds

/**
 * A custom hook to automatically save the current project state to local storage.
 * It also provides status indicators for saving.
 *
 * @param state The ProjectState object to be autosaved.
 * @param projectId The ID of the currently active project (can be null for unsaved new projects).
 * @param lastManualSaveTimestamp Timestamp of the last explicit manual save.
 * @returns An array containing:
 *   - `isSaving`: A boolean indicating if the project is currently being autosaved.
 *   - `autosaveStatusMessage`: A string indicating the status ("Saved", "Saving...", "Error").
 *   - `loadLastAutosave`: A function to load the last autosaved project.
 *   - `clearLastAutosave`: A function to clear the last autosaved project.
 */
export function useAutoSave(
  state: ProjectState,
  projectId: string | null,
  lastManualSaveTimestamp: number | null
) {
  const [isSaving, setIsSaving] = useState(false);
  const [autosaveStatusMessage, setAutosaveStatusMessage] = useState('Standby');
  const stateRef = useRef(state); // Use a ref to get the latest state inside useEffect
  const projectIdRef = useRef(projectId);
  const lastManualSaveTimestampRef = useRef(lastManualSaveTimestamp);

  // Update refs when props change
  useEffect(() => {
    stateRef.current = state;
    projectIdRef.current = projectId;
    lastManualSaveTimestampRef.current = lastManualSaveTimestamp;
  }, [state, projectId, lastManualSaveTimestamp]);

  const triggerAutoSave = useCallback(() => {
    if (!stateRef.current) return;

    // Only autosave if the state has changed since the last autosave,
    // AND if it's different from the last manual save.
    // This prevents autosaving an identical state immediately after a manual save.
    const lastAutosaveData = loadAutosavedProject();
    const currentSerializedState = JSON.stringify(stateRef.current);

    if (
      lastAutosaveData &&
      lastAutosaveData.projectId === projectIdRef.current &&
      // Fix: lastAutosaveData.state is already a ProjectState object, stringify it directly
      JSON.stringify(lastAutosaveData.state) === currentSerializedState
    ) {
      // State hasn't changed since last autosave, or it's the same as what was just autosaved for this project.
      setAutosaveStatusMessage(`Saved ${new Date(lastAutosaveData.timestamp).toLocaleTimeString()}`);
      return;
    }

    if (
      lastManualSaveTimestampRef.current &&
      lastAutosaveData &&
      lastAutosaveData.timestamp < lastManualSaveTimestampRef.current &&
      lastAutosaveData.projectId === projectIdRef.current
    ) {
        // If autosave is older than last manual save for the *same* project,
        // and the current state is likely what was just manually saved,
        // we can assume it's up to date. This is an optimization, not strictly necessary.
        setAutosaveStatusMessage(`Saved ${new Date(lastManualSaveTimestampRef.current).toLocaleTimeString()}`);
        return;
    }


    setIsSaving(true);
    setAutosaveStatusMessage('Saving...');
    try {
      saveAutosavedProject(projectIdRef.current, stateRef.current);
      setAutosaveStatusMessage(`Saved ${new Date().toLocaleTimeString()}`);
    } catch (e) {
      console.error('Autosave failed:', e);
      setAutosaveStatusMessage('Error saving!');
    } finally {
      setIsSaving(false);
    }
  }, []);

  useEffect(() => {
    const intervalId = setInterval(triggerAutoSave, AUTOSAVE_INTERVAL_MS);

    // Initial save after component mounts or state is set the first time
    const timeoutId = setTimeout(triggerAutoSave, 500); // Small delay to avoid race conditions on initial render

    return () => {
      clearInterval(intervalId);
      clearTimeout(timeoutId);
    };
  }, [triggerAutoSave]);

  const loadLastAutosave = useCallback(() => {
    try {
      const autosaved = loadAutosavedProject();
      if (autosaved) {
        return autosaved.state;
      }
    } catch (e) {
      console.error('Failed to load autosaved project:', e);
      alert('Could not load autosaved project. It might be corrupted.');
      clearAutosavedProject();
    }
    return null;
  }, []);

  const clearLastAutosave = useCallback(() => {
    clearAutosavedProject();
    setAutosaveStatusMessage('Standby');
  }, []);

  return { isSaving, autosaveStatusMessage, loadLastAutosave, clearLastAutosave };
}

import { GoogleGenAI, Type } from "@google/genai";

const sleep = (ms: number) => new Promise(resolve => setTimeout(resolve, ms));

/**
 * Executes API calls with high resilience.
 * Handles 429 (Quota) via backoff and 404 (Key Selection) via the studio dialog.
 */
async function executeWithNeuralResilience<T>(operation: (ai: GoogleGenAI) => Promise<T>, maxRetries = 3): Promise<T> {
  let lastError: any;

  for (let attempt = 0; attempt < maxRetries; attempt++) {
    // Fresh instance ensures we pick up the latest injected API key
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    try {
      return await operation(ai);
    } catch (error: any) {
      lastError = error;
      const errorMessage = error?.message || "";

      const isQuotaError = errorMessage.includes("429") || errorMessage.includes("quota") || errorMessage.includes("exhausted") || (error?.code === 429);
      const isNotFoundKeyError = errorMessage.includes("Requested entity was not found") || errorMessage.includes("404") || (error?.code === 404);

      // Handle 404 (Key Selection) - High priority, retry immediately
      if (isNotFoundKeyError) {
        console.warn("Neural Link severed (API Key Not Found). Prompting for API key selection...");
        if (typeof window !== 'undefined' && (window as any).aistudio?.openSelectKey) {
          await (window as any).aistudio.openSelectKey();
          // After key selection, give one more immediate retry attempt with the new key.
          if (attempt === maxRetries - 1) { // If it failed on the last attempt, allow one more.
            maxRetries++; // Temporarily increment maxRetries to allow one extra attempt.
          }
          continue; // Retry immediately.
        }
      }

      // Handle 429 (Rate Limit) with exponential backoff
      if (isQuotaError) {
        if (attempt < maxRetries - 1) {
          const waitTime = Math.pow(2, attempt) * 2000;
          console.warn(`Neural Throttling: Retrying in ${waitTime}ms (Attempt ${attempt + 1}/${maxRetries})...`);
          await sleep(waitTime);
          continue; // Retry after delay.
        } else {
          // All retries exhausted for quota. Throw a more specific, user-friendly error.
          const quotaError = new Error(
            "API Quota Exceeded. You've sent too many requests or exceeded your usage limits. Please check your Google Cloud project's billing and API quotas, or try again later. For more information, visit ai.google.dev/gemini-api/docs/rate-limits."
          );
          (quotaError as any).code = 429; // Attach original error code for potential upstream handling.
          throw quotaError;
        }
      }

      // If it's another type of error or not specifically handled, re-throw the original error.
      throw error;
    }
  }
  // This line should ideally not be reached if an error was thrown or the operation was successful.
  throw lastError; // Re-throw the last recorded error if all attempts fail without specific handling.
}

export const generateGame = async (
  prompt: string,
  assets: GameAsset[],
  history: ChatMessage[] = [],
  currentCode: string = "",
  mode: AIModelMode = 'thinking'
): Promise<{ code: string; title: string; explanation: string; suggestions: string[]; proposedLogicNodes?: string[] }> => {

  const assetMetadata = assets.map(a => ({
    name: a.name,
    type: a.type,
    mimeType: a.mimeType,
    category: a.category,
    isOptimized: !!a.isOptimized,
    logicContext: a.type === 'dialogue' ? a.content : undefined
  }));

  const isRefinement = history.length > 0 && currentCode !== "";

  const systemInstruction = `
    You are the "Core Neural Architect" of ForgeAI Studio. Your mission is to synthesize high-fidelity, fully playable HTML5 games.

    CORE OPERATING MANDATE:
    Deliver a complete, polished 3D simulation using Three.js. The output must be a self-contained substrate.

    I. RESPONSIVE ARCHITECTURE:
    - Implement dynamic window resizing.
    - HUD and UI elements must use flexible CSS layouts or Sprite overlays.

    II. UNIFIED CONTROL SYSTEM:
    - Automatically detect input modality (Touch/Keyboard).
    - MOBILE: Implement a virtual joystick or touch-gestures.
    - DESKTOP: Bind WASD and PointerLock support.

    III. ASSET & MOTION INTEGRATION:
    - Load all binaries via 'window.getAssetUrl(name)'.
    - MANDATORY: Sync "character" assets with "motion" assets using 'THREE.AnimationMixer'.
    - SPECIAL: Use THREE.GLTFLoader for '.glb' and '.gltf' Environment world substrates.

    IV. LOGIC NODE SYNTHESIS:
    - When providing the 'proposedLogicNodes', generate complex behavioral nodes that can be injected into the simulation.
    - Examples: "Level_Start: Initialize Player at Vector3(0,5,0) with Invulnerability for 3s", "Combat_Loop: On Collision(Player, Enemy), decrement Health by 10 and trigger Impulse", "Victory_Condition: If EnemyCount == 0, trigger Scene_Transition('Success')".

    MANDATORY EXPLANATION STRUCTURE:
    [GENRE ANALYSIS]: Mechanical intent and genre conventions.
    [MECHANICAL DERIVATION]: Technical breakdown of physics/input.
    [LOGIC NODE BINDING]: Detail the complex behavioral blueprints being implemented and how they interact with assets.
    [ASSET MAPPING]: Character-motion pairing details.

    RESPONSE FORMAT: JSON with { code, title, explanation, suggestions, proposedLogicNodes }.
  `;

  const userPrompt = isRefinement 
    ? `REFINEMENT: ${prompt}\n\nAssets: ${JSON.stringify(assetMetadata)}\n\nCode: ${currentCode}`
    : `NEW PROJECT: ${prompt}\n\nAssets: ${JSON.stringify(assetMetadata)}`;

  const modelName = mode === 'thinking' ? 'gemini-3-pro-preview' : 'gemini-3-flash-preview';

  const config: any = {
    systemInstruction,
    responseMimeType: "application/json",
    responseSchema: {
      type: Type.OBJECT,
      properties: {
        code: { type: Type.STRING },
        title: { type: Type.STRING },
        explanation: { type: Type.STRING },
        suggestions: { type: Type.ARRAY, items: { type: Type.STRING } },
        proposedLogicNodes: { type: Type.ARRAY, items: { type: Type.STRING }, description: "Actionable logic statements for the project." }
      },
      required: ['code', 'title', 'explanation', 'suggestions']
    }
  };

  if (mode === 'thinking') {
    config.thinkingConfig = { thinkingBudget: 32768 };
  }

  return executeWithNeuralResilience(async (ai) => {
    const response = await ai.models.generateContent({
      model: modelName,
      contents: userPrompt,
      config,
    });
    return JSON.parse(response.text || '{}');
  });
};

