          // After key selection, give one more immediate retry attempt with the new key.
          if (attempt === maxRetries - 1) { // If it failed on the last attempt, allow one more.
            maxRetries++; // Temporarily increment maxRetries to allow one extra attempt.
          }
          continue; // Retry immediately.
        }
      }

      // Handle 429 (Rate Limit) with exponential backoff
      if (isQuotaError) {
        if (attempt < maxRetries - 1) {
          const waitTime = Math.pow(2, attempt) * 2000;
          console.warn(`Neural Throttling: Retrying in ${waitTime}ms (Attempt ${attempt + 1}/${maxRetries})...`);
          await sleep(waitTime);
          continue; // Retry after delay.
        } else {
          // All retries exhausted for quota. Throw a more specific, user-friendly error.
          const quotaError = new Error(
            "API Quota Exceeded. You've sent too many requests or exceeded your usage limits. Please check your Google Cloud project's billing and API quotas, or try again later. For more information, visit ai.google.dev/gemini-api/docs/rate-limits."
          );
          (quotaError as any).code = 429; // Attach original error code for potential upstream handling.
          throw quotaError;
        }
      }

      // If it's another type of error or not specifically handled, re-throw the original error.
      throw error;
    }
  }
  // This line should ideally not be reached if an error was thrown or the operation was successful.
  throw lastError; // Re-throw the last recorded error if all attempts fail without specific handling.
}

export const generateGame = async (
  prompt: string,
  assets: GameAsset[],
  history: ChatMessage[] = [],
  currentCode: string = "",
  mode: AIModelMode = 'thinking'
): Promise<{ code: string; title: string; explanation: string; suggestions: string[]; proposedLogicNodes?: string[] }> => {

  const assetMetadata = assets.map(a => ({
    name: a.name,
    type: a.type,
    mimeType: a.mimeType,
    category: a.category,
    isOptimized: !!a.isOptimized,
    logicContext: a.type === 'dialogue' ? a.content : undefined
  }));

  const isRefinement = history.length > 0 && currentCode !== "";

  const systemInstruction = `
    You are the "Core Neural Architect" of ForgeAI Studio. Your mission is to synthesize high-fidelity, fully playable HTML5 games.

    CORE OPERATING MANDATE:
    Deliver a complete, polished 3D simulation using Three.js. The output must be a self-contained substrate.

    PERFORMANCE OPTIMIZATION MANDATE:
    - Prioritize lightweight, high-performance JavaScript.
    - Minimize object allocations in critical update/render loops to reduce garbage collection overhead.
    - Utilize 'requestAnimationFrame' for smooth animation loops, aligning with browser refresh rates.
    - Employ efficient Three.js rendering techniques:
        - Implement frustum culling for all non-static objects.
        - Consider geometry instancing for repeated objects (e.g., many coins, bullets).
        - Use texture atlases and batching where possible to reduce draw calls.
        - Optimize material usage and texture loading (e.g., power-of-two textures, compressed formats).
        - Avoid unnecessary object traversals or expensive operations within the render loop.
    - Optimize physics calculations: use simple bounding box/sphere checks for initial broad-phase collision detection before more complex narrow-phase tests.
    - Minimize redundant computations in the game loop. Cache results of expensive calculations.
    - Use Web Workers for heavy, non-rendering computations (e.g., complex AI, detailed physics simulations that aren't integrated with Three.js's rendering directly).
    - Implement immutable data patterns for game state where appropriate to prevent unintended side effects and simplify change detection.
    - Favor lazy loading or deferred loading for non-critical assets to improve initial load times.

    I. RESPONSIVE ARCHITECTURE:
    - Implement dynamic window resizing.
    - HUD and UI elements must use flexible CSS layouts or Sprite overlays.

    II. UNIFIED CONTROL SYSTEM:
    - Automatically detect input modality (Touch/Keyboard).
    - MOBILE: Implement a virtual joystick or touch-gestures.
    - DESKTOP: Bind WASD and PointerLock support.

    III. ASSET & MOTION INTEGRATION:
    - Load all binaries via 'window.getAssetUrl(name)'.
    - MANDATORY: Sync "character" assets with "motion" assets using 'THREE.AnimationMixer'.
    - SPECIAL: Use THREE.GLTFLoader for '.glb' and '.gltf' Environment world substrates.

    IV. LOGIC NODE SYNTHESIS:
    - When providing the 'proposedLogicNodes', generate complex behavioral nodes that can be injected into the simulation.
    - Examples: "Level_Start: Initialize Player at Vector3(0,5,0) with Invulnerability for 3s", "Combat_Loop: On Collision(Player, Enemy), decrement Health by 10 and trigger Impulse", "Victory_Condition: If EnemyCount == 0, trigger Scene_Transition('Success')".

    MANDATORY EXPLANATION STRUCTURE:
    [GENRE ANALYSIS]: Mechanical intent and genre conventions.
    [MECHANICAL DERIVATION]: Technical breakdown of physics/input.
    [LOGIC NODE BINDING]: Detail the complex behavioral blueprints being implemented and how they interact with assets.
    [ASSET MAPPING]: Character-motion pairing details.

    RESPONSE FORMAT: JSON with { code, title, explanation, suggestions, proposedLogicNodes }.
  `;

  const userPrompt = isRefinement 
    ? `REFINEMENT: ${prompt}\n\nAssets: ${JSON.stringify(assetMetadata)}\n\nCode: ${currentCode}`
    : `NEW PROJECT: ${prompt}\n\nAssets: ${JSON.stringify(assetMetadata)}`;

  const modelName = mode === 'thinking' ? 'gemini-3-pro-preview' : 'gemini-3-flash-preview';

  const config: any = {
    systemInstruction,
    responseMimeType: "application/json",
    responseSchema: {
      type: Type.OBJECT,
      properties: {
        code: { type: Type.STRING },
        title: { type: Type.STRING },
        explanation: { type: Type.STRING },
        suggestions: { type: Type.ARRAY, items: { type: Type.STRING } },
        proposedLogicNodes: { type: Type.ARRAY, items: { type: Type.STRING }, description: "Actionable logic statements for the project." }
      },
      required: ['code', 'title', 'explanation', 'suggestions']
    }
  };

  if (mode === 'thinking') {
    config.thinkingConfig = { thinkingBudget: 32768 };
  }

  return executeWithNeuralResilience(async (ai) => {
    const response = await ai.models.generateContent({
      model: modelName,
      contents: userPrompt,
      config,
    });
    return JSON.parse(response.text || '{}');
  });
};

export const brainstormGame = async (assets: GameAsset[]): Promise<string> => {
  const assetMetadata = assets.map(a => ({ name: a.name, type: a.type, category: a.category }));

  return executeWithNeuralResilience(async (ai) => {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: `Generate a Lead Game Architect Design Report for these assets: ${JSON.stringify(assetMetadata)}. Focus on synergies between character animations and glTF environment layouts.`,
      config: {
        thinkingConfig: { thinkingBudget: 16000 }
      }
    });
    return response.text || "Synthesis error.";
  });
};

export const generateLogicNodes = async (prompt: string, assets: GameAsset[]): Promise<string[]> => {
  const assetMetadata = assets.map(a => ({ name: a.name, type: a.type, category: a.category }));

  return executeWithNeuralResilience(async (ai) => {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: `Prompt: ${prompt}\n\nAssets: ${JSON.stringify(assetMetadata)}\n\nGenerate 5-7 complex, actionable game logic nodes (short behavioral statements) for this project.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: { type: Type.STRING }
        },
        thinkingConfig: { thinkingBudget: 10000 }
      }
    });
    return JSON.parse(response.text || '[]');
  });
};
